fn assert_compile_repeated_function_body(snippet: &str, is_async: bool) {
    for repeats in 1..=4 {
        let mut source = String::new();
        if is_async {
            source.push_str("async ");
        }
        source.push_str("def func():\n");
        for _ in 0..repeats {
            for line in snippet.trim_matches('\n').lines() {
                source.push_str("    ");
                source.push_str(line);
                source.push('\n');
            }
        }
        assert_compile_ok(&source);
    }
}

