fn assert_token_span(
    token: &SpannedToken,
    expected_token: Token,
    expected_line: usize,
    expected_column: usize,
    expected_end_line: usize,
    expected_end_column: usize,
) {
    assert_eq!(token.token, expected_token);
    assert_eq!(token.line, expected_line);
    assert_eq!(token.column, expected_column);
    assert_eq!(token.end_line, expected_end_line);
    assert_eq!(token.end_column, expected_end_column);
}

fn spanned_token_text(source: &str, token: &SpannedToken) -> String {
    source
        .chars()
        .skip(token.start)
        .take(token.end - token.start)
        .collect()
}

fn assert_token_text(
    source: &str,
    token: &SpannedToken,
    expected_token: Token,
    expected_text: &str,
) {
    assert_eq!(token.token, expected_token);
    assert_eq!(spanned_token_text(source, token), expected_text);
}

fn assert_token_text_span(
    source: &str,
    token: &SpannedToken,
    expected_token: Token,
    expected_text: &str,
    expected_line: usize,
    expected_column: usize,
    expected_end_line: usize,
    expected_end_column: usize,
) {
    assert_token_text(source, token, expected_token, expected_text);
    assert_eq!(token.line, expected_line);
    assert_eq!(token.column, expected_column);
    assert_eq!(token.end_line, expected_end_line);
    assert_eq!(token.end_column, expected_end_column);
}

fn assert_token_kinds(source: &str, expected: Vec<Token>) {
    let mut actual = tokenize_with_spans(source)
        .unwrap_or_else(|error| panic!("tokenize failed for {source:?}: {error:?}"))
        .into_iter()
        .map(|token| token.token)
        .collect::<Vec<_>>();
    assert_eq!(actual.pop(), Some(Token::Eof), "source:\n{source}");
    if actual.last() == Some(&Token::Newline) {
        actual.pop();
    }
    assert_eq!(actual, expected, "source:\n{source}");
}

fn first_number_token_text(source: &str) -> Result<Option<String>, String> {
    let tokens = tokenize_with_spans(source).map_err(|error| error.message)?;
    Ok(tokens
        .iter()
        .find(|token| {
            matches!(
                token.token,
                Token::Number(_) | Token::BigInt(_) | Token::Float(_) | Token::Imaginary(_)
            )
        })
        .map(|token| spanned_token_text(source, token)))
}

