// Adapted from CPython's shared `VALID_UNDERSCORE_LITERALS` table in
// Lib/test/support/numbers.py. CPython checks that each literal evaluates the
// same as the same spelling with underscores removed.
#[test]
fn cpython_valid_underscore_number_literals_subset() {
    for literal in [
        "0_0_0",
        "4_2",
        "1_0000_0000",
        "0b1001_0100",
        "0xffff_ffff",
        "0o5_7_7",
        "1_00_00.5",
        "1_00_00.5e5",
        "1_00_00e5_1",
        "1e1_0",
        ".1_4",
        ".1_4e1",
        "0b_0",
        "0x_f",
        "0o_5",
        "1_00_00j",
        "1_00_00.5j",
        "1_00_00e5_1j",
        ".1_4j",
        "(1_2.5+3_3j)",
        "(.5_6j)",
    ] {
        let normalized = literal.replace('_', "");
        assert_output(&format!("print({literal} == {normalized})"), &["True"]);
    }
}

