// Adapted from CPython grammar coverage in
// Lib/test/test_grammar.py::test_float_exponent_tokenization. CPython accepts
// lowercase keyword boundaries such as `1else` as `1 else`, while rejecting the
// non-keyword `1Else` spelling at parse time.
#[test]
fn cpython_float_exponent_tokenization_subset() {
    assert_eval("1 if 1else 0", "1");
    assert_eval("1 if 0else 0", "0");
    assert_rejected("0 if 1Else 0");
}

// Adapted from CPython grammar coverage in
// Lib/test/test_grammar.py::test_end_of_numerical_literals. MiniPython checks
// both accepted/rejected source shapes and the tokenizer SyntaxWarning messages
// that CPython emits for number-keyword boundaries.
#[test]
fn cpython_end_of_numerical_literals_subset() {
    fn assert_eval_warning(source: &str, expected: &str) {
        assert_eval_parse_ok(source);
        assert_warnings(source, &[expected]);
    }

    fn assert_eval_lex_error_no_warnings(source: &str, expected: &str) {
        assert_eq!(
            parse_eval_source(source),
            Err(format!("lex error: {expected}")),
            "source:\n{source}"
        );
        assert_eq!(
            source_warnings(source),
            Err(format!("lex error: {expected}")),
            "source:\n{source}"
        );
    }

    let literal_cases = [
        ("0xf", "invalid hexadecimal literal", None),
        ("0o7", "invalid octal literal", None),
        ("0b1", "invalid binary literal", None),
        ("9", "invalid decimal literal", None),
        (
            "0",
            "invalid decimal literal",
            Some("invalid octal literal"),
        ),
        ("1.", "invalid decimal literal", None),
        ("1e3", "invalid decimal literal", None),
        ("1j", "invalid imaginary literal", None),
    ];

    for (literal, warning, or_error) in literal_cases {
        assert_eval_parse_ok(literal);

        let and_case = format!("{literal}and x");
        if literal == "0xf" {
            assert_eval_lex_error_no_warnings(&and_case, warning);
        } else {
            assert_eval_warning(&and_case, warning);
        }

        let or_case = format!("{literal}or x");
        if let Some(or_error) = or_error {
            assert_eval_lex_error_no_warnings(&or_case, or_error);
        } else {
            assert_eval_warning(&or_case, warning);
        }

        for source in [
            format!("{literal}in x"),
            format!("{literal}not in x"),
            format!("{literal}if x else y"),
        ] {
            assert_eval_warning(&source, warning);
        }

        let else_case = format!("x if {literal}else y");
        if literal == "0xf" {
            assert_eval_lex_error_no_warnings(&else_case, warning);
        } else {
            assert_eval_warning(&else_case, warning);
        }

        assert_eval_warning(&format!("[{literal}for x in ()]"), warning);
        assert_eval_lex_error_no_warnings(&format!("{literal}spam"), warning);
        assert_eval_lex_error_no_warnings(
            &format!("{literal}⁄7"),
            "invalid character '⁄' (U+2044)",
        );

        let is_case = format!("{literal}is x");
        assert_eval_warning(&is_case, warning);
        assert_warning_as_error(&is_case, warning);
    }

    for source in ["[0x1ffor x in ()]", "[0x1for x in ()]", "[0xfor x in ()]"] {
        assert_eval_warning(source, "invalid hexadecimal literal");
    }

    assert_lex_error_diagnostic("0or True", "invalid octal literal", 1, 1, 1, 4);
    assert_lex_error_diagnostic("0xfelse", "invalid hexadecimal literal", 1, 1, 1, 8);
    assert_lex_error_diagnostic("0xfspam", "invalid hexadecimal literal", 1, 1, 1, 8);
    assert_lex_error_diagnostic("1spam", "invalid decimal literal", 1, 1, 1, 6);
    assert_lex_error_diagnostic("1Else", "invalid decimal literal", 1, 1, 1, 6);
    assert_lex_error_diagnostic("1jspam", "invalid imaginary literal", 1, 1, 1, 7);
    assert_lex_error_diagnostic("0xfand True", "invalid hexadecimal literal", 1, 1, 1, 7);
    assert_lex_error_diagnostic("1⁄7", "invalid character '⁄' (U+2044)", 1, 2, 1, 3);
    assert_lex_error_diagnostic("0xf⁄7", "invalid character '⁄' (U+2044)", 1, 4, 1, 5);
    assert_warning_as_error_diagnostic("1and x", "invalid decimal literal", 1, 2, 1, 5);
    assert_warning_as_error_diagnostic("0xfis x", "invalid hexadecimal literal", 1, 4, 1, 6);
}

#[test]
fn cpython_numeric_literal_warning_subset() {
    for source in [
        "9and x",
        "9or x",
        "9in x",
        "9not in x",
        "9if x else y",
        "x if 9else y",
        "[9for x in ()]",
        "9is x",
        "0and x",
        "0in x",
        "0not in x",
        "0if x else y",
        "x if 0else y",
        "[0for x in ()]",
        "0is x",
        "1.and x",
        "1.or x",
        "1.in x",
        "1.not in x",
        "1.if x else y",
        "x if 1.else y",
        "[1.for x in ()]",
        "1.is x",
        "1e3and x",
        "1e3or x",
        "1e3in x",
        "1e3not in x",
        "1e3if x else y",
        "x if 1e3else y",
        "[1e3for x in ()]",
        "1e3is x",
        "1and x",
        "1else x",
    ] {
        assert_warnings(source, &["invalid decimal literal"]);
    }

    for source in [
        "1jand x",
        "1jor x",
        "1jin x",
        "1jnot in x",
        "1jif x else y",
        "x if 1jelse y",
        "[1jfor x in ()]",
        "1jis x",
    ] {
        assert_warnings(source, &["invalid imaginary literal"]);
    }

    for source in [
        "0b1and x",
        "0b1or x",
        "0b1in x",
        "0b1not in x",
        "0b1if x else y",
        "x if 0b1else y",
        "[0b1for x in ()]",
        "0b1is x",
        "0b1and 2",
    ] {
        assert_warnings(source, &["invalid binary literal"]);
    }

    for source in [
        "0o7and x",
        "0o7or x",
        "0o7in x",
        "0o7not in x",
        "0o7if x else y",
        "x if 0o7else y",
        "[0o7for x in ()]",
        "0o7is x",
    ] {
        assert_warnings(source, &["invalid octal literal"]);
    }

    for source in [
        "0xfor x",
        "0xfin x",
        "0xfnot in x",
        "0xfif x else y",
        "[0xffor x in ()]",
        "0xfis x",
    ] {
        assert_warnings(source, &["invalid hexadecimal literal"]);
    }
}

// Adapted from CPython's bad numerical literal coverage in
// Lib/test/test_grammar.py::test_bad_numerical_literals and the shared
// INVALID_UNDERSCORE_LITERALS table in Lib/test/support/numbers.py.
#[test]
fn cpython_bad_numerical_literals_subset() {
    for source in [
        "0b12",
        "0b1_2",
        "0b2",
        "0b1_",
        "0b",
        "0o18",
        "0o1_8",
        "0o8",
        "0o1_",
        "0o",
        "0x1_",
        "0x",
        "1_",
        "012",
        "1.2_",
        "1e2_",
        "1e+",
        "0_",
        "42_",
        "1.4j_",
        "0x_",
        "0xf_",
        "0o5_",
        "0_b0",
        "0_xf",
        "0_o5",
        "0_7",
        "09_99",
        "4_______2",
        "0.1__4",
        "0.1__4j",
        "0b1001__0100",
        "0xffff__ffff",
        "0x___",
        "0o5__77",
        "1e1__0",
        "1e1__0j",
        "1_.4",
        "1_.4j",
        "1._4",
        "1._4j",
        "._5",
        "._5j",
        "1.0e+_1",
        "1.0e+_1j",
        "1.4_j",
        "1.4e5_j",
        "1_e1",
        "1.4_e1",
        "1.4_e1j",
        "1e_1",
        "1.4e_1",
        "1.4e_1j",
        "(1+1.5_j_)",
        "(1+1.5_j)",
        "077787",
        "0xj",
        "0x.",
        "0e",
        "090000000000000",
        "080000000000000",
        "000000000000009",
        "000000000000008",
        "0b42",
        "0BADCAFE",
        "0o123456789",
        "0b1.1",
        "0o4.2",
        "0b101j",
        "0o153j",
        "0b100e1",
        "0o777e1",
        "0777",
        "000777",
        "000000000000007",
    ] {
        assert_rejected(source);
    }

    assert_lex_error_diagnostic("0b12", "invalid digit '2' in binary literal", 1, 1, 1, 5);
    assert_lex_error_diagnostic("0o18", "invalid digit '8' in octal literal", 1, 1, 1, 5);
    assert_lex_error_diagnostic("0x", "invalid hexadecimal literal", 1, 1, 1, 3);
    assert_lex_error_diagnostic("0b1_", "invalid binary literal", 1, 1, 1, 5);
    assert_lex_error_diagnostic("1e+", "invalid decimal literal", 1, 1, 1, 4);
    assert_lex_error_diagnostic(
        "012",
        "leading zeros in decimal integer literals are not permitted; use an 0o prefix for octal integers",
        1,
        1,
        1,
        4,
    );
    assert_lex_error_diagnostic("1_.4", "invalid decimal literal", 1, 1, 1, 5);
    assert_lex_error_diagnostic("._5", "invalid decimal literal", 1, 1, 1, 4);
    assert_lex_error_diagnostic("1.4j_", "invalid number: 1.4j_", 1, 1, 1, 6);
}

// Adapted from CPython Lib/test/test_compile.py::test_literals_with_leading_zeroes.
// Decimal integers with meaningful leading zeroes are invalid, but the same
// leading zero text is accepted when the literal is a float, exponent form, or
// imaginary number.
#[test]
fn cpython_compile_literals_with_leading_zeroes_subset() {
    assert_output(
        "print(0xff, 0b101010, -0b000000000010, 0o777, -0o0000010)",
        &["255 42 -2 511 -8"],
    );
    assert_output(
        "print(0777., 0777.0, 000000000000000000000000000000000000000000000000000777e0)\nprint(0777e1, 0e0, 0000e-012, 09.5)\nprint(0777j, 000, 00j, 00.0)\nprint(0e3, 090000000000000., 090000000000000.0000000000000000000000)\nprint(090000000000000e0, 090000000000000e-0, 090000000000000j)\nprint(000000000000008., 000000000000009.)",
        &[
            "777.0 777.0 777.0",
            "7770.0 0.0 0.0 9.5",
            "777j 0 0j 0.0",
            "0.0 90000000000000.0 90000000000000.0",
            "90000000000000.0 90000000000000.0 90000000000000j",
            "8.0 9.0",
        ],
    );
}

// Adapted from CPython grammar NUMBER coverage in
// Lib/test/test_grammar.py::test_disallow_kwargs_after_starargs and underscore
// literal coverage in Lib/test/support/numbers.py, plus complex repr
// expectations in Lib/test/test_complex.py. MiniPython covers imaginary
// literals and the arithmetic form Python uses to build complex numbers.
#[test]
fn cpython_grammar_imaginary_literals_subset() {
    assert_eval("1j", "1j");
    assert_eval(".5j", "0.5j");
    assert_eval("1.j", "1j");
    assert_eval("1e3j", "1000j");
    assert_eval("1 + 2j", "(1+2j)");
    assert_eval("1 - 2j", "(1-2j)");
    assert_eval("-1j", "(-0-1j)");
    assert_eval("-0j", "(-0-0j)");
    assert_output(
        "print(1_00_00j, 1_00_00.5j, .1_4j, (1_2.5+3_3j), (.5_6j))",
        &["10000j 10000.5j 0.14j (12.5+33j) 0.56j"],
    );
    assert_error("1.4j_", "lex error: invalid number: 1.4j_");
}

// Adapted from CPython Lib/test/test_float.py::GeneralFloatCases::test_float,
// ::test_noargs, ::test_error_message, and the locale-independent assertions
// from ::test_float_with_comma. The lone-surrogate row is intentionally left
// out because Rust strings cannot represent isolated surrogate code points.
#[test]
fn cpython_float_constructor_core_subset() {
    assert_output(
        r#"def show(label, expr):
    try:
        value = expr()
        print(label, repr(value), type(value).__name__)
    except BaseException as error:
        print(label, type(error).__name__, error.args[0])

for label, expr in [
    ('noargs', lambda: float()),
    ('float-float', lambda: float(3.14)),
    ('float-int', lambda: float(314)),
    ('float-spaces', lambda: float('  3.14  ')),
    ('arabic-digits', lambda: float('  ٣.١٤  ')),
    ('unicode-space', lambda: float('\u20033.14\u2002')),
    ('long-bytes', lambda: float(b'.' + b'1' * 1000)),
    ('long-str', lambda: float('.' + '1' * 1000)),
    ('comma', lambda: float('  3,14  ')),
    ('plus-comma', lambda: float('  +3,14  ')),
    ('minus-comma', lambda: float('  -3,14  ')),
    ('bad-hex-a', lambda: float('  0x3.1  ')),
    ('bad-hex-b', lambda: float('  -0x3.p-1  ')),
    ('bad-hex-c', lambda: float('  +0x3.p-1  ')),
    ('bad-sign-pp', lambda: float('++3.14')),
    ('bad-sign-pm', lambda: float('+-3.14')),
    ('bad-sign-mp', lambda: float('-+3.14')),
    ('bad-sign-mm', lambda: float('--3.14')),
    ('bad-dotnan', lambda: float('.nan')),
    ('bad-dotinf', lambda: float('+.inf')),
    ('bad-dot', lambda: float('.')),
    ('bad-negdot', lambda: float('-.')),
    ('bad-dict', lambda: float({})),
    ('bad-d-exp', lambda: float('-1.7d29')),
    ('bad-D-exp', lambda: float('3D-14')),
    ('bad-japanese', lambda: float('こんにちは')),
    ('bad-half', lambda: float('½')),
    ('bad-mixed-half', lambda: float('123½')),
    ('bad-embedded-space', lambda: float('  123 456  ')),
    ('bad-bytes-space', lambda: float(b'  123 456  ')),
    ('bad-empty', lambda: float('')),
    ('bad-space', lambda: float(' ')),
    ('bad-whitespace', lambda: float('\t \n')),
    ('bad-arabic-suffix', lambda: float('٣١٤!')),
    ('bad-nul-a', lambda: float('123\0')),
    ('bad-nul-b', lambda: float('123\0 245')),
    ('bad-nul-c', lambda: float('123\x00245')),
    ('bad-bytes-nul', lambda: float(b'123\0')),
    ('bad-bytes-nonutf8', lambda: float(b'123\xa0')),
]:
    show(label, expr)"#,
        &[
            "noargs 0.0 float",
            "float-float 3.14 float",
            "float-int 314.0 float",
            "float-spaces 3.14 float",
            "arabic-digits 3.14 float",
            "unicode-space 3.14 float",
            "long-bytes 0.1111111111111111 float",
            "long-str 0.1111111111111111 float",
            "comma ValueError could not convert string to float: '  3,14  '",
            "plus-comma ValueError could not convert string to float: '  +3,14  '",
            "minus-comma ValueError could not convert string to float: '  -3,14  '",
            "bad-hex-a ValueError could not convert string to float: '  0x3.1  '",
            "bad-hex-b ValueError could not convert string to float: '  -0x3.p-1  '",
            "bad-hex-c ValueError could not convert string to float: '  +0x3.p-1  '",
            "bad-sign-pp ValueError could not convert string to float: '++3.14'",
            "bad-sign-pm ValueError could not convert string to float: '+-3.14'",
            "bad-sign-mp ValueError could not convert string to float: '-+3.14'",
            "bad-sign-mm ValueError could not convert string to float: '--3.14'",
            "bad-dotnan ValueError could not convert string to float: '.nan'",
            "bad-dotinf ValueError could not convert string to float: '+.inf'",
            "bad-dot ValueError could not convert string to float: '.'",
            "bad-negdot ValueError could not convert string to float: '-.'",
            "bad-dict TypeError float() argument must be a string or a real number, not 'dict'",
            "bad-d-exp ValueError could not convert string to float: '-1.7d29'",
            "bad-D-exp ValueError could not convert string to float: '3D-14'",
            "bad-japanese ValueError could not convert string to float: 'こんにちは'",
            "bad-half ValueError could not convert string to float: '½'",
            "bad-mixed-half ValueError could not convert string to float: '123½'",
            "bad-embedded-space ValueError could not convert string to float: '  123 456  '",
            "bad-bytes-space ValueError could not convert string to float: b'  123 456  '",
            "bad-empty ValueError could not convert string to float: ''",
            "bad-space ValueError could not convert string to float: ' '",
            "bad-whitespace ValueError could not convert string to float: '\\t \\n'",
            "bad-arabic-suffix ValueError could not convert string to float: '٣١٤!'",
            "bad-nul-a ValueError could not convert string to float: '123\\x00'",
            "bad-nul-b ValueError could not convert string to float: '123\\x00 245'",
            "bad-nul-c ValueError could not convert string to float: '123\\x00245'",
            "bad-bytes-nul ValueError could not convert string to float: b'123\\x00'",
            "bad-bytes-nonutf8 ValueError could not convert string to float: b'123\\xa0'",
        ],
    );
}

// Adapted from CPython Lib/test/test_float.py::GeneralFloatCases::
