// Adapted from CPython float numeric-protocol coverage in
// Lib/test/test_float.py::test_is_integer and ::test_floatasratio, plus the
// documented float real/imag/conjugate attributes.
#[test]
fn cpython_float_ratio_and_component_methods_subset() {
    assert_output(
        "for value in [0.875, -0.875, 0.0, 11.5, 2.1, -2.1, -2100.0]:\n    print(value.real, value.imag, value.conjugate(), value.is_integer(), value.as_integer_ratio())",
        &[
            "0.875 0.0 0.875 False (7, 8)",
            "-0.875 0.0 -0.875 False (-7, 8)",
            "0.0 0.0 0.0 True (0, 1)",
            "11.5 0.0 11.5 False (23, 2)",
            "2.1 0.0 2.1 False (4728779608739021, 2251799813685248)",
            "-2.1 0.0 -2.1 False (-4728779608739021, 2251799813685248)",
            "-2100.0 0.0 -2100.0 True (-2100, 1)",
        ],
    );
    assert_output(
        "for text in ['inf', '-inf', 'nan']:\n    value = float(text)\n    print(value.is_integer())\n    try:\n        print(value.as_integer_ratio())\n    except Exception as error:\n        print(error.__class__.__name__, error)",
        &[
            "False",
            "OverflowError cannot convert Infinity to integer ratio",
            "False",
            "OverflowError cannot convert Infinity to integer ratio",
            "False",
            "ValueError cannot convert NaN to integer ratio",
        ],
    );
}

