// Adapted from CPython token coverage for ATEQUAL and ELLIPSIS in
// Grammar/Tokens, plus Lib/test/test_grammar.py::test_matrix_mul and
// Lib/test/test_operator.py::test_matmul coverage for `@` object protocol
// dispatch.
#[test]
fn cpython_tokenize_matrix_multiply_and_ellipsis_subset() {
    assert_output(
        "print(...)\nprint(Ellipsis)\nprint(... is Ellipsis)",
        &["Ellipsis", "Ellipsis", "True"],
    );
    assert_output(
        "try:\n    print(1 @ 2)\nexcept TypeError as error:\n    print(type(error).__name__, str(error))",
        &["TypeError unsupported operand type(s) for @: 'int' and 'int'"],
    );
    assert_output(
        "try:\n    x = 1\n    x @= 2\nexcept TypeError as error:\n    print(type(error).__name__, str(error))",
        &["TypeError unsupported operand type(s) for @=: 'int' and 'int'"],
    );
    assert_output(
        "class M:\n    def __matmul__(self, other):\n        return 4\n    def __imatmul__(self, other):\n        self.other = other\n        return self\nm = M()\nprint(m @ m)\nm @= 42\nprint(m.other)",
        &["4", "42"],
    );
    assert_output(
        "class M:\n    def __matmul__(self, other):\n        return other - 1\nprint(M() @ 42)",
        &["41"],
    );
    assert_output(
        "class M:\n    def __rmatmul__(self, other):\n        return other + 2\nprint(40 @ M())",
        &["42"],
    );
    assert_output(
        concat!(
            "class Left:\n",
            "    def __matmul__(self, other):\n",
            "        return NotImplemented\n",
            "class Right:\n",
            "    def __rmatmul__(self, other):\n",
            "        return 'right'\n",
            "print(Left() @ Right())\n",
        ),
        &["right"],
    );
}

