// Adapted from CPython's invalid arithmetic/factor grammar rules. MiniPython
// rejects the same unparenthesized `not` forms after arithmetic operators.
#[test]
fn cpython_invalid_arithmetic_and_factor_syntax_subset() {
    for source in [
        "print(1 + not 2)",
        "print(1 - not 2)",
        "print(1 * not 2)",
        "print(1 / not 2)",
        "print(1 % not 2)",
        "print(1 // not 2)",
        "print(1 @ not 2)",
        "print(+not 2)",
        "print(-not 2)",
        "print(~not 2)",
    ] {
        assert_error(
            source,
            "parse error: 'not' after an operator must be parenthesized",
        );
    }

    assert_output("print(not 0)", &["True"]);
    assert_output("print((not 0))", &["True"]);
}

// Adapted from CPython expression grammar for bitwise and shift expressions.
// MiniPython currently supports integer-only bitwise operators.
#[test]
fn cpython_grammar_bitwise_and_shift_subset() {
    assert_output("x = 1 & 1", &[]);
    assert_output("x = 1 ^ 1", &[]);
    assert_output("x = 1 | 1", &[]);
    assert_output("x = 1 << 1", &[]);
    assert_output("x = 1 >> 1", &[]);
    assert_output("x = 1 << 1 >> 1", &[]);
    assert_output("print(1 | 2, 3 ^ 1, 6 & 3)", &["3 2 2"]);
    assert_output("print(1 << 3, 8 >> 1)", &["8 4"]);
    assert_output("print(1 + 2 << 2, 8 >> 1 + 1)", &["12 2"]);
    assert_output("print(1 & 1, 1 ^ 1, 1 | 1)", &["1 0 1"]);
    assert_output("print(1 << 1, 1 >> 1, 1 << 1 >> 1)", &["2 0 1"]);
}

// Adapted from CPython expression grammar for conditional expressions:
// `disjunction 'if' disjunction 'else' expression`. The last case verifies
// right associativity and branch short-circuiting in MiniPython.
#[test]
fn cpython_grammar_conditional_expression_subset() {
    assert_output("print(1 if True else 2)", &["1"]);
    assert_output("print(1 if False else 2)", &["2"]);
    assert_output("print(\"yes\" if 1 < 2 else \"no\")", &["yes"]);
    assert_output("print(1 if True else unknown)", &["1"]);
    assert_output("print(1 if False else 2 if True else 3)", &["2"]);
}

// Adapted from CPython Lib/test/test_grammar.py::GrammarTests.test_if_else_expr.
// This keeps the method-level conditional-expression precedence and
// short-circuiting cases together, including lambdas inside comprehensions.
#[test]
fn cpython_grammar_if_else_expr_method_subset() {
    let source = r#"def _checkeval(msg, ret):
    print(msg)
    return ret

print([x() for x in (lambda: True, lambda: False) if x()])
print([x(False) for x in (lambda x: False if x else True, lambda x: True if x else False) if x(False)])
print(5 if 1 else _checkeval("check 1", 0))
print(_checkeval("check 2", 0) if 0 else 5)
print(5 and 6 if 0 else 1)
print((5 and 6) if 0 else 1)
print(5 and (6 if 1 else 1))
print(0 or _checkeval("check 3", 2) if 0 else 3)
print(1 or _checkeval("check 4", 2) if 1 else _checkeval("check 5", 3))
print(0 or 5 if 1 else _checkeval("check 6", 3))
print(not 5 if 1 else 1)
print(not 5 if 0 else 1)
print(6 + 1 if 1 else 2)
print(6 - 1 if 1 else 2)
print(6 * 2 if 1 else 4)
print(6 / 2 if 1 else 3)
print(6 < 4 if 0 else 2)"#;
    assert_output(
        source,
        &[
            "[True]", "[True]", "5", "5", "1", "1", "6", "3", "1", "5", "False", "1", "7", "5",
            "12", "3.0", "2",
        ],
    );
}

// Adapted from CPython's internal `expression_without_invalid` grammar rule.
