// First public `ast` module slice. CPython's Lib/ast.py routes parse() through
// compile(..., PyCF_ONLY_AST); MiniPython now exposes the same entry point, but
// ast.dump() still returns the internal parser dump while the public AST node
// tree is being built out.
#[test]
fn cpython_ast_module_parse_dump_first_pass_subset() {
    assert_output(
        "import ast\nnode = ast.parse('x = 1')\nprint(type(node).__name__, type(node) == ast.Module)\nassign = node.body[0]\ntarget = assign.targets[0]\nprint(node._fields, assign._fields)\nprint(type(assign).__name__, isinstance(assign, ast.Assign), isinstance(node, ast.AST))\nprint(target.id, type(target.ctx).__name__, assign.value.value)\ndump = ast.dump(node)\nprint('Assign' in dump, 'Name' in dump, 'Constant' in dump)\nexpr = ast.parse('1 + 2', mode='eval')\nprint(type(expr).__name__)\nprint(type(expr.body).__name__, type(expr.body.op).__name__, 'BinOp' in ast.dump(expr), 'Add' in ast.dump(expr))\nsingle = ast.parse('1 + 2', mode='single')\nprint(type(single).__name__)\nfunc_type = ast.parse('(int, str) -> bool', mode='func_type')\nprint(type(func_type).__name__, 'FunctionType' in ast.dump(func_type))\nprint(ast.parse(node) is node)\nprint(ast.PyCF_ONLY_AST)",
        &[
            "Module True",
            "('body', 'type_ignores') ('targets', 'value', 'type_comment')",
            "Assign True True",
            "x Store 1",
            "True True True",
            "Expression",
            "BinOp Add True True",
            "Interactive",
            "FunctionType True",
            "True",
            "1024",
        ],
    );
    assert_output(
        "import ast\nfor call in [lambda: ast.parse(123), lambda: ast.parse('1', 123), lambda: ast.parse('1', mode='bad'), lambda: ast.dump('x')]:\n    try:\n        call()\n    except (TypeError, ValueError) as error:\n        print(error.__class__.__name__)",
        &["TypeError", "TypeError", "ValueError", "TypeError"],
    );
    assert_output(
        "import ast\nclass S(str):\n    pass\nclass B(bytes):\n    pass\nclass BA(bytearray):\n    pass\nfor source in [S('x = 1'), B(b'x = 2'), BA(b'x = 3')]:\n    node = ast.parse(source)\n    print(type(source).__name__, type(node).__name__, type(node.body[0]).__name__)",
        &["S Module Assign", "B Module Assign", "BA Module Assign"],
    );
    assert_output(
        "import ast\nclass S(str):\n    pass\nnode = ast.parse('1 + 2', mode=S('eval'))\nprint(type(node).__name__, type(node.body).__name__)",
        &["Expression BinOp"],
    );
    assert_output(
        "import ast\nclass S(str):\n    pass\nclass B(bytes):\n    pass\nclass FakePath:\n    def __init__(self, path):\n        self.path = path\n    def __fspath__(self):\n        return self.path\nfor filename in [S('<afile>'), B(b'<bfile>'), FakePath(S('<apath>')), FakePath(B(b'<bpath>'))]:\n    node = ast.parse('x = 1', filename=filename)\n    print(type(filename).__name__, type(node).__name__, type(node.body[0]).__name__)\nclass BadPath:\n    def __fspath__(self):\n        return 123\ntry:\n    ast.parse('x = 1', filename=BadPath())\nexcept TypeError as error:\n    print(error.__class__.__name__, 'BadPath.__fspath__' in str(error), str(error).endswith('not int'))",
        &[
            "S Module Assign",
            "B Module Assign",
            "FakePath Module Assign",
            "FakePath Module Assign",
            "TypeError True True",
        ],
    );
    assert_output(
        "import ast\nclass S(str):\n    pass\nclass FakePath:\n    def __init__(self, path):\n        self.path = path\n    def __fspath__(self):\n        return self.path\nfor label, filename in [('str-subclass', S('<sfile>')), ('path-str-subclass', FakePath(S('<psfile>')),)]:\n    try:\n        ast.parse('x =', filename=filename)\n    except SyntaxError as error:\n        print(label, repr(error.filename), type(error.filename).__name__, error.args[1][0] is error.filename)",
        &[
            "str-subclass '<sfile>' S True",
            "path-str-subclass '<psfile>' S True",
        ],
    );
}

// Adapted from CPython `Lib/test/test_ast/test_ast.py::AST_Tests.test_null_bytes`.
#[test]
fn cpython_ast_parse_null_bytes_subset() {
    assert_output(
        r#"import ast
try:
    ast.parse("a\0b")
except SyntaxError as error:
    print(error.__class__.__name__, str(error) == "source code string cannot contain null bytes")
    print(error.args)
    print(error.msg)
    print(error.text, error.filename, error.lineno, error.offset, error.end_lineno, error.end_offset)
else:
    print("no error")"#,
        &[
            "SyntaxError True",
            "('source code string cannot contain null bytes',)",
            "source code string cannot contain null bytes",
            "None None None None None None",
        ],
    );
}

// Adapted from CPython `AST_Tests.test_issue18374_binop_col_offset` and
// `AST_Tests.test_issue39579_dotted_name_end_col_offset`.
#[test]
fn cpython_ast_binop_and_dotted_decorator_locations_subset() {
    assert_output(
        r#"import ast
tree = ast.parse('4+5+6+7')
parent_binop = tree.body[0].value
child_binop = parent_binop.left
grandchild_binop = child_binop.left
print(parent_binop.col_offset, parent_binop.end_col_offset)
print(child_binop.col_offset, child_binop.end_col_offset)
print(grandchild_binop.col_offset, grandchild_binop.end_col_offset)

tree = ast.parse('4+5-\\\n 6-7')
parent_binop = tree.body[0].value
child_binop = parent_binop.left
grandchild_binop = child_binop.left
print(parent_binop.col_offset, parent_binop.lineno, parent_binop.end_col_offset, parent_binop.end_lineno)
print(child_binop.col_offset, child_binop.lineno, child_binop.end_col_offset, child_binop.end_lineno)
print(grandchild_binop.col_offset, grandchild_binop.lineno, grandchild_binop.end_col_offset, grandchild_binop.end_lineno)

tree = ast.parse('@a.b.c\ndef f(): pass')
attr_b = tree.body[0].decorator_list[0].value
print(attr_b.end_col_offset)"#,
        &["0 7", "0 5", "0 3", "0 1 4 2", "0 1 2 2", "0 1 3 1", "4"],
    );
}

// Adapted from CPython `Lib/test/test_ast/test_ast.py::AST_Tests.test_tstring`.
#[test]
fn cpython_ast_tstring_structure_subset() {
    assert_output(
        r#"import ast
tree = ast.parse('t"Hello"')
value = tree.body[0].value
print(isinstance(value, ast.TemplateStr), isinstance(value.values[0], ast.Constant))

tree = ast.parse('t"Hello {name}"')
value = tree.body[0].value
print(isinstance(value, ast.TemplateStr), isinstance(value.values[0], ast.Constant), isinstance(value.values[1], ast.Interpolation))"#,
        &["True True", "True True True"],
    );
}

