#[test]
fn cpython_ast_validator_match_pattern_subset() {
    assert_output(
        "import ast\n\nconstant_1 = ast.Constant(1)\npattern_1 = ast.MatchValue(constant_1)\nconstant_x = ast.Constant('x')\npattern_x = ast.MatchValue(constant_x)\nconstant_true = ast.Constant(True)\npattern_true = ast.MatchSingleton(True)\nname_carter = ast.Name('carter', ast.Load())\n\nbad_patterns = [\n    ast.MatchValue(ast.Attribute(ast.Attribute(ast.Name('x', ast.Store()), 'y', ast.Load()), 'z', ast.Load())),\n    ast.MatchValue(ast.Attribute(ast.Attribute(ast.Name('x', ast.Load()), 'y', ast.Store()), 'z', ast.Load())),\n    ast.MatchValue(ast.Constant(...)),\n    ast.MatchValue(ast.Constant(True)),\n    ast.MatchValue(ast.Constant((1, 2, 3))),\n    ast.MatchSingleton('string'),\n    ast.MatchSequence([ast.MatchSingleton('string')]),\n    ast.MatchSequence([ast.MatchSequence([ast.MatchSingleton('string')])]),\n    ast.MatchMapping([constant_1, constant_true], [pattern_x]),\n    ast.MatchMapping([constant_true, constant_1], [pattern_x, pattern_1], rest='True'),\n    ast.MatchMapping([constant_true, ast.Starred(ast.Name('lol', ast.Load()), ast.Load())], [pattern_x, pattern_1], rest='legit'),\n    ast.MatchClass(ast.Attribute(ast.Attribute(constant_x, 'y', ast.Load()), 'z', ast.Load()), patterns=[], kwd_attrs=[], kwd_patterns=[]),\n    ast.MatchClass(name_carter, patterns=[], kwd_attrs=['True'], kwd_patterns=[pattern_1]),\n    ast.MatchClass(name_carter, patterns=[], kwd_attrs=[], kwd_patterns=[pattern_1]),\n    ast.MatchClass(name_carter, patterns=[ast.MatchSingleton('string')], kwd_attrs=[], kwd_patterns=[]),\n    ast.MatchClass(name_carter, patterns=[ast.MatchStar()], kwd_attrs=[], kwd_patterns=[]),\n    ast.MatchClass(name_carter, patterns=[], kwd_attrs=[], kwd_patterns=[ast.MatchStar()]),\n    ast.MatchClass(constant_true, patterns=[], kwd_attrs=['True'], kwd_patterns=[pattern_1]),\n    ast.MatchSequence([ast.MatchStar('True')]),\n    ast.MatchAs(name='False'),\n    ast.MatchOr([]),\n    ast.MatchOr([pattern_1]),\n    ast.MatchOr([pattern_1, pattern_x, ast.MatchSingleton('xxx')]),\n    ast.MatchAs(name='_'),\n    ast.MatchStar(name='x'),\n    ast.MatchSequence([ast.MatchStar('_')]),\n    ast.MatchMapping([], [], rest='_'),\n]\n\nfor pattern in bad_patterns:\n    node = ast.Match(\n        subject=ast.Name('x', ast.Load()),\n        cases=[ast.match_case(pattern=pattern, body=[ast.Pass()])],\n    )\n    module = ast.Module([node], [])\n    ast.fix_missing_locations(module)\n    try:\n        compile(module, '<test>', 'exec')\n    except ValueError:\n        print('ValueError')\n    else:\n        print('ok')",
        &[
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
        ],
    );
}

