#[test]
fn cpython_ast_dump_incomplete_first_pass_subset() {
    assert_output(
        "import ast\nnode = ast.Raise(lineno=3, col_offset=4)\nprint(ast.dump(node))\nprint(ast.dump(node, include_attributes=True))\nnode = ast.Raise(exc=ast.Name(id='e', ctx=ast.Load()), lineno=3, col_offset=4)\nprint(ast.dump(node))\nprint(ast.dump(node, annotate_fields=False))\nprint(ast.dump(node, include_attributes=True))\nprint(ast.dump(node, annotate_fields=False, include_attributes=True))\nnode = ast.Raise(cause=ast.Name(id='e', ctx=ast.Load()))\nprint(ast.dump(node))\nprint(ast.dump(node, annotate_fields=False))\nprint(ast.dump(ast.arguments(args=[ast.arg('x')]), annotate_fields=False))\nprint(ast.dump(ast.arguments(posonlyargs=[ast.arg('x')]), annotate_fields=False))\nprint(ast.dump(ast.arguments(posonlyargs=[ast.arg('x')], kwonlyargs=[ast.arg('y')]), annotate_fields=False))\nprint(ast.dump(ast.arguments(args=[ast.arg('x')], kwonlyargs=[ast.arg('y')]), annotate_fields=False))\nprint(ast.dump(ast.arguments(), annotate_fields=False))\nnode = ast.ClassDef('T', [], [ast.keyword('a', ast.Constant(None))], [], [ast.Name('dataclass', ctx=ast.Load())])\nprint(ast.dump(node))\nprint(ast.dump(node, annotate_fields=False))",
        &[
            "Raise()",
            "Raise(lineno=3, col_offset=4)",
            "Raise(exc=Name(id='e'))",
            "Raise(Name('e'))",
            "Raise(exc=Name(id='e'), lineno=3, col_offset=4)",
            "Raise(Name('e'), lineno=3, col_offset=4)",
            "Raise(cause=Name(id='e'))",
            "Raise(cause=Name('e'))",
            "arguments([], [arg('x')])",
            "arguments([arg('x')])",
            "arguments([arg('x')], kwonlyargs=[arg('y')])",
            "arguments([], [arg('x')], kwonlyargs=[arg('y')])",
            "arguments()",
            "ClassDef(name='T', keywords=[keyword(arg='a', value=Constant(value=None))], decorator_list=[Name(id='dataclass')])",
            "ClassDef('T', [], [keyword('a', Constant(None))], [], [Name('dataclass')])",
        ],
    );
}

