expected = "\n".join([
"Module(",
"\t[",
"\t\tExpr(",
"\t\t\tCall(",
"\t\t\t\tName('spam'),",
"\t\t\t\t[",
"\t\t\t\t\tName('eggs'),",
"\t\t\t\t\tConstant('and cheese')]))])",
])
