#[test]
fn cpython_ast_constructor_first_pass_subset() {
    assert_output(
        "import ast\nnode = ast.AST()\nprint(node._fields, node.__dict__)\nnode.foobar = 42\nprint(node.foobar, node.__dict__['foobar'])\ntry:\n    ast.AST(2)\nexcept TypeError as error:\n    print(error.__class__.__name__)\nargs = ast.arguments()\nprint(args.posonlyargs, args.args, args.vararg, args.kwonlyargs, args.kw_defaults, args.kwarg, args.defaults)\nname = ast.Name('x')\nprint(name.id, type(name.ctx).__name__, isinstance(name.ctx, ast.Load))\nname2 = ast.Name('x', ast.Store())\nname3 = ast.Name('x', ctx=ast.Del())\nprint(type(name2.ctx).__name__, type(name3.ctx).__name__)\nfn = ast.FunctionDef(args=args)\nprint(hasattr(fn, 'name'), fn.body, fn.decorator_list, fn.returns, fn.type_params)\nfn = ast.FunctionDef(name='foo', args=args)\nprint(fn.name, fn.decorator_list)\nmanual = ast.Module(body=[ast.Assign([ast.Name('x', ast.Store())], ast.Constant(1))], type_ignores=[])\nassign = manual.body[0]\nprint(type(manual).__name__, type(assign).__name__, assign.targets[0].id, assign.value.value)\nprint('Assign' in ast.dump(manual), 'Constant' in ast.dump(manual))\ncustom = ast.Name('y', bogus=5)\nprint(custom.id, custom.bogus)",
        &[
            "() {}",
            "42 42",
            "TypeError",
            "[] [] None [] [] None []",
            "x Load True",
            "Store Del",
            "False [] [] None []",
            "foo []",
            "Module Assign x 1",
            "True True",
            "y 5",
        ],
    );
}

// Adapted from CPython `ASTConstructorTests` in
// Lib/test/test_ast/test_ast.py. This extends the constructor migration from
// builtin public AST node constructors to custom `ast.AST` subclasses with
// `_fields`, `_field_types`, and `_attributes`.
#[test]
fn cpython_ast_constructor_subclass_fields_first_pass_subset() {
    assert_output(
        r#"import ast
class NoInit(ast.AST):
    pass
obj = NoInit()
print(isinstance(obj, NoInit), hasattr(obj, "a"))

class Fields(ast.AST):
    _fields = ("a",)
obj = Fields()
print(hasattr(obj, "a"))
obj = Fields(a=1)
print(obj.a)

class FieldsAndTypes(ast.AST):
    _fields = ("a",)
    _field_types = {"a": int | None}
    a: int | None = None
print(FieldsAndTypes().a, FieldsAndTypes(a=1).a)

class MyAttrs(ast.AST):
    _attributes = ("a", "b")
obj = MyAttrs(a=1, b=2)
print(obj.a, obj.b)
obj = MyAttrs(c=3)
print(obj.c)

class FieldsAndTypesNoDefault(ast.AST):
    _fields = ("a",)
    _field_types = {"a": int}
obj = FieldsAndTypesNoDefault()
print(hasattr(obj, "a"))
print(FieldsAndTypesNoDefault(a=1).a)

class MoreFieldsThanTypes(ast.AST):
    _fields = ("a", "b")
    _field_types = {"a": int | None}
    a: int | None = None
    b: int | None = None
obj = MoreFieldsThanTypes()
print(obj.a, obj.b)
obj = MoreFieldsThanTypes(a=1, b=2)
print(obj.a, obj.b)

class BadFields(ast.AST):
    _fields = (b"\xff",)
    _field_types = {"a": int}
print(hasattr(BadFields(), "a"))

class _AllFieldTypes(ast.AST):
    _fields = ("a", "b")
    _field_types = {"a": int | None, "b": list[str]}
    a: int | None = None
    b: list[str]
obj = _AllFieldTypes()
print(obj.a, obj.b)

class ContextDefault(ast.AST):
    _fields = ("ctx",)
    _field_types = {"ctx": ast.expr_context}
obj = ContextDefault()
print(type(obj.ctx).__name__, isinstance(obj.ctx, ast.Load), isinstance(obj.ctx, ast.expr_context), issubclass(ast.Load, ast.expr_context))

try:
    Fields(1, a=2)
except TypeError as error:
    print(error.__class__.__name__, error)
try:
    Fields(1, 2)
except TypeError as error:
    print(error.__class__.__name__, error)"#,
        &[
            "True False",
            "False",
            "1",
            "None 1",
            "1 2",
            "3",
            "False",
            "1",
            "None None",
            "1 2",
            "False",
            "None []",
            "Load True True True",
            "TypeError Fields constructor got multiple values for argument 'a'",
            "TypeError Fields constructor takes at most 1 positional argument",
        ],
    );
}

// Adapted from CPython `ASTConstructorTests::test_non_str_kwarg`.
// MiniPython does not yet expose DeprecationWarning capture for AST constructor
// calls, but this ports the TypeError side and the field-name equality edge.
#[test]
fn cpython_ast_constructor_non_str_kwarg_first_pass_subset() {
    assert_output(
        r#"import ast
try:
    ast.Name(**{object(): "y"})
except TypeError as error:
    print(error.__class__.__name__, error)

class FakeStr:
    def __init__(self, value):
        self.value = value
    def __hash__(self):
        return hash(self.value)
    def __eq__(self, other):
        return isinstance(other, str) and self.value == other

try:
    ast.Name("x", **{FakeStr("id"): "y"})
except TypeError as error:
    print(error.__class__.__name__, error)"#,
        &[
            "TypeError Name constructor got an unexpected keyword argument <object object>",
            "TypeError Name constructor got multiple values for argument 'id'",
        ],
    );
}

// Adapted from CPython `ASTConstructorTests` warning assertions. MiniPython's
// minimal `warnings` module records the same warning category/message surface
// needed by the migrated AST constructor cases.
#[test]
fn cpython_ast_constructor_deprecation_warnings_subset() {
    assert_output(
        r#"import ast
import warnings

with warnings.catch_warnings(record=True) as caught:
    warnings.simplefilter("always")
    fn = ast.FunctionDef(args=ast.arguments())
print(len(caught), caught[0].category.__name__, "FunctionDef.__init__ missing 1 required positional argument: 'name'" in str(caught[0].message), hasattr(fn, "name"))

with warnings.catch_warnings(record=True) as caught:
    warnings.simplefilter("always")
    name = ast.Name()
print(len(caught), caught[0].category.__name__, "Name.__init__ missing 1 required positional argument: 'id'" in str(caught[0].message), type(name.ctx).__name__)

class MyAttrs(ast.AST):
    _attributes = ("a", "b")
with warnings.catch_warnings(record=True) as caught:
    warnings.simplefilter("always")
    obj = MyAttrs(c=3)
print(len(caught), "MyAttrs.__init__ got an unexpected keyword argument 'c'" in str(caught[0].message), obj.c)

class FieldsAndTypesNoDefault(ast.AST):
    _fields = ("a",)
    _field_types = {"a": int}
with warnings.catch_warnings(record=True) as caught:
    warnings.simplefilter("always")
    obj = FieldsAndTypesNoDefault()
print(len(caught), "FieldsAndTypesNoDefault.__init__ missing 1 required positional argument: 'a'" in str(caught[0].message), hasattr(obj, "a"))

class MoreFieldsThanTypes(ast.AST):
    _fields = ("a", "b")
    _field_types = {"a": int | None}
    a: int | None = None
    b: int | None = None
with warnings.catch_warnings(record=True) as caught:
    warnings.simplefilter("always")
    obj = MoreFieldsThanTypes()
print(len(caught), "Field 'b' is missing from MoreFieldsThanTypes._field_types" in str(caught[0].message), obj.a, obj.b)

class BadFields(ast.AST):
    _fields = (b"\xff" * 4,)
    _field_types = {"a": int}
with warnings.catch_warnings(record=True) as caught:
    warnings.simplefilter("always")
    obj = BadFields()
print(len(caught), "Field b'\\xff\\xff" in str(caught[0].message))

class ContextDefault(ast.AST):
    _fields = ("ctx",)
    _field_types = {"ctx": ast.expr_context}
with warnings.catch_warnings(record=True) as caught:
    warnings.simplefilter("always")
    obj = ContextDefault()
print(len(caught), type(obj.ctx).__name__, isinstance(obj.ctx, ast.expr_context))

with warnings.catch_warnings(record=True) as caught:
    warnings.simplefilter("always")
    try:
        ast.Name(**{object(): "y"})
    except TypeError as error:
        print(error.__class__.__name__, "unexpected keyword argument <object object>" in str(error))
print(len(caught), caught[0].category.__name__, "unexpected keyword argument <object object>" in str(caught[0].message))

with warnings.catch_warnings(record=True) as caught:
    warnings.simplefilter("always")
    warnings.warn("manual", DeprecationWarning)
print(len(caught), caught[0].category.__name__, str(caught[0].message))"#,
        &[
            "1 DeprecationWarning True False",
            "1 DeprecationWarning True Load",
            "1 True 3",
            "1 True False",
            "1 True None None",
            "1 True",
            "0 Load True",
            "TypeError True",
            "1 DeprecationWarning True",
            "1 DeprecationWarning manual",
        ],
    );
}

