// Adapted from CPython's generated `_ast` type hierarchy from
// `Parser/Python.asdl`. This checks the abstract sum classes that sit between
// `ast.AST` and concrete native AST node classes.
#[test]
fn cpython_ast_native_abstract_class_hierarchy_subset() {
    assert_output(
        r#"import ast

location_attrs = ("lineno", "col_offset", "end_lineno", "end_col_offset")

print(ast.mod.__bases__[0] is ast.AST, ast.stmt.__bases__[0] is ast.AST, ast.expr.__bases__[0] is ast.AST)
print(ast.Module.__bases__[0] is ast.mod, ast.FunctionDef.__bases__[0] is ast.stmt, ast.Name.__bases__[0] is ast.expr)
print(ast.ExceptHandler.__bases__[0] is ast.excepthandler, ast.MatchValue.__bases__[0] is ast.pattern, ast.TypeIgnore.__bases__[0] is ast.type_ignore, ast.TypeVar.__bases__[0] is ast.type_param)
print(issubclass(ast.AsyncFor, ast.stmt), isinstance(ast.Pass(), ast.stmt), issubclass(ast.Module, ast.mod), isinstance(ast.Module([], []), ast.mod))
print(issubclass(ast.MatchClass, ast.pattern), isinstance(ast.MatchAs(), ast.pattern), issubclass(ast.TypeIgnore, ast.type_ignore), issubclass(ast.ParamSpec, ast.type_param))
print(ast.stmt in ast.AST.__subclasses__(), ast.FunctionDef in ast.stmt.__subclasses__(), ast.Set in ast.expr.__subclasses__(), ast.ExceptHandler in ast.excepthandler.__subclasses__())
print(ast.MatchSequence in ast.pattern.__subclasses__(), ast.TypeIgnore in ast.type_ignore.__subclasses__(), ast.TypeVarTuple in ast.type_param.__subclasses__())
print(ast.mod._fields == (), ast.stmt._fields == (), ast.pattern._fields == (), ast.type_param._fields == ())
print(ast.mod._attributes == (), ast.type_ignore._attributes == (), ast.stmt._attributes == location_attrs, ast.expr._attributes == location_attrs, ast.pattern._attributes == location_attrs, ast.type_param._attributes == location_attrs, ast.excepthandler._attributes == location_attrs)
print(ast.TypeVar._fields, ast.TypeVarTuple._fields, ast.ParamSpec._fields)"#,
        &[
            "True True True",
            "True True True",
            "True True True True",
            "True True True True",
            "True True True True",
            "True True True True",
            "True True True",
            "True True True True",
            "True True True True True True True",
            "('name', 'bound', 'default_value') ('name', 'default_value') ('name', 'default_value')",
        ],
    );
}

