// Adapted from CPython `AST_Tests.test_ast_asdl_signature`. This checks the
// public ASDL signatures exposed through native AST class `__doc__` strings.
#[test]
fn cpython_ast_asdl_signature_doc_subset() {
    assert_output(
        r#"import ast

print(ast.withitem.__doc__ == "withitem(expr context_expr, expr? optional_vars)")
print(ast.GtE.__doc__ == "GtE")
print(ast.Name.__doc__ == "Name(identifier id, expr_context ctx)")
print(ast.cmpop.__doc__ == "cmpop = Eq | NotEq | Lt | LtE | Gt | GtE | Is | IsNot | In | NotIn")

expressions = [f"     | {node.__doc__}" for node in ast.expr.__subclasses__()]
expressions[0] = f"expr = {ast.expr.__subclasses__()[0].__doc__}"
lines = ast.expr.__doc__.split("\n")
print(len(lines) == len(expressions), all(line in lines for line in expressions))
print(ast.Name.__dict__["__doc__"] == ast.Name.__doc__)"#,
        &["True", "True", "True", "True", "True True", "True"],
    );
}

// Adapted from CPython `AST_Tests.test_arguments`. This ports the ASDL
