fn cpython_ast_arguments_annotations_subset() {
    assert_output(
        r#"import ast

x = ast.arguments()
print(x._fields == ("posonlyargs", "args", "vararg", "kwonlyargs", "kw_defaults", "kwarg", "defaults"))
print(ast.arguments.__annotations__ == {
    "posonlyargs": list[ast.arg],
    "args": list[ast.arg],
    "vararg": ast.arg | None,
    "kwonlyargs": list[ast.arg],
    "kw_defaults": list[ast.expr],
    "kwarg": ast.arg | None,
    "defaults": list[ast.expr],
})
print(ast.arguments._field_types == ast.arguments.__annotations__)
print(x.args, x.vararg)
x = ast.arguments(*range(1, 8))
print(x.args, x.vararg)

print(ast.Name.__annotations__ == {"id": str, "ctx": ast.expr_context})
print(ast.Module.__annotations__["type_ignores"].__origin__ is list, ast.Module.__annotations__["type_ignores"].__args__[0] is ast.type_ignore)
print(ast.Constant.__annotations__["value"] is object, ast.ImportFrom.__annotations__["level"] == int | None)"#,
        &[
            "True",
            "True",
            "True",
            "[] None",
            "2 3",
            "True",
            "True True",
            "True True",
        ],
    );
}

// Adapted from CPython `AST_Tests` class/field metadata checks in
// Lib/test/test_ast/test_ast.py. This covers writable `_fields`, missing
// field/attribute lookup, class-level constructor behavior, fieldless nodes,
// and subclassing `ast.Constant`.
#[test]
fn cpython_ast_node_class_metadata_subset() {
    assert_output(
        r#"import ast
import warnings

def missing_attr(obj, name):
    try:
        getattr(obj, name)
    except AttributeError:
        return True
    return False

x = ast.Constant(1)
x._fields = 666
print(x._fields)

with warnings.catch_warnings(record=True) as caught:
    warnings.simplefilter("always")
    empty = ast.Constant()
print(empty._fields, missing_attr(empty, "value"), len(caught), caught[0].category.__name__)

node = ast.Constant(42)
print(node.value, missing_attr(node, "lineno"), missing_attr(node, "foobar"))
node = ast.Constant(lineno=2, value=3)
print(node.value, node.lineno)
node = ast.Constant(42, lineno=0)
print(node.value, node.lineno, node._fields)

try:
    ast.Constant(1, None, 2)
except TypeError as error:
    print(error.__class__.__name__)
try:
    ast.Constant(1, None, 2, lineno=0)
except TypeError as error:
    print(error.__class__.__name__)

with warnings.catch_warnings(record=True) as caught:
    warnings.simplefilter("always")
    custom = ast.Constant(1, foo="bar")
print(custom.foo, len(caught), caught[0].category.__name__)

try:
    ast.Constant(1, value=2)
except TypeError as error:
    print(error.__class__.__name__, "multiple values" in str(error))

print(ast.Constant(4.25).value, ast.Constant(4.25j).value)
print(ast.Constant("42").value, ast.Constant(b"42").value)
print(ast.Constant(True).value is True, ast.Constant(False).value is False, ast.Constant(None).value is None, ast.Constant(...).value is ...)

with warnings.catch_warnings(record=True) as caught:
    warnings.simplefilter("always")
    binop = ast.BinOp()
print(binop._fields, len(caught), caught[0].category.__name__)
binop.foobarbaz = 5
print(binop.foobarbaz)
left = ast.Constant(1)
right = ast.Constant(3)
op = ast.Add()
binop = ast.BinOp(left, op, right)
print(binop.left is left, binop.op is op, binop.right is right)
binop = ast.BinOp(1, 2, 3, lineno=0)
print(binop.left, binop.op, binop.right, binop.lineno)
for kwargs in ({}, {"lineno": 0}):
    try:
        ast.BinOp(1, 2, 3, 4, **kwargs)
    except TypeError as error:
        print(error.__class__.__name__)
binop = ast.BinOp(left=1, op=2, right=3, lineno=0)
print(binop.left, binop.op, binop.right, binop.lineno)
with warnings.catch_warnings(record=True) as caught:
    warnings.simplefilter("always")
    binop = ast.BinOp(1, 2, 3, foobarbaz=42)
print(binop.foobarbaz, len(caught), caught[0].category.__name__)

print(ast.Sub()._fields)

class N(ast.Constant):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.z = "spam"
class N2(ast.Constant):
    pass
n = N(42)
print(n.value, n.z, type(n) is N, isinstance(n, N), isinstance(n, ast.Constant), isinstance(n, N2))
print(isinstance(ast.Constant(42), N))
n = N(value=42)
print(n.value, type(n) is N)

body = [ast.Constant(42)]
module = ast.Module(body, [])
print(module.body is body)"#,
        &[
            "666",
            "('value', 'kind') True 1 DeprecationWarning",
            "42 True True",
            "3 2",
            "42 0 ('value', 'kind')",
            "TypeError",
            "TypeError",
            "bar 1 DeprecationWarning",
            "TypeError True",
            "4.25 4.25j",
            "42 b'42'",
            "True True True True",
            "('left', 'op', 'right') 3 DeprecationWarning",
            "5",
            "True True True",
            "1 2 3 0",
            "TypeError",
            "TypeError",
            "1 2 3 0",
            "42 1 DeprecationWarning",
            "()",
            "42 spam True True True False",
            "False",
            "42 True",
            "True",
        ],
    );
}

