// Adapted from CPython `AST_Tests.test_filter_syntax_warnings_by_module`.
// MiniPython keeps the same warning-producing source rows and checks that
// `ast.parse()` emits tokenizer SyntaxWarnings through the public `warnings`
// capture surface.
#[test]
fn cpython_ast_filter_syntax_warnings_by_module_subset() {
    assert_output(
        r##"import ast
import warnings

source = r"""# Syntax warnings emitted in different parts of the Python compiler.

# Parser/lexer/lexer.c
x = 1or 0  # line 4

# Parser/tokenizer/helpers.c
'\z'  # line 7

# Parser/string_parser.c
'\400'  # line 10

# _PyCompile_Warn() in Python/codegen.c
assert(x, 'message')  # line 13
x is 1  # line 14

# _PyErr_EmitSyntaxWarning() in Python/ast_preprocess.c
def f():
    try:
        pass
    finally:
        return 42  # line 21
"""

def show(wlog):
    print(sorted([wm.lineno for wm in wlog]))
    for wm in wlog:
        print(wm.filename, wm.category is SyntaxWarning)

with warnings.catch_warnings(record=True) as wlog:
    warnings.simplefilter("error")
    warnings.filterwarnings("always", module=r"<unknown>\z")
    ast.parse(source)
show(wlog)

with warnings.catch_warnings(record=True) as wlog:
    warnings.simplefilter("error")
    warnings.filterwarnings("always", module=r"package\.module\z")
    warnings.filterwarnings("error", module=r"<unknown>")
    ast.parse(source, "syntax_warnings.py", module="package.module")
show(wlog)"##,
        &[
            "[4, 7, 10]",
            "<unknown> True",
            "<unknown> True",
            "<unknown> True",
            "[4, 7, 10]",
            "syntax_warnings.py True",
            "syntax_warnings.py True",
            "syntax_warnings.py True",
        ],
    );
}

// Adapted from CPython `AST_Tests.test_AST_objects` and
// `test_AST_fields_NULL_check`. This covers base `ast.AST` instances with
// custom attributes plus the CPython crash-regression path where deleting the
// class-level `_fields` descriptor makes AST construction raise AttributeError.
#[test]
fn cpython_ast_base_object_and_missing_fields_subset() {
    assert_output(
        r#"import ast

def show_error(fn, expected_type, fragment):
    try:
        fn()
    except Exception as error:
        print(error.__class__.__name__ == expected_type, fragment in str(error))
    else:
        print(False, False)

x = ast.AST()
print(x._fields == ())
x.foobar = 42
print(x.foobar)
print(x.__dict__["foobar"])
show_error(lambda: x.vararg, "AttributeError", "vararg")
show_error(lambda: ast.AST(2), "TypeError", "0 positional")

old_value = ast.AST._fields
try:
    del ast.AST._fields
    msg = "type object 'ast.AST' has no attribute '_fields'"
    show_error(lambda: ast.AST(arg1=123), "AttributeError", msg)
    show_error(lambda: ast.AST(), "AttributeError", msg)
finally:
    ast.AST._fields = old_value
print(ast.AST._fields == old_value)"#,
        &[
            "True",
            "42",
            "42",
            "True True",
            "True True",
            "True True",
            "True True",
            "True",
        ],
    );
}

// Adapted from CPython `AST_Tests.test_none_checks`. This mutates parser-built
// public AST nodes by replacing required fields with `None`, then checks that
// compile-from-AST rejects the tree with the CPython-style required-field
// `ValueError` instead of a generic type error or panic.
#[test]
fn cpython_ast_none_required_fields_subset() {
    assert_output(
        r#"import ast

def check(node_type, attr, source):
    tree = ast.parse(source)
    found = 0
    for child in ast.walk(tree):
        if isinstance(child, node_type):
            setattr(child, attr, None)
            found += 1
    print(found)
    try:
        compile(tree, "<test>", "exec")
    except ValueError as error:
        print(str(error) == "field '" + attr + "' is required for " + node_type.__name__)
    else:
        print(False)

check(ast.alias, "name", "import spam as SPAM")
check(ast.arg, "arg", "def spam(SPAM): spam")
check(ast.comprehension, "target", "[spam for SPAM in spam]")
check(ast.comprehension, "iter", "[spam for spam in SPAM]")
check(ast.keyword, "value", "spam(**SPAM)")
check(ast.match_case, "pattern", "match spam:\n case SPAM: spam")
check(ast.withitem, "context_expr", "with SPAM: spam")"#,
        &[
            "1", "True", "1", "True", "1", "True", "1", "True", "1", "True", "1", "True", "1",
            "True",
        ],
    );
}

// Adapted from CPython `AST_Tests.test_field_attr_existence`. This walks the
// public `ast.__dict__` class surface and constructs each public AST class from
// its generated `__annotations__` shape, proving constructed AST nodes expose
// tuple-valued `_fields`.
#[test]
fn cpython_ast_field_attr_existence_subset() {
    assert_output(
        r#"import ast

def is_ast_node(name, node):
    if not isinstance(node, type):
        return False
    if "ast" not in node.__module__:
        return False
    return name != "AST" and name[0].isupper()

def construct_ast_class(cls):
    kwargs = {}
    for name, typ in cls.__annotations__.items():
        if typ is str:
            kwargs[name] = "capybara"
        elif typ is int:
            kwargs[name] = 42
        elif typ is object:
            kwargs[name] = b"capybara"
        elif isinstance(typ, type) and issubclass(typ, ast.AST):
            kwargs[name] = construct_ast_class(typ)
    return cls(**kwargs)

checked = 0
failures = []
for name, item in ast.__dict__.items():
    if name == "Index":
        continue
    if is_ast_node(name, item):
        node = construct_ast_class(item)
        if isinstance(node, ast.AST):
            checked += 1
            if type(node._fields) is not tuple:
                failures.append(name)

print(checked > 50, len(failures), ast.Constant in [value for _, value in ast.__dict__.items()])
print(isinstance(construct_ast_class(ast.Name), ast.AST), type(construct_ast_class(ast.Name)._fields) is tuple)
print(isinstance(construct_ast_class(ast.BinOp), ast.AST), type(construct_ast_class(ast.BinOp)._fields) is tuple)"#,
        &["True 0 True", "True True", "True True"],
    );
}

// Adapted from CPython `AST_Tests` compare methods in
// Lib/test/test_ast/test_ast.py. This ports the public `ast.compare()` behavior
// for structural equality, runtime `_fields` / `_attributes` mutation, exact
// primitive type checks, fieldless operator nodes, and missing fields/attrs.
#[test]
fn cpython_ast_compare_first_pass_subset() {
    assert_output(
        r#"import ast

print(ast.compare(ast.parse("x = 10"), ast.parse("x = 10")))
print(ast.compare(ast.parse("x = 10"), ast.parse("")))
print(ast.compare(ast.parse("x = 10"), ast.parse("x")))
print(ast.compare(ast.parse("x = 10; y = 20"), ast.parse("class C: pass")))

a = ast.parse("m * x + b", mode="eval")
b = ast.parse("m * x + b", mode="eval")
print(ast.compare(a, b))
a._fields = a._fields + ("spam",)
a.spam = "Spam"
print(ast.compare(a, b), ast.compare(b, a))
b._fields = a._fields
b.spam = a.spam
print(ast.compare(a, b), ast.compare(b, a))
b._attributes = b._attributes + ("eggs",)
b.eggs = "eggs"
print(ast.compare(a, b, compare_attributes=True), ast.compare(b, a, compare_attributes=True))
a._attributes = b._attributes
a.eggs = b.eggs
print(ast.compare(a, b, compare_attributes=True), ast.compare(b, a, compare_attributes=True))

print(ast.compare(ast.Constant(1), ast.Constant(1)))
print(ast.compare(ast.Constant(1), ast.Constant(1.0)))
print(ast.compare(ast.Constant(1), ast.Constant(True)))
print(ast.compare(ast.Constant(0), ast.Constant(False)))
print(ast.compare(ast.Constant("x"), ast.Constant("x")))
print(ast.compare(ast.Constant(()), ast.Constant(())))
print(ast.compare(ast.Constant(frozenset()), ast.Constant(frozenset())))

print(ast.compare(ast.Add(), ast.Add()), ast.compare(ast.Sub(), ast.Add()))
a1, a2 = ast.Name("a"), ast.Name("a")
print(ast.compare(a1, a2))
del a1.id
print(ast.compare(a1, a2))
del a2.id
print(ast.compare(a1, a2))

a, b = ast.parse("2 + 2"), ast.parse("2+2")
print(ast.compare(a, b), ast.compare(a, b, compare_attributes=False), ast.compare(a, b, compare_attributes=True))
a1, a2 = ast.Name("a", lineno=1), ast.Name("a", lineno=1)
print(ast.compare(a1, a2), ast.compare(a1, a2, compare_attributes=True))
del a1.lineno
print(ast.compare(a1, a2, compare_attributes=True))
del a2.lineno
print(ast.compare(a1, a2, compare_attributes=True))"#,
        &[
            "True",
            "False",
            "False",
            "False",
            "True",
            "False False",
            "True True",
            "False False",
            "True True",
            "True",
            "False",
            "False",
            "False",
            "True",
            "True",
            "True",
            "True False",
            "True",
            "False",
            "True",
            "True True False",
            "True True",
            "False",
            "True",
        ],
    );
}

// Adapted from CPython `AST_Tests.test_compare_literals`. This pins
// `ast.compare()` literal equality to both value equality and exact public
// constant type, so bool/int/float/complex values that compare equal at runtime
// still compare unequal as AST constants.
#[test]
fn cpython_ast_compare_literals_exact_subset() {
    assert_output(
        r#"import ast

constants = (
    -20,
    20,
    20.0,
    1,
    1.0,
    True,
    0,
    False,
    frozenset(),
    tuple(),
    "ABCD",
    "abcd",
    "中文字",
    1e1000,
    -1e1000,
)

same = 0
adjacent_unequal = 0
for index in range(len(constants) - 1):
    constant = constants[index]
    next_constant = constants[index + 1]
    if ast.compare(ast.Constant(constant), ast.Constant(constant)):
        same += 1
    if not ast.compare(ast.Constant(constant), ast.Constant(next_constant)):
        adjacent_unequal += 1
print(same, adjacent_unequal)

same_looking_literal_pairs = [
    (1, 1.0),
    (1, True),
    (1, 1 + 0j),
    (1.0, True),
    (1.0, 1 + 0j),
    (True, 1 + 0j),
    (0, 0.0),
    (0, False),
    (0, 0 + 0j),
    (0.0, False),
    (0.0, 0 + 0j),
    (False, 0 + 0j),
]
checked = 0
for left, right in same_looking_literal_pairs:
    if not ast.compare(ast.Constant(left), ast.Constant(right)):
        checked += 1
print(checked, len(same_looking_literal_pairs))
print(constants[13] > 0, constants[14] < 0)"#,
        &["14 14", "12 12", "True True"],
    );
}

