fn assert_ast_compare_mode_source(mode: &str, source: &str) {
    let program = format!(
        "import ast\nsource = {source:?}\nmode = {mode:?}\na = ast.parse(source, mode=mode)\nb = ast.parse(source, mode=mode)\nprint(ast.compare(a, b))"
    );
    assert_output(&program, &["True"]);
}

