#[test]
fn cpython_ast_location_helpers_first_pass_subset() {
    assert_output(
        "import ast\nsrc = ast.Constant(1, lineno=3, col_offset=4, end_lineno=5, end_col_offset=6)\ndst = ast.Constant(2)\nprint(ast.copy_location(dst, src) is dst)\nprint(dst.lineno, dst.col_offset, dst.end_lineno, dst.end_col_offset)\nprint(ast.dump(dst, include_attributes=True))\nsrc2 = ast.Constant(1, lineno=None, col_offset=None, end_lineno=None, end_col_offset=None)\ndst2 = ast.Constant(2, lineno=9, col_offset=9, end_lineno=9, end_col_offset=9)\nast.copy_location(dst2, src2)\nprint(dst2.lineno, dst2.col_offset, dst2.end_lineno, dst2.end_col_offset)\nexpr = ast.Expr(ast.Call(ast.Name('spam', ast.Load()), [ast.Constant('eggs')], []))\nprint(ast.fix_missing_locations(expr) is expr)\nprint(expr.lineno, expr.col_offset, expr.end_lineno, expr.end_col_offset)\nprint(expr.value.lineno, expr.value.func.lineno, expr.value.args[0].lineno)\nprint(ast.dump(expr, include_attributes=True))\nbinop = ast.BinOp(ast.Constant(1, lineno=10, col_offset=2, end_lineno=11, end_col_offset=3), ast.Add(), ast.Constant(2))\nprint(ast.increment_lineno(binop, n=3) is binop)\nprint(binop.lineno, binop.end_lineno, binop.left.lineno, binop.left.end_lineno, binop.right.lineno, binop.right.end_lineno)\ncall = ast.Call(func=ast.Name('test', ast.Load()), args=[], keywords=[], lineno=1)\nast.increment_lineno(call)\nprint(call.lineno, call.end_lineno)",
        &[
            "True",
            "3 4 5 6",
            "Constant(value=2, lineno=3, col_offset=4, end_lineno=5, end_col_offset=6)",
            "9 9 None None",
            "True",
            "1 0 1 0",
            "1 1 1",
            "Expr(value=Call(func=Name(id='spam', lineno=1, col_offset=0, end_lineno=1, end_col_offset=0), args=[Constant(value='eggs', lineno=1, col_offset=0, end_lineno=1, end_col_offset=0)], lineno=1, col_offset=0, end_lineno=1, end_col_offset=0), lineno=1, col_offset=0, end_lineno=1, end_col_offset=0)",
            "True",
            "3 None 13 14 3 None",
            "2 None",
        ],
    );
}

