#[test]
fn cpython_ast_get_source_segment_first_pass_subset() {
    assert_output(
        "import ast\nsource = 'spam(eggs, \"and cheese\")'\ncall = ast.parse(source).body[0].value\nprint(ast.get_source_segment(source, call))\nprint(ast.get_source_segment(source, call.func))\nprint(ast.get_source_segment(source, call.args[0]))\nprint(ast.get_source_segment(source, call.args[1]))\nsource = 'x = 1 + 2'\nassign = ast.parse(source).body[0]\nprint(ast.get_source_segment(source, assign))\nprint(ast.get_source_segment(source, assign.value))\nprint(ast.get_source_segment(source, assign.value.left))\nprint(ast.get_source_segment(source, assign.value.right))\nsource = 'top\\n    abc\\nxyz'\nnode = ast.Constant(0, lineno=2, col_offset=4, end_lineno=3, end_col_offset=3)\nprint(ast.get_source_segment(source, node))\nprint(ast.get_source_segment(source, node, padded=True))\nfor attr in ['lineno', 'end_lineno', 'col_offset', 'end_col_offset']:\n    node = ast.parse('x = 1').body[0]\n    delattr(node, attr)\n    print(ast.get_source_segment('x = 1', node) is None)\nprint(ast.get_source_segment(source, object()) is None)",
        &[
            "spam(eggs, \"and cheese\")",
            "spam",
            "eggs",
            "\"and cheese\"",
            "x = 1 + 2",
            "1 + 2",
            "1",
            "2",
            "abc\nxyz",
            "    abc\nxyz",
            "True",
            "True",
            "True",
            "True",
            "True",
        ],
    );
}

