// Adapted from CPython `EndPositionTests.test_redundant_parenthesis` and
// `test_trailers_with_redundant_parenthesis`.
#[test]
fn cpython_ast_redundant_parentheses_source_segment_subset() {
    assert_output(
        "import ast\n\ndef show_expr(source, expected_type, expected_segment):\n    value = ast.parse(source).body[0].value\n    print(type(value).__name__, ast.get_source_segment(source, value) == expected_segment)\n\ndef show_await_expr(source, expected_type, expected_segment):\n    value = ast.parse('await ' + source).body[0].value.value\n    print(type(value).__name__, ast.get_source_segment('await ' + source, value) == expected_segment)\n\nsource = '( ( ( a + b ) ) )'\nshow_expr(source, 'BinOp', 'a + b')\nshow_await_expr(source, 'BinOp', 'a + b')\n\nfor source, expected_type in [\n    ('( ( ( a ) ) ) ( )', 'Call'),\n    ('( ( ( a ) ) ) ( b )', 'Call'),\n    ('( ( ( a ) ) ) [ b ]', 'Subscript'),\n    ('( ( ( a ) ) ) . b', 'Attribute'),\n]:\n    show_expr(source, expected_type, source)\n    show_await_expr(source, expected_type, source)",
        &[
            "BinOp True",
            "BinOp True",
            "Call True",
            "Call True",
            "Call True",
            "Call True",
            "Subscript True",
            "Subscript True",
            "Attribute True",
            "Attribute True",
        ],
    );
}

