// Adapted from CPython Lib/test/test_builtin.py::BuiltinTest::test_eval.
// This builtin slice covers string and code-object expression evaluation in the
// current globals/locals environment plus dict-backed globals/locals.
#[test]
fn cpython_eval_builtin_subset() {
    assert_output(
        "print(eval('1+1'))\nprint(eval(' 1+1\\n'))\nprint(eval('\"Ä\"'))",
        &["2", "2", "Ä"],
    );
    assert_output(
        "x = 10\ndef probe(y):\n    z = 5\n    print(eval('x + y + z'))\n    print(eval('globals()[\"x\"]'), eval('locals()[\"z\"]'))\nprobe(3)",
        &["18", "10 5"],
    );
    assert_output(
        "data = {'a': 1, 'b': 2}\nlocal = {'b': 200, 'c': 300}\nprint(eval('a', data), eval('a', data, local))\nprint(eval('b', data, local), eval('c', data, local))\nprint(eval('globals()[\"a\"]', data, local), eval('locals()[\"c\"]', data, local))",
        &["1 1", "200 300", "1 300"],
    );
    assert_output(
        "data = {'a': 1, 'b': 2}\nlocal = {'b': 200, 'c': 300}\nprint(eval(b'\\xef\\xbb\\xbfa', data, local))",
        &["1"],
    );
    assert_output(
        "class S(str):\n    pass\nclass B(bytes):\n    pass\nclass BA(bytearray):\n    pass\nprint(eval(S('1 + 2')))\nprint(eval(B(b'1 + 3')))\nprint(eval(BA(b'1 + 4')))",
        &["3", "4", "5"],
    );
    assert_output(
        "A_GLOBAL_VALUE = 123\ndata = {'A_GLOBAL_VALUE': 456}\nprint(eval(\"globals()['A_GLOBAL_VALUE']\", globals=data))\nprint(eval(\"globals()['A_GLOBAL_VALUE']\", locals=data))\nprint(eval(source=\"A_GLOBAL_VALUE\", globals=data))",
        &["456", "123", "456"],
    );
    assert_output("print(eval(\"print('inside')\"))", &["inside", "None"]);
    assert_output(
        "data = {'a': 1}\nfor expr in [lambda: eval(), lambda: eval((), data), lambda: eval('1+'), lambda: eval('a', ()), lambda: eval('a', data, ())]:\n    try:\n        expr()\n    except (TypeError, SyntaxError) as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "SyntaxError",
            "TypeError",
            "TypeError",
        ],
    );
    assert_output(
        "g = {}\ntry:\n    eval('x =', g)\nexcept SyntaxError:\n    print('__builtins__' in g)\ng = {}\ntry:\n    eval((), g)\nexcept TypeError:\n    print('__builtins__' in g)",
        &["True", "True"],
    );
    assert_output(
        "g = {}\nprint(eval('(x := 4)', g, g), g['x'], '__builtins__' in g)\ng = {}\nl = {}\nprint(eval('(x := 5)', g, l), 'x' in g, l['x'])\ng = {}\ntry:\n    eval('(x := 6) / 0', g, g)\nexcept ZeroDivisionError:\n    print(g['x'])",
        &["4 4 True", "5 False 5", "6"],
    );
    assert_output_with_stack(
        "class M:\n    def __getitem__(self, key):\n        if key == 'a':\n            return 12\n        raise KeyError\n    def keys(self):\n        return list('xyz')\nm = M()\ng = globals()\nprint(eval('a', g, m))\ntry:\n    eval('b', g, m)\nexcept NameError as error:\n    print(error.__class__.__name__)\nprint(eval('dir()', g, m))\nprint(eval('globals()', g, m) is g, eval('locals()', g, m) is m)\ntry:\n    eval('a', m)\nexcept TypeError as error:\n    print(error.__class__.__name__)\nclass A:\n    pass\ntry:\n    eval('a', g, A())\nexcept TypeError as error:\n    print(error.__class__.__name__)\nclass D(dict):\n    def __getitem__(self, key):\n        if key == 'a':\n            return 12\n        return dict.__getitem__(self, key)\n    def keys(self):\n        return list('xyz')\nd = D()\nprint(eval('a', g, d))\ntry:\n    eval('b', g, d)\nexcept NameError as error:\n    print(error.__class__.__name__)\nprint(eval('dir()', g, d))\nprint(eval('locals()', g, d) is d)\nclass SpreadSheet:\n    _cells = {}\n    def __setitem__(self, key, formula):\n        self._cells[key] = formula\n    def __getitem__(self, key):\n        return eval(self._cells[key], globals(), self)\nss = SpreadSheet()\nss['a1'] = '5'\nss['a2'] = 'a1*6'\nss['a3'] = 'a2*7'\nprint(ss['a3'])\nclass C:\n    def __getitem__(self, item):\n        raise KeyError(item)\n    def keys(self):\n        return 1\ntry:\n    eval('dir()', globals(), C())\nexcept TypeError as error:\n    print(error.__class__.__name__)",
        &[
            "12",
            "NameError",
            "['x', 'y', 'z']",
            "True True",
            "TypeError",
            "TypeError",
            "12",
            "NameError",
            "['x', 'y', 'z']",
            "True",
            "210",
            "TypeError",
        ],
        16 * 1024 * 1024,
    );
}

// Adapted from CPython Lib/test/test_builtin.py::BuiltinTest::test_exec.
// This exec slice covers string and code-object execution in the current scope
// and dict-backed globals/locals environments. Custom mapping objects are later
// runtime work.
#[test]
fn cpython_exec_builtin_subset() {
    assert_output(
        "print(exec('z = 1'))\nprint(z)\nexec('z = z + 1')\nprint(z)",
        &["None", "1", "2"],
    );
    assert_output(
        "g = {}\nprint(exec('z = 1', g))\nprint(g['z'])\nexec('z = 1 + 1', g)\nprint(g['z'])",
        &["None", "1", "2"],
    );
    assert_output(
        "g = {}\nl = {}\nexec('global a\\na = 1\\nb = 2', g, l)\nprint(g['a'], 'b' in g, l['b'])",
        &["1 False 2"],
    );
    assert_output(
        "g = {}\nexec('global z\\nz = 1', globals=g)\nprint(g['z'])\ng = {}\nexec('global z\\nz = 2', locals=g)\nprint(g == {}, z)\nexec(source='byte_value = 8', globals=g)\nprint(g['byte_value'])",
        &["1", "True 2", "8"],
    );
    assert_output(
        "print(exec(b'byte_exec = 9'))\nprint(byte_exec)",
        &["None", "9"],
    );
    assert_output(
        "class S(str):\n    pass\nclass B(bytes):\n    pass\nclass BA(bytearray):\n    pass\nfor source in [S('x = 5'), B(b'x = 6'), BA(b'x = 7')]:\n    namespace = {}\n    exec(source, namespace)\n    print(type(source).__name__, namespace['x'])",
        &["S 5", "B 6", "BA 7"],
    );
    assert_output(
        "g = {}\nfor expr in [lambda: exec(), lambda: exec((), g), lambda: exec('x ='), lambda: exec('x = 1', ())]:\n    try:\n        expr()\n    except (TypeError, SyntaxError) as error:\n        print(error.__class__.__name__)",
        &["TypeError", "TypeError", "SyntaxError", "TypeError"],
    );
    assert_output(
        "g = {}\ntry:\n    exec('x = 1\\n1/0', g)\nexcept ZeroDivisionError:\n    print(g['x'], '__builtins__' in g)\ng = {}\nl = {}\ntry:\n    exec('y = 2\\n1/0', g, l)\nexcept ZeroDivisionError:\n    print('y' in g, l['y'], '__builtins__' in g, '__builtins__' in l)",
        &["1 True", "False 2 True False"],
    );
    assert_output(
        "g = {}\ntry:\n    exec('x =', g)\nexcept SyntaxError:\n    print('__builtins__' in g, 'x' in g)\ng = {}\ntry:\n    exec((), g)\nexcept TypeError:\n    print('__builtins__' in g)",
        &["True False", "True"],
    );
    assert_output(
        "g = {}\nexec('x = 1', g, g)\nprint(g['x'], '__builtins__' in g)\ng = {}\nexec('global y\\ny = 2\\nz = 3', g, g)\nprint(g['y'], g['z'])\ng = {}\ntry:\n    exec('x = 4\\n1/0', g, g)\nexcept ZeroDivisionError:\n    print(g['x'])",
        &["1 True", "2 3", "4"],
    );
    assert_output(
        "import sys\nsaved = sys.stdout\nsys.stdout = None\ntry:\n    exec('a')\nexcept NameError as error:\n    sys.stdout = saved\n    print(error.__class__.__name__, 'a' in str(error))\nfinally:\n    sys.stdout = saved",
        &["NameError True"],
    );
}

// Adapted from CPython Lib/test/test_builtin.py::BuiltinTest::test_exec_globals
// and ::test_eval_builtins_mapping.
#[test]
fn cpython_eval_exec_builtins_mapping_subset() {
    assert_error(
        "code = compile(\"print('Hello World!')\", \"\", \"exec\")\nexec(code, {'__builtins__': {}})",
        "runtime error: NameError: name 'print' is not defined",
    );
    assert_error(
        "code = compile(\"print('Hello World!')\", \"\", \"exec\")\nexec(code, {'__builtins__': 123})",
        "runtime error: TypeError: __builtins__ must be a dict, not int",
    );
    assert_output(
        "from types import MappingProxyType\ncode = compile('superglobal', 'test', 'eval')\nns = {'__builtins__': MappingProxyType({'superglobal': 1})}\nprint(eval(code, ns))",
        &["1"],
    );
    assert_error(
        "from types import MappingProxyType\ncode = compile('superglobal', 'test', 'eval')\nns = {'__builtins__': MappingProxyType({})}\neval(code, ns)",
        "runtime error: NameError: name 'superglobal' is not defined",
    );
    assert_output(
        "class customdict(dict):\n    pass\ncode = compile('result = superglobal', 'test', 'exec')\nns = {'__builtins__': customdict({'superglobal': 1})}\nexec(code, ns)\nprint(ns['result'])",
        &["1"],
    );
    assert_error(
        "class customdict(dict):\n    pass\ncode = compile('result = superglobal', 'test', 'exec')\nexec(code, {'__builtins__': customdict()})",
        "runtime error: NameError: name 'superglobal' is not defined",
    );
    assert_error(
        "from types import MappingProxyType\ncode = compile('import foo.bar', 'test', 'exec')\nns = {'__builtins__': MappingProxyType({})}\nexec(code, ns)",
        "runtime error: ImportError: __import__ not found",
    );
    assert_output(
        "from types import MappingProxyType\ncode = compile('import foo.bar', 'test', 'exec')\nns = {'__builtins__': MappingProxyType({'__import__': lambda *args: args})}\nexec(code, ns)\nprint(ns['foo'][0], ns['foo'][1] is ns['foo'][2], ns['foo'][3], ns['foo'][4])",
        &["foo.bar True None 0"],
    );
    assert_output(
        "class setonlyerror(Exception):\n    pass\nclass setonlydict(dict):\n    def __getitem__(self, key):\n        raise setonlyerror\ncode = compile('globalname', 'test', 'exec')\ntry:\n    exec(code, setonlydict({'globalname': 1}))\nexcept setonlyerror:\n    print('globals getitem error')\ncode = compile('superglobal', 'test', 'exec')\ntry:\n    exec(code, {'__builtins__': setonlydict({'superglobal': 1})})\nexcept setonlyerror:\n    print('builtins getitem error')",
        &["globals getitem error", "builtins getitem error"],
    );
    assert_output(
        "ns = {}\nexec('value = len([1, 2])', ns)\nprint('__builtins__' in ns, 'len' in ns['__builtins__'], ns['value'])",
        &["True True 2"],
    );
    assert_output(
        "ns = {}\nprint(eval('len([1, 2, 3])', ns))\nprint('__builtins__' in ns, 'len' in ns['__builtins__'])",
        &["3", "True True"],
    );
    assert_output(
        "g = {}\nl = {}\nexec('value = len([1])', g, l)\nprint('__builtins__' in g, '__builtins__' in l, l['value'])",
        &["True False 1"],
    );
    assert_output(
        "g = {}\nexec('import math\\nname = math.__name__', g)\nprint(g['name'], '__import__' in g['__builtins__'])",
        &["math True"],
    );
    assert_output(
        "import builtins\nclass frozendict_error(Exception):\n    pass\nclass frozendict(dict):\n    def __setitem__(self, key, value):\n        raise frozendict_error('frozendict is readonly')\nfrozen_builtins = frozendict({'__build_class__': builtins.__build_class__, 'print': print})\nprint(hasattr(builtins, '__build_class__'))\ncode = compile(\"__builtins__['superglobal']=2; print(superglobal)\", 'test', 'exec')\ntry:\n    exec(code, {'__builtins__': frozen_builtins, '__name__': 'test'})\nexcept frozendict_error as error:\n    print('builtins-write', error.__class__.__name__, error)\nclass keyfrozendict(dict):\n    def __setitem__(self, key, value):\n        raise frozendict_error('readonly ' + key)\nnamespace = keyfrozendict({'__name__': 'test'})\ncode = compile('x=1', 'test', 'exec')\ntry:\n    exec(code, namespace)\nexcept frozendict_error as error:\n    print('globals-write', error.__class__.__name__, error)\nprint('globals-clean', 'x' in namespace)\ncode = compile('class A: pass', '', 'exec')\ntry:\n    exec(code, {'__builtins__': {}, '__name__': 'test'})\nexcept NameError as error:\n    print('no-build-class', error.__class__.__name__, '__build_class__' in str(error))\ntry:\n    exec(code, {'__builtins__': frozendict(), '__name__': 'test'})\nexcept NameError as error:\n    print('empty-frozen-build-class', error.__class__.__name__, '__build_class__' in str(error))\nns = {'__builtins__': frozen_builtins, '__name__': 'test'}\nexec(code, ns)\nprint('build-class-ok', ns['A'].__name__)",
        &[
            "True",
            "builtins-write frozendict_error frozendict is readonly",
            "globals-write frozendict_error readonly x",
            "globals-clean False",
            "no-build-class NameError True",
            "empty-frozen-build-class NameError True",
            "build-class-ok A",
        ],
    );
    assert_output(
        "from types import MappingProxyType\ncode = compile('x.__reduce__()', 'test', 'eval')\nns = {'__builtins__': MappingProxyType({'iter': iter}), 'x': iter([1, 2])}\nfunc, args, index = eval(code, ns)\nprint(func is iter, args, index)\nns = {'__builtins__': MappingProxyType({'iter': iter}), 'x': iter((1, 2))}\nfunc, args, index = eval(code, ns)\nprint(func is iter, args, index)",
        &["True ([1, 2],) 0", "True ((1, 2),) 0"],
    );
    assert_output(
        "from types import MappingProxyType\nit = iter([1, 2])\nnext(it)\nfunc, args, index = it.__reduce__()\nprint(func is iter, args, index)\ncode = compile('x.__reduce__()', 'test', 'eval')\ntry:\n    eval(code, {'__builtins__': MappingProxyType({}), 'x': iter([1, 2])})\nexcept AttributeError as error:\n    print(error.__class__.__name__, 'iter' in str(error))",
        &["True ([1, 2],) 1", "AttributeError True"],
    );
    assert_output(
        "items = [1]\nit = iter(items)\nnext(it)\ntry:\n    next(it)\nexcept StopIteration:\n    print('stopped')\nitems.append(2)\nprint(list(it))\nreduced = it.__reduce__()\nprint(len(reduced), reduced[0] is iter, reduced[1])",
        &["stopped", "[]", "2 True ([],)"],
    );
}

// Adapted from CPython Lib/test/test_builtin.py::BuiltinTest::test_exec_closure.
#[test]
fn cpython_exec_closure_subset() {
    assert_output(
        "from types import CellType\n\ndef outer():\n    result = 0\n    def function_without_closures():\n        return 3 * 5\n    def make_closure_functions():\n        a = 2\n        b = 3\n        c = 5\n        def three_freevars():\n            nonlocal result\n            nonlocal a\n            nonlocal b\n            result = a * b\n        def four_freevars():\n            nonlocal result\n            nonlocal a\n            nonlocal b\n            nonlocal c\n            result = a * b * c\n        return three_freevars, four_freevars\n    three_freevars, four_freevars = make_closure_functions()\n    print(three_freevars.__code__.co_freevars)\n    print([cell.cell_contents for cell in three_freevars.__closure__])\n    exec(three_freevars.__code__, three_freevars.__globals__, closure=three_freevars.__closure__)\n    print(result)\n    my_closure = (CellType(35), CellType(72), three_freevars.__closure__[2])\n    print(isinstance(my_closure[0], CellType), my_closure[0].cell_contents)\n    exec(three_freevars.__code__, three_freevars.__globals__, closure=my_closure)\n    print(result)\n    for expr in [\n        lambda: exec(function_without_closures.__code__, function_without_closures.__globals__, closure=my_closure),\n        lambda: exec(three_freevars.__code__, three_freevars.__globals__, closure=None),\n        lambda: exec(three_freevars.__code__, three_freevars.__globals__, closure=four_freevars.__closure__),\n        lambda: exec(three_freevars.__code__, three_freevars.__globals__, closure=list(my_closure)),\n        lambda: exec('pass', closure=int),\n        lambda: exec('pass', closure=my_closure),\n        lambda: exec(three_freevars.__code__, three_freevars.__globals__, closure=(int, my_closure[1], my_closure[2])),\n    ]:\n        try:\n            expr()\n        except TypeError as error:\n            print(error.__class__.__name__)\nouter()",
        &[
            "('a', 'b', 'result')",
            "[2, 3, 0]",
            "6",
            "True 35",
            "2520",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython Lib/test/test_builtin.py::BuiltinTest::
// test_exec_filter_syntax_warnings_by_module. CPython reads this source from
// Lib/test/test_import/data/syntax_warnings.py; MiniPython keeps the same
// warning-producing source inline while preserving `exec()`'s `<string>`
// filename and globals-derived warning module behavior.
#[test]
fn cpython_exec_filter_syntax_warnings_by_module_subset() {
    assert_output(
        r##"import warnings

source = r"""# Syntax warnings emitted in different parts of the Python compiler.

# Parser/lexer/lexer.c
x = 1or 0  # line 4

# Parser/tokenizer/helpers.c
'\z'  # line 7

# Parser/string_parser.c
'\400'  # line 10

# _PyCompile_Warn() in Python/codegen.c
assert(x, 'message')  # line 13
x is 1  # line 14

# _PyErr_EmitSyntaxWarning() in Python/ast_preprocess.c
def f():
    try:
        pass
    finally:
        return 42  # line 21
"""

def show(wlog):
    print(sorted([wm.lineno for wm in wlog]))
    for wm in wlog:
        print(wm.filename, wm.category is SyntaxWarning)

with warnings.catch_warnings(record=True) as wlog:
    warnings.simplefilter("error")
    warnings.filterwarnings("always", module=r"<string>\z")
    exec(source, {})
show(wlog)

with warnings.catch_warnings(record=True) as wlog:
    warnings.simplefilter("error")
    warnings.filterwarnings("always", module=r"package\.module\z")
    warnings.filterwarnings("error", module=r"<string>")
    exec(source, {"__name__": "package.module", "__file__": "test/test_import/data/syntax_warnings.py"})
show(wlog)"##,
        &[
            "[4, 7, 10, 13, 14, 21]",
            "<string> True",
            "<string> True",
            "<string> True",
            "<string> True",
            "<string> True",
            "<string> True",
            "[4, 7, 10, 13, 14, 21]",
            "<string> True",
            "<string> True",
            "<string> True",
            "<string> True",
            "<string> True",
            "<string> True",
        ],
    );
}

// Adapted from CPython Lib/test/test_compile.py::TestSpecifics::
// test_exec_with_general_mapping_for_locals. CPython accepts a general mapping
// as the explicit locals object for exec(), reading through `__getitem__`,
// writing through `__setitem__`, using `keys()` for dir(), and exposing the
// original mapping through locals().
#[test]
fn cpython_compile_specifics_exec_general_mapping_locals_subset() {
    assert_output_with_stack(
        "class M:\n    def __getitem__(self, key):\n        if key == 'a':\n            return 12\n        raise KeyError\n    def __setitem__(self, key, value):\n        self.results = (key, value)\n    def keys(self):\n        return list('xyz')\nm = M()\ng = globals()\nexec('z = a', g, m)\nprint(m.results)\ntry:\n    exec('z = b', g, m)\nexcept NameError:\n    print('name-error')\nexec('z = dir()', g, m)\nprint(m.results)\nexec('z = globals()', g, m)\nprint(m.results[0], m.results[1] is g)\nexec('z = locals()', g, m)\nprint(m.results[0], m.results[1] is m)\nclass A:\n    pass\ntry:\n    exec('z = a', g, A())\nexcept TypeError:\n    print('locals-type-error')\ntry:\n    exec('z = b', m)\nexcept TypeError:\n    print('globals-type-error')",
        &[
            "('z', 12)",
            "name-error",
            "('z', ['x', 'y', 'z'])",
            "z True",
            "z True",
            "locals-type-error",
            "globals-type-error",
        ],
        32 * 1024 * 1024,
    );
    assert_output(
        "class D(dict):\n    def __getitem__(self, key):\n        if key == 'a':\n            return 12\n        raise KeyError\nd = D()\ng = globals()\nexec('z = a', g, d)\nprint(d.get('z'))",
        &["12"],
    );
}

