// Adapted from CPython Lib/test/test_compile.py::TestSpecifics::test_import.
// This checks the compile-time grammar boundary for ordinary and parenthesized
// import/from-import forms without requiring the imported modules to execute.
#[test]
fn cpython_compile_specifics_import_syntax_subset() {
    assert_output(
        r#"succeed = [
    'import sys',
    'import os, sys',
    'import os as bar',
    'import os.path as bar',
    'from __future__ import nested_scopes, generators',
    'from __future__ import (nested_scopes,\ngenerators)',
    'from __future__ import (nested_scopes,\ngenerators,)',
    'from sys import stdin, stderr, stdout',
    'from sys import (stdin, stderr,\nstdout)',
    'from sys import (stdin, stderr,\nstdout,)',
    'from sys import (stdin\n, stderr, stdout)',
    'from sys import (stdin\n, stderr, stdout,)',
    'from sys import stdin as si, stdout as so, stderr as se',
    'from sys import (stdin as si, stdout as so, stderr as se)',
    'from sys import (stdin as si, stdout as so, stderr as se,)',
]
for stmt in succeed:
    compile(stmt, 'tmp', 'exec')
fail = [
    'import (os, sys)',
    'import (os), (sys)',
    'import ((os), (sys))',
    'import (sys',
    'import sys)',
    'import (os,)',
    'import os As bar',
    'import os.path a bar',
    'from sys import stdin As stdout',
    'from sys import stdin a stdout',
    'from (sys) import stdin',
    'from __future__ import (nested_scopes',
    'from __future__ import nested_scopes)',
    'from __future__ import nested_scopes,\ngenerators',
    'from sys import (stdin',
    'from sys import stdin)',
    'from sys import stdin, stdout,\nstderr',
    'from sys import stdin si',
    'from sys import stdin,',
    'from sys import (*)',
    'from sys import (stdin,, stdout, stderr)',
    'from sys import (stdin, stdout),',
]
for stmt in fail:
    try:
        compile(stmt, 'tmp', 'exec')
    except SyntaxError:
        pass
    else:
        print('accepted', stmt)
print('import-syntax-ok')"#,
        &["import-syntax-ok"],
    );
}

// Adapted from CPython Lib/test/test_compile.py::TestSpecifics successful
// compile/runtime regression methods that do not require code-object metadata:
// `test_extended_arg`, `test_sequence_unpacking_error`, `test_annotation_limit`,
// `test_condition_expression_with_dead_blocks_compiles`,
// `test_condition_expression_with_redundant_comparisons_compiles`,
// `test_dead_code_with_except_handler_compiles`, and
// `test_try_except_in_while_with_chained_condition_compiles`.
