fn cpython_compile_specifics_compile_stability_subset() {
    let longexpr = format!("x = x or {}", "-x".repeat(100));
    assert_output(
        &format!(
            "def f(x):\n    {}\n    {}\n    {}\n    {}\n    {}\n    {}\n    {}\n    {}\n    {}\n    {}\n    while x:\n        x -= 1\n    return x\nprint(f(5))",
            longexpr,
            longexpr,
            longexpr,
            longexpr,
            longexpr,
            longexpr,
            longexpr,
            longexpr,
            longexpr,
            longexpr
        ),
        &["0"],
    );

    assert_output("i, j = (1, -1) or (-1, 1)\nprint(i, j)", &["1 -1"]);

    let params = (0..300)
        .map(|index| format!("a{index}:{index}"))
        .collect::<Vec<_>>()
        .join(", ");
    assert_output(
        &format!("compile('def f({params}): pass', '?', 'exec')\nprint('annotation-limit-ok')"),
        &["annotation-limit-ok"],
    );

    assert_output(
        r#"sources = [
    'if (5 if 5 else T): 0',
    'if 9<9<9and 9or 9:9',
    'if 9<9<9and 9or 9or 9:9',
    'if 9<9<9and 9or 9or 9or 9:9',
    'if 9<9<9and 9or 9or 9or 9or 9:9',
    '''
if None:
    with CM:
        x = 1
else:
    x = 2
''',
    '''
name_1, name_2, name_3 = 1, 2, 3
while name_3 <= name_2 > name_1:
    try:
        raise
    except:
        pass
    finally:
        pass
''',
]
for source in sources:
    compile(source, '<eval>', 'exec')
print('compile-stability-ok')"#,
        &["compile-stability-ok"],
    );
}

