// Adapted from CPython Lib/test/test_builtin.py::BuiltinTest::test_compile.
// MiniPython supports the core string-source compile path for eval, exec, and
// single modes, then feeds the produced code object back through eval()/exec().
#[test]
fn cpython_compile_builtin_code_object_subset() {
    assert_output(
        "code = compile('1 + 2', '<mini>', 'eval')\nprint(type(code).__name__)\nprint(eval(code))\nprint(eval(code, {'x': 1}, {'y': 2}))",
        &["code", "3", "3"],
    );
    assert_output(
        "code = compile('value = 4\\nprint(value)', '<mini>', 'exec')\nprint(exec(code))\ng = {}\nexec(compile('x = 5', '<mini>', 'exec'), g)\nprint(g['x'])",
        &["4", "None", "5"],
    );
    assert_output(
        "print(exec(compile(b'\\xef\\xbb\\xbfprint(6)\\n', '<mini>', 'exec')))",
        &["6", "None"],
    );
    assert_output(
        "class S(str):\n    pass\nclass B(bytes):\n    pass\nclass BA(bytearray):\n    pass\nfor source in [S('x = 11'), B(b'x = 12'), BA(b'x = 13')]:\n    namespace = {}\n    exec(compile(source, '<mini>', 'exec'), namespace)\n    print(type(source).__name__, namespace['x'])",
        &["S 11", "B 12", "BA 13"],
    );
    assert_output(
        "class S(str):\n    pass\ncode = compile('1 + 6', '<mini>', S('eval'))\nprint(eval(code), type(code).__name__)",
        &["7 code"],
    );
    assert_output(
        "print(exec(compile('2 + 3', '<mini>', 'single')))\nprint(eval(compile('z = 9', '<mini>', 'exec')))\nprint(z)",
        &["5", "None", "None", "9"],
    );
    assert_output(
        "code = compile(source='a + b', filename='tmp', mode='eval')\nprint(eval(code, {'a': 2}, {'b': 5}))\ncompile('pass', '?', dont_inherit=True, mode='exec')\ncompile(dont_inherit=False, filename='tmp', source='0', mode='eval')\nfor expr in [lambda: compile(), lambda: compile('print(42)', '<string>', 'badmode'), lambda: compile('x =', '<string>', 'exec'), lambda: compile('pass', '?', 'exec', mode='eval', source='0', filename='tmp')]:\n    try:\n        expr()\n    except (TypeError, ValueError, SyntaxError) as error:\n        print(error.__class__.__name__)",
        &["7", "TypeError", "ValueError", "SyntaxError", "TypeError"],
    );
}

