// Adapted from CPython's `interactive` starting rule and
// Lib/test/test_compile.py::test_single_statement / test_bad_single_statement.
// MiniPython models the same one-input boundary and displays expression
// statements through its REPL-style output.
#[test]
fn cpython_interactive_input_subset() {
    assert_interactive("1 + 2", &["3"]);
    assert_interactive("\n1 + 2", &["3"]);
    assert_interactive("1 + 2\n\n", &["3"]);
    assert_interactive("1; 2", &["1", "2"]);
    assert_interactive("import sys; sys.__name__", &["sys"]);
    assert_interactive("if True:\n   print(\"then\")", &["then"]);
    assert_interactive("class T:\n   pass", &[]);
    assert_interactive("\n", &[]);
    assert_interactive_error(
        "1\n2",
        "parse error: expected end of input, found Number(2)",
    );
    assert_interactive_error(
        "x = 5 # comment\nx = 6\n",
        "parse error: expected end of input, found Identifier(\"x\")",
    );
    assert_interactive_error("f{}", "parse error: invalid syntax");
}

// Adapted from CPython's `statement_newline` interactive-input rule. The rule
// accepts one compound statement, one simple-statement line, a blank line, or
// end-of-input.
#[test]
fn cpython_statement_newline_subset() {
    assert_interactive("", &[]);
    assert_interactive("\n", &[]);
    assert_interactive("1 + 2\n", &["3"]);
    assert_interactive("1; 2;\n", &["1", "2"]);
    assert_interactive("if True:\n    print(\"ok\")\n", &["ok"]);
}

// Adapted from CPython's `func_type` starting rule and
// Lib/test/test_type_comments.py::test_func_type_input. The CPython AST
// FunctionType mode ignores `*` and `**` markers and keeps the underlying type
// expressions.
#[test]
fn cpython_func_type_input_subset() {
    assert_func_type("() -> int", &["arg_types: []", "returns: Name(\"int\")"]);
    assert_func_type(
        "(int) -> List[str]",
        &[
            "Name(\"int\")",
            "Subscript",
            "Name(\"List\")",
            "Name(\"str\")",
        ],
    );
    assert_func_type(
        "(int, *str, **Any) -> float",
        &[
            "Name(\"int\")",
            "Name(\"str\")",
            "Name(\"Any\")",
            "returns: Name(\"float\")",
        ],
    );
    assert_func_type(
        "(int, str, *tuple, **dict) -> float\n\n",
        &[
            "Name(\"int\")",
            "Name(\"str\")",
            "Name(\"tuple\")",
            "Name(\"dict\")",
            "returns: Name(\"float\")",
        ],
    );
    assert_func_type("(*int) -> None", &["Name(\"int\")", "returns: None"]);
    assert_func_type("(**int) -> None", &["Name(\"int\")", "returns: None"]);
    assert_func_type(
        "(*int, **str) -> None",
        &["Name(\"int\")", "Name(\"str\")", "returns: None"],
    );
    assert_eq!(
        parse_func_type_source("(int, *str, *Any) -> float"),
        Err("parse error: multiple '*' type expressions are not allowed".to_string())
    );
    assert_eq!(
        parse_func_type_source("(int, **str, Any) -> float"),
        Err("parse error: '**' type expression must be last".to_string())
    );
    assert_eq!(
        parse_func_type_source("(**int, **str) -> float"),
        Err("parse error: '**' type expression must be last".to_string())
    );
}

// Adapted from CPython's `type_expressions` helper rule in
// Grammar/python.gram and Lib/test/test_type_comments.py::test_func_type_input.
// FunctionType mode ignores `*` and `**` markers but still enforces their
// ordering and rejects trailing commas.
#[test]
fn cpython_type_expression_helper_rules_subset() {
    assert_func_type(
        "(int, str) -> None",
        &["Name(\"int\")", "Name(\"str\")", "returns: None"],
    );
    assert_func_type(
        "(int, *str) -> None",
        &["Name(\"int\")", "Name(\"str\")", "returns: None"],
    );
    assert_func_type(
        "(int, **Any) -> None",
        &["Name(\"int\")", "Name(\"Any\")", "returns: None"],
    );
    assert_func_type(
        "(int, str, **dict) -> None",
        &[
            "Name(\"int\")",
            "Name(\"str\")",
            "Name(\"dict\")",
            "returns: None",
        ],
    );
    assert_func_type(
        "(*str, **Any) -> None",
        &["Name(\"str\")", "Name(\"Any\")", "returns: None"],
    );
    assert_func_type(
        "(int, str, *tuple, **dict) -> None",
        &[
            "Name(\"int\")",
            "Name(\"str\")",
            "Name(\"tuple\")",
            "Name(\"dict\")",
            "returns: None",
        ],
    );
    assert_func_type(
        "(list[int], dict[str, int]) -> tuple[str, int]",
        &[
            "Subscript",
            "Name(\"list\")",
            "Name(\"dict\")",
            "Name(\"tuple\")",
        ],
    );
    assert_eq!(
        parse_func_type_source("(int,) -> None"),
        Err("parse error: trailing comma in type expressions is not allowed".to_string())
    );
    assert_eq!(
        parse_func_type_source("(*int,) -> None"),
        Err("parse error: trailing comma in type expressions is not allowed".to_string())
    );
    assert_eq!(
        parse_func_type_source("(**int,) -> None"),
        Err("parse error: trailing comma in type expressions is not allowed".to_string())
    );
    assert_eq!(
        parse_func_type_source("(*int, str) -> None"),
        Err("parse error: plain type expression cannot follow '*' or '**'".to_string())
    );
}

// Adapted from Lib/test/test_type_comments.py. MiniPython currently preserves
// TYPE_COMMENT and TYPE_IGNORE at the lexer boundary, then treats them as
// parser trivia so executable behavior matches the supported syntax subset.
#[test]
fn cpython_type_comments_and_ignores_subset() {
    assert_output("x = 1  # type: int\nprint(x)", &["1"]);
    assert_output(
        "def foo():  # type: () -> int\n    return 1\nprint(foo())",
        &["1"],
    );
    assert_output("for item in [1]:  # type: int\n    print(item)", &["1"]);
    assert_output(
        "pass  # type: ignore\nx = 1  # type: ignore[assignment]\nprint(x)",
        &["1"],
    );
    assert_output("pass  # type: ignorewhatever\nprint(\"ok\")", &["ok"]);
}

// Adapted from CPython's `func_type_comment` helper rule and
// Lib/test/test_type_comments.py function-definition coverage. MiniPython
// accepts the same inline and own-line function type-comment shapes, exposes
// statement-level `type_comment` metadata through `ast.parse(...,
// type_comments=True)`, and rejects duplicate comments.
#[test]
fn cpython_func_type_comment_helper_rules_subset() {
    assert_output(
        "def foo():\n    # type: () -> int\n    return 1\nprint(foo())",
        &["1"],
    );
    assert_output(
        "def bar():  # type: () -> None\n    pass\nprint(bar())",
        &["None"],
    );
    assert_output(
        "async def foo():\n    # type: () -> int\n    return 1\nvalue = foo()\nprint(value)",
        &["<coroutine object foo>"],
    );
    assert_output(
        "async def bar():  # type: () -> int\n    return 2\nvalue = bar()\nprint(value)",
        &["<coroutine object bar>"],
    );
    assert_error(
        "def redundant():  # type: () -> int\n    # type: () -> str\n    return 1",
        "parse error: Cannot have two type comments on def",
    );
    assert_error(
        "async def redundant():  # type: () -> int\n    # type: () -> str\n    return 1",
        "parse error: Cannot have two type comments on def",
    );
}

// Adapted from CPython Lib/test/test_type_comments.py. `ast.parse(...,
// type_comments=True)` preserves statement-level type comments for functions,
// async functions, assignments, for-loops, async for-loops, with-statements,
// and async with-statements; ordinary
// `ast.parse()` keeps the same fields as `None`.
#[test]
fn cpython_type_comment_public_ast_metadata_subset() {
    assert_output(
        r#"import ast
source = """\
def foo():
    # type: () -> int
    pass

def bar():  # type: () -> None
    pass

async def async_foo():
    # type: () -> str
    pass

async def async_bar():  # type: () -> bytes
    pass

async def async_controls():  # type: () -> object
    async for item in items:  # type: async-iter
        pass
    async with context() as value:  # type: async-ctx
        pass

a = 0  # type: int

for item in []:  # type: str
    pass

with context() as value:  # type: ctx
    pass

with (context() as value):  # type: parenthesized
    pass
"""
tree = ast.parse(source, type_comments=True)
for stmt in tree.body:
    print(type(stmt).__name__, stmt.type_comment)
    for nested in getattr(stmt, "body", []):
        if hasattr(nested, "type_comment"):
            print("nested", type(nested).__name__, nested.type_comment)
classic = ast.parse(source)
for stmt in classic.body:
    print("classic", type(stmt).__name__, getattr(stmt, "type_comment", None))
compile(tree, "<ast>", "exec")"#,
        &[
            "FunctionDef () -> int",
            "FunctionDef () -> None",
            "AsyncFunctionDef () -> str",
            "AsyncFunctionDef () -> bytes",
            "AsyncFunctionDef () -> object",
            "nested AsyncFor async-iter",
            "nested AsyncWith async-ctx",
            "Assign int",
            "For str",
            "With ctx",
            "With parenthesized",
            "classic FunctionDef None",
            "classic FunctionDef None",
            "classic AsyncFunctionDef None",
            "classic AsyncFunctionDef None",
            "classic AsyncFunctionDef None",
            "classic Assign None",
            "classic For None",
            "classic With None",
            "classic With None",
        ],
    );
}

// Adapted from CPython Lib/test/test_type_comments.py. Function parameter
// comments are exposed on public `ast.arg.type_comment` nodes only when
// `ast.parse(..., type_comments=True)` is requested.
#[test]
fn cpython_type_comment_argument_ast_metadata_subset() {
    assert_output(
        r#"import ast
source = """\
def typed(
    pos,  # type: pos
    only=1,  # type: only
    /,
    normal=2,  # type: normal
    *args,  # type: args
    kw,  # type: kw
    default_kw=3,  # type: default-kw
    **kwargs  # type: kwargs
):
    pass

def annotated(
    value: int,  # type: annotated
):
    pass
"""
module = ast.parse(source, type_comments=True)
typed = module.body[0]
args = typed.args
for group_name, group in (
    ("posonly", args.posonlyargs),
    ("args", args.args),
    ("kwonly", args.kwonlyargs),
):
    for arg in group:
        print(group_name, arg.arg, arg.type_comment)
print("vararg", args.vararg.arg, args.vararg.type_comment)
print("kwarg", args.kwarg.arg, args.kwarg.type_comment)
annotated = module.body[1].args.args[0]
print("annotated", annotated.arg, type(annotated.annotation).__name__, annotated.type_comment)
classic = ast.parse(source).body[0].args
for arg in classic.posonlyargs + classic.args + classic.kwonlyargs:
    print("classic", arg.arg, arg.type_comment)
print("classic vararg", classic.vararg.type_comment)
print("classic kwarg", classic.kwarg.type_comment)
compile(module, "<ast>", "exec")"#,
        &[
            "posonly pos pos",
            "posonly only only",
            "args normal normal",
            "kwonly kw kw",
            "kwonly default_kw default-kw",
            "vararg args args",
            "kwarg kwargs kwargs",
            "annotated value Name annotated",
            "classic pos None",
            "classic only None",
            "classic normal None",
            "classic kw None",
            "classic default_kw None",
            "classic vararg None",
            "classic kwarg None",
        ],
    );
}

// Adapted from CPython Lib/test/test_type_comments.py::
// TypeCommentTests.test_inappropriate_type_comments. These comments are
// ordinary comments when type comment parsing is off, but become SyntaxError
// when `ast.parse(..., type_comments=True)` asks the frontend to interpret
// them as type comments.
#[test]
fn cpython_inappropriate_type_comments_subset() {
    assert_output(
        r#"import ast
bad_sources = [
    "pass  # type: int\n",
    "foo()  # type: int\n",
    "x += 1  # type: int\n",
    "while True:  # type: int\n  continue\n",
    "while True:\n  continue  # type: int\n",
    "try:  # type: int\n  pass\nfinally:\n  pass\n",
    "try:\n  pass\nfinally:  # type: int\n  pass\n",
    "pass  # type: ignorewhatever\n",
    "pass  # type: ignoreé\n",
]
for source in bad_sources:
    ast.parse(source, type_comments=False)
    try:
        ast.parse(source, type_comments=True)
    except SyntaxError:
        print("strict-error", source.splitlines()[0])
    else:
        print("missing-error", source.splitlines()[0])

good_sources = [
    "x = 1  # type: int\n",
    "x = foo(y=1)  # type: int\n",
    "def f():  # type: () -> int\n  pass\n",
    "def f():\n  # type: () -> int\n  pass\n",
    "def f(a,  # type: A\n):\n  pass\n",
    "for a in []:  # type: int\n  pass\n",
    "with context() as a:  # type: int\n  pass\n",
]
for source in good_sources:
    ast.parse(source, type_comments=True)
print("legal-ok")"#,
        &[
            "strict-error pass  # type: int",
            "strict-error foo()  # type: int",
            "strict-error x += 1  # type: int",
            "strict-error while True:  # type: int",
            "strict-error while True:",
            "strict-error try:  # type: int",
            "strict-error try:",
            "strict-error pass  # type: ignorewhatever",
            "strict-error pass  # type: ignoreé",
            "legal-ok",
        ],
    );
}

// Adapted from CPython Lib/test/test_type_comments.py. These method-level
// smoke checks prove that enabling `type_comments=True` does not regress newer
// syntax forms, keeps non-ASCII function type comments intact, preserves the
// exact public `TypeIgnore.tag` strings, and still rejects `async` / `await` as
// ordinary assignment targets in the default parser mode.
#[test]
fn cpython_type_comment_modern_syntax_and_ignores_subset() {
    assert_output(
        r#"import ast
parse_only_sources = [
    ("asynccomp", "async def foo(xs):\n    [x async for x in xs]\n"),
    ("matmul", "a = b @ c\n"),
    ("fstring", "a = 42\nf\"{a}\"\n"),
    ("underscorednumber", "a = 42_42_42\n"),
]
for label, source in parse_only_sources:
    ast.parse(source, type_comments=True)
    print("parse", label)

try:
    ast.parse("async = 12\nawait = 13\n")
except SyntaxError:
    print("asyncvar SyntaxError")
else:
    print("asyncvar accepted")

nonascii = """\
def foo():
    # type: () -> àçčéñt
    pass
"""
typed = ast.parse(nonascii, type_comments=True)
classic = ast.parse(nonascii)
print(typed.body[0].type_comment)
print(classic.body[0].type_comment)

with_source = """\
with (a as b):  # type: int
    pass

with (a, b):  # type: int
    pass
"""
for stmt in ast.parse(with_source, type_comments=True).body:
    print(type(stmt).__name__, stmt.type_comment)
for stmt in ast.parse(with_source).body:
    print("classic", type(stmt).__name__, stmt.type_comment)

ignores = """\
def foo():
    pass  # type: ignore

def bar():
    x = 1  # type: ignore

def baz():
    pass  # type: ignore[excuse]
    pass  # type: ignore=excuse
    pass  # type: ignore [excuse]
    x = 1  # type: ignore whatever
"""
module = ast.parse(ignores, type_comments=True)
for type_ignore in module.type_ignores:
    print(type_ignore.lineno, repr(type_ignore.tag))
print(len(ast.parse(ignores).type_ignores))"#,
        &[
            "parse asynccomp",
            "parse matmul",
            "parse fstring",
            "parse underscorednumber",
            "asyncvar SyntaxError",
            "() -> àçčéñt",
            "None",
            "With int",
            "With int",
            "classic With None",
            "classic With None",
            "2 ''",
            "5 ''",
            "8 '[excuse]'",
            "9 '=excuse'",
            "10 ' [excuse]'",
            "11 ' whatever'",
            "0",
        ],
    );
}

// Adapted from CPython's `invalid_def_raw` grammar rule and
// Lib/test/test_syntax.py function-definition header diagnostics. MiniPython
// preserves the same rejected source shapes before VM execution, with its own
// Rust parser wording.
#[test]
fn cpython_invalid_function_def_raw_subset() {
    assert_error("def f:\n    pass", "parse error: expected '(', found Colon");
    assert_error(
        "async def f:\n    pass",
        "parse error: expected '(', found Colon",
    );
    assert_error(
        "def f -> int:\n    pass",
        "parse error: expected '(', found Arrow",
    );
    assert_error(
        "async def f -> int:  # type: int\n    pass",
        "parse error: expected '(', found Arrow",
    );
    assert_error(
        "async def f[T]:\n    pass",
        "parse error: expected '(', found Colon",
    );
    assert_error(
        "def f[T] -> str:\n    pass",
        "parse error: expected '(', found Arrow",
    );
    assert_error(
        "def foo(x, /, y, *, z=2):\npass",
        "parse error: expected an indented block",
    );
    assert_error(
        "async def foo(x, /, y, *, z=2):\npass",
        "parse error: expected an indented block",
    );
    assert_error(
        "def foo[T](x, /, y, *, z=2):\npass",
        "parse error: expected an indented block",
    );
    assert_error(
        "async def foo[T](x) -> int:\npass",
        "parse error: expected an indented block",
    );
    assert_error(
        "def foo(x)\n    pass",
        "parse error: expected ':', found Newline",
    );
    assert_error(
        "def foo[T](x)\n    pass",
        "parse error: expected ':', found Newline",
    );
    assert_error(
        "async def foo(x)\n    pass",
        "parse error: expected ':', found Newline",
    );

    assert_parse_error_diagnostic("def f:\n    pass", "expected '(', found Colon", 1, 6, 1, 7);
    assert_parse_error_diagnostic(
        "async def f:\n    pass",
        "expected '(', found Colon",
        1,
        12,
        1,
        13,
    );
    assert_parse_error_diagnostic(
        "def f -> int:\n    pass",
        "expected '(', found Arrow",
        1,
        7,
        1,
        9,
    );
    assert_parse_error_diagnostic(
        "def foo(x, /, y, *, z=2):\npass",
        "expected an indented block",
        2,
        1,
        2,
        5,
    );
    assert_parse_error_diagnostic(
        "def foo(x)\n    pass",
        "expected ':', found Newline",
        1,
        11,
        2,
        1,
    );
}

// Adapted from CPython AST constant coverage in Lib/test/test_ast/test_ast.py.
