// Adapted from CPython's builtin exception hierarchy in
// Lib/test/test_exceptions.py. MiniPython checks the common base-class catches
// that are needed by migrated runtime tests.
#[test]
fn cpython_builtin_exception_hierarchy_subset() {
    assert_output(
        "try:\n    raise OverflowError('big')\nexcept ArithmeticError as error:\n    print(error.__class__.__name__, error)\ntry:\n    1 / 0\nexcept ArithmeticError as error:\n    print(error.__class__.__name__, error)\ntry:\n    [][0]\nexcept LookupError as error:\n    print(error.__class__.__name__, error)\ntry:\n    {}['key']\nexcept LookupError as error:\n    print(error.__class__.__name__, error)\nprint(OverflowError.__bases__[0].__name__, ZeroDivisionError.__bases__[0].__name__, KeyError.__bases__[0].__name__)\nprint(isinstance(OverflowError('x'), ArithmeticError), isinstance(KeyError('x'), LookupError), isinstance(ValueError('x'), ArithmeticError))\ntry:\n    raise GeneratorExit('stop')\nexcept Exception:\n    print('wrong')\nexcept BaseException as error:\n    print(error.__class__.__name__, error)",
        &[
            "OverflowError big",
            "ZeroDivisionError division by zero",
            "IndexError list index out of range",
            "KeyError 'key'",
            "ArithmeticError ArithmeticError LookupError",
            "True True False",
            "GeneratorExit stop",
        ],
    );
}

// Adapted from CPython `Lib/test/test_builtin.py::BuiltinTest::test_issubclass`.
// MiniPython covers direct user-class inheritance, tuple classinfo, builtin
// scalar hierarchy, builtin exception hierarchy, and the common TypeError paths.
#[test]
fn cpython_issubclass_builtin_subset() {
    assert_output(
        "class C:\n    pass\nclass D(C):\n    pass\nclass E:\n    pass\nprint(issubclass(D, C), issubclass(C, C), issubclass(C, D))\nprint(issubclass(D, (E, C)), issubclass(E, (C, D)))\nprint(issubclass(bool, int), issubclass(int, object), issubclass(C, object))\nprint(issubclass(OverflowError, ArithmeticError), issubclass(KeyError, LookupError), issubclass(ValueError, ArithmeticError))\nfor expr in [lambda: issubclass('foo', E), lambda: issubclass(E, 'foo'), lambda: issubclass()]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &[
            "True True False",
            "True False",
            "True True True",
            "True True False",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython `Lib/test/test_builtin.py::BuiltinTest::test_isinstance`.
#[test]
fn cpython_isinstance_builtin_subset() {
    assert_output(
        "class C:\n    pass\nclass D(C):\n    pass\nclass E:\n    pass\nc = C()\nd = D()\ne = E()\nprint(isinstance(c, C), isinstance(d, C), isinstance(e, C), isinstance(c, D))\nprint(isinstance('foo', E), isinstance(d, (E, C)), isinstance(e, (C, D)))\nprint(isinstance(True, int), isinstance(False, bool), isinstance(1, object))\nprint(isinstance(OverflowError('x'), ArithmeticError), isinstance(KeyError('x'), LookupError), isinstance(ValueError('x'), ArithmeticError))\nfor expr in [lambda: isinstance(E, 'foo'), lambda: isinstance(), lambda: isinstance(e, (C, 'bad'))]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &[
            "True True False False",
            "False True False",
            "True True True",
            "True True False",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

