// `::test_getattr`, `::test_hasattr`, `::test_setattr`, and `::test_delattr`.
#[test]
fn cpython_attribute_introspection_builtins_subset() {
    assert_output(
        "import sys\nprint(callable(len), callable('a'), callable(callable))\ndef f():\n    pass\nprint(callable(f))\nclass C1:\n    def meth(self):\n        pass\nc = C1()\nprint(callable(C1), callable(c.meth), callable(c))\nc.__call__ = None\nprint(callable(c))\nc.__call__ = lambda self: 0\nprint(callable(c))\ndel c.__call__\nprint(callable(c))\nclass C2:\n    def __call__(self, value):\n        return value + 1\nc2 = C2()\nprint(callable(c2), c2(4))\nc2.__call__ = None\nprint(callable(c2), c2(5))\nclass C3(C2):\n    pass\nc3 = C3()\nprint(callable(c3), c3(6))\nsetattr(sys, 'spam', 1)\nprint(getattr(sys, 'spam'), hasattr(sys, 'spam'))\ndelattr(sys, 'spam')\nprint(hasattr(sys, 'spam'), getattr(sys, 'spam', 'missing'))\nclass Box:\n    pass\nbox = Box()\nsetattr(box, 'value', 3)\nprint(getattr(box, 'value'), hasattr(box, 'value'))\nsetattr(Box, 'label', 'box')\nprint(getattr(box, 'label'), getattr(Box, 'label'))\ndelattr(box, 'value')\nprint(hasattr(box, 'value'), getattr(box, 'value', 42))\ntry:\n    print((1).missing)\nexcept AttributeError:\n    print('caught')",
        &[
            "True False True",
            "True",
            "True True False",
            "False",
            "False",
            "False",
            "True 5",
            "True 6",
            "True 7",
            "1 True",
            "False missing",
            "3 True",
            "box box",
            "False 42",
            "caught",
        ],
    );
    assert_output(
        "for expr in [lambda: getattr(), lambda: getattr(1), lambda: getattr(1, 2), lambda: getattr(1, 'x', 2, 3), lambda: hasattr(), lambda: hasattr(1), lambda: hasattr(1, 2), lambda: setattr(), lambda: setattr(1, 'x'), lambda: setattr(1, 2, 3), lambda: setattr(1, 'x', 2), lambda: delattr(), lambda: delattr(1), lambda: delattr(1, 2), lambda: callable(), lambda: callable(1, 2)]:\n    try:\n        expr()\n    except (TypeError, AttributeError) as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "AttributeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
    assert_output(
        "import sys\nprint(hasattr(sys, 'stdout'), getattr(sys, 'stdout') is sys.stdout)\nfrom sys import stdin, stderr, stdout\nprint(stdin is sys.stdin, stderr is sys.stderr, stdout is sys.stdout)\nprint(hasattr(sys, chr(0x10ffff)))\ntry:\n    getattr(sys, chr(0x10ffff))\nexcept AttributeError as error:\n    print(error.__class__.__name__)\nclass A:\n    def __getattr__(self, what):\n        raise SystemExit('exit')\nclass B:\n    def __getattr__(self, what):\n        raise ValueError('bad')\nfor obj in [A(), B()]:\n    try:\n        hasattr(obj, 'b')\n    except BaseException as error:\n        print(error.__class__.__name__, str(error))",
        &[
            "True True",
            "True True True",
            "False",
            "AttributeError",
            "SystemExit exit",
            "ValueError bad",
        ],
    );
}

// Focused slice from CPython `Lib/test/test_builtin.py::BuiltinTest::test_getattr`.
#[test]
fn cpython_builtin_getattr_public_subset() {
    assert_output(
        concat!(
            "import sys\n",
            "setattr(sys, 'spam', 1)\n",
            "print(getattr(sys, 'spam'), getattr(sys, 'missing', 'fallback'))\n",
            "delattr(sys, 'spam')\n",
            "class Box:\n",
            "    pass\n",
            "box = Box()\n",
            "box.value = 3\n",
            "Box.label = 'box'\n",
            "print(getattr(box, 'value'), getattr(box, 'label'), getattr(Box, 'label'))\n",
            "del box.value\n",
            "print(getattr(box, 'value', 42))\n",
            "print(hasattr(sys, 'stdout'), getattr(sys, 'stdout') is sys.stdout)\n",
            "name = chr(0x10ffff)\n",
            "print(hasattr(sys, name))\n",
            "try:\n",
            "    getattr(sys, name)\n",
            "except AttributeError as error:\n",
            "    print(error.__class__.__name__)\n",
            "for expr in [lambda: getattr(), lambda: getattr(1), lambda: getattr(1, 2), lambda: getattr(1, 2, 'fallback'), lambda: getattr(1, 'x', 2, 3), lambda: getattr(object=sys, name='missing'), lambda: getattr(sys, 'missing', default='fallback')]:\n",
            "    try:\n",
            "        expr()\n",
            "    except TypeError as error:\n",
            "        print(error.__class__.__name__, str(error))"
        ),
        &[
            "1 fallback",
            "3 box box",
            "42",
            "True True",
            "False",
            "AttributeError",
            "TypeError getattr expected at least 2 arguments, got 0",
            "TypeError getattr expected at least 2 arguments, got 1",
            "TypeError attribute name must be string, not 'int'",
            "TypeError attribute name must be string, not 'int'",
            "TypeError getattr expected at most 3 arguments, got 4",
            "TypeError getattr() takes no keyword arguments",
            "TypeError getattr() takes no keyword arguments",
        ],
    );
}

