// Adapted from CPython `Lib/test/test_descr.py` getattr/setattr hook coverage
// and `Lib/test/test_builtin.py::BuiltinTest::test_hasattr`.
#[test]
fn cpython_instance_attribute_hooks_subset() {
    assert_output(
        r#"class Hook:
    def __getattr__(self, name):
        if name == 'missing':
            return 'fallback'
        raise AttributeError(name)
    def __setattr__(self, name, value):
        if name == 'blocked':
            raise AttributeError(name)
        object.__setattr__(self, name, value + 1)
    def __delattr__(self, name):
        if name == 'blocked':
            raise AttributeError(name)
        object.__delattr__(self, name)

h = Hook()
print(h.missing, getattr(h, 'missing'), hasattr(h, 'missing'), hasattr(h, 'absent'))
h.value = 3
print(h.value)
setattr(h, 'other', 4)
print(h.other)
del h.value
print(hasattr(h, 'value'), getattr(h, 'value', 42))
try:
    h.blocked = 1
except AttributeError:
    print('set blocked')
object.__setattr__(h, 'blocked', 9)
print(h.blocked)
try:
    del h.blocked
except AttributeError:
    print('delete blocked')
object.__delattr__(h, 'blocked')
print(hasattr(h, 'blocked'))
class Bad:
    def __getattr__(self, name):
        raise RuntimeError('boom')
try:
    hasattr(Bad(), 'x')
except RuntimeError as error:
    print(error)
class Child(Hook):
    pass
c = Child()
c.value = 10
print(c.value, c.missing)"#,
        &[
            "fallback fallback True False",
            "4",
            "5",
            "False 42",
            "set blocked",
            "9",
            "delete blocked",
            "False",
            "boom",
            "11 fallback",
        ],
    );
}

