// Adapted from CPython AST FunctionDef snippets in
// Lib/test/test_ast/snippets.py. MiniPython currently supports plain function
// definitions with inline and indented suites, positional parameters, calls,
// type parameters, and implicit `None` returns.
#[test]
fn cpython_ast_function_def_subset() {
    assert_output("def f():\n    pass\nprint(f())", &["None"]);
    assert_output("def f(): pass\nprint(f())", &["None"]);
    assert_output("def f(): ...\nprint(f())", &["None"]);
    assert_output("def f(): return 4\nprint(f())", &["4"]);
    assert_output("def f(a):\n    return a\nprint(f(3))", &["3"]);
    assert_output("def add(a, b):\n    return a + b\nprint(add(2, 3))", &["5"]);
    assert_output(
        "def generic[T, *Ts, **P](): pass\nprint(generic.__type_params__[0].__name__, generic.__type_params__[1].__kind__, generic.__type_params__[2].__kind__)",
        &["T TypeVarTuple ParamSpec"],
    );
    assert_output_with_stack(
        "def fact(n):\n    if n <= 1:\n        return 1\n    return n * fact(n - 1)\nprint(fact(5))",
        &["120"],
        8 * 1024 * 1024,
    );
}

// Adapted from CPython grammar `function_def_raw`, whose valid alternatives are
// ordinary `def` and `async def` headers with optional type parameters, params,
// return annotations, function type comments, and either inline or indented
// blocks. Invalid header shapes are covered by
// `cpython_invalid_function_def_raw_subset`.
#[test]
fn cpython_function_def_raw_rule_subset() {
    assert_output(
        "def typed():  # type: () -> int\n    return 9\nprint(typed())",
        &["9"],
    );
    assert_output(
        "def f[T](x: T, y: int = 2, *args: str, flag: bool = True, **kwargs: list) -> T:\n    return x\nprint(f(5, \"extra\", flag=False, bonus=9), f.__type_params__[0].__name__, f.__annotations__[\"x\"].__name__, f.__annotations__[\"return\"].__name__)",
        &["5 T T T"],
    );
    assert_output(
        "async def coro[T = int](value: T) -> T: return value\nc = coro(7)\ntry:\n    coro_result = c.send(None)\nexcept StopIteration as done:\n    print(done, coro.__type_params__[0].__default__.__name__, coro.__annotations__[\"value\"].__name__, coro.__annotations__[\"return\"].__name__)",
        &["7 int T T"],
    );
}

// Adapted from CPython grammar `function_def`, which is either decorators plus
// `function_def_raw` or the raw definition itself. This keeps the parent rule
// covered independently from the broader decorator helper tests.
#[test]
fn cpython_function_def_decorated_rule_subset() {
    assert_output(
        "def identity(fn):\n    return fn\n@identity\ndef plain(): return 3\n@identity\nasync def async_plain(): return 4\nprint(plain(), plain.__name__)\nc = async_plain()\ntry:\n    c.send(None)\nexcept StopIteration as done:\n    print(done, async_plain.__name__)",
        &["3 plain", "4 async_plain"],
    );
}

// Adapted from CPython grammar `class_def` and primary selector coverage.
// MiniPython checks class bodies, class attributes, instance creation,
// positional bases, and unpacked class-header arguments through observable
// runtime behavior.
#[test]
fn cpython_grammar_class_def_subset() {
    assert_output(
        "class Box:\n    pass\nbox = Box()\nbox.value = 3\nprint(box.value)",
        &["3"],
    );
    assert_output("class Inline: pass\nprint(Inline.__name__)", &["Inline"]);
    assert_output(
        "class Thing:\n    kind = \"thing\"\nprint(Thing.__name__, Thing.kind)\nThing.kind = \"changed\"\nprint(Thing.kind)",
        &["Thing thing", "changed"],
    );
    assert_output(
        "class Counter:\n    def __init__(self, start):\n        self.value = start\n    def inc(self):\n        self.value += 1\n        return self.value\nc = Counter(2)\nprint(c.value, c.inc(), c.value)",
        &["2 3 3"],
    );
    assert_output(
        "class Base:\n    kind = \"base\"\n    def __init__(self, value):\n        self.value = value\nclass Child(Base):\n    pass\nc = Child(4)\nprint(Child.__bases__[0].__name__, Child.kind, c.value)",
        &["Base base 4"],
    );
    assert_output(
        "class Base:\n    label = \"base\"\nbases = (Base,)\nkwargs = {'metaclass': type}\nclass FromUnpack(*bases, **kwargs):\n    pass\nprint(FromUnpack.__bases__[0].__name__, FromUnpack.label)",
        &["Base base"],
    );
}

#[test]
fn cpython_user_class_new_staticmethod_subset() {
    assert_output(
        r#"class A:
    def __new__(cls, x):
        print('new', cls.__name__, x)
        return object.__new__(cls)
    def __init__(self, x):
        print('init', type(self).__name__, x)
print(type(A.__dict__['__new__']).__name__)
print(type(A.__new__).__name__)
a = A(3)
print(type(a).__name__)
class B:
    def __new__(cls):
        return 42
    def __init__(self):
        print('bad init')
print(B())
class C:
    def __new__(cls):
        return object.__new__(D)
    def __init__(self):
        print('C init', type(self).__name__)
class D(C):
    pass
print(type(C()).__name__)
class E:
    def __new__(cls, x):
        print('new only', x)
        return object.__new__(cls)
print(type(E(9)).__name__)
class G:
    @classmethod
    def __new__(cls):
        return object.__new__(cls)
try:
    G()
except Exception as error:
    print('classmethod-new', type(error).__name__)
class FloatNew(float):
    def __new__(cls, value):
        print('float-new', cls.__name__, value)
        return float.__new__(cls, value + 1)
    def __init__(self, value):
        print('float-init', type(self).__name__, value)
float_value = FloatNew(1.5)
print(type(float_value).__name__, float_value, isinstance(float_value, float), float_value.hex())"#,
        &[
            "staticmethod",
            "function",
            "new A 3",
            "init A 3",
            "A",
            "42",
            "C init D",
            "D",
            "new only 9",
            "E",
            "classmethod-new TypeError",
            "float-new FloatNew 1.5",
            "float-init FloatNew 1.5",
            "FloatNew 2.5 True 0x1.4000000000000p+1",
        ],
    );
}

// Adapted from CPython Lib/test/test_grammar.py::GrammarTests.test_classdef.
// CPython's method mainly checks that these class definition and decorator
// shapes compile and execute, so this prints representative metadata and method
// call results for the same source forms.
#[test]
fn cpython_grammar_classdef_method_subset() {
    let source = r#"class B: pass
class B2(): pass
class C1(B): pass
class C2(B): pass
class D(C1, C2, B): pass
class C:
    def meth1(self): pass
    def meth2(self, arg): pass
    def meth3(self, a1, a2): pass

print(B.__name__, B2.__name__)
print(C1.__bases__[0] is B, C2.__bases__[0] is B)
print(D.__bases__[0] is C1, D.__bases__[1] is C2, D.__bases__[2] is B)
c = C()
print(c.meth1(), c.meth2(1), c.meth3(1, 2))

def class_decorator(x): return x
@class_decorator
class G: pass

@False or class_decorator
class H: pass
@d := class_decorator
class I: pass
@lambda c: class_decorator(c)
class J: pass
@[..., class_decorator, ...][1]
class K: pass
@class_decorator(class_decorator)(class_decorator)
class L: pass
@[class_decorator][0].__call__.__call__
class M: pass

print(G.__name__, H.__name__, I.__name__, J.__name__)
print(K.__name__, L.__name__, M.__name__, d.__name__)"#;
    assert_output(
        source,
        &[
            "B B2",
            "True True",
            "True True True",
            "None None None",
            "G H I J",
            "K L M class_decorator",
        ],
    );
}

// Adapted from CPython's `class_def_raw` and `invalid_class_def_raw` grammar
// rules. MiniPython supports the same raw class-header subset for names, type
// params, optional parentheses, base arguments, keyword arguments, and unpacked
// class-header arguments. It rejects the CPython-invalid missing-colon and
// missing-suite shapes before VM execution.
#[test]
fn cpython_class_def_raw_helper_rules_subset() {
    assert_output("class Plain:\n    pass\nprint(Plain.__name__)", &["Plain"]);
    assert_output(
        "class EmptyArgs():\n    pass\nprint(EmptyArgs.__name__)",
        &["EmptyArgs"],
    );
    assert_output(
        "class InlineEmptyArgs(): ...\nprint(InlineEmptyArgs.__name__)",
        &["InlineEmptyArgs"],
    );
    assert_output(
        "class Base:\n    label = \"base\"\nclass Child[T](Base):\n    pass\nprint(Child.__name__, Child.__type_params__[0].__name__, Child.__bases__[0].__name__, Child.label)",
        &["Child T Base base"],
    );
    assert_output(
        "class Base:\n    label = \"base\"\nbases = (Base,)\nkwargs = {'metaclass': type}\nclass FromArgs[T](*bases, **kwargs):\n    pass\nprint(FromArgs.__name__, FromArgs.__type_params__[0].__name__, FromArgs.__bases__[0].__name__, FromArgs.label)",
        &["FromArgs T Base base"],
    );
    assert_error(
        "class MissingColon\n    pass",
        "parse error: expected ':', found Newline",
    );
    assert_error(
        "class MissingColon[T]\n    pass",
        "parse error: expected ':', found Newline",
    );
    assert_error(
        "class MissingColon(Base)\n    pass",
        "parse error: expected ':', found Newline",
    );
    assert_error(
        "class MissingSuite:\npass",
        "parse error: expected an indented block",
    );
    assert_error(
        "class MissingSuite[T](Base):\npass",
        "parse error: expected an indented block",
    );
    assert_error(
        "class MissingSuite[T]():\npass",
        "parse error: expected an indented block",
    );
}

