// Adapted from CPython Lib/test/test_grammar.py::GrammarTests.test_atoms.
// CPython's method is compile-and-run oriented, so this keeps the exact atom
// source shapes together and prints representative values for each family.
#[test]
fn cpython_grammar_atoms_subset() {
    let source = r#"x = (1)
print(x)
x = (1 or 2 or 3)
print(x)
x = (1 or 2 or 3, 2, 3)
print(x)

x = []
print(x)
x = [1]
print(x)
x = [1 or 2 or 3]
print(x)
x = [1 or 2 or 3, 2, 3]
print(x)
x = []
print(x)

x = {}
print(x)
x = {'one': 1}
print(x == {'one': 1})
x = {'one': 1,}
print(x == {'one': 1})
x = {'one' or 'two': 1 or 2}
print(x == {'one': 1})
x = {'one': 1, 'two': 2}
print(x == {'one': 1, 'two': 2})
x = {'one': 1, 'two': 2,}
print(x == {'one': 1, 'two': 2})
x = {'one': 1, 'two': 2, 'three': 3, 'four': 4, 'five': 5, 'six': 6}
print(x['one'], x['six'], len(x))

x = {'one'}
print(len(x), 'one' in x)
x = {'one', 1,}
print(len(x), 'one' in x, 1 in x)
x = {'one', 'two', 'three'}
print(len(x), 'two' in x)
x = {2, 3, 4,}
print(len(x), 2 in x, 4 in x)

x = x
print(len(x))
x = 'x'
print(x)
x = 123
print(x)"#;
    assert_output(
        source,
        &[
            "1",
            "1",
            "(1, 2, 3)",
            "[]",
            "[1]",
            "[1]",
            "[1, 2, 3]",
            "[]",
            "{}",
            "True",
            "True",
            "True",
            "True",
            "True",
            "1 6 6",
            "1 True",
            "2 True True",
            "3 True",
            "3 True True",
            "3",
            "x",
            "123",
        ],
    );
}

// Adapted from CPython grammar selector coverage in
// Lib/test/test_grammar.py::test_selectors and AST subscript snippets in
// Lib/test/test_ast/snippets.py. MiniPython currently supports single integer
// indices for list, string, and range values; slices and assignment targets are
// tracked separately.
#[test]
fn cpython_grammar_subscript_index_subset() {
    assert_output("a = [10, 20, 30]\nprint(a[0])\nprint(a[-1])", &["10", "30"]);
    assert_output("a = (10, 20, 30)\nprint(a[0])\nprint(a[-1])", &["10", "30"]);
    assert_output("print([1, 2, 3][0], [1, 2, 3][2])", &["1 3"]);
    assert_output("a = \"01234\"\nprint(a[0])\nprint(a[-1])", &["0", "4"]);
    assert_output("r = range(1, 6, 2)\nprint(r[0], r[-1])", &["1 5"]);
}

// Adapted from CPython grammar selector coverage in
// Lib/test/test_grammar.py::test_selectors and AST `Slice` snippets in
// Lib/test/test_ast/snippets.py. MiniPython supports one-dimensional slices
// with optional start, stop, and step for list, string, and range values.
#[test]
fn cpython_grammar_slice_subset() {
    assert_output(
        "a = \"01234\"\nprint(a[0:5])\nprint(a[:5])\nprint(a[0:])\nprint(a[:])\nprint(a[-5:])\nprint(a[:-1])\nprint(a[-4:-3])",
        &["01234", "01234", "01234", "01234", "01234", "0123", "1"],
    );
    assert_output(
        "a = [0, 1, 2, 3, 4]\nprint(a[1:4])\nprint(a[:2])\nprint(a[2:])\nprint(a[::2])\nprint(a[::-1])",
        &[
            "[1, 2, 3]",
            "[0, 1]",
            "[2, 3, 4]",
            "[0, 2, 4]",
            "[4, 3, 2, 1, 0]",
        ],
    );
    assert_output(
        "a = (0, 1, 2, 3, 4)\nprint(a[1:4])\nprint(a[:2])\nprint(a[::-1])",
        &["(1, 2, 3)", "(0, 1)", "(4, 3, 2, 1, 0)"],
    );
    assert_output(
        "print([5][1:])\nprint([5][:1])\nprint([5][::1])",
        &["[]", "[5]", "[5]"],
    );
    assert_output("r = range(1, 8, 2)\nprint(r[1:])", &["range(3, 9, 2)"]);
}

// Adapted from CPython's selector helper grammar rules: `slices` and `slice`.
// MiniPython covers simple index expressions, tuple-key subscripts, first-class
// slice values, and one-dimensional sequence slicing.
#[test]
fn cpython_selector_helper_rules_subset() {
    assert_output(
        "items = [0, 1, 2, 3, 4]\nprint(items[0], items[-1])\nprint(items[:], items[1:4], items[::2], items[::-1])",
        &["0 4", "[0, 1, 2, 3, 4] [1, 2, 3] [0, 2, 4] [4, 3, 2, 1, 0]"],
    );
    assert_output("text = \"abcdef\"\nprint(text[1:5:2])", &["bd"]);
    assert_output(
        "mapping = {(1,): 'single', (1, 2): 'pair'}\nprint(mapping[1,], mapping[1, 2])",
        &["single pair"],
    );
    assert_output(
        "alias = list[1:2, ::-1, 3]\nprint(alias.__args__)\nprint(alias.__args__[0].start, alias.__args__[0].stop, alias.__args__[0].step)",
        &["(slice(1, 2, None), slice(None, None, -1), 3)", "1 2 None"],
    );
    assert_output(
        "alias = dict[str:int]\nprint(alias.__args__[0].start.__name__, alias.__args__[0].stop.__name__, alias.__args__[0].step)",
        &["str int None"],
    );
    assert_output(
        "s = slice(1, 4, 2)\nprint([0, 1, 2, 3, 4][s])\nprint(s.start, s.stop, s.step)\nprint(slice(None, 2) == slice(None, 2, None))",
        &["[1, 3]", "1 4 2", "True"],
    );
    assert_output(
        "mapping = {slice(1, 2): 'window'}\nprint(mapping[slice(1, 2)])",
        &["window"],
    );
    assert_output(
        "print(slice(None).indices(10))\nprint(slice(None, None, 2).indices(10))\nprint(slice(1, None, 2).indices(10))\nprint(slice(None, None, -1).indices(10))\nprint(slice(None, None, -2).indices(10))\nprint(slice(3, None, -2).indices(10))\nprint(slice(None, -9).indices(10))\nprint(slice(None, -10).indices(10))\nprint(slice(None, -11).indices(10))\nprint(slice(None, -10, -1).indices(10))\nprint(slice(None, -11, -1).indices(10))\nprint(slice(None, -12, -1).indices(10))\nprint(slice(None, 9).indices(10))\nprint(slice(None, 10).indices(10))\nprint(slice(None, 11).indices(10))\nprint(slice(None, 8, -1).indices(10))\nprint(slice(None, 9, -1).indices(10))\nprint(slice(None, 10, -1).indices(10))\nprint(slice(-100, 100).indices(10) == slice(None).indices(10))\nprint(slice(100, -100, -1).indices(10) == slice(None, None, -1).indices(10))\nprint(slice(-100, 100, 2).indices(10))",
        &[
            "(0, 10, 1)",
            "(0, 10, 2)",
            "(1, 10, 2)",
            "(9, -1, -1)",
            "(9, -1, -2)",
            "(3, -1, -2)",
            "(0, 1, 1)",
            "(0, 0, 1)",
            "(0, 0, 1)",
            "(9, 0, -1)",
            "(9, -1, -1)",
            "(9, -1, -1)",
            "(0, 9, 1)",
            "(0, 10, 1)",
            "(0, 10, 1)",
            "(9, 8, -1)",
            "(9, 9, -1)",
            "(9, 9, -1)",
            "True",
            "True",
            "(0, 10, 2)",
        ],
    );
    assert_output(
        "class I:\n    def __init__(self, value):\n        self.value = value\n    def __index__(self):\n        return self.value\nprint(slice(I(0), I(10), I(1)).indices(I(5)))",
        &["(0, 5, 1)"],
    );
    assert_output(
        "for expr in [lambda: slice(None).indices(-1), lambda: slice(0, 10, 0).indices(5), lambda: slice(0.0, 10, 1).indices(5), lambda: slice(0, 10, 1).indices(5.0)]:\n    try:\n        expr()\n    except (TypeError, ValueError) as error:\n        print(error.__class__.__name__, error)",
        &[
            "ValueError length should not be negative",
            "ValueError slice step cannot be zero",
            "TypeError slice indices must be integers or None or have an __index__ method",
            "TypeError 'float' object cannot be interpreted as an integer",
        ],
    );
    assert_output(
        "mapping = {(1, 2): 'pair', (1, 2, 3): 'triple'}\nprint(mapping[*[1, 2]])\nprint(mapping[*[1, 2], 3])",
        &["pair", "triple"],
    );
    assert_output(
        "mapping = {}\nmapping[*[1, 2]] = \"pair\"\nmapping[*[1, 2]] += \"!\"\nprint(mapping[1, 2])\ndel mapping[*[1, 2]]\nprint(len(mapping))",
        &["pair!", "0"],
    );
    assert_output(
        "type Alias[*Ts] = tuple[*Ts]\nprint(Alias.__value__)\nprint(Alias.__value__.__args__[0].__value__.__name__)",
        &["tuple[*Ts]", "Ts"],
    );
}

// Adapted from CPython tokenizer and grammar string-literal coverage in
// Lib/test/test_tokenize.py, Lib/test/test_grammar.py, and
// Lib/test/test_str.py::test_literals. MiniPython covers an executable subset
// of quoting forms, escapes, raw strings, adjacent literal concatenation, and
// string `+`.
#[test]
fn cpython_string_literal_and_concat_subset() {
    assert_output("x = \"x\"\nprint(x)", &["x"]);
    assert_output("y = \"ABC\" + \"ABC\"\nprint(y)", &["ABCABC"]);
    assert_output("print(\"mini\" + \"python\")", &["minipython"]);
    assert_output(
        "print('single', \"double\", '''triple''')",
        &["single double triple"],
    );
    assert_output("print(\"mini\" 'python')", &["minipython"]);
    assert_output("print('line\\nbreak')", &["line\nbreak"]);
    assert_output("print(r\"\\u0020\" == \" \")", &["False"]);
    assert_output("print(\"\\x41\", \"\\u0042\", \"\\U00000043\")", &["A B C"]);
}

// Adapted from CPython's string method coverage in
// Lib/test/string_tests.py::test_startswith and ::test_endswith. MiniPython
// covers ordinary string prefixes/suffixes, optional bounds, negative bounds,
// tuple prefixes/suffixes, and representative TypeError paths.
#[test]
fn cpython_string_startswith_endswith_subset() {
    assert_output(
        "print('hello'.startswith('he'), 'hello'.startswith('hello'), 'hello'.startswith('hello world'), 'hello'.startswith(''), 'hello'.startswith('ello'))\nprint('hello'.startswith('ello', 1), 'hello'.startswith('o', 4), 'hello'.startswith('o', 5), 'hello'.startswith('', 5), 'hello'.startswith('lo', 6))\nprint('helloworld'.startswith('lowo', 3), 'helloworld'.startswith('lowo', 3, 7), 'helloworld'.startswith('lowo', 3, 6))\nprint('hello'.startswith('he', 0, -1), 'hello'.startswith('he', -53, -1), 'hello'.startswith('ello', -4), 'hello'.startswith('o', -1), 'hello'.startswith('', -3, -3))\nprint(''.startswith('', 0, 1), ''.startswith('', 1, 0))\nprint('hello'.startswith(('he', 'ha')), 'hello'.startswith(('lo', 'llo')), 'hello'.startswith(('hellox', 'hello')), 'hello'.startswith(()), 'hello'.startswith(('he', 'hel'), 0, 2))",
        &[
            "True True False True False",
            "True True False True False",
            "True True False",
            "True True True True True",
            "True False",
            "True False True False True",
        ],
    );
    assert_output(
        "print('hello'.endswith('lo'), 'hello'.endswith('he'), 'hello'.endswith(''), 'hello'.endswith('hello world'))\nprint('helloworld'.endswith('worl', 3, 9), 'helloworld'.endswith('world', 3, 12), 'helloworld'.endswith('lowo', 1, 7), 'helloworld'.endswith('lowo', 4, 7))\nprint('ab'.endswith('ab', 0, 1), 'ab'.endswith('ab', 0, 0), ''.endswith('', 0, 1), ''.endswith('', 1, 0))\nprint('hello'.endswith('lo', -2), 'hello'.endswith('he', -2), 'hello'.endswith('', -3, -3), 'helloworld'.endswith('world', -7, 12), 'helloworld'.endswith('lowo', -8, -3))\nprint('hello'.endswith(('he', 'ha')), 'hello'.endswith(('lo', 'llo')), 'hello'.endswith(('hellox', 'hello')), 'hello'.endswith(()), 'hello'.endswith(('he', 'hell'), 0, 4))",
        &[
            "True False True False",
            "True True True False",
            "False False True False",
            "True False True True True",
            "False True True False True",
        ],
    );
    assert_output(
        "for expr in [lambda: 'hello'.startswith(), lambda: 'hello'.startswith(42), lambda: 'hello'.startswith((42,)), lambda: 'hello'.endswith(), lambda: 'hello'.endswith(42), lambda: 'hello'.endswith((42,))]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython's string method coverage in
// Lib/test/string_tests.py::test_find, ::test_rfind, ::test_index, and
// ::test_rindex. MiniPython covers forward/reverse search, optional bounds,
// `None` defaults, empty needle behavior, Unicode character positions, and
// representative TypeError/ValueError paths.
#[test]
fn cpython_string_find_index_subset() {
    assert_output(
        "print('abcdefghiabc'.find('abc'), 'abcdefghiabc'.find('abc', 1), 'abcdefghiabc'.find('def', 4))\nprint('abc'.find('', 0), 'abc'.find('', 3), 'abc'.find('', 4))\nprint('rrarrrrrrrrra'.find('a'), 'rrarrrrrrrrra'.find('a', 4), 'rrarrrrrrrrra'.find('a', 4, 6), 'rrarrrrrrrrra'.find('a', 4, None), 'rrarrrrrrrrra'.find('a', None, 6))\nprint(''.find(''), ''.find('', 1, 1), ''.find('', 10 ** 30, 0))\nprint(''.find('xx'), ''.find('xx', 1, 1), ''.find('xx', 10 ** 30, 0))",
        &["0 9 -1", "0 3 -1", "2 12 -1 12 2", "0 -1 -1", "-1 -1 -1"],
    );
    assert_output(
        "print('abcdefghiabc'.rfind('abc'), 'abcdefghiabc'.rfind(''), 'abcdefghiabc'.rfind('abcd'), 'abcdefghiabc'.rfind('abcz'))\nprint('abc'.rfind('', 0), 'abc'.rfind('', 3), 'abc'.rfind('', 4))\nprint('rrarrrrrrrrra'.rfind('a'), 'rrarrrrrrrrra'.rfind('a', 4), 'rrarrrrrrrrra'.rfind('a', 4, 6), 'rrarrrrrrrrra'.rfind('a', 4, None), 'rrarrrrrrrrra'.rfind('a', None, 6))\nprint('<......м...'.rfind('<'))\nprint('ab'.rfind('xxx', 10 ** 30, 0))",
        &["9 12 0 -1", "3 3 -1", "12 12 -1 12 2", "0", "-1"],
    );
    assert_output(
        "print('abcdefghiabc'.index(''), 'abcdefghiabc'.index('def'), 'abcdefghiabc'.index('abc'), 'abcdefghiabc'.index('abc', 1))\nprint('rrarrrrrrrrra'.index('a'), 'rrarrrrrrrrra'.index('a', 4), 'rrarrrrrrrrra'.index('a', 4, None), 'rrarrrrrrrrra'.index('a', None, 6))\nprint('abcdefghiabc'.rindex(''), 'abcdefghiabc'.rindex('def'), 'abcdefghiabc'.rindex('abc'), 'abcdefghiabc'.rindex('abc', 0, -1))\nprint('rrarrrrrrrrra'.rindex('a'), 'rrarrrrrrrrra'.rindex('a', 4), 'rrarrrrrrrrra'.rindex('a', 4, None), 'rrarrrrrrrrra'.rindex('a', None, 6))",
        &["0 3 0 9", "2 12 12 2", "12 3 9 0", "12 12 12 2"],
    );
    assert_output(
        "for expr in [lambda: 'hello'.find(), lambda: 'hello'.find(42), lambda: 'hello'.rfind(), lambda: 'hello'.rfind(42), lambda: 'hello'.index(), lambda: 'hello'.index(42), lambda: 'hello'.rindex(), lambda: 'hello'.rindex(42)]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
    assert_output(
        "for expr in [lambda: 'abcdefghiabc'.index('hib'), lambda: 'abcdefghiab'.index('abc', 1), lambda: 'abcdefghi'.index('ghi', 8), lambda: 'abcdefghi'.index('ghi', -1), lambda: 'rrarrrrrrrrra'.index('a', 4, 6), lambda: 'abcdefghiabc'.rindex('hib'), lambda: 'defghiabc'.rindex('def', 1), lambda: 'defghiabc'.rindex('abc', 0, -1), lambda: 'abcdefghi'.rindex('ghi', 0, 8), lambda: 'abcdefghi'.rindex('ghi', 0, -1), lambda: 'rrarrrrrrrrra'.rindex('a', 4, 6)]:\n    try:\n        expr()\n    except ValueError as error:\n        print(error.__class__.__name__)",
        &[
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
        ],
    );
}

// Adapted from CPython's string method coverage in
// Lib/test/string_tests.py::test_count, ::test_lower, and ::test_upper.
// MiniPython covers bounded non-overlapping counts, empty-needle edge cases,
// Unicode-aware case conversion, and representative TypeError paths.
#[test]
fn cpython_string_count_case_subset() {
    assert_output(
        "print('aaa'.count('a'), 'aaa'.count('b'), 'aaa'.count('aa'))\nprint('aaa'.count('a', 1), 'aaa'.count('a', 10), 'aaa'.count('a', -1), 'aaa'.count('a', -10))\nprint('aaa'.count('a', 0, 1), 'aaa'.count('a', 0, 10), 'aaa'.count('a', 0, -1), 'aaa'.count('a', 0, -10))",
        &["3 0 1", "2 0 1 3", "1 3 2 0"],
    );
    assert_output(
        "print('aaa'.count('', 1), 'aaa'.count('', 3), 'aaa'.count('', 10), 'aaa'.count('', -1), 'aaa'.count('', -10))\nprint(''.count(''), ''.count('', 1, 1), ''.count('', 10 ** 30, 0))\nprint(''.count('xx'), ''.count('xx', 1, 1), ''.count('xx', 10 ** 30, 0))",
        &["3 1 0 2 4", "1 0 0", "0 0 0"],
    );
    assert_output(
        "print('HeLLo'.lower(), 'hello'.lower(), 'Straße'.upper())\nprint('HeLLo'.upper(), 'HELLO'.upper(), 'MIXED 123'.lower())",
        &["hello hello STRASSE", "HELLO HELLO mixed 123"],
    );
    assert_output(
        "for expr in [lambda: 'hello'.count(), lambda: 'hello'.count(42), lambda: 'hello'.lower(42), lambda: 'hello'.upper(42)]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &["TypeError", "TypeError", "TypeError", "TypeError"],
    );
}

// Adapted from CPython's string method coverage in
// Lib/test/string_tests.py::test_capitalize, ::test_title, and ::test_swapcase,
// plus Lib/test/test_str.py::test_casefold and selected Unicode case mappings.
// MiniPython covers representative ASCII behavior, common Unicode expansions,
// casefold mappings, and TypeError paths.
#[test]
fn cpython_string_capitalize_title_swapcase_casefold_subset() {
    assert_output(
        "print(' hello '.capitalize())\nprint('Hello '.capitalize())\nprint('hello '.capitalize())\nprint('aaaa'.capitalize())\nprint('AaAa'.capitalize())",
        &[" hello ", "Hello ", "Hello ", "Aaaa", "Aaaa"],
    );
    assert_output(
        "print(' hello '.title())\nprint('hello '.title())\nprint('Hello '.title())\nprint('fOrMaT thIs aS titLe String'.title())\nprint('fOrMaT,thIs-aS*titLe;String'.title())\nprint('getInt'.title())",
        &[
            " Hello ",
            "Hello ",
            "Hello ",
            "Format This As Title String",
            "Format,This-As*Title;String",
            "Getint",
        ],
    );
    assert_output(
        "print('HeLLo cOmpUteRs'.swapcase())\nprint('hello'.casefold(), 'hELlo'.casefold())\nprint('ß'.casefold(), 'ﬁ'.casefold(), 'Σ'.casefold(), 'AͅΣ'.casefold(), 'µ'.casefold())",
        &["hEllO CoMPuTErS", "hello hello", "ss fi σ aισ μ"],
    );
    assert_output(
        "print('\\U0001044f'.capitalize() == '\\U00010427')\nprint('h\\u0130'.capitalize() == 'Hi\\u0307')\nprint('ﬁnnish'.capitalize() == 'Finnish')\nprint('\\U0001044f\\U0001044f'.title() == '\\U00010427\\U0001044f')\nprint('ﬁ'.swapcase() == 'FI')\nprint('\\u0130'.swapcase() == 'i\\u0307')\nprint('ß'.swapcase() == 'SS')",
        &["True", "True", "True", "True", "True", "True", "True"],
    );
    assert_output(
        "print('A\\u03a3'.lower() == 'a\\u03c2')\nprint('A\\u03a3A'.lower() == 'a\\u03c3a')\nprint('A\\u0345\\u03a3'.capitalize() == 'A\\u0345\\u03c2')\nprint('A\\u03a3 A\\u03a3'.title() == 'A\\u03c2 A\\u03c2')\nprint('A\\u03a3A'.title() == 'A\\u03c3a')\nprint('A\\u03a3 \\u1fa1xy'.title() == 'A\\u03c2 \\u1fa9xy')",
        &["True", "True", "True", "True", "True", "True"],
    );
    assert_output(
        "for expr in [lambda: 'hello'.capitalize(42), lambda: 'hello'.title(42), lambda: 'hello'.swapcase(42), lambda: 'hello'.casefold(42)]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &["TypeError", "TypeError", "TypeError", "TypeError"],
    );
}

// Adapted from CPython's string predicate coverage in
