// Adapted from CPython's string method coverage in
// Lib/test/string_tests.py::test_ljust, ::test_rjust, ::test_center, and
// ::test_zfill, plus non-BMP fill-character checks from Lib/test/test_str.py.
// MiniPython covers width handling, custom one-character fill, sign-aware zfill,
// Unicode fill characters, and representative TypeError paths.
#[test]
fn cpython_string_alignment_and_zfill_subset() {
    assert_output(
        "print(repr('abc'.ljust(10)), repr('abc'.ljust(6)), repr('abc'.ljust(3)), repr('abc'.ljust(2)), repr('abc'.ljust(10, '*')))\nprint(repr('abc'.rjust(10)), repr('abc'.rjust(6)), repr('abc'.rjust(3)), repr('abc'.rjust(2)), repr('abc'.rjust(10, '*')))\nprint(repr('abc'.center(10)), repr('abc'.center(6)), repr('abc'.center(3)), repr('abc'.center(2)), repr('abc'.center(10, '*')))",
        &[
            "'abc       ' 'abc   ' 'abc' 'abc' 'abc*******'",
            "'       abc' '   abc' 'abc' 'abc' '*******abc'",
            "'   abc    ' ' abc  ' 'abc' 'abc' '***abc****'",
        ],
    );
    assert_output(
        "print('x'.center(2, '\\U0010ffff') == 'x\\U0010ffff')\nprint('x'.center(3, '\\U0010ffff') == '\\U0010ffffx\\U0010ffff')\nprint('x'.center(4, '\\U0010ffff') == '\\U0010ffffx\\U0010ffff\\U0010ffff')\nprint('\\U00100000'.ljust(3, '\\U00010000') == '\\U00100000\\U00010000\\U00010000')\nprint('\\U00100000'.rjust(3, '\\U00010000') == '\\U00010000\\U00010000\\U00100000')",
        &["True", "True", "True", "True", "True"],
    );
    assert_output(
        "print('123'.zfill(2), '123'.zfill(3), '123'.zfill(4))\nprint('+123'.zfill(3), '+123'.zfill(4), '+123'.zfill(5))\nprint('-123'.zfill(3), '-123'.zfill(4), '-123'.zfill(5))\nprint(repr(''.zfill(3)), '34'.zfill(1), '34'.zfill(4))",
        &[
            "123 123 0123",
            "+123 +123 +0123",
            "-123 -123 -0123",
            "'000' 34 0034",
        ],
    );
    assert_output(
        "for expr in [lambda: 'abc'.ljust(), lambda: 'abc'.rjust(), lambda: 'abc'.center(), lambda: '123'.zfill(), lambda: 'abc'.ljust('x'), lambda: 'abc'.rjust(5, ''), lambda: 'abc'.center(5, '**'), lambda: '123'.zfill(4, '0')]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython's string method coverage in
// Lib/test/string_tests.py::test_split and ::test_rsplit. MiniPython covers
// default whitespace splitting, explicit separators, right splitting,
// `maxsplit`, keyword `sep` / `maxsplit`, empty input, empty fields, and
// representative TypeError / ValueError paths.
#[test]
fn cpython_string_split_rsplit_subset() {
    assert_output(
        "print('a b c d'.split())\nprint('a  b  c d'.split())\nprint(''.split())\nprint('a b c d'.split(None, 1))\nprint('  a b  '.split(None, 0))",
        &[
            "['a', 'b', 'c', 'd']",
            "['a', 'b', 'c', 'd']",
            "[]",
            "['a', 'b c d']",
            "['a b  ']",
        ],
    );
    assert_output(
        "print('a|b|c|d'.split('|'))\nprint('a|b|c|d'.split('|', 0))\nprint('a|b|c|d'.split('|', 1))\nprint('a||b||c||d'.split('|', 2))\nprint('abcd'.split('|'), ''.split('|'), 'endcase |'.split('|'), '| startcase'.split('|'), '|bothcase|'.split('|'))",
        &[
            "['a', 'b', 'c', 'd']",
            "['a|b|c|d']",
            "['a', 'b|c|d']",
            "['a', '', 'b||c||d']",
            "['abcd'] [''] ['endcase ', ''] ['', ' startcase'] ['', 'bothcase', '']",
        ],
    );
    assert_output(
        "print('a//b//c//d'.split('//'))\nprint('a//b//c//d'.split('//', 2))\nprint('a////b////c////d'.split('//', 2))\nprint('test begincase'.split('test'), 'endcase test'.split('test'), 'aaa'.split('aaa'), 'abbaab'.split('ba'))",
        &[
            "['a', 'b', 'c', 'd']",
            "['a', 'b', 'c//d']",
            "['a', '', 'b////c////d']",
            "['', ' begincase'] ['endcase ', ''] ['', ''] ['ab', 'ab']",
        ],
    );
    assert_output(
        "print('a b c d'.rsplit())\nprint('a  b  c d'.rsplit())\nprint(''.rsplit())\nprint('a b c d'.rsplit(None, 1))\nprint('  a b  '.rsplit(None, 0))",
        &[
            "['a', 'b', 'c', 'd']",
            "['a', 'b', 'c', 'd']",
            "[]",
            "['a b c', 'd']",
            "['  a b']",
        ],
    );
    assert_output(
        "print('a|b|c|d'.rsplit('|'))\nprint('a|b|c|d'.rsplit('|', 1))\nprint('a|b|c|d'.rsplit('|', 2))\nprint('a||b||c||d'.rsplit('|', 2))\nprint('| begincase'.rsplit('|'), 'endcase |'.rsplit('|'), '|bothcase|'.rsplit('|'))",
        &[
            "['a', 'b', 'c', 'd']",
            "['a|b|c', 'd']",
            "['a|b', 'c', 'd']",
            "['a||b||c', '', 'd']",
            "['', ' begincase'] ['endcase ', ''] ['', 'bothcase', '']",
        ],
    );
    assert_output(
        "print('a//b//c//d'.rsplit('//', 2))\nprint('a////b////c////d'.rsplit('//', 2))\nprint('test begincase'.rsplit('test'), 'endcase test'.rsplit('test'), 'aaa'.rsplit('aaa'), 'abbaab'.rsplit('ba'))\nprint('a|b|c|d'.split(sep='|'), 'a|b|c|d'.split('|', maxsplit=1), 'a b c d'.split(maxsplit=1))\nprint('a|b|c|d'.rsplit(sep='|'), 'a|b|c|d'.rsplit('|', maxsplit=1), 'a b c d'.rsplit(maxsplit=1))",
        &[
            "['a//b', 'c', 'd']",
            "['a////b////c', '', 'd']",
            "['', ' begincase'] ['endcase ', ''] ['', ''] ['ab', 'ab']",
            "['a', 'b', 'c', 'd'] ['a', 'b|c|d'] ['a', 'b c d']",
            "['a', 'b', 'c', 'd'] ['a|b|c', 'd'] ['a b c', 'd']",
        ],
    );
    assert_output(
        "for expr in [lambda: 'hello'.split(42, 42, 42), lambda: 'hello'.rsplit(42, 42, 42), lambda: 'hello'.split(maxsplit=None), lambda: 'hello'.rsplit(maxsplit=None)]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)\nfor expr in [lambda: 'hello'.split(''), lambda: 'hello'.split('', 0), lambda: 'hello'.rsplit(''), lambda: 'hello'.rsplit('', 0)]:\n    try:\n        expr()\n    except ValueError as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
        ],
    );
}

