// Adapted from CPython's string method coverage in
// Lib/test/string_tests.py::test_partition and ::test_rpartition. MiniPython
// covers first/last separator search, not-found triples, Unicode separators,
// and representative TypeError / ValueError paths.
#[test]
fn cpython_string_partition_rpartition_subset() {
    assert_output(
        "S = 'http://www.python.org'\nprint(S.partition('://'))\nprint(S.partition('?'))\nprint(S.partition('http://'))\nprint(S.partition('org'))",
        &[
            "('http', '://', 'www.python.org')",
            "('http://www.python.org', '', '')",
            "('', 'http://', 'www.python.org')",
            "('http://www.python.', 'org', '')",
        ],
    );
    assert_output(
        "S = 'http://www.python.org'\nprint(S.rpartition('://'))\nprint(S.rpartition('?'))\nprint(S.rpartition('http://'))\nprint(S.rpartition('org'))",
        &[
            "('http', '://', 'www.python.org')",
            "('', '', 'http://www.python.org')",
            "('', 'http://', 'www.python.org')",
            "('http://www.python.', 'org', '')",
        ],
    );
    assert_output(
        "left = 'āĀ' * 3\nright = '𐌁𐌀' * 3\nprint((left + right).partition('Ă'))\nprint((left + 'Ă' + right).partition('Ă'))\nprint((left + 'ĂĂ' + right).rpartition('ĂĂ'))",
        &[
            "('āĀāĀāĀ𐌁𐌀𐌁𐌀𐌁𐌀', '', '')",
            "('āĀāĀāĀ', 'Ă', '𐌁𐌀𐌁𐌀𐌁𐌀')",
            "('āĀāĀāĀ', 'ĂĂ', '𐌁𐌀𐌁𐌀𐌁𐌀')",
        ],
    );
    assert_output(
        "S = 'http://www.python.org'\nfor expr in [lambda: S.partition(''), lambda: S.rpartition(''), lambda: S.partition(None), lambda: S.rpartition(None), lambda: S.partition('x', 'y')]:\n    try:\n        expr()\n    except (TypeError, ValueError) as error:\n        print(error.__class__.__name__)",
        &[
            "ValueError",
            "ValueError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython's string method coverage in
// Lib/test/string_tests.py::test_join. MiniPython covers list, tuple, generator,
// sequence-protocol, repeated-item, and representative TypeError join paths.
#[test]
fn cpython_string_join_subset() {
    assert_output(
        "print(' '.join(['a', 'b', 'c', 'd']))\nprint(''.join(('a', 'b', 'c', 'd')))\nprint(''.join(('', 'b', '', 'd')))\nprint(''.join(('a', '', 'c', '')))\nprint('a'.join(('abc',)))\nprint('.'.join(['a', 'b', 'c']))",
        &["a b c d", "abcd", "bd", "ac", "abc", "a.b.c"],
    );
    assert_output(
        "class Sequence:\n    def __init__(self, seq='wxyz'):\n        self.seq = seq\n    def __getitem__(self, i):\n        return self.seq[i]\nclass LiesAboutLengthSeq(Sequence):\n    def __init__(self):\n        self.seq = ['a', 'b', 'c']\n    def __len__(self):\n        return 8\nprint(' '.join(Sequence()))\nprint(' '.join(LiesAboutLengthSeq()))\nprint(''.join(x for x in ['a', 'b', 'c']))",
        &["w x y z", "a b c", "abc"],
    );
    assert_output(
        "for i in [5, 25, 125]:\n    value = '-'.join(['a' * i] * i)\n    expected = ((('a' * i) + '-') * i)[:-1]\n    print(value == expected, len(value))",
        &["True 29", "True 649", "True 15749"],
    );
    assert_output(
        "for expr in [lambda: ' '.join(), lambda: ' '.join(None), lambda: ' '.join(7), lambda: '.'.join(['a', 'b', 3]), lambda: ' '.join([1, 2, bytes()])]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
    assert_output(
        "def f():\n    yield 4 + ''\ntry:\n    ' '.join(f())\nexcept TypeError as error:\n    print('+' in str(error))",
        &["True"],
    );
}

