#[test]
fn cpython_json_dumps_separators_subset() {
    assert_output(
        "import json\nclass Sep(str):\n    pass\nclass SepAsBang(str):\n    def __str__(self):\n        return '!'\nclass SepNonString(str):\n    def __str__(self):\n        return 42\nclass SepBoom(str):\n    def __str__(self):\n        raise RuntimeError('sep boom')\nclass SepList(list):\n    pass\nclass SepTuple(tuple):\n    pass\nclass SepIter:\n    def __iter__(self):\n        return iter((',', ':'))\nclass SepGen:\n    def __iter__(self):\n        yield ','\n        yield ':'\nvalue = {'b': [1, 2], 'a': {'é': '𝄠'}}\nfor separators in [None, (',', ':'), [',', ': '], (Sep(' | '), Sep(' => ')), SepList([',', ':']), SepTuple((Sep(' / '), Sep(' -> ')))]:\n    print(json.dumps(value, separators=separators))\nsimple = {'a': [1, 2]}\nprint('str-override', json.dumps(simple, separators=(SepAsBang('|'), SepAsBang('='))))\nfor separators in [(SepNonString('|'), '='), ('|', SepNonString('=')), (SepBoom('|'), '='), ('|', SepBoom('='))]:\n    try:\n        json.dumps(simple, separators=separators)\n    except Exception as error:\n        print(type(error).__name__, isinstance(error, (TypeError, RuntimeError)), str(error))\nfor separators in [iter((',', ':')), SepIter(), SepGen()]:\n    print(json.dumps({'b': [1, 2], 'a': 3}, separators=separators, sort_keys=True))\nprint(json.dumps({'é': ['𝄠', {'b': 1, 'a': 2}]}, ensure_ascii=False, sort_keys=True, separators=(',', ':')))\n# CPython oracle text: not enough values to unpack (expected 2, got 0); too many values to unpack (expected 2, got 3); too many values to unpack (expected 2); cannot unpack non-iterable int object; make_encoder() argument 6 must be str, not int; make_encoder() argument 5 must be str, not int; make_encoder() argument 5 must be str, not None\nfor separators in [(), [], (',',), [','], (',', ':', 'x'), [',', ':', 'x'], 'bad', 7, object(), (1, ':'), (',', 1), (None, ':'), (',', None), (None, None), (False, ':'), (',', False), (False, False)]:\n    try:\n        json.dumps(value, separators=separators)\n    except Exception as error:\n        print(type(error).__name__, isinstance(error, (TypeError, ValueError)), str(error))",
        &[
            "{\"b\": [1, 2], \"a\": {\"\\u00e9\": \"\\ud834\\udd20\"}}",
            "{\"b\":[1,2],\"a\":{\"\\u00e9\":\"\\ud834\\udd20\"}}",
            "{\"b\": [1,2],\"a\": {\"\\u00e9\": \"\\ud834\\udd20\"}}",
            "{\"b\" => [1 | 2] | \"a\" => {\"\\u00e9\" => \"\\ud834\\udd20\"}}",
            "{\"b\":[1,2],\"a\":{\"\\u00e9\":\"\\ud834\\udd20\"}}",
            "{\"b\" -> [1 / 2] / \"a\" -> {\"\\u00e9\" -> \"\\ud834\\udd20\"}}",
            "str-override {\"a\"![1!2]}",
            "TypeError True __str__ returned non-string (type int)",
            "TypeError True __str__ returned non-string (type int)",
            "RuntimeError True sep boom",
            "RuntimeError True sep boom",
            "{\"a\":3,\"b\":[1,2]}",
            "{\"a\":3,\"b\":[1,2]}",
            "{\"a\":3,\"b\":[1,2]}",
            "{\"é\":[\"𝄠\",{\"a\":2,\"b\":1}]}",
            "ValueError True not enough values to unpack (expected 2, got 0)",
            "ValueError True not enough values to unpack (expected 2, got 0)",
            "ValueError True not enough values to unpack (expected 2, got 1)",
            "ValueError True not enough values to unpack (expected 2, got 1)",
            "ValueError True too many values to unpack (expected 2, got 3)",
            "ValueError True too many values to unpack (expected 2, got 3)",
            "ValueError True too many values to unpack (expected 2)",
            "TypeError True cannot unpack non-iterable int object",
            "TypeError True cannot unpack non-iterable object object",
            "TypeError True make_encoder() argument 6 must be str, not int",
            "TypeError True make_encoder() argument 5 must be str, not int",
            "TypeError True make_encoder() argument 6 must be str, not None",
            "TypeError True make_encoder() argument 5 must be str, not None",
            "TypeError True make_encoder() argument 5 must be str, not None",
            "TypeError True make_encoder() argument 6 must be str, not bool",
            "TypeError True make_encoder() argument 5 must be str, not bool",
            "TypeError True make_encoder() argument 5 must be str, not bool",
        ],
    );
}

#[test]
fn cpython_json_dumps_skipkeys_subset() {
    assert_output(
        "import json\nclass K:\n    pass\nclass S(str):\n    pass\nclass I(int):\n    pass\ncases = [\n    ({(1, 2): 'tuple', 'a': 1, None: 2, 3: 'three'}, False, False),\n    ({(1, 2): 'tuple', 'a': 1, None: 2, 3: 'three'}, True, False),\n    ({K(): 'custom', 'a': [1, 2]}, True, False),\n    ({(1, 2): 'tuple', S('s'): I(4)}, True, False),\n    ({(1, 2): 'tuple', 'b': 1, 'a': 2}, True, True),\n]\nfor value, skipkeys, sort_keys in cases:\n    try:\n        print(json.dumps(value, skipkeys=skipkeys, sort_keys=sort_keys))\n    except Exception as error:\n        print(type(error).__name__, isinstance(error, TypeError))\nprint(json.dumps({'outer': {(1, 2): 'drop', 'keep': 1}, 'list': [{(3, 4): 'drop2', 'ok': 2}]}, skipkeys=True))\ntry:\n    json.dumps({'outer': {(1, 2): 'drop', 'keep': 1}, 'list': [{(3, 4): 'drop2', 'ok': 2}]}, skipkeys=False)\nexcept Exception as error:\n    print(type(error).__name__, isinstance(error, TypeError))\nprint(json.dumps({(1, 2): 'tuple', 'é': '𝄠'}, skipkeys=True, ensure_ascii=False, separators=(',', ':')))\nfor skipkeys in [[], {}, K()]:\n    try:\n        json.dumps({(1, 2): 'tuple', 'a': 1}, skipkeys=skipkeys)\n    except Exception as error:\n        print(type(error).__name__, isinstance(error, TypeError))\n    else:\n        print('ok')",
        &[
            "TypeError True",
            "{\"a\": 1, \"null\": 2, \"3\": \"three\"}",
            "{\"a\": [1, 2]}",
            "{\"s\": 4}",
            "TypeError True",
            "{\"outer\": {\"keep\": 1}, \"list\": [{\"ok\": 2}]}",
            "TypeError True",
            "{\"é\":\"𝄠\"}",
            "TypeError True",
            "TypeError True",
            "ok",
        ],
    );
}

#[test]
fn cpython_json_dumps_allow_nan_subset() {
    assert_output(
        "import json\nclass F(float):\n    pass\nvalues = [float('nan'), float('inf'), float('-inf'), F(float('nan')), F(float('inf')), 1.5]\nfor allow_nan in [True, 1, False, 0]:\n    for value in values:\n        try:\n            print(allow_nan, json.dumps(value, allow_nan=allow_nan))\n        except Exception as error:\n            print(allow_nan, type(error).__name__, isinstance(error, ValueError))\nfor allow_nan in [True, False]:\n    try:\n        print('key', allow_nan, json.dumps({float('nan'): 'nan', float('inf'): 'inf', 1.0: 'one'}, allow_nan=allow_nan))\n    except Exception as error:\n        print('key', allow_nan, type(error).__name__, isinstance(error, ValueError))\nnested = {'outer': [float('nan'), {'x': float('inf'), 'y': float('-inf')}]}\nfor allow_nan in [True, False]:\n    try:\n        print('nested', allow_nan, json.dumps(nested, allow_nan=allow_nan, sort_keys=True))\n    except Exception as error:\n        print('nested', allow_nan, type(error).__name__, isinstance(error, ValueError))\ntry:\n    json.dumps([float('nan')], allow_nan=[])\nexcept Exception as error:\n    print('list', type(error).__name__, isinstance(error, ValueError))\nelse:\n    print('list ok')\nfor label, value in [('nan-msg', float('nan')), ('inf-msg', float('inf')), ('neg-inf-msg', float('-inf'))]:\n    try:\n        json.dumps(value, allow_nan=False)\n    except Exception as error:\n        print(label, type(error).__name__, str(error))",
        &[
            "True NaN",
            "True Infinity",
            "True -Infinity",
            "True NaN",
            "True Infinity",
            "True 1.5",
            "1 NaN",
            "1 Infinity",
            "1 -Infinity",
            "1 NaN",
            "1 Infinity",
            "1 1.5",
            "False ValueError True",
            "False ValueError True",
            "False ValueError True",
            "False ValueError True",
            "False ValueError True",
            "False 1.5",
            "0 ValueError True",
            "0 ValueError True",
            "0 ValueError True",
            "0 ValueError True",
            "0 ValueError True",
            "0 1.5",
            "key True {\"NaN\": \"nan\", \"Infinity\": \"inf\", \"1.0\": \"one\"}",
            "key False ValueError True",
            "nested True {\"outer\": [NaN, {\"x\": Infinity, \"y\": -Infinity}]}",
            "nested False ValueError True",
            "list ValueError True",
            "nan-msg ValueError Out of range float values are not JSON compliant: nan",
            "inf-msg ValueError Out of range float values are not JSON compliant: inf",
            "neg-inf-msg ValueError Out of range float values are not JSON compliant: -inf",
        ],
    );
}

#[test]
fn cpython_json_dumps_check_circular_subset() {
    assert_output(
        "import json\nfrom collections import namedtuple\ncases = []\ncycle_list = []\ncycle_list.append(cycle_list)\ncases.append(('list', cycle_list))\ncycle_dict = {}\ncycle_dict['self'] = cycle_dict\ncases.append(('dict', cycle_dict))\ninner = []\ncycle_tuple = (inner,)\ninner.append(cycle_tuple)\ncases.append(('tuple', cycle_tuple))\nPoint = namedtuple('Point', 'items')\nitems = []\ncycle_namedtuple = Point(items)\nitems.append(cycle_namedtuple)\ncases.append(('namedtuple', cycle_namedtuple))\nfor check_circular in [True, 1, False, 0, []]:\n    for label, value in cases:\n        try:\n            json.dumps(value, check_circular=check_circular)\n        except Exception as error:\n            print(repr(check_circular), label, type(error).__name__, isinstance(error, (ValueError, RecursionError)))\n        else:\n            print(repr(check_circular), label, 'OK')\nfor value in [[1, 2], {'a': [1]}, (1, 2)]:\n    print(json.dumps(value, check_circular=False))\ntry:\n    json.dumps([1], check_circular=object())\nexcept Exception as error:\n    print('object', type(error).__name__)\nelse:\n    print('object ok')",
        &[
            "True list ValueError True",
            "True dict ValueError True",
            "True tuple ValueError True",
            "True namedtuple ValueError True",
            "1 list ValueError True",
            "1 dict ValueError True",
            "1 tuple ValueError True",
            "1 namedtuple ValueError True",
            "False list RecursionError True",
            "False dict RecursionError True",
            "False tuple RecursionError True",
            "False namedtuple RecursionError True",
            "0 list RecursionError True",
            "0 dict RecursionError True",
            "0 tuple RecursionError True",
            "0 namedtuple RecursionError True",
            "[] list RecursionError True",
            "[] dict RecursionError True",
            "[] tuple RecursionError True",
            "[] namedtuple RecursionError True",
            "[1, 2]",
            "{\"a\": [1]}",
            "[1, 2]",
            "object ok",
        ],
    );
}

#[test]
fn cpython_json_dumps_indent_subset() {
    assert_output(
        "import json\nvalue = {'b': [1, {'x': 2}], 'a': {'é': '𝄠'}, 'empty': []}\nfor indent in [None, 0, 2, '', '--']:\n    print('CASE', repr(indent))\n    print(repr(json.dumps(value, indent=indent, sort_keys=True, ensure_ascii=False)))\nfor args in [dict(indent=2, separators=None), dict(indent=2, separators=(',', ':')), dict(indent=2, separators=(', ', ': ')), dict(indent=0, separators=(',', ':'))]:\n    print('SEP', args['indent'], repr(args['separators']))\n    print(repr(json.dumps({'b': [1, 2], 'a': 3}, **args)))\nfor indent in [-1, -2]:\n    print('NEG', indent, repr(json.dumps({'b': [1, 2], 'a': 3}, indent=indent)))\nclass IndexIndent:\n    def __index__(self):\n        return 2\nclass BoolIndexIndent:\n    def __index__(self):\n        return True\nfor indent in [IndexIndent(), BoolIndexIndent()]:\n    print('INDEX', type(indent).__name__, repr(json.dumps([1, 2], indent=indent)))\nclass BadIndexIndent:\n    def __index__(self):\n        raise RuntimeError('boom-index')\ntry:\n    json.dumps([1], indent=BadIndexIndent())\nexcept Exception as error:\n    print('INDEX-ERROR', type(error).__name__, str(error))\nfor indent in [True, False, 1.5, [], object()]:\n    try:\n        print('BAD', repr(json.dumps([1, 2], indent=indent)))\n    except Exception as error:\n        print('BAD', type(error).__name__, str(error))",
        &[
            "CASE None",
            r#"'{"a": {"é": "𝄠"}, "b": [1, {"x": 2}], "empty": []}'"#,
            "CASE 0",
            r#"'{\n"a": {\n"é": "𝄠"\n},\n"b": [\n1,\n{\n"x": 2\n}\n],\n"empty": []\n}'"#,
            "CASE 2",
            r#"'{\n  "a": {\n    "é": "𝄠"\n  },\n  "b": [\n    1,\n    {\n      "x": 2\n    }\n  ],\n  "empty": []\n}'"#,
            "CASE ''",
            r#"'{\n"a": {\n"é": "𝄠"\n},\n"b": [\n1,\n{\n"x": 2\n}\n],\n"empty": []\n}'"#,
            "CASE '--'",
            r#"'{\n--"a": {\n----"é": "𝄠"\n--},\n--"b": [\n----1,\n----{\n------"x": 2\n----}\n--],\n--"empty": []\n}'"#,
            "SEP 2 None",
            r#"'{\n  "b": [\n    1,\n    2\n  ],\n  "a": 3\n}'"#,
            "SEP 2 (',', ':')",
            r#"'{\n  "b":[\n    1,\n    2\n  ],\n  "a":3\n}'"#,
            "SEP 2 (', ', ': ')",
            r#"'{\n  "b": [\n    1, \n    2\n  ], \n  "a": 3\n}'"#,
            "SEP 0 (',', ':')",
            r#"'{\n"b":[\n1,\n2\n],\n"a":3\n}'"#,
            r#"NEG -1 '{\n"b": [\n1,\n2\n],\n"a": 3\n}'"#,
            r#"NEG -2 '{\n"b": [\n1,\n2\n],\n"a": 3\n}'"#,
            r#"INDEX IndexIndent '[\n  1,\n  2\n]'"#,
            r#"INDEX BoolIndexIndent '[\n 1,\n 2\n]'"#,
            "INDEX-ERROR RuntimeError boom-index",
            r#"BAD '[\n 1,\n 2\n]'"#,
            r#"BAD '[\n1,\n2\n]'"#,
            "BAD TypeError can't multiply sequence by non-int of type 'float'",
            "BAD TypeError can't multiply sequence by non-int of type 'list'",
            "BAD TypeError can't multiply sequence by non-int of type 'object'",
        ],
    );
}

