#[test]
fn cpython_json_dumps_default_hook_subset() {
    assert_output(
        "import json\n\nclass Box:\n    pass\n\nclass Bad:\n    pass\n\ndef box(value):\n    item = Box()\n    item.value = value\n    return item\n\ndef default(obj):\n    print('default', type(obj).__name__, getattr(obj, 'value', 'missing'))\n    if isinstance(obj, Box):\n        return {'box': obj.value}\n    raise TypeError('nope')\n\nfor label, obj, kwargs in [\n    ('top', box(1), dict(default=default, sort_keys=True)),\n    ('nested', {'x': [box(2)]}, dict(default=default, sort_keys=True)),\n    ('scalar-ok', box('s'), dict(default=lambda o: o.value)),\n    ('none-ok', box(6), dict(default=lambda o: None)),\n    ('list-ok', box(7), dict(default=lambda o: [o.value])),\n    ('dict-list-ok', box(8), dict(default=lambda o: {'v': [o.value]}, sort_keys=True)),\n    ('noncallable-unused', {'x': 1}, dict(default=1, sort_keys=True)),\n    ('noncallable-used', box(3), dict(default=1)),\n    ('typeerror', Bad(), dict(default=default)),\n]:\n    try:\n        print(label, json.dumps(obj, **kwargs))\n    except Exception as error:\n        if label == 'noncallable-used':\n            print(label, type(error).__name__, str(error))\n        else:\n            print(label, type(error).__name__, str(error), isinstance(error, TypeError))\n\ndef boom(obj):\n    raise ValueError('boom-default')\n\ntry:\n    json.dumps(box(4), default=boom)\nexcept Exception as error:\n    print('boom', type(error).__name__, str(error))\n\nself_box = box(5)\ntry:\n    json.dumps(self_box, default=lambda obj: obj)\nexcept Exception as error:\n    print('same-default', type(error).__name__, str(error) == 'Circular reference detected', isinstance(error, ValueError))\n\nfor label, hook in [\n    ('list-default-cycle', lambda obj: [obj]),\n    ('dict-default-cycle', lambda obj: {'x': obj}),\n    ('tuple-default-cycle', lambda obj: (obj,)),\n]:\n    try:\n        json.dumps(self_box, default=hook)\n    except Exception as error:\n        print(label, type(error).__name__, str(error) == 'Circular reference detected', isinstance(error, ValueError))\nfor label, hook in [\n    ('same-default-unchecked', lambda obj: obj),\n    ('list-default-cycle-unchecked', lambda obj: [obj]),\n    ('dict-default-cycle-unchecked', lambda obj: {'x': obj}),\n]:\n    try:\n        json.dumps(self_box, default=hook, check_circular=False)\n    except Exception as error:\n        print(label, type(error).__name__, isinstance(error, RecursionError))\n\nshared_bytes = b'xy'\nshared_bytearray = bytearray(b'xy')\nshared_memoryview = memoryview(b'xy')\nfor label, replacement in [\n    ('shared-bytes-default', shared_bytes),\n    ('shared-bytearray-default', shared_bytearray),\n    ('shared-memoryview-default', shared_memoryview),\n]:\n    try:\n        json.dumps(object(), default=lambda obj, replacement=replacement: replacement)\n    except Exception as error:\n        print(label, type(error).__name__, str(error) == 'Circular reference detected', isinstance(error, ValueError))\nfor label, replacement in [\n    ('shared-bytes-default-unchecked', shared_bytes),\n    ('shared-bytearray-default-unchecked', shared_bytearray),\n    ('shared-memoryview-default-unchecked', shared_memoryview),\n]:\n    try:\n        json.dumps(object(), default=lambda obj, replacement=replacement: replacement, check_circular=False)\n    except Exception as error:\n        print(label, type(error).__name__, isinstance(error, RecursionError))\n\nshared_set = {1}\nshared_frozenset = frozenset([1])\nfor label, replacement in [\n    ('shared-set-default', shared_set),\n    ('shared-frozenset-default', shared_frozenset),\n]:\n    try:\n        json.dumps(object(), default=lambda obj, replacement=replacement: replacement)\n    except Exception as error:\n        print(label, type(error).__name__, str(error) == 'Circular reference detected', isinstance(error, ValueError))\nfor label, replacement in [\n    ('shared-set-default-unchecked', shared_set),\n    ('shared-frozenset-default-unchecked', shared_frozenset),\n]:\n    try:\n        json.dumps(object(), default=lambda obj, replacement=replacement: replacement, check_circular=False)\n    except Exception as error:\n        print(label, type(error).__name__, isinstance(error, RecursionError))\n\nclass FreshDefault:\n    def __call__(self, obj):\n        return object()\n\ntry:\n    json.dumps(object(), default=FreshDefault())\nexcept Exception as error:\n    print('fresh-default', type(error).__name__, isinstance(error, RecursionError))",
        &[
            "default Box 1",
            "top {\"box\": 1}",
            "default Box 2",
            "nested {\"x\": [{\"box\": 2}]}",
            "scalar-ok \"s\"",
            "none-ok null",
            "list-ok [7]",
            "dict-list-ok {\"v\": [8]}",
            "noncallable-unused {\"x\": 1}",
            "noncallable-used TypeError 'int' object is not callable",
            "default Bad missing",
            "typeerror TypeError nope True",
            "boom ValueError boom-default",
            "same-default ValueError True True",
            "list-default-cycle ValueError True True",
            "dict-default-cycle ValueError True True",
            "tuple-default-cycle ValueError True True",
            "same-default-unchecked RecursionError True",
            "list-default-cycle-unchecked RecursionError True",
            "dict-default-cycle-unchecked RecursionError True",
            "shared-bytes-default ValueError True True",
            "shared-bytearray-default ValueError True True",
            "shared-memoryview-default ValueError True True",
            "shared-bytes-default-unchecked RecursionError True",
            "shared-bytearray-default-unchecked RecursionError True",
            "shared-memoryview-default-unchecked RecursionError True",
            "shared-set-default ValueError True True",
            "shared-frozenset-default ValueError True True",
            "shared-set-default-unchecked RecursionError True",
            "shared-frozenset-default-unchecked RecursionError True",
            "fresh-default RecursionError True",
        ],
    );
}

#[test]
fn cpython_json_dumps_default_hook_slice_identity_subset() {
    assert_output_with_stack(
        r#"import json

shared = slice(1, 3, 1)

def fresh_slice_then_value():
    calls = []
    def hook(obj):
        calls.append(1)
        if len(calls) == 1:
            return slice(1, 3, 1)
        return 'fresh-slice-ok'
    return hook, calls

print('kind', type(shared).__name__, callable(shared))
try:
    json.dumps(object(), default=lambda obj: shared)
except Exception as error:
    print('shared-slice-default', type(error).__name__, str(error) == 'Circular reference detected', isinstance(error, ValueError), isinstance(error, RecursionError))
hook, calls = fresh_slice_then_value()
print('fresh-slice-progress', json.dumps(object(), default=hook), len(calls))
try:
    json.dumps(object(), default=lambda obj: shared, check_circular=False)
except Exception as error:
    print('shared-slice-default-unchecked', type(error).__name__, isinstance(error, RecursionError))
hook, calls = fresh_slice_then_value()
print('fresh-slice-progress-unchecked', json.dumps(object(), default=hook, check_circular=False), len(calls))"#,
        &[
            "kind slice False",
            "shared-slice-default ValueError True True False",
            "fresh-slice-progress \"fresh-slice-ok\" 2",
            "shared-slice-default-unchecked RecursionError True",
            "fresh-slice-progress-unchecked \"fresh-slice-ok\" 2",
        ],
        16 * 1024 * 1024,
    );
}

