#[test]
fn cpython_json_loads_number_and_whitespace_subset() {
    assert_output(
        "import json\nprint(json.loads(' \\t\\r\\n[1, 2, 3]\\n '))\nvalue = json.loads('{\"negzero\": -0, \"negfloat\": -0.0, \"exp\": 6.02e+23, \"small\": 1E-2}')\nprint(value['negzero'], type(value['negzero']).__name__)\nprint(value['negfloat'], type(value['negfloat']).__name__)\nprint(value['exp'])\nprint(value['small'])\nfor label, source in [('dash', '-'), ('dash-dot', '-.1'), ('dash-nan', '-NaN'), ('dot-tail', '1.'), ('exp-tail', '1e'), ('signed-exp-tail', '1e+')]:\n    try:\n        json.loads(source)\n    except ValueError as error:\n        message = str(error)\n        print(label, 'Expecting value' in message, 'Extra data' in message, 'Invalid number' in message)",
        &[
            "[1, 2, 3]",
            "0 int",
            "-0.0 float",
            "6.02e+23",
            "0.01",
            "dash True False False",
            "dash-dot True False False",
            "dash-nan True False False",
            "dot-tail False True False",
            "exp-tail False True False",
            "signed-exp-tail False True False",
        ],
    );
}

#[test]
fn cpython_json_loads_int_digit_limit_subset() {
    assert_output(
        "import json, sys\nold_limit = sys.get_int_max_str_digits()\nsys.set_int_max_str_digits(640)\ntry:\n    maxdigits = sys.get_int_max_str_digits()\n    print(type(json.loads('1' * maxdigits)).__name__)\n    print(type(json.loads('-' + '1' * maxdigits)).__name__)\n    for label, source in [('top', '1' * (maxdigits + 1)), ('negative', '-' + '1' * (maxdigits + 1)), ('array', '[' + '1' * (maxdigits + 1) + ']'), ('object', '{\"n\": ' + '1' * (maxdigits + 1) + '}')]:\n        try:\n            json.loads(source)\n        except ValueError as error:\n            message = str(error)\n            print(label, 'Exceeds the limit' in message, 'conversion' in message)\n        else:\n            print(label, 'OK')\n    sys.set_int_max_str_digits(0)\n    print(type(json.loads('1' * (maxdigits + 1))).__name__)\nfinally:\n    sys.set_int_max_str_digits(old_limit)",
        &[
            "int",
            "int",
            "top True True",
            "negative True True",
            "array True True",
            "object True True",
            "int",
        ],
    );
}

