fn cpython_json_loads_object_hook_subset() {
    assert_output(
        "import json\n\nevents = []\ndef hook(value):\n    print('hook', sorted(value.items()))\n    events.append(sorted(value.items()))\n    return {'seen': len(events), 'value': value}\n\nprint(json.loads('{}', object_hook=hook))\nprint(json.loads('{\"outer\": {\"inner\": 1}, \"list\": [{\"x\": 2}]}', object_hook=hook))\nprint(json.loads('{\"a\": 1}', object_hook=lambda value: None))\nprint(json.loads('{\"a\": 1}', object_hook=lambda value: [value]))\nprint(json.loads('{\"outer\": {\"inner\": 1}}', object_hook=lambda value: list(sorted(value))))\nprint(json.loads('[1, 2]', object_hook=1))\n\ndef boom(value):\n    raise ValueError('boom-object')\n\nfor label, source, kwargs in [\n    ('object-hook-noncallable', '{}', dict(object_hook=1)),\n    ('object-hook-boom', '{}', dict(object_hook=boom)),\n]:\n    try:\n        json.loads(source, **kwargs)\n    except Exception as error:\n        if label == 'object-hook-boom':\n            print(label, type(error).__name__, str(error))\n        else:\n            print(label, type(error).__name__, str(error))",
        &[
            "hook []",
            "{'seen': 1, 'value': {}}",
            "hook [('inner', 1)]",
            "hook [('x', 2)]",
            "hook [('list', [{'seen': 3, 'value': {'x': 2}}]), ('outer', {'seen': 2, 'value': {'inner': 1}})]",
            "{'seen': 4, 'value': {'outer': {'seen': 2, 'value': {'inner': 1}}, 'list': [{'seen': 3, 'value': {'x': 2}}]}}",
            "None",
            "[{'a': 1}]",
            "['outer']",
            "[1, 2]",
            "object-hook-noncallable TypeError 'int' object is not callable",
            "object-hook-boom ValueError boom-object",
        ],
    );
}

#[test]
fn cpython_json_loads_object_pairs_hook_subset() {
    assert_output(
        "import json\n\ndef pairs(value):\n    print('pairs', value)\n    return ('pairs', value)\n\ndef obj(value):\n    print('obj', value)\n    return ('obj', value)\n\nprint(json.loads('{}', object_pairs_hook=pairs))\nprint(json.loads('{\"a\": 1, \"a\": 2, \"b\": {\"c\": 3}}', object_pairs_hook=pairs))\nprint(json.loads('{\"a\": 1, \"b\": {\"c\": 2}}', object_hook=obj, object_pairs_hook=pairs))\nprint(json.loads('{\"a\": 1}', object_pairs_hook=lambda value: None))\nprint(json.loads('{\"a\": 1}', object_pairs_hook=lambda value: [value]))\nprint(json.loads('{\"outer\": {\"inner\": 1}}', object_pairs_hook=lambda value: [key for key, _ in value]))\nprint(json.loads('[1, 2]', object_pairs_hook=1))\n\ndef boom(value):\n    raise ValueError('boom-pairs')\n\nfor label, source, kwargs in [\n    ('pairs-noncallable', '{}', dict(object_pairs_hook=1)),\n    ('pairs-boom', '{}', dict(object_pairs_hook=boom)),\n]:\n    try:\n        json.loads(source, **kwargs)\n    except Exception as error:\n        if label == 'pairs-boom':\n            print(label, type(error).__name__, str(error))\n        else:\n            print(label, type(error).__name__, str(error))",
        &[
            "pairs []",
            "('pairs', [])",
            "pairs [('c', 3)]",
            "pairs [('a', 1), ('a', 2), ('b', ('pairs', [('c', 3)]))]",
            "('pairs', [('a', 1), ('a', 2), ('b', ('pairs', [('c', 3)]))])",
            "pairs [('c', 2)]",
            "pairs [('a', 1), ('b', ('pairs', [('c', 2)]))]",
            "('pairs', [('a', 1), ('b', ('pairs', [('c', 2)]))])",
            "None",
            "[[('a', 1)]]",
            "['outer']",
            "[1, 2]",
            "pairs-noncallable TypeError 'int' object is not callable",
            "pairs-boom ValueError boom-pairs",
        ],
    );
}

#[test]
fn cpython_json_loads_dumps_error_boundary_subset() {
    assert_output(
        "import json\nfrom collections import namedtuple\n\ndef show(label, callback):\n    try:\n        callback()\n    except Exception as error:\n        print(label, isinstance(error, TypeError), isinstance(error, ValueError))\n    else:\n        print(label, 'OK')\n\ndef show_message(label, callback, text):\n    try:\n        callback()\n    except Exception as error:\n        print(label, text in str(error))\n    else:\n        print(label, 'OK')\n\nshow('loads-no-args', lambda: json.loads())\nshow('loads-extra-arg', lambda: json.loads('{}', 1))\nshow('loads-unknown-keyword', lambda: json.loads('{}', unknown=1))\nshow('loads-memoryview', lambda: json.loads(memoryview(b'{}')))\nshow('loads-invalid-utf8', lambda: json.loads(b'\\xff'))\ntry:\n    json.loads(bytes([255]))\nexcept Exception as error:\n    print('loads-invalid-utf8-unicode', isinstance(error, UnicodeDecodeError))\ntry:\n    json.loads(chr(65279) + '{}')\nexcept Exception as error:\n    print('loads-string-bom', isinstance(error, ValueError), 'Unexpected UTF-8 BOM' in str(error))\nfor label, data, text in [\n    ('loads-odd-leading-nul', bytes([0, ord('1'), 0]), 'Expecting value'),\n    ('loads-odd-trailing-nul', bytes([ord('1'), 0, 0]), 'Extra data'),\n]:\n    try:\n        json.loads(data)\n    except Exception as error:\n        print(label, isinstance(error, ValueError), isinstance(error, UnicodeDecodeError), text in str(error))\nshow('loads-trailing-data', lambda: json.loads('{} []'))\nshow('loads-array-trailing-comma', lambda: json.loads('[1,]'))\nshow('loads-object-trailing-comma', lambda: json.loads('{\"a\": 1,}'))\nshow('loads-missing-colon', lambda: json.loads('{\"a\" 1}'))\nshow_message('loads-missing-colon-text', lambda: json.loads('{\"a\" 1}'), \"Expecting ':' delimiter\")\nshow_message('loads-array-missing-comma-text', lambda: json.loads('[1 2]'), \"Expecting ',' delimiter\")\nshow_message('loads-object-missing-comma-text', lambda: json.loads('{\"a\":1 \"b\":2}'), \"Expecting ',' delimiter\")\nshow('loads-uppercase-true', lambda: json.loads('True'))\nshow('loads-uppercase-null', lambda: json.loads('NULL'))\nshow('loads-leading-zero', lambda: json.loads('01'))\ntry:\n    json.loads('01')\nexcept Exception as error:\n    print('loads-leading-zero-extra', 'Extra data' in str(error))\nshow('loads-invalid-escape', lambda: json.loads('\"\\\\x\"'))\nshow('loads-unclosed-array', lambda: json.loads('[1'))\nshow('dumps-no-args', lambda: json.dumps())\nshow('dumps-extra-arg', lambda: json.dumps({}, 1))\nshow('dumps-unknown-keyword', lambda: json.dumps({}, unknown=1))\nshow('dumps-object', lambda: json.dumps(object()))\nshow('dumps-bytes', lambda: json.dumps(b'abc'))\nshow('dumps-bytearray', lambda: json.dumps(bytearray(b'abc')))\nshow('dumps-memoryview', lambda: json.dumps(memoryview(b'abc')))\nshow('dumps-bad-key', lambda: json.dumps({(1, 2): 3}))\ncycle_list = []\ncycle_list.append(cycle_list)\nshow('dumps-list-cycle', lambda: json.dumps(cycle_list))\ncycle_dict = {}\ncycle_dict['self'] = cycle_dict\nshow('dumps-dict-cycle', lambda: json.dumps(cycle_dict))\ninner = []\ncycle_tuple = (inner,)\ninner.append(cycle_tuple)\nshow('dumps-tuple-cycle', lambda: json.dumps(cycle_tuple))\nclass JsonList(list):\n    pass\nclass JsonDict(dict):\n    pass\nsub_list = JsonList()\nsub_list.append(sub_list)\nshow('dumps-list-subclass-cycle', lambda: json.dumps(sub_list))\nsub_dict = JsonDict()\nsub_dict['self'] = sub_dict\nshow('dumps-dict-subclass-cycle', lambda: json.dumps(sub_dict))\nitems = []\nCycle = namedtuple('Cycle', 'items')\ncycle_namedtuple = Cycle(items)\nitems.append(cycle_namedtuple)\nshow('dumps-namedtuple-cycle', lambda: json.dumps(cycle_namedtuple))",
        &[
            "loads-no-args True False",
            "loads-extra-arg True False",
            "loads-unknown-keyword True False",
            "loads-memoryview True False",
            "loads-invalid-utf8 False True",
            "loads-invalid-utf8-unicode True",
            "loads-string-bom True True",
            "loads-odd-leading-nul True False True",
            "loads-odd-trailing-nul True False True",
            "loads-trailing-data False True",
            "loads-array-trailing-comma False True",
            "loads-object-trailing-comma False True",
            "loads-missing-colon False True",
            "loads-missing-colon-text True",
            "loads-array-missing-comma-text True",
            "loads-object-missing-comma-text True",
            "loads-uppercase-true False True",
            "loads-uppercase-null False True",
            "loads-leading-zero False True",
            "loads-leading-zero-extra True",
            "loads-invalid-escape False True",
            "loads-unclosed-array False True",
            "dumps-no-args True False",
            "dumps-extra-arg True False",
            "dumps-unknown-keyword True False",
            "dumps-object True False",
            "dumps-bytes True False",
            "dumps-bytearray True False",
            "dumps-memoryview True False",
            "dumps-bad-key True False",
            "dumps-list-cycle False True",
            "dumps-dict-cycle False True",
            "dumps-tuple-cycle False True",
            "dumps-list-subclass-cycle False True",
            "dumps-dict-subclass-cycle False True",
            "dumps-namedtuple-cycle False True",
        ],
    );
}

