// Adapted from CPython Lib/test/test_builtin.py::test_chr and ::test_ord.
// MiniPython keeps this slice to Unicode scalar values because its string
// storage is UTF-8 rather than CPython's wider internal code-point model.
#[test]
fn cpython_chr_ord_builtin_subset() {
    assert_output(
        "print(chr(65), chr(97))\nprint(ord(' '), ord('A'), ord('a'), ord('\\xff'))\nprint(ord(b'A'), ord(bytearray(b'\\xff')))\nprint(ord(chr(0)), ord(chr(32)), ord(chr(0xff)), ord(chr(0x10ffff)))",
        &["A a", "32 65 97 255", "65 255", "0 32 255 1114111"],
    );
    assert_output(
        "values = [0x0000ffff, 0x00010000, 0x00010001, 0x000ffffe, 0x000fffff, 0x00100000, 0x00100001, 0x0010fffe, 0x0010ffff]\nprint([ord(chr(value)) for value in values])",
        &["[65535, 65536, 65537, 1048574, 1048575, 1048576, 1048577, 1114110, 1114111]"],
    );
    assert_output(
        "for expr in [lambda: chr(), lambda: chr(65.0), lambda: chr(-1), lambda: chr(0x110000), lambda: chr(1 << 24), lambda: chr(2**32 - 1), lambda: chr(-(2**32)), lambda: chr(2**1000), lambda: chr(-(2**1000)), lambda: ord(), lambda: ord(42), lambda: ord('ab'), lambda: ord(b'ab')]:\n    try:\n        expr()\n    except (TypeError, ValueError) as error:\n        print(error.__class__.__name__)\nfor label, expr in [\n    ('chr-keyword', lambda: chr(i=65)),\n    ('ord-keyword', lambda: ord(c='A')),\n]:\n    try:\n        expr()\n    except TypeError as error:\n        print(label, str(error))",
        &[
            "TypeError",
            "TypeError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "ValueError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "chr-keyword chr() takes no keyword arguments",
            "ord-keyword ord() takes no keyword arguments",
        ],
    );
}

