// Adapted from CPython Lib/test/test_builtin.py::test_divmod.
#[test]
fn cpython_divmod_builtin_subset() {
    assert_output(
        "print(divmod(12, 7), divmod(-12, 7), divmod(12, -7), divmod(-12, -7))\nprint(divmod(-(2 ** 63), -1))\nprint(divmod(True, 2), divmod(False, 2))",
        &[
            "(1, 5) (-2, 2) (-2, -2) (1, -5)",
            "(9223372036854775808, 0)",
            "(0, 1) (0, 0)",
        ],
    );
    assert_output(
        "for pair in [(3.25, 1.0), (-3.25, 1.0), (3.25, -1.0), (-3.25, -1.0), (12, 7.0), (12.0, 7)]:\n    print(divmod(pair[0], pair[1]))",
        &[
            "(3.0, 0.25)",
            "(-4.0, 0.75)",
            "(-4.0, -0.75)",
            "(3.0, -0.25)",
            "(1.0, 5.0)",
            "(1.0, 5.0)",
        ],
    );
    assert_output(
        "for expr in [lambda: divmod(), lambda: divmod(1), lambda: divmod(1, 2, 3), lambda: divmod(1, 0), lambda: divmod(1.0, 0), lambda: divmod(1, 0.0), lambda: divmod('x', 2), lambda: divmod(1, y=2)]:\n    try:\n        expr()\n    except (TypeError, ZeroDivisionError) as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "ZeroDivisionError",
            "ZeroDivisionError",
            "ZeroDivisionError",
            "TypeError",
            "TypeError",
        ],
    );
    assert_output(
        "for label, callback in [('list-int', lambda: divmod([], 1)), ('int-list', lambda: divmod(1, [])), ('bool-list', lambda: divmod(True, [])), ('complex-int', lambda: divmod(1+2j, 1)), ('str-int', lambda: divmod('x', 2))]:\n    try:\n        callback()\n    except TypeError as error:\n        print(label, str(error))",
        &[
            "list-int unsupported operand type(s) for divmod(): 'list' and 'int'",
            "int-list unsupported operand type(s) for divmod(): 'int' and 'list'",
            "bool-list unsupported operand type(s) for divmod(): 'bool' and 'list'",
            "complex-int unsupported operand type(s) for divmod(): 'complex' and 'int'",
            "str-int unsupported operand type(s) for divmod(): 'str' and 'int'",
        ],
    );
}

// Adapted from CPython Lib/test/test_builtin.py::test_round,
// ::test_round_large, and ::test_bug_27936. This covers the core int/float,
// `__round__` protocol behavior, and public Decimal/Fraction `round(x, None)`
// regression shape.
#[test]
fn cpython_round_builtin_subset() {
    assert_output(
        "print(round(0.0), round(1.0), round(10.0), round(1000000000.0), round(1e20))\nprint(round(-1.0), round(-10.0), round(-1000000000.0), round(-1e20))",
        &[
            "0 1 10 1000000000 100000000000000000000",
            "-1 -10 -1000000000 -100000000000000000000",
        ],
    );
    assert_output(
        "print(round(0.1), round(1.1), round(10.1), round(1000000000.1))\nprint(round(-1.1), round(-10.1), round(-1000000000.1))\nprint(round(0.9), round(9.9), round(999999999.9))\nprint(round(-0.9), round(-9.9), round(-999999999.9))",
        &[
            "0 1 10 1000000000",
            "-1 -10 -1000000000",
            "1 10 1000000000",
            "-1 -10 -1000000000",
        ],
    );
    assert_output(
        "print(round(5.5), round(6.5), round(-5.5), round(-6.5))\nprint(round(-8.0, -1), type(round(-8.0, -1)).__name__)\nprint(type(round(-8.0, 0)).__name__, type(round(-8.0, 1)).__name__)\nprint(round(15.0, -1), round(25.0, -1), round(35.0, -1))",
        &["6 6 -6 -6", "-10.0 float", "float float", "20.0 20.0 40.0"],
    );
    assert_output(
        "print(round(0), round(8), round(-8), type(round(0)).__name__)\nprint(round(-8, -1), type(round(-8, -1)).__name__)\nprint(round(-8, 0), type(round(-8, 0)).__name__)\nprint(round(-8, 1), type(round(-8, 1)).__name__)\nprint(round(1234, None), round(1234.56, None), type(round(1234.56, None)).__name__)",
        &["0 8 -8 int", "-10 int", "-8 int", "-8 int", "1234 1235 int"],
    );
    assert_output(
        "import decimal, fractions\nfor x in [1234, 1234.56, decimal.Decimal('1234.56'), fractions.Fraction(123456, 100)]:\n    a = round(x, None)\n    b = round(x)\n    print(a, b, type(a).__name__, type(b).__name__, a == b, type(a) is type(b))",
        &[
            "1234 1234 int int True True",
            "1235 1235 int int True True",
            "1235 1235 int int True True",
            "1235 1235 int int True True",
        ],
    );
    assert_output(
        "print(round(1234.56, 1), round(1234.56, -1))\nprint(round(number=-8.0, ndigits=-1))",
        &["1234.6 1230.0", "-10.0"],
    );
    assert_output(
        "for value in [5e15 - 1, 5e15, 5e15 + 1, 5e15 + 2, 5e15 + 3]:\n    rounded = round(value)\n    print(rounded == value, type(rounded).__name__)",
        &["True int", "True int", "True int", "True int", "True int"],
    );
    assert_output(
        "class TestRound:\n    def __round__(self):\n        return 23\nclass TestRoundWithDigits:\n    def __round__(self, ndigits):\n        return ndigits\nprint(round(TestRound()))\nprint(round(TestRoundWithDigits(), 4))",
        &["23", "4"],
    );
    assert_output(
        "class TestNoRound:\n    pass\nt = TestNoRound()\nt.__round__ = lambda *args: args\nfor expr in [lambda: round(), lambda: round(1, 2, 3), lambda: round(TestNoRound()), lambda: round(t), lambda: round(t, 0), lambda: round(1.2, 'x')]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython Lib/test/test_builtin.py::BuiltinTest::test_type,
// TestType::test_bad_args, and Lib/test/test_descr.py coverage that verifies
// `type(instance)` returns the class object without calling metaclass hooks.
#[test]
fn cpython_type_builtin_subset() {
    assert_output(
        "print(type('').__name__, type('123').__name__, type(()).__name__)\nprint(type('') == type('123'), type('') != type(()))",
        &["str str tuple", "True True"],
    );
    assert_output(
        "print(type(None).__name__, type(True).__name__, type(1).__name__, type(1.5).__name__)\nprint(type([]).__name__, type({}).__name__, type(set()).__name__)",
        &["NoneType bool int float", "list dict set"],
    );
    assert_output(
        "print(type(type('')).__name__, type(len).__name__, type(type(len)).__name__)",
        &["type builtin_function_or_method type"],
    );
    assert_output(
        "class A:\n    pass\na = A()\nprint(type(a) is A, a.__class__ is A, type(A).__name__)",
        &["True True type"],
    );
    assert_output(
        "for name in ['A', 'Ä', '🐍', 'B.A', '42', '']:\n    A = type(name, (), {})\n    print(A.__name__, A.__qualname__, A.__module__)\nclass Base:\n    label = 'base'\ndef dyn_method(self):\n    return self.value + 1\nDynamic = type('Dynamic', (Base,), {'value': 7, 'plus': dyn_method})\ninst = Dynamic()\nprint(Dynamic.__name__, Dynamic.__qualname__, Dynamic.__module__)\nprint(Dynamic.__bases__[0] is Base, Dynamic.label, inst.value, inst.plus())",
        &[
            "A A __main__",
            "Ä Ä __main__",
            "🐍 🐍 __main__",
            "B.A B.A __main__",
            "42 42 __main__",
            "  __main__",
            "Dynamic Dynamic __main__",
            "True base 7 8",
        ],
    );
    assert_output(
        "for expr in [lambda: type(), lambda: type('A', ()), lambda: type('A', (), {}, extra=1), lambda: type(obj=1), lambda: type(b'A', (), {}), lambda: type('A\\0B', (), {}), lambda: type('A', [], {}), lambda: type('A', (), [])]:\n    try:\n        expr()\n    except (TypeError, ValueError) as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "ValueError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython Lib/test/test_builtin.py::TestType::test_new_type and
// ::test_bad_args. This covers the three-argument dynamic class constructor for
// ordinary MiniPython classes plus the public int-subclass layout behavior that
// CPython exercises through type('C', (B, int), ...).
#[test]
fn cpython_type_dynamic_class_subset() {
    assert_output(
        "A = type('A', (), {})\na = A()\nprint(A.__name__, A.__qualname__, A.__module__)\nprint(A.__bases__[0].__name__, A.__base__.__name__, '__firstlineno__' in A.__dict__)\nprint(type(a) is A, a.__class__ is A)",
        &["A A __main__", "object object False", "True True"],
    );
    assert_output(
        "class B:\n    def ham(self):\n        return 'ham'\nC = type('C', (B,), {'spam': lambda self: 'spam'})\nx = C()\nprint(C.__name__, C.__qualname__, C.__module__)\nprint(C.__bases__[0] is B, C.__base__ is B, 'spam' in C.__dict__, 'ham' in C.__dict__)\nprint(type(x) is C, x.__class__ is C, x.ham(), x.spam())",
        &["C C __main__", "True True True False", "True True ham spam"],
    );
    assert_output(
        "class B:\n    def ham(self):\n        return 'ham'\nC = type('C', (B, int), {'spam': lambda self: 'spam'})\nx = C(42)\nprint(isinstance(x, C), isinstance(x, B), isinstance(x, int), issubclass(C, int))\nprint(C.__bases__[0] is B, C.__bases__[1] is int, type(x) is C, x.__class__ is C)\nprint(x == 42, x + 1, x.ham(), x.spam())\nprint(x.bit_length(), x.as_integer_ratio(), x.to_bytes(1, 'big'))",
        &[
            "True True True True",
            "True True True True",
            "True 43 ham spam",
            "6 (42, 1) b'*'",
        ],
    );
    assert_output(
        "import types\nfor expr in [lambda: type('A', [], {}), lambda: type('A', (), []), lambda: type('A', (), {}, ()), lambda: type('A', (), types.MappingProxyType({})), lambda: type(b'A', (), {}), lambda: type('A\\0B', (), {}), lambda: type('A', (None,), {}), lambda: type('A', (bool,), {}), lambda: type('A', (int, str), {})]:\n    try:\n        expr()\n    except (TypeError, ValueError) as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "ValueError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython Lib/test/test_builtin.py::TestType::test_type_name and
// ::test_type_qualname. MiniPython covers the supported string and bytes/null
// rejection paths, leaving surrogate UnicodeEncodeError behavior for a later
// Unicode runtime slice.
#[test]
fn cpython_type_name_qualname_subset() {
    assert_output(
        "C = type('C', (), {})\nfor name in ['A', 'Ä', '🐍', 'B.A', '42', '']:\n    C.__name__ = name\n    print(C.__name__, C.__qualname__, C.__module__)",
        &[
            "A C __main__",
            "Ä C __main__",
            "🐍 C __main__",
            "B.A C __main__",
            "42 C __main__",
            " C __main__",
        ],
    );
    assert_output(
        "A = type('A', (), {'__qualname__': 'B.C'})\nprint(A.__name__, A.__qualname__, A.__module__, '__qualname__' in A.__dict__)\nA.__qualname__ = 'D.E'\nprint(A.__name__, A.__qualname__)",
        &["A B.C __main__ False", "A D.E"],
    );
    assert_output(
        "A = type('A', (), {'__name__': 'B'})\nprint(A.__name__, A.__dict__['__name__'])\nA.__name__ = 'C'\nprint(A.__name__, A.__dict__['__name__'])",
        &["A B", "C B"],
    );
    assert_output(
        "A = type('C', (), {})\nfor expr in [lambda: setattr(A, '__name__', b'A'), lambda: setattr(A, '__name__', 'A\\0B'), lambda: type('A', (), {'__qualname__': b'B'}), lambda: setattr(A, '__qualname__', b'B')]:\n    try:\n        expr()\n    except (TypeError, ValueError) as error:\n        print(error.__class__.__name__, A.__name__, A.__qualname__)",
        &[
            "TypeError C C",
            "ValueError C C",
            "TypeError C C",
            "TypeError C C",
        ],
    );
}

// Adapted from CPython Lib/test/test_builtin.py::TestType::test_type_doc and
