// Adapted from CPython Lib/test/test_builtin.py::TestType::test_namespace_order.
// MiniPython covers the public behavior that a dynamic class preserves the
// insertion order of an ordered namespace mapping in its class dictionary.
#[test]
fn cpython_type_namespace_order_subset() {
    assert_output(
        "from collections import OrderedDict\nod = OrderedDict([('a', 1), ('b', 2)])\nprint(OrderedDict.__module__, OrderedDict.__qualname__, type(OrderedDict.__doc__).__name__, bool(OrderedDict.__doc__))\nprint(type(od.__doc__).__name__, bool(od.__doc__))\ndisplay = OrderedDict([('a', 1)])\nprint(display.__repr__(), display.__str__(), display.__format__(''))\nprint(OrderedDict.__repr__(display), OrderedDict.__str__(display), OrderedDict.__format__(display, ''))\nrecursive = OrderedDict()\nrecursive['self'] = recursive\nprint(repr(recursive), recursive.__repr__(), str(recursive))\ntry:\n    display.__format__('x')\nexcept TypeError as error:\n    print(error.__class__.__name__)\nalias = OrderedDict[str, int]\nprint(repr(alias), alias.__origin__ is OrderedDict, alias.__origin__.__module__)\nfk = OrderedDict.fromkeys(['b', 'a'], 3)\nifk = od.fromkeys(['x', 'y'])\nprint(type(fk).__name__, repr(fk), list(fk.items()))\nprint(type(ifk).__name__, repr(ifk), list(ifk.items()))\ncopy = od.copy()\ntcopy = OrderedDict.copy(od)\nprint(type(copy).__name__, repr(copy), copy == od, copy is od)\nprint(type(tcopy).__name__, repr(tcopy), tcopy == od, tcopy is od)\nother = OrderedDict([('b', 2), ('a', 1)])\nplain = {'b': 2, 'a': 1}\nprint(od.__eq__(other), od.__ne__(other), OrderedDict.__eq__(od, other), OrderedDict.__ne__(od, other))\nprint(od.__eq__(plain), od.__ne__(plain), OrderedDict.__eq__(od, []), OrderedDict.__ne__(od, []))\nunion = od | {'c': 3}\nrunion = {'z': 0} | od\ndunion = OrderedDict.__or__(od, {'d': 4})\nprint(type(union).__name__, repr(union), list(union.items()))\nprint(type(runion).__name__, repr(runion), list(runion.items()))\nprint(type(dunion).__name__, repr(dunion), OrderedDict.__or__(od, []))\nmut = OrderedDict([('a', 1)])\nret = mut.__ior__({'b': 2})\nmut |= {'c': 3}\nprint(type(ret).__name__, ret is mut, list(mut.items()))\nfor args in [(), (False,)]:\n    sample = OrderedDict([('a', 1), ('b', 2)])\n    print(sample.popitem(*args), list(sample.items()))\nsample = OrderedDict([('a', 1), ('b', 2)])\nprint(sample.popitem(last=False), list(sample.items()))\nprint(list(od.__reversed__()), list(OrderedDict.__reversed__(od)))\nod.move_to_end('a')\nexpected = list(od.items())\nC = type('C', (), od)\nprint(expected)\nprint(list(C.__dict__.items())[:2])\nprint(expected == list(C.__dict__.items())[:2])\nprint(type(od).__name__, 'fromkeys' in dir(OrderedDict), 'move_to_end' in dir(od), '__eq__' in dir(od), '__ne__' in dir(od), '__or__' in dir(od), '__ior__' in dir(od), '__ror__' in dir(od), '__repr__' in dir(od), '__format__' in dir(od), '__reversed__' in dir(od), 'move_to_end' in dir({}))",
        &[
            "collections OrderedDict str True",
            "str True",
            "OrderedDict({'a': 1}) OrderedDict({'a': 1}) OrderedDict({'a': 1})",
            "OrderedDict({'a': 1}) OrderedDict({'a': 1}) OrderedDict({'a': 1})",
            "OrderedDict({'self': ...}) OrderedDict({'self': ...}) OrderedDict({'self': ...})",
            "TypeError",
            "collections.OrderedDict[str, int] True collections",
            "OrderedDict OrderedDict({'b': 3, 'a': 3}) [('b', 3), ('a', 3)]",
            "OrderedDict OrderedDict({'x': None, 'y': None}) [('x', None), ('y', None)]",
            "OrderedDict OrderedDict({'a': 1, 'b': 2}) True False",
            "OrderedDict OrderedDict({'a': 1, 'b': 2}) True False",
            "False True False True",
            "True False NotImplemented NotImplemented",
            "OrderedDict OrderedDict({'a': 1, 'b': 2, 'c': 3}) [('a', 1), ('b', 2), ('c', 3)]",
            "OrderedDict OrderedDict({'z': 0, 'a': 1, 'b': 2}) [('z', 0), ('a', 1), ('b', 2)]",
            "OrderedDict OrderedDict({'a': 1, 'b': 2, 'd': 4}) NotImplemented",
            "OrderedDict True [('a', 1), ('b', 2), ('c', 3)]",
            "('b', 2) [('a', 1)]",
            "('a', 1) [('b', 2)]",
            "('a', 1) [('b', 2)]",
            "['b', 'a'] ['b', 'a']",
            "[('b', 2), ('a', 1)]",
            "[('b', 2), ('a', 1)]",
            "True",
            "OrderedDict True True True True True True True True True True False",
        ],
    );
}

// Adapted from CPython public OrderedDict mapping behavior. This keeps the
// minimal OrderedDict sandbox surface aligned with dict-style mutation helpers
// without promoting the full OrderedDict API.
#[test]
fn cpython_ordered_dict_mapping_mutation_subset() {
    assert_output(
        "from collections import OrderedDict\nod = OrderedDict([('a', 1), ('b', 2)])\nprint(od.setdefault('a', 9), od.setdefault('c', 3), list(od.items()))\nprint(od.update({'d': 4}), list(od.items()))\nprint(od.pop('a'), od.pop('missing', 'fallback'), list(od.items()))\nprint(od.get('b'), 'b' in od, OrderedDict.__contains__(od, 'b'))\nprint(len(od), bool(od), list(od), list(OrderedDict.__iter__(od)))\nprint(OrderedDict.__len__(od), OrderedDict.__getitem__(od, 'b'))\nod['e'] = 5\nOrderedDict.__setitem__(od, 'f', 6)\nprint(list(od.items()))\ndel od['b']\nprint(type(od).__name__, list(od.items()), 'b' in od)\ndef delete_missing():\n    del od['missing']\nfor label, action in [\n    ('delitem-missing', lambda: OrderedDict.__delitem__(od, 'missing')),\n    ('del-syntax-missing', delete_missing),\n]:\n    try:\n        action()\n    except KeyError as error:\n        print(label, error.args[0] == 'missing', type(error.args[0]).__name__, str(error))\nprint(od.clear(), list(od.items()), repr(od))",
        &[
            "1 3 [('a', 1), ('b', 2), ('c', 3)]",
            "None [('a', 1), ('b', 2), ('c', 3), ('d', 4)]",
            "1 fallback [('b', 2), ('c', 3), ('d', 4)]",
            "2 True True",
            "3 True ['b', 'c', 'd'] ['b', 'c', 'd']",
            "3 2",
            "[('b', 2), ('c', 3), ('d', 4), ('e', 5), ('f', 6)]",
            "OrderedDict [('c', 3), ('d', 4), ('e', 5), ('f', 6)] False",
            "delitem-missing True str 'missing'",
            "del-syntax-missing True str 'missing'",
            "None [] OrderedDict()",
        ],
    );
}

// This ports the pure in-memory constructor/update edge of the OrderedDict
// public surface without depending on version-specific OrderedDict repr shapes.
#[test]
fn cpython_ordered_dict_constructor_update_subset() {
    assert_output(
        "from collections import OrderedDict\nsamples = [\n    OrderedDict(a=1, b=2),\n    OrderedDict([('a', 1)], b=2),\n    OrderedDict({'b': 2, 'a': 1}),\n]\nfor od in samples:\n    print(type(od).__name__, list(od.items()), bool(od))\nod = OrderedDict()\nprint(od.update([('b', 2), ('a', 1)], c=3), list(od.items()))\nfor expr in [lambda: OrderedDict(1), lambda: OrderedDict([('a', 1, 2)])]:\n    try:\n        expr()\n        print('ok')\n    except (TypeError, ValueError) as error:\n        print(error.__class__.__name__)",
        &[
            "OrderedDict [('a', 1), ('b', 2)] True",
            "OrderedDict [('a', 1), ('b', 2)] True",
            "OrderedDict [('b', 2), ('a', 1)] True",
            "None [('b', 2), ('a', 1), ('c', 3)]",
            "TypeError",
            "ValueError",
        ],
    );
}

// Adapted from CPython public OrderedDict move/pop keyword behavior. This
// keeps `last=` binding and type-level method calls covered without requiring
// version-specific error message strings.
#[test]
fn cpython_ordered_dict_move_pop_keyword_subset() {
    assert_output(
        "from collections import OrderedDict\nod = OrderedDict([('a', 1), ('b', 2), ('c', 3)])\nprint('move-last-false', (od.move_to_end('b', last=False), list(od.items())))\nod = OrderedDict([('a', 1), ('b', 2), ('c', 3)])\nprint('move-last-true', (od.move_to_end('a', last=True), list(od.items())))\nod = OrderedDict([('a', 1), ('b', 2), ('c', 3)])\nprint('move-direct-keyword', (OrderedDict.move_to_end(od, 'c', last=False), list(od.items())))\nfor label, expr in [\n    ('move-missing', \"OrderedDict([('a', 1)]).move_to_end('x')\"),\n    ('move-unknown-kw', \"OrderedDict([('a', 1)]).move_to_end('a', nope=False)\"),\n    ('move-dup-last', \"OrderedDict([('a', 1)]).move_to_end('a', True, last=False)\"),\n]:\n    try:\n        eval(expr)\n    except Exception as error:\n        print(label, error.__class__.__name__)\ntry:\n    OrderedDict([('a', 1)]).move_to_end('x')\nexcept KeyError as error:\n    print('move-missing-payload', error.args[0] == 'x', type(error.args[0]).__name__, str(error))\nod = OrderedDict([('a', 1), ('b', 2), ('c', 3)])\nprint('pop-last-false', (od.popitem(last=False), list(od.items())))\nod = OrderedDict([('a', 1), ('b', 2), ('c', 3)])\nprint('pop-last-true', (od.popitem(last=True), list(od.items())))\nod = OrderedDict([('a', 1), ('b', 2), ('c', 3)])\nprint('pop-direct-keyword', (OrderedDict.popitem(od, last=False), list(od.items())))\nfor label, expr in [\n    ('pop-empty', \"OrderedDict().popitem()\"),\n    ('pop-unknown-kw', \"OrderedDict([('a', 1)]).popitem(nope=False)\"),\n    ('pop-dup-last', \"OrderedDict([('a', 1)]).popitem(True, last=False)\"),\n]:\n    try:\n        eval(expr)\n    except Exception as error:\n        print(label, error.__class__.__name__)",
        &[
            "move-last-false (None, [('b', 2), ('a', 1), ('c', 3)])",
            "move-last-true (None, [('b', 2), ('c', 3), ('a', 1)])",
            "move-direct-keyword (None, [('c', 3), ('a', 1), ('b', 2)])",
            "move-missing KeyError",
            "move-unknown-kw TypeError",
            "move-dup-last TypeError",
            "move-missing-payload True str 'x'",
            "pop-last-false (('a', 1), [('b', 2), ('c', 3)])",
            "pop-last-true (('c', 3), [('a', 1), ('b', 2)])",
            "pop-direct-keyword (('a', 1), [('b', 2), ('c', 3)])",
            "pop-empty KeyError",
            "pop-unknown-kw TypeError",
            "pop-dup-last TypeError",
        ],
    );
    assert_output(
        "from collections import OrderedDict\ntry:\n    OrderedDict().popitem()\nexcept KeyError as error:\n    print('pop-empty-payload', error.args[0] == 'dictionary is empty', type(error.args[0]).__name__, str(error) == repr(error.args[0]))",
        &["pop-empty-payload True str True"],
    );
}

// Adapted from CPython public OrderedDict view behavior. The supported
// sandbox surface preserves live ordered views and their public display names
// while leaving broader OrderedDict internals out of scope.
#[test]
fn cpython_ordered_dict_view_display_subset() {
    assert_output(
        "from collections import OrderedDict\nod = OrderedDict([('a', 1), ('b', 2)])\nkeys = od.keys()\nitems = od.items()\nvalues = od.values()\nprint(type(keys).__name__, list(keys), list(items), list(values))\nod['c'] = 3\nod.move_to_end('a')\nprint(list(keys), list(items), list(values))\nprint('b' in keys, ('b', 2) in items, 2 in values)\nprint(list(OrderedDict.keys(od)), list(OrderedDict.items(od)), list(OrderedDict.values(od)))\nprint(repr(keys), repr(items), repr(values))\nfor view in [keys, items, values]:\n    mapping = view.mapping\n    print(type(mapping).__name__, repr(mapping).startswith('mappingproxy(OrderedDict('), list(mapping.items()))\nod['d'] = 4\nprint('mapping-live', list(keys.mapping.items()))\nempty = OrderedDict()\nprint(type(empty.keys()).__name__, repr(empty.keys()), repr(empty.items()), repr(empty.values()))\nd = {'x': 1}\nprint(type(d.keys()).__name__, repr(d.keys()), repr(d.items()), repr(d.values()))",
        &[
            "odict_keys ['a', 'b'] [('a', 1), ('b', 2)] [1, 2]",
            "['b', 'c', 'a'] [('b', 2), ('c', 3), ('a', 1)] [2, 3, 1]",
            "True True True",
            "['b', 'c', 'a'] [('b', 2), ('c', 3), ('a', 1)] [2, 3, 1]",
            "odict_keys(['b', 'c', 'a']) odict_items([('b', 2), ('c', 3), ('a', 1)]) odict_values([2, 3, 1])",
            "mappingproxy True [('b', 2), ('c', 3), ('a', 1)]",
            "mappingproxy True [('b', 2), ('c', 3), ('a', 1)]",
            "mappingproxy True [('b', 2), ('c', 3), ('a', 1)]",
            "mapping-live [('b', 2), ('c', 3), ('a', 1), ('d', 4)]",
            "odict_keys odict_keys([]) odict_items([]) odict_values([])",
            "dict_keys dict_keys(['x']) dict_items([('x', 1)]) dict_values([1])",
        ],
    );
}

// Adapted from CPython Lib/test/test_builtin.py::BuiltinTest::test_dir and
// ::test_vars. This covers the executable introspection subset over local
// scopes, modules, module subclasses, classes, instances, custom __dir__, and
// __dict__ properties.
#[test]
fn cpython_vars_dir_builtin_subset() {
    assert_output(
        "def local_probe():\n    local_var = 1\n    print('local_var' in dir(), 'local_var' in vars())\n    return 'local_var' in vars()\nprint(local_probe())",
        &["True True", "True"],
    );
    assert_output(
        "import sys\nprint(set(vars(sys)) == set(dir(sys)), 'path' in dir(sys), '__name__' in vars(sys))",
        &["True True True"],
    );
    assert_output(
        "import sys\nsys.__dict__['live_probe'] = 7\nprint(sys.live_probe)\nvars(sys)['live_probe2'] = 8\nprint(sys.live_probe2)\ndel sys.__dict__['live_probe']\nprint(hasattr(sys, 'live_probe'), 'live_probe2' in dir(sys))\nsys.__dict__['__name__'] = 'renamed_sys'\nprint(sys.__name__, vars(sys)['__name__'])",
        &["7", "8", "False True", "renamed_sys renamed_sys"],
    );
    assert_output(
        "import types\nclass Foo(types.ModuleType):\n    __dict__ = 8\nf = Foo('foo')\nprint(isinstance(f, types.ModuleType), f.__name__, f.__dict__)\ntry:\n    dir(f)\nexcept TypeError as error:\n    print(error.__class__.__name__, error)",
        &[
            "True foo 8",
            "TypeError <module>.__dict__ is not a dictionary",
        ],
    );
    assert_output(
        "print('strip' in dir(str), '__mro__' in dir(str))\nclass Box:\n    class_attr = 3\n    def __init__(self):\n        self.y = 8\nbox = Box()\nprint('y' in dir(box), 'class_attr' in dir(box), sorted(vars(box).keys()))\nprint('class_attr' in vars(Box), '__module__' in vars(Box))",
        &["True False", "True True ['y']", "True True"],
    );
    assert_output(
        "class ListDir:\n    def __dir__(self):\n        return ['kan', 'ga', 'roo']\nclass TupleDir:\n    def __dir__(self):\n        return ('b', 'c', 'a')\nclass SetDir:\n    def __dir__(self):\n        return {'b', 'c', 'a'}\nprint(dir(ListDir()))\nprint(dir(TupleDir()))\nprint(dir(SetDir()))",
        &["['ga', 'kan', 'roo']", "['a', 'b', 'c']", "['a', 'b', 'c']"],
    );
    assert_output(
        "class DictProperty:\n    def getDict(self):\n        return {'a': 2}\n    __dict__ = property(getDict)\nprint(vars(DictProperty()))",
        &["{'a': 2}"],
    );
    assert_output(
        "class BadDir:\n    def __dir__(self):\n        return 7\nfor expr in [lambda: dir(1, 2), lambda: vars(1, 2), lambda: vars(42), lambda: dir(BadDir())]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &["TypeError", "TypeError", "TypeError", "TypeError"],
    );
    assert_output(
        "print(sorted([].__dir__()) == dir([]))\nprint(sorted(object.__dir__([])) == dir([]), '__dir__' in dir([]))",
        &["True", "True True"],
    );
    assert_output(
        "class SlotOnly:\n    __slots__ = []\nprint('__repr__' in dir(SlotOnly()))\nclass ClassShadow:\n    __slots__ = ['__class__', '__dict__']\n    def __init__(self):\n        self.bar = 'wow'\nshadow = ClassShadow()\nprint(dir(shadow))\ntry:\n    shadow.__class__\nexcept AttributeError as error:\n    print(error.__class__.__name__)\nshadow.__class__ = int\nnames = dir(shadow)\nprint('bit_length' in names, '__repr__' in names, 'bar' in names, shadow.__class__ is int, type(shadow).__name__)\nshadow.__class__ = 7\nnames = dir(shadow)\nprint('__repr__' in names, 'bar' in names, '__class__' in names, shadow.__class__)",
        &[
            "True",
            "['bar']",
            "AttributeError",
            "True True True True ClassShadow",
            "False True False 7",
        ],
    );
    assert_output(
        "try:\n    raise IndexError\nexcept IndexError as error:\n    names = dir(error.__traceback__)\nprint(len(names), names)",
        &["4 ['tb_frame', 'tb_lasti', 'tb_lineno', 'tb_next']"],
    );
}

// Adapted from CPython's builtin namespace behavior around `globals()` and
// `locals()`. MiniPython covers module-level live mappings and a function-local
// snapshot for the supported scope model.
#[test]
fn cpython_globals_locals_builtin_subset() {
    assert_output(
        "x = 1\ng = globals()\nl = locals()\nprint(g is l, g['x'], l['x'])\ng['from_globals'] = 2\nl['from_locals'] = 3\nprint(from_globals, from_locals, globals() is g, locals() is l)",
        &["True 1 1", "2 3 True True"],
    );
    assert_output(
        concat!(
            "scope_temp = 1\n",
            "g = globals()\n",
            "print(isinstance(g, dict), g.__class__ is dict, type(g) is dict)\n",
            "copied = g.copy()\n",
            "print(type(copied).__name__, copied.get('scope_temp'), copied is g)\n",
            "print(g.get('scope_temp'), g.get('missing'), g.get('missing', 42))\n",
            "print(g.setdefault('scope_temp', 2), scope_temp)\n",
            "print(g.setdefault('new_scope', 3), new_scope)\n",
            "print(g.pop('scope_temp'), 'scope_temp' in g)\n",
            "print(g.pop('new_scope'), 'new_scope' in g)\n",
            "g['scope_popitem_temp'] = 7\n",
            "print(g.popitem())\n",
            "del copied\n",
            "g['scope_rev_a'] = 10\n",
            "g['scope_rev_b'] = 11\n",
            "print(list(reversed(g))[:2])\n",
            "print(list(reversed(g.keys()))[:2])\n",
            "print(list(reversed(g.items()))[:2])\n",
            "print(list(reversed(g.values()))[:2])\n",
            "g['scope_reinsert_a'] = 12\n",
            "g['scope_reinsert_b'] = 13\n",
            "del g['scope_reinsert_a']\n",
            "g.update({'scope_reinsert_a': 14})\n",
            "print(list(g)[-2:])\n",
            "print(list(reversed(g))[:2])\n",
            "print(g.popitem())\n",
            "del g['scope_reinsert_b']\n",
            "print(hasattr(g, '__or__'), hasattr(g, '__ior__'), hasattr(g, '__ror__'))\n",
            "scope_union = g | {'scope_union_b': 15}\n",
            "print(type(scope_union).__name__, scope_union['scope_rev_a'], scope_union['scope_union_b'], 'scope_union_b' in g)\n",
            "scope_runion = {'scope_union_z': 0} | g\n",
            "print(type(scope_runion).__name__, scope_runion['scope_union_z'], scope_runion['scope_rev_a'])\n",
            "print(g.__or__({'scope_union_q': 16})['scope_union_q'], g.__ror__({'scope_union_r': 17})['scope_rev_a'])\n",
            "print(g.fromkeys(('scope_fk_a', 'scope_fk_b'), 20))\n",
            "print(g.__class_getitem__((str, int)) == dict[str, int])\n",
            "print(g.__str__() == g.__repr__(), 'scope_rev_a' in g.__repr__())\n",
            "print(g.__format__('') == g.__str__())\n",
            "g |= {'scope_ior_c': 18}\n",
            "print(scope_ior_c, g['scope_ior_c'])\n",
            "g |= [('scope_ior_d', 19)]\n",
            "print(scope_ior_d, g['scope_ior_d'])\n",
            "try:\n",
            "    g | [('scope_bad', 1)]\n",
            "except TypeError as error:\n",
            "    print(error.__class__.__name__, 'unsupported operand' in str(error))\n",
            "print(hasattr(g, '__eq__'), hasattr(g, '__ne__'))\n",
            "print(g == dict(g), dict(g) == g, g != dict(g))\n",
            "print(g.__eq__(dict(g)), g.__ne__(dict(g)))\n",
            "print(g == [], g.__eq__([]))\n",
            "g['scope_self'] = g\n",
            "print('scope_self' in repr(g), '{...}' in repr(g))\n",
            "items = dict(g.items())\n",
            "print('scope_self' in items, '{...}' in repr(items['scope_self']))\n",
            "scope_keys = g.keys()\n",
            "scope_items = g.items()\n",
            "scope_values = g.values()\n",
            "print(type(scope_keys).__name__, type(scope_items).__name__, type(scope_values).__name__)\n",
            "print(scope_keys.__len__() == len(g), scope_keys.__contains__('scope_rev_a'), scope_items.__contains__(('scope_rev_a', 10)), scope_keys.__repr__().startswith('dict_keys'))\n",
            "for view in [scope_keys, scope_items, scope_values]:\n",
            "    rendered = repr(view)\n",
            "    print(type(view).__name__, 'scope_keys' in rendered, '...' in rendered)\n",
            "g['scope_view_temp'] = 9\n",
            "print('scope_view_temp' in scope_keys, ('scope_view_temp', 9) in scope_items, 9 in scope_values)\n",
            "del g['scope_view_temp']\n",
            "print('scope_view_temp' in scope_keys)\n",
            "print(g.pop('missing', 'fallback'))\n",
            "try:\n",
            "    g.pop('missing')\n",
            "except KeyError as error:\n",
            "    print(error.__class__.__name__)\n",
            "def clear_global_mapping(p, mapping):\n",
            "    mapping['scope_clear_temp'] = 8\n",
            "    p('clear-before', 'scope_clear_temp' in mapping)\n",
            "    result = mapping.clear()\n",
            "    p('clear-after', result, len(mapping), 'scope_clear_temp' in mapping)\n",
            "clear_global_mapping(print, g)",
        ),
        &[
            "True True True",
            "dict 1 False",
            "1 None 42",
            "1 1",
            "3 3",
            "1 False",
            "3 False",
            "('scope_popitem_temp', 7)",
            "['scope_rev_b', 'scope_rev_a']",
            "['scope_rev_b', 'scope_rev_a']",
            "[('scope_rev_b', 11), ('scope_rev_a', 10)]",
            "[11, 10]",
            "['scope_reinsert_b', 'scope_reinsert_a']",
            "['scope_reinsert_a', 'scope_reinsert_b']",
            "('scope_reinsert_a', 14)",
            "True True True",
            "dict 10 15 False",
            "dict 0 10",
            "16 10",
            "{'scope_fk_a': 20, 'scope_fk_b': 20}",
            "True",
            "True True",
            "True",
            "18 18",
            "19 19",
            "TypeError True",
            "True True",
            "True True False",
            "True False",
            "False NotImplemented",
            "True True",
            "True True",
            "dict_keys dict_items dict_values",
            "True True True True",
            "dict_keys True False",
            "dict_items True True",
            "dict_values True True",
            "True True True",
            "False",
            "fallback",
            "KeyError",
            "clear-before True",
            "clear-after None 0 False",
        ],
    );
    assert_output(
        "x = 1\ndef probe(arg):\n    local_value = 4\n    snapshot = locals()\n    copied = snapshot.copy()\n    print(type(copied).__name__, copied.get('arg'), copied is snapshot)\n    print('arg' in snapshot, snapshot['arg'], 'local_value' in snapshot, snapshot['local_value'])\n    print(snapshot.get('arg'), snapshot.get('missing', 9))\n    print(snapshot.setdefault('arg', 8), snapshot['arg'])\n    print(snapshot.setdefault('new_local', 5), snapshot['new_local'])\n    print(snapshot.pop('local_value'), 'local_value' in snapshot)\n    print(globals() is locals(), globals()['x'])\nprobe(3)",
        &[
            "dict 3 False",
            "True 3 True 4",
            "3 9",
            "3 3",
            "5 5",
            "4 False",
            "False 1",
        ],
    );
    assert_output(
        "for expr in [lambda: globals(1), lambda: locals(1)]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &["TypeError", "TypeError"],
    );
}

