#[test]
fn cpython_itertools_keyword_error_subset() {
    assert_output(
        concat!(
            "import itertools\n",
            "def show(label, callback):\n",
            "    try:\n",
            "        callback()\n",
            "    except TypeError as error:\n",
            "        print(label, error.__class__.__name__, str(error))\n",
            "show('count-badkw', lambda: itertools.count(foo=1))\n",
            "show('count-dup-start', lambda: itertools.count(1, start=2))\n",
            "show('count-dup-step', lambda: itertools.count(1, 2, step=3))\n",
            "show('count-many-kw', lambda: itertools.count(start=1, step=2, foo=3))\n",
            "show('repeat-badkw', lambda: itertools.repeat(object=1, bad=3))\n",
            "show('repeat-many-kw', lambda: itertools.repeat(object=1, times=2, bad=3))\n",
            "show('repeat-dup-object', lambda: itertools.repeat(1, object=2))\n",
            "show('repeat-dup-times', lambda: itertools.repeat(1, 2, times=3))\n",
            "show('chain-keyword', lambda: itertools.chain(iterable=[1]))\n",
            "show('chain-from-iterable-keyword', lambda: itertools.chain.from_iterable(iterable=[[1]]))\n",
            "show('islice-keyword', lambda: itertools.islice(iterable=range(3), stop=2))\n",
            "show('accumulate-dup-func', lambda: itertools.accumulate([1], func=lambda left, right: left + right, **{'func': lambda left, right: left}))\n",
            "show('zip-longest-dup-fillvalue', lambda: itertools.zip_longest([1], fillvalue=0, **{'fillvalue': 1}))\n",
            "show('compress-noargs', lambda: itertools.compress())\n",
            "show('compress-one', lambda: itertools.compress([1]))\n",
            "show('compress-dup-data', lambda: itertools.compress([1], data=[]))\n",
            "show('compress-extra', lambda: itertools.compress([1], [1], data=[]))\n",
            "show('groupby-noargs', lambda: itertools.groupby())\n",
            "show('groupby-dup-iterable', lambda: itertools.groupby([1], iterable=[]))\n",
            "show('groupby-extra', lambda: itertools.groupby([1], None, 3))\n",
            "show('combinations-noargs', lambda: itertools.combinations())\n",
            "show('combinations-one', lambda: itertools.combinations([1]))\n",
            "show('combinations-extra', lambda: itertools.combinations([1], 1, r=2))\n",
            "show('combinations_with_replacement-noargs', lambda: itertools.combinations_with_replacement())\n",
            "show('combinations_with_replacement-one', lambda: itertools.combinations_with_replacement([1]))\n",
            "show('combinations_with_replacement-extra', lambda: itertools.combinations_with_replacement([1], 1, r=2))\n",
            "show('permutations-noargs', lambda: itertools.permutations())\n",
            "show('permutations-extra', lambda: itertools.permutations([1], 1, r=2))",
        ),
        &[
            "count-badkw TypeError count() got an unexpected keyword argument 'foo'",
            "count-dup-start TypeError argument for count() given by name ('start') and position (1)",
            "count-dup-step TypeError count() takes at most 2 arguments (3 given)",
            "count-many-kw TypeError count() takes at most 2 keyword arguments (3 given)",
            "repeat-badkw TypeError repeat() got an unexpected keyword argument 'bad'",
            "repeat-many-kw TypeError repeat() takes at most 2 keyword arguments (3 given)",
            "repeat-dup-object TypeError argument for repeat() given by name ('object') and position (1)",
            "repeat-dup-times TypeError repeat() takes at most 2 arguments (3 given)",
            "chain-keyword TypeError chain() takes no keyword arguments",
            "chain-from-iterable-keyword TypeError chain.from_iterable() takes no keyword arguments",
            "islice-keyword TypeError islice() takes no keyword arguments",
            "accumulate-dup-func TypeError itertools.accumulate() got multiple values for keyword argument 'func'",
            "zip-longest-dup-fillvalue TypeError itertools.zip_longest() got multiple values for keyword argument 'fillvalue'",
            "compress-noargs TypeError compress() missing required argument 'data' (pos 1)",
            "compress-one TypeError compress() missing required argument 'selectors' (pos 2)",
            "compress-dup-data TypeError compress() missing required argument 'selectors' (pos 2)",
            "compress-extra TypeError compress() takes at most 2 arguments (3 given)",
            "groupby-noargs TypeError groupby() missing required argument 'iterable' (pos 1)",
            "groupby-dup-iterable TypeError argument for groupby() given by name ('iterable') and position (1)",
            "groupby-extra TypeError groupby() takes at most 2 arguments (3 given)",
            "combinations-noargs TypeError combinations() missing required argument 'iterable' (pos 1)",
            "combinations-one TypeError combinations() missing required argument 'r' (pos 2)",
            "combinations-extra TypeError combinations() takes at most 2 arguments (3 given)",
            "combinations_with_replacement-noargs TypeError combinations_with_replacement() missing required argument 'iterable' (pos 1)",
            "combinations_with_replacement-one TypeError combinations_with_replacement() missing required argument 'r' (pos 2)",
            "combinations_with_replacement-extra TypeError combinations_with_replacement() takes at most 2 arguments (3 given)",
            "permutations-noargs TypeError permutations() missing required argument 'iterable' (pos 1)",
            "permutations-extra TypeError permutations() takes at most 2 arguments (3 given)",
        ],
    );
}

