// Adapted from CPython Lib/test/test_list.py::ListTest::test_basic,
// Lib/test/test_tuple.py::TupleTest::test_constructors, and
// Lib/test/test_set.py::TestSet constructor/literal coverage.
#[test]
fn cpython_sequence_constructor_builtins_subset() {
    assert_output(
        "print(list([]))\nitems = [0, 1, 2, 3]\ncopy = list(items)\nprint(items == copy, items is copy)\nprint(list(()))\nprint(list((0, 1, 2, 3)))\nprint(list(''))\nprint(list('spam'))\nprint(list(x for x in range(10) if x % 2))\nprint(tuple())\nvalues = (0, 1, 2, 3)\ncopy = tuple(values)\nprint(values == copy, values is copy)\nprint(tuple([]))\nprint(tuple([0, 1, 2, 3]))\nprint(tuple(''))\nprint(tuple('spam'))\nprint(tuple(x for x in range(10) if x % 2))\nprint(sorted(set()))\nprint(sorted(set([1, 2, 1])))\nprint(sorted(set('aba')))",
        &[
            "[]",
            "True False",
            "[]",
            "[0, 1, 2, 3]",
            "[]",
            "['s', 'p', 'a', 'm']",
            "[1, 3, 5, 7, 9]",
            "()",
            "True True",
            "()",
            "(0, 1, 2, 3)",
            "()",
            "('s', 'p', 'a', 'm')",
            "(1, 3, 5, 7, 9)",
            "[]",
            "[1, 2]",
            "['a', 'b']",
        ],
    );
    assert_output(
        concat!(
            "s = set()\n",
            "alias = s\n",
            "print(s.__init__('simsalabim'), sorted(s), s is alias)\n",
            "print(s.__init__('madagascar'), sorted(s), s is alias)\n",
            "print(s.__init__(), sorted(s), s is alias)\n",
            "s = set([1, 2])\n",
            "print(s.__init__(s), sorted(s))\n",
            "for expr in [lambda: s.__init__(s, 2), lambda: s.__init__(1), lambda: s.__init__([3, []])]:\n",
            "    try:\n",
            "        expr()\n",
            "    except TypeError as error:\n",
            "        print(error.__class__.__name__, sorted(s))",
        ),
        &[
            "None ['a', 'b', 'i', 'l', 'm', 's'] True",
            "None ['a', 'c', 'd', 'g', 'm', 'r', 's'] True",
            "None [] True",
            "None []",
            "TypeError []",
            "TypeError []",
            "TypeError [3]",
        ],
    );
    assert_output(
        concat!(
            "s = set(range(3))\n",
            "t = set(s)\n",
            "print(s == t, s is t)\n",
            "print(set([1, 2, 3]) == {1, 2, 3})\n",
            "dedup = {1, 1.0, True}\n",
            "stored = dedup.pop()\n",
            "print(len(dedup) + 1, type(stored).__name__)\n",
            "events = []\n",
            "def record(obj):\n",
            "    events.append(obj)\n",
            "{record(1), record(2), record(3)}\n",
            "print(events)\n",
            "try:\n",
            "    hash(set('abc'))\n",
            "except TypeError as error:\n",
            "    print(error.__class__.__name__)\n",
            "source = set('abc')\n",
            "dup = source.copy()\n",
            "print(source == dup, source is dup, type(dup).__name__)",
        ),
        &[
            "True False",
            "True",
            "1 int",
            "[1, 2, 3]",
            "TypeError",
            "True False set",
        ],
    );
    assert_output(
        "for expr in [lambda: list(1, 2), lambda: tuple(1, 2), lambda: set(1, 2), lambda: list(sequence=[]), lambda: tuple(sequence=()), lambda: set(sequence=[]), lambda: list(42), lambda: tuple(42), lambda: set(42), lambda: set([[]])]:\n    try:\n        expr()\n    except TypeError as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython public list-subclass behavior used by
// Lib/test/test_weakref.py::ReferencesTestCase::test_basic_proxy.
// This pins the supported sequence protocol without depending on subclass repr.
#[test]
fn cpython_list_subclass_core_sequence_subset() {
    assert_output(
        concat!(
            "class ListSubclass(list):\n",
            "    pass\n",
            "items = ListSubclass()\n",
            "print('type', type(items).__name__, isinstance(items, list), items.__class__ is ListSubclass)\n",
            "print('empty', bool(items), len(items), list(items))\n",
            "items.append(12)\n",
            "print('append', bool(items), len(items), 12 in items, items[0], list(items))\n",
            "items[:] = [2, 3]\n",
            "print('slice-set', len(items), items[:], 3 in items)\n",
            "items[1] = 5\n",
            "print('item-set', items[1], list(items))\n",
            "print('reversed', list(reversed(items)))\n",
            "names = dir(items)\n",
            "print('dir', 'append' in names, '__len__' in names)\n",
            "print('construct', list(ListSubclass([1, 2])), list(ListSubclass((3, 4))))\n",
            "print('repr', repr(ListSubclass()), str(ListSubclass([1, 2])), f'{ListSubclass([\"x\"])!r}', f'{ListSubclass([\"x\"])!s}')\n",
            "recursive = ListSubclass([1])\n",
            "recursive.append(recursive)\n",
            "print('recursive', repr(recursive), str(recursive))\n",
            "for expr in [lambda: ListSubclass(sequence=[]), lambda: ListSubclass(42)]:\n",
            "    try:\n",
            "        expr()\n",
            "    except TypeError as error:\n",
            "        print('error', error.__class__.__name__)",
        ),
        &[
            "type ListSubclass True True",
            "empty False 0 []",
            "append True 1 True 12 [12]",
            "slice-set 2 [2, 3] True",
            "item-set 5 [2, 5]",
            "reversed [5, 2]",
            "dir True True",
            "construct [1, 2] [3, 4]",
            "repr [] [1, 2] ['x'] ['x']",
            "recursive [1, [...]] [1, [...]]",
            "error TypeError",
            "error TypeError",
        ],
    );
}

// Adapted from CPython public tuple-subclass behavior used by sequence and
