// without depending on CPython's object layout.
#[test]
fn cpython_tuple_subclass_core_sequence_subset() {
    assert_output(
        concat!(
            "class TupleSubclass(tuple):\n",
            "    pass\n",
            "items = TupleSubclass([1, 2])\n",
            "print('type', type(items).__name__, isinstance(items, tuple), items.__class__ is TupleSubclass)\n",
            "print('state', bool(items), len(items), list(items), repr(items), str(items), f'{items!r}', f'{items!s}')\n",
            "print('index-slice', items[0], items[:], list(reversed(items)))\n",
            "empty = TupleSubclass()\n",
            "print('empty', bool(empty), len(empty), list(empty), repr(empty), list(reversed(empty)))\n",
            "for expr in [lambda: TupleSubclass(sequence=[]), lambda: TupleSubclass(1, 2), lambda: TupleSubclass(42)]:\n",
            "    try:\n",
            "        expr()\n",
            "    except TypeError as error:\n",
            "        print('error', error.__class__.__name__)",
        ),
        &[
            "type TupleSubclass True True",
            "state True 2 [1, 2] (1, 2) (1, 2) (1, 2) (1, 2)",
            "index-slice 1 (1, 2) [2, 1]",
            "empty False 0 [] () []",
            "error TypeError",
            "error TypeError",
            "error TypeError",
        ],
    );
}

// Adapted from CPython Lib/test/seq_tests.py tuple index missing-value
// ValueError message behavior for supported instance calls.
#[test]
fn cpython_tuple_index_missing_valueerror_message_subset() {
    assert_output(
        r#"class T(tuple):
    pass
class Needle:
    def __repr__(self):
        return '<needle-repr>'
    def __str__(self):
        return '<needle-str>'

for label, expr in [
    ('tuple', lambda: (1, 2).index(3)),
    ('subclass', lambda: T((1, 2)).index(3)),
    ('repr-needle', lambda: (1, 2).index(Needle())),
    ('window', lambda: (1, 2, 3).index(3, 0, 2)),
]:
    try:
        expr()
    except ValueError as error:
        print(label, type(error).__name__, str(error), error.args)"#,
        &[
            "tuple ValueError tuple.index(x): x not in tuple ('tuple.index(x): x not in tuple',)",
            "subclass ValueError tuple.index(x): x not in tuple ('tuple.index(x): x not in tuple',)",
            "repr-needle ValueError tuple.index(x): x not in tuple ('tuple.index(x): x not in tuple',)",
            "window ValueError tuple.index(x): x not in tuple ('tuple.index(x): x not in tuple',)",
        ],
    );
}

#[test]
fn cpython_immutable_sequence_index_rich_compare_subset() {
    assert_output_with_stack(
        r#"class Probe:
    def __init__(self, tag):
        self.tag = tag
    def __eq__(self, other):
        print("tuple-eq", self.tag, getattr(other, "tag", other))
        return self.tag == getattr(other, "tag", other)
items = (Probe("a"), Probe("b"), Probe("a"))
class T(tuple):
    pass
def show(label, expr):
    try:
        print(label, expr())
    except Exception as error:
        print(label, type(error).__name__, str(error), error.args)
show("tuple-match", lambda: items.index(Probe("b")))
show("tuple-window", lambda: items.index(Probe("a"), 1))
show("tuple-subclass", lambda: T(items).index(Probe("b")))
class Boom:
    def __eq__(self, other):
        raise ValueError("boom")
show("tuple-error", lambda: (Boom(),).index(1))
class I(int):
    pass
for label, value in [
    ("range-int-missing", 5),
    ("range-float-match", 2.0),
    ("range-float-missing", 5.0),
    ("range-subint-match", I(2)),
    ("range-subint-missing", I(5)),
]:
    show(label, lambda value=value: range(3).index(value))
class RangeProbe:
    def __eq__(self, other):
        print("range-eq", other)
        return False
show("range-object-missing", lambda: range(3).index(RangeProbe()))"#,
        &[
            "tuple-eq a b",
            "tuple-eq b b",
            "tuple-match 1",
            "tuple-eq b a",
            "tuple-eq a a",
            "tuple-window 2",
            "tuple-eq a b",
            "tuple-eq b b",
            "tuple-subclass 1",
            "tuple-error ValueError boom ('boom',)",
            "range-int-missing ValueError range.index(x): x not in range ('range.index(x): x not in range',)",
            "range-float-match 2",
            "range-float-missing ValueError sequence.index(x): x not in sequence ('sequence.index(x): x not in sequence',)",
            "range-subint-match 2",
            "range-subint-missing ValueError sequence.index(x): x not in sequence ('sequence.index(x): x not in sequence',)",
            "range-eq 0",
            "range-eq 1",
            "range-eq 2",
            "range-object-missing ValueError sequence.index(x): x not in sequence ('sequence.index(x): x not in sequence',)",
        ],
        64 * 1024 * 1024,
    );
}

