// Adapted from CPython Lib/test/test_set.py::TestJointOps. This keeps the
// common set/frozenset behavioral contract separate from mutation-only set
// methods and subclass/pickle/GC coverage.
#[test]
fn cpython_set_frozenset_joint_ops_subset() {
    assert_output(
        concat!(
            "for typ in (set, frozenset):\n",
            "    s = typ('simsalabim')\n",
            "    d = dict.fromkeys('simsalabim')\n",
            "    print(typ.__name__, sorted(s), len(s) == len(d))\n",
            "    print([c in s for c in 'abcxyz'])\n",
            "    nested = typ([frozenset('abc')])\n",
            "    print(typ('abc') in nested)\n",
            "    rejected = 0\n",
            "    for op in (lambda: s | 'madagascar', lambda: s & 'madagascar', lambda: s - 'madagascar', lambda: s ^ 'madagascar'):\n",
            "        try:\n",
            "            op()\n",
            "        except TypeError:\n",
            "            rejected += 1\n",
            "    print(rejected)\n",
            "    print(type(s.union('madagascar')).__name__, sorted(s.union('madagascar')))\n",
            "    print(type(s.intersection('madagascar')).__name__, sorted(s.intersection('madagascar')))\n",
            "    print(type(s.difference('madagascar')).__name__, sorted(s.difference('madagascar')))\n",
            "    print(type(s.symmetric_difference('madagascar')).__name__, sorted(s.symmetric_difference('madagascar')))\n",
            "    p, q, r = typ('ab'), typ('abcde'), typ('def')\n",
            "    print(p < q, p <= q, q <= q, q > p, q >= p, q < r, q <= r, q > r, q >= r)\n",
            "    print(typ('a').issubset('abc'), typ('abc').issuperset('a'), typ('a').issubset('cbs'), typ('cbs').issuperset('a'))",
        ),
        &[
            "set ['a', 'b', 'i', 'l', 'm', 's'] True",
            "[True, True, False, False, False, False]",
            "True",
            "4",
            "set ['a', 'b', 'c', 'd', 'g', 'i', 'l', 'm', 'r', 's']",
            "set ['a', 'm', 's']",
            "set ['b', 'i', 'l']",
            "set ['b', 'c', 'd', 'g', 'i', 'l', 'r']",
            "True True True True True False False False False",
            "True True False False",
            "frozenset ['a', 'b', 'i', 'l', 'm', 's'] True",
            "[True, True, False, False, False, False]",
            "True",
            "4",
            "frozenset ['a', 'b', 'c', 'd', 'g', 'i', 'l', 'm', 'r', 's']",
            "frozenset ['a', 'm', 's']",
            "frozenset ['b', 'i', 'l']",
            "frozenset ['b', 'c', 'd', 'g', 'i', 'l', 'r']",
            "True True True True True False False False False",
            "True True False False",
        ],
    );
}

// Adapted from CPython Lib/test/test_set.py::TestJointOps equality,
// set-of-frozensets, and isdisjoint matrix cases.
#[test]
fn cpython_set_frozenset_relationship_matrix_subset() {
    assert_output(
        concat!(
            "args = ['', 'a', 'ab', 'abc', 'ababac', 'cdc', 'cc', 'efgfe', 'ccb', 'ef']\n",
            "constructors = (set, frozenset, dict.fromkeys, str, list, tuple)\n",
            "for typ in (set, frozenset):\n",
            "    word = 'simsalabim'\n",
            "    otherword = 'madagascar'\n",
            "    s = typ(word)\n",
            "    print(typ.__name__, s == set(word), s == frozenset(word), s == word, s != otherword)\n",
            "    print(len(typ(map(frozenset, ['abcdef', 'bcd', 'bdcb', 'fed', 'fedccba']))))\n",
            "    failures = 0\n",
            "    true_count = 0\n",
            "    false_count = 0\n",
            "    for larg in args:\n",
            "        s1 = typ(larg)\n",
            "        for rarg in args:\n",
            "            for C in constructors:\n",
            "                s2 = C(rarg)\n",
            "                actual = s1.isdisjoint(s2)\n",
            "                expected = not set(s1).intersection(s2)\n",
            "                if actual:\n",
            "                    true_count += 1\n",
            "                else:\n",
            "                    false_count += 1\n",
            "                if actual != expected or not (actual is True or actual is False):\n",
            "                    failures += 1\n",
            "    print(failures, true_count, false_count)"
        ),
        &[
            "set True True False True",
            "3",
            "0 342 258",
            "frozenset True True False True",
            "3",
            "0 342 258",
        ],
    );
}

// Adapted from CPython Lib/test/test_set.py::TestJointOps union,
// intersection, difference, and symmetric_difference constructor matrix cases.
#[test]
fn cpython_set_frozenset_algebra_matrix_subset() {
    assert_output(
        concat!(
            "constructors = (set, frozenset, dict.fromkeys, str, list, tuple)\n",
            "for typ in (set, frozenset):\n",
            "    failures = 0\n",
            "    for C in constructors:\n",
            "        if typ('abcba').union(C('cdc')) != set('abcd'):\n",
            "            failures += 1\n",
            "        if typ('abcba').union(C('efgfe')) != set('abcefg'):\n",
            "            failures += 1\n",
            "        if typ('abcba').union(C('ccb')) != set('abc'):\n",
            "            failures += 1\n",
            "        if typ('abcba').union(C('ef'), C('fg')) != set('abcefg'):\n",
            "            failures += 1\n",
            "        if typ('abcba').intersection(C('cdc')) != set('c'):\n",
            "            failures += 1\n",
            "        if typ('abcba').intersection(C('efgfe')) != set(''):\n",
            "            failures += 1\n",
            "        if typ('abcba').intersection(C('ccb')) != set('bc'):\n",
            "            failures += 1\n",
            "        if typ('abcba').intersection(C('cbcf'), C('bag')) != set('b'):\n",
            "            failures += 1\n",
            "        if typ('abcba').difference(C('cdc')) != set('ab'):\n",
            "            failures += 1\n",
            "        if typ('abcba').difference(C('efgfe')) != set('abc'):\n",
            "            failures += 1\n",
            "        if typ('abcba').difference(C('ccb')) != set('a'):\n",
            "            failures += 1\n",
            "        if typ('abcba').difference(C('a'), C('b')) != set('c'):\n",
            "            failures += 1\n",
            "        if typ('abcba').symmetric_difference(C('cdc')) != set('abd'):\n",
            "            failures += 1\n",
            "        if typ('abcba').symmetric_difference(C('efgfe')) != set('abcefg'):\n",
            "            failures += 1\n",
            "        if typ('abcba').symmetric_difference(C('ccb')) != set('a'):\n",
            "            failures += 1\n",
            "        if typ('abcba').symmetric_difference(C('ef')) != set('abcef'):\n",
            "            failures += 1\n",
            "    x = typ()\n",
            "    issue_6573 = x.union(set([1]), x, set([2])) == typ([1, 2])\n",
            "    print(typ.__name__, failures, issue_6573)\n",
            "    print(type(typ('abc').union('d')).__name__, type(typ('abc').intersection('bc')).__name__, type(typ('abc').difference('bc')).__name__, type(typ('abc').symmetric_difference('bc')).__name__)"
        ),
        &[
            "set 0 True",
            "set set set set",
            "frozenset 0 True",
            "frozenset frozenset frozenset frozenset",
        ],
    );
}

// Adapted from CPython Lib/test/test_set.py::TestSet mutation method cases:
// clear, add, remove, discard, pop, and update. Subclass, pickle, GC, and
// exact KeyError object identity checks are left for later object-model work.
#[test]
fn cpython_set_mutation_methods_subset() {
    assert_output(
        concat!(
            "s = set('simsalabim')\n",
            "s.clear()\n",
            "print(s == set(), len(s))\n",
            "s = set('simsalabim')\n",
            "print(s.add('Q'), 'Q' in s)\n",
            "dup = s.copy()\n",
            "print(s.add('Q'), s == dup)\n",
            "for expr in [lambda: s.add([]), lambda: s.remove([]), lambda: s.discard([])]:\n",
            "    try:\n",
            "        expr()\n",
            "    except TypeError as error:\n",
            "        print(error.__class__.__name__)\n",
            "s.remove('a')\n",
            "print('a' in s)\n",
            "try:\n",
            "    s.remove('not-there')\n",
            "except KeyError as error:\n",
            "    print(error.__class__.__name__)\n",
            "nested = set([frozenset('simsalabim')])\n",
            "print(set('simsalabim') in nested)\n",
            "nested.remove(set('simsalabim'))\n",
            "print(set('simsalabim') in nested)\n",
            "nested.discard(set('simsalabim'))\n",
            "print(len(nested))\n",
            "items = set('abc')\n",
            "seen = []\n",
            "while len(items):\n",
            "    elem = items.pop()\n",
            "    print(elem in items)\n",
            "    seen.append(elem)\n",
            "print(sorted(seen))\n",
            "try:\n",
            "    items.pop()\n",
            "except KeyError as error:\n",
            "    print(error.__class__.__name__)\n",
            "s = set('abcba')\n",
            "print(s.update('cdc'), sorted(s))\n",
            "print(s.update(frozenset('ef')), sorted(s))\n",
            "try:\n",
            "    s.update([[]])\n",
            "except TypeError as error:\n",
            "    print(error.__class__.__name__)",
        ),
        &[
            "True 0",
            "None True",
            "None True",
            "TypeError",
            "TypeError",
            "TypeError",
            "False",
            "KeyError",
            "True",
            "False",
            "0",
            "False",
            "False",
            "False",
            "['a', 'b', 'c']",
            "KeyError",
            "None ['a', 'b', 'c', 'd']",
            "None ['a', 'b', 'c', 'd', 'e', 'f']",
            "TypeError",
        ],
    );
}

