// Adapted from CPython Lib/test/test_dict.py::DictTest::test_constructor,
// ::test_update, and ::test_fromkeys.
#[test]
fn cpython_dict_constructor_update_fromkeys_subset() {
    assert_output(
        "print(dict())\nprint(dict({'a': 1, 'b': 2}))\nprint(dict([('a', 1), ['b', 2]]))\nprint(dict(a=1, b=2))\nprint(dict([('a', 1)], a=2))\nclass SimpleUserDict:\n    def __init__(self):\n        self.d = {1: 1, 2: 2, 3: 3}\n    def keys(self):\n        return self.d.keys()\n    def __getitem__(self, key):\n        return self.d[key]\nprint(dict(SimpleUserDict()))\nd = {}\nd.update({1: 100})\nd.update({2: 20})\nd.update({1: 1, 2: 2, 3: 3})\nprint(d)\nd.update()\nprint(d)\nd.clear()\nd.update(SimpleUserDict())\nprint(d)\nd.clear()\nd.update([(1, 1), (2, 2)])\nd.update(c=3)\nprint(d)\nprint(dict.fromkeys('abc'))\nprint(dict.fromkeys((4, 5), 0))\nprint({}.fromkeys(('x', 'y'), 6))\nprint({}.__repr__(), {}.__str__(), dict.__repr__({}), dict.__str__({}))\nprint({}.__format__(''), dict.__format__({}, ''))\nprint(dict.fromkeys([]))\ndef g():\n    yield 1\nprint(dict.fromkeys(g()))",
        &[
            "{}",
            "{'a': 1, 'b': 2}",
            "{'a': 1, 'b': 2}",
            "{'a': 1, 'b': 2}",
            "{'a': 2}",
            "{1: 1, 2: 2, 3: 3}",
            "{1: 1, 2: 2, 3: 3}",
            "{1: 1, 2: 2, 3: 3}",
            "{1: 1, 2: 2, 3: 3}",
            "{1: 1, 2: 2, 'c': 3}",
            "{'a': None, 'b': None, 'c': None}",
            "{4: 0, 5: 0}",
            "{'x': 6, 'y': 6}",
            "{} {} {} {}",
            "{} {}",
            "{}",
            "{1: None}",
        ],
    );
    assert_output(
        "for expr in [lambda: dict(1, 2), lambda: dict(None), lambda: dict([[1, 2, 3]]), lambda: dict.fromkeys(), lambda: dict.fromkeys(3), lambda: {}.update(None), lambda: {}.update([(1, 2, 3)])]:\n    try:\n        expr()\n    except (TypeError, ValueError) as error:\n        print(error.__class__.__name__)",
        &[
            "TypeError",
            "TypeError",
            "ValueError",
            "TypeError",
            "TypeError",
            "TypeError",
            "ValueError",
        ],
    );
    assert_output(
        "class FailingKeys:\n    def keys(self):\n        raise ValueError\nclass FailingKeyIterator:\n    def keys(self):\n        return self\n    def __iter__(self):\n        return self\n    def __next__(self):\n        raise ValueError\n    def __getitem__(self, key):\n        return key\nclass FailingGetItem:\n    def keys(self):\n        return ['a']\n    def __getitem__(self, key):\n        raise ValueError\nfor source in [FailingKeys(), FailingKeyIterator(), FailingGetItem()]:\n    try:\n        {}.update(source)\n    except ValueError as error:\n        print(error.__class__.__name__)",
        &["ValueError", "ValueError", "ValueError"],
    );
}

// Adapted from CPython public dict popitem empty-error behavior. The message
// is stored as the original KeyError argument while str(error) renders repr().
#[test]
fn cpython_dict_popitem_empty_keyerror_subset() {
    assert_output(
        "class D(dict):\n    pass\n\ndef show(label, action):\n    try:\n        action()\n    except KeyError as error:\n        print(label, error.args[0] == 'popitem(): dictionary is empty', type(error.args[0]).__name__, str(error) == repr(error.args[0]))\nshow('popitem-empty', lambda: {}.popitem())\nshow('direct-popitem-empty', lambda: dict.popitem({}))\nshow('subclass-popitem-empty', lambda: D().popitem())\nshow('subclass-direct-popitem-empty', lambda: dict.popitem(D()))\nprint('popitem-nonempty', {'a': 1}.popitem())\nprint('subclass-popitem-nonempty', D({'a': 1}).popitem())",
        &[
            "popitem-empty True str True",
            "direct-popitem-empty True str True",
            "subclass-popitem-empty True str True",
            "subclass-direct-popitem-empty True str True",
            "popitem-nonempty ('a', 1)",
            "subclass-popitem-nonempty ('a', 1)",
        ],
    );
}

// Adapted from CPython public dict missing-key behavior. KeyError display uses
// repr(key), but KeyError.args must preserve the original missing key object.
#[test]
fn cpython_dict_missing_keyerror_payload_subset() {
    assert_output(
        "def show(label, key, callback):\n    try:\n        callback()\n    except KeyError as error:\n        print(label, error.args[0] == key, type(error.args[0]).__name__, str(error))\nclass D(dict):\n    pass\ng = globals()\ndef delete_str():\n    d = {}\n    del d['missing']\ndef delete_subclass_str():\n    d = D()\n    del d['missing']\nshow('subscript-str', 'missing', lambda: {}['missing'])\nshow('subscript-int', 42, lambda: {}[42])\nshow('getitem-str', 'missing', lambda: dict.__getitem__({}, 'missing'))\nshow('delitem-str', 'missing', lambda: dict.__delitem__({}, 'missing'))\nshow('del-subscript-str', 'missing', delete_str)\nshow('pop-str', 'missing', lambda: {}.pop('missing'))\nshow('pop-int', 42, lambda: {}.pop(42))\nshow('subclass-subscript', 'missing', lambda: D()['missing'])\nshow('subclass-getitem', 'missing', lambda: dict.__getitem__(D(), 'missing'))\nshow('subclass-delitem', 'missing', lambda: dict.__delitem__(D(), 'missing'))\nshow('subclass-del-subscript', 'missing', delete_subclass_str)\nshow('scope-subscript', 'scope_missing', lambda: g['scope_missing'])\nshow('scope-pop', 'scope_missing', lambda: g.pop('scope_missing'))",
        &[
            "subscript-str True str 'missing'",
            "subscript-int True int 42",
            "getitem-str True str 'missing'",
            "delitem-str True str 'missing'",
            "del-subscript-str True str 'missing'",
            "pop-str True str 'missing'",
            "pop-int True int 42",
            "subclass-subscript True str 'missing'",
            "subclass-getitem True str 'missing'",
            "subclass-delitem True str 'missing'",
            "subclass-del-subscript True str 'missing'",
            "scope-subscript True str 'scope_missing'",
            "scope-pop True str 'scope_missing'",
        ],
    );
}

// Covers CPython dict/set key matching for bool, int, float, complex, and
// numeric subclasses whose hashes and equality results match.
#[test]
fn cpython_dict_numeric_key_equivalence_subset() {
    assert_output(
        "class I(int):\n    pass\nclass F(float):\n    pass\nclass C(complex):\n    pass\npairs = [(I(1), True), (I(0), False), (I(2), 2), (I(1), 1.0), (F(1.0), 1), (F(0.0), False), (I(1), 1+0j), (F(1.0), 1+0j), (C(1+0j), 1), (C(1+2j), 1+2j)]\nfor a, b in pairs:\n    print(type(a).__name__, repr(a), type(b).__name__, repr(b), a == b, hash(a) == hash(b), {a: 'a', b: 'b'})\ns = {I(1), True, 1, 1.0, F(1.0), 1+0j, C(1+0j)}\nprint(s, len(s), I(1) in {True}, True in {I(1)}, 1.0 in {I(1)}, F(1.0) in {1}, C(1+0j) in {I(1)})\nd = {I(1): 'i'}\nd[True] = 'b'\nd[1.0] = 'f'\nd[1+0j] = 'c'\nprint(d, len(d), d[I(1)], d[1], d[True], d[1.0], d[1+0j])\ne = {}\ne[I(0)] = 'i'\ne[False] = 'f'\ne[F(0.0)] = 'z'\ne[0j] = 'c'\nprint(e, len(e), e[I(0)], e[0], e[False], e[0.0], e[0j])\nnc = {C(1+2j): 'sub'}\nnc[1+2j] = 'exact'\nprint(nc, len(nc), nc[C(1+2j)], nc[1+2j])\nnan = float('nan')\nother = float('nan')\nprint(nan != nan, nan in {nan}, other in {nan})\nnd = {nan: 'n'}\nprint(nd[nan])\ntry:\n    print(nd[other])\nexcept KeyError as error:\n    print(type(error).__name__)",
        &[
            "I 1 bool True True True {1: 'b'}",
            "I 0 bool False True True {0: 'b'}",
            "I 2 int 2 True True {2: 'b'}",
            "I 1 float 1.0 True True {1: 'b'}",
            "F 1.0 int 1 True True {1.0: 'b'}",
            "F 0.0 bool False True True {0.0: 'b'}",
            "I 1 complex (1+0j) True True {1: 'b'}",
            "F 1.0 complex (1+0j) True True {1.0: 'b'}",
            "C (1+0j) int 1 True True {(1+0j): 'b'}",
            "C (1+2j) complex (1+2j) True True {(1+2j): 'b'}",
            "{1} 1 True True True True True",
            "{1: 'c'} 1 c c c c c",
            "{0: 'c'} 1 c c c c c",
            "{(1+2j): 'exact'} 1 exact exact",
            "True True False",
            "n",
            "KeyError",
        ],
    );
}

// Adapted from CPython Lib/test/test_enumerate.py::TestReversed::test_simple
// and Lib/test/test_dict.py reverse-iterator coverage.
#[test]
fn cpython_reversed_builtin_subset() {
    assert_output(
        "class A:\n    def __getitem__(self, index):\n        if index < 5:\n            return str(index)\n        raise StopIteration\n    def __len__(self):\n        return 5\nprint(list(reversed('abc')))\nprint(list(reversed(range(5))))\nprint(list(reversed(tuple(enumerate('abc')))))\nprint(list(reversed(A())))\nprint(list(reversed(range(1, 17, 5))))\nprint(list(reversed(dict.fromkeys('abcde'))))\nprint(list(reversed({})), list(reversed({}.items())), list(reversed({}.values())), list(reversed({}.keys())))\nprint(list(reversed(dict())), list(reversed(dict().items())), list(reversed(dict().values())), list(reversed(dict().keys())))\nclass ReverseCustom:\n    def __reversed__(self):\n        return iter([3, 2, 1])\nprint(list(reversed(ReverseCustom())))\nr = reversed([1, 2])\nprint(next(r), next(r))\ntry:\n    next(r)\nexcept StopIteration:\n    print('stopped')",
        &[
            "['c', 'b', 'a']",
            "[4, 3, 2, 1, 0]",
            "[(2, 'c'), (1, 'b'), (0, 'a')]",
            "['4', '3', '2', '1', '0']",
            "[16, 11, 6, 1]",
            "['e', 'd', 'c', 'b', 'a']",
            "[] [] [] []",
            "[] [] [] []",
            "[3, 2, 1]",
            "2 1",
            "stopped",
        ],
    );
    assert_output(
        concat!(
            "class BadReverse:\n",
            "    def __reversed__(self):\n",
            "        return 42\n",
            "class BlockReverse:\n",
            "    __reversed__ = None\n",
            "    def __len__(self):\n",
            "        return 2\n",
            "    def __getitem__(self, index):\n",
            "        if index < 2:\n",
            "            return index\n",
            "        raise IndexError\n",
            "class BlockOnly:\n",
            "    __reversed__ = None\n",
            "for expr in [lambda: reversed(), lambda: reversed([], a=1), lambda: reversed({1}), lambda: list(reversed(BadReverse()))]:\n",
            "    try:\n",
            "        expr()\n",
            "    except TypeError as error:\n",
            "        print(error.__class__.__name__)\n",
            "for label, expr in [('fallback', lambda: list(reversed(BlockReverse()))), ('only', lambda: reversed(BlockOnly()))]:\n",
            "    try:\n",
            "        expr()\n",
            "    except TypeError as error:\n",
            "        print(label, error)",
        ),
        &[
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "fallback 'BlockReverse' object is not reversible",
            "only 'BlockOnly' object is not reversible",
        ],
    );
    assert_output(
        "for label, expr in [('missing', lambda: reversed()), ('too-many', lambda: reversed([], []))]:\n    try:\n        expr()\n    except TypeError as error:\n        print(label, error.__class__.__name__, str(error))",
        &[
            "missing TypeError reversed expected 1 argument, got 0",
            "too-many TypeError reversed expected 1 argument, got 2",
        ],
    );
}

// Adapted from CPython Lib/test/test_operator.py public helper smoke coverage.
#[test]
fn cpython_operator_public_helpers_subset() {
    assert_output(
        concat!(
            "import operator\n",
            "class Box:\n",
            "    pass\n",
            "box = Box()\n",
            "box.x = 7\n",
            "box.child = Box()\n",
            "box.child.y = 9\n",
            "print(operator.lt(1, 2), operator.eq('a', 'a'), operator.ne('a', 'b'))\n",
            "print(operator.truth([0]), operator.not_([]), operator.is_(None, None), operator.is_not(None, 0))\n",
            "print(operator.add(2, 3), operator.sub(5, 2), operator.mul('x', 3), operator.floordiv(7, 2), operator.mod(7, 2), operator.pow(2, 5))\n",
            "print(operator.and_(6, 3), operator.or_(4, 1), operator.xor(6, 3), operator.lshift(3, 2), operator.rshift(8, 1))\n",
            "print(operator.concat('py', 'thon'), operator.contains([1, 2, 3], 2), operator.countOf([1, 2, 1], 1), operator.indexOf(['a', 'b'], 'b'))\n",
            "class I(int):\n",
            "    pass\n",
            "class IndexSubclass:\n",
            "    def __index__(self):\n",
            "        return I(7)\n",
            "for value in [True, False, I(5), IndexSubclass(), 2**100]:\n",
            "    result = operator.index(value)\n",
            "    print('index', type(value).__name__, type(result).__name__, repr(result))\n",
            "items = [10, 20, 30]\n",
            "print(operator.getitem(items, 1))\n",
            "print(operator.setitem(items, 0, 99), items)\n",
            "print(operator.delitem(items, 1), items)\n",
            "print(operator.attrgetter('x')(box), operator.attrgetter('child.y')(box))\n",
            "print(operator.itemgetter(1)(['a', 'b', 'c']), operator.itemgetter(0, 2)(['a', 'b', 'c']))\n",
            "print(operator.methodcaller('replace', 'a', 'o')('banana'))"
        ),
        &[
            "True True True",
            "True True True True",
            "5 3 xxx 3 1 32",
            "2 5 5 12 4",
            "python True 2 1",
            "index bool int 1",
            "index bool int 0",
            "index I int 5",
            "index IndexSubclass int 7",
            "index int int 1267650600228229401496703205376",
            "20",
            "None [99, 20, 30]",
            "None [99, 30]",
            "7 9",
            "b ('a', 'c')",
            "bonono",
        ],
    );
}

