// Adapted from CPython Lib/test/test_operator.py::OperatorTestCase::test_length_hint
// and Lib/test/test_enumerate.py::TestReversed::test_len. This covers the public
// operator.length_hint fallback rules plus reversed iterator length hints.
#[test]
fn cpython_operator_length_hint_subset() {
    assert_output(
        concat!(
            "import operator\n",
            "import itertools\n",
            "class X:\n",
            "    def __init__(self, value):\n",
            "        self.value = value\n",
            "    def __length_hint__(self):\n",
            "        if type(self.value) is type:\n",
            "            raise self.value\n",
            "        return self.value\n",
            "class Y:\n",
            "    pass\n",
            "class I(int):\n",
            "    pass\n",
            "class IndexLike:\n",
            "    def __index__(self):\n",
            "        return 2\n",
            "class BadIndex:\n",
            "    def __index__(self):\n",
            "        return 'x'\n",
            "print(operator.length_hint([], 2), operator.length_hint(iter([1, 2, 3])))\n",
            "print(operator.length_hint(X(NotImplemented)))\n",
            "print(operator.length_hint(X(2)), operator.length_hint(X(NotImplemented), 4), operator.length_hint(X(TypeError), 12), operator.length_hint(Y(), 10))\n",
            "for default in [True, False, I(5), -1]:\n",
            "    print('default', type(default).__name__, repr(operator.length_hint(Y(), default)), repr(operator.length_hint(X(NotImplemented), default)))\n",
            "print('index-default', operator.length_hint(Y(), IndexLike()), operator.length_hint(X(NotImplemented), IndexLike()))\n",
            "for default in [2**63, -(2**100)]:\n",
            "    try:\n",
            "        operator.length_hint(Y(), default)\n",
            "    except OverflowError as error:\n",
            "        print('default-overflow', type(error).__name__)\n",
            "for hint in [True, False, I(6)]:\n",
            "    result = operator.length_hint(X(hint))\n",
            "    print('hint', type(hint).__name__, type(result).__name__, repr(result))\n",
            "try:\n",
            "    operator.length_hint(X(2**100))\n",
            "except OverflowError as error:\n",
            "    print('hint-overflow', type(error).__name__)\n",
            "for value in [X('abc'), X(-2), X(LookupError)]:\n",
            "    try:\n",
            "        operator.length_hint(value)\n",
            "    except (TypeError, ValueError, LookupError) as error:\n",
            "        print(type(error).__name__)\n",
            "try:\n",
            "    operator.length_hint(X(1.5))\n",
            "except TypeError as error:\n",
            "    print('bad-hint', type(error).__name__, str(error))\n",
            "try:\n",
            "    operator.length_hint(X(2), 'abc')\n",
            "except TypeError as error:\n",
            "    print(type(error).__name__)\n",
            "try:\n",
            "    operator.length_hint(Y(), BadIndex())\n",
            "except TypeError as error:\n",
            "    print('bad-index', type(error).__name__, str(error))\n",
            "for label, callback in [\n",
            "    ('missing', lambda: operator.length_hint()),\n",
            "    ('kw', lambda: operator.length_hint(obj=[])),\n",
            "    ('defaultkw', lambda: operator.length_hint([], default=2)),\n",
            "    ('default-float', lambda: operator.length_hint([], 1.5)),\n",
            "    ('many', lambda: operator.length_hint([], 1, 2)),\n",
            "]:\n",
            "    try:\n",
            "        callback()\n",
            "    except TypeError as error:\n",
            "        print(label, type(error).__name__, str(error))\n",
            "lengths = []\n",
            "for seq in ('hello', tuple('hello'), list('hello'), range(5)):\n",
            "    rev = reversed(seq)\n",
            "    lengths.append((operator.length_hint(rev), len(seq)))\n",
            "    list(rev)\n",
            "    lengths.append(operator.length_hint(rev))\n",
            "print(lengths)\n",
            "class SeqWithWeirdLen:\n",
            "    called = False\n",
            "    def __len__(self):\n",
            "        if not self.called:\n",
            "            self.called = True\n",
            "            return 10\n",
            "        raise ZeroDivisionError\n",
            "    def __getitem__(self, index):\n",
            "        return index\n",
            "try:\n",
            "    operator.length_hint(reversed(SeqWithWeirdLen()))\n",
            "except ZeroDivisionError as error:\n",
            "    print(type(error).__name__)\n",
            "r = itertools.repeat('x', 3)\n",
            "print(operator.length_hint(r), next(r), operator.length_hint(r), list(r), operator.length_hint(r))\n",
            "print(operator.length_hint(itertools.repeat('x')), operator.length_hint(itertools.repeat('x'), 9))\n",
            "try:\n",
            "    itertools.repeat('x').__length_hint__()\n",
            "except TypeError as error:\n",
            "    print(type(error).__name__, str(error))\n",
            "try:\n",
            "    itertools.repeat('x', 1).__length_hint__(1)\n",
            "except TypeError as error:\n",
            "    print(type(error).__name__)\n",
        ),
        &[
            "0 3",
            "0",
            "2 4 12 10",
            "default bool 1 1",
            "default bool 0 0",
            "default I 5 5",
            "default int -1 -1",
            "index-default 2 2",
            "default-overflow OverflowError",
            "default-overflow OverflowError",
            "hint bool int 1",
            "hint bool int 0",
            "hint I int 6",
            "hint-overflow OverflowError",
            "TypeError",
            "ValueError",
            "LookupError",
            "bad-hint TypeError __length_hint__ must be an integer, not float",
            "TypeError",
            "bad-index TypeError __index__ returned non-int (type str)",
            "missing TypeError length_hint expected at least 1 argument, got 0",
            "kw TypeError _operator.length_hint() takes no keyword arguments",
            "defaultkw TypeError _operator.length_hint() takes no keyword arguments",
            "default-float TypeError 'float' object cannot be interpreted as an integer",
            "many TypeError length_hint expected at most 2 arguments, got 3",
            "[(5, 5), 0, (5, 5), 0, (5, 5), 0, (5, 5), 0]",
            "ZeroDivisionError",
            "3 x 2 ['x', 'x'] 0",
            "0 9",
            "TypeError len() of unsized object",
            "TypeError",
        ],
    );
}

// Adapted from CPython Lib/test/test_operator.py::OperatorTestCase comparison
// and predicate helper tests. MiniPython uses list aliasing for identity checks
// instead of relying on CPython string interning details.
#[test]
fn cpython_operator_comparison_predicate_subset() {
    assert_output(
        concat!(
            "import operator\n",
            "print(operator.lt(1, 0), operator.lt(1, 1), operator.lt(1, 2))\n",
            "print(operator.le(1, 0), operator.le(1, 1), operator.le(1, 2))\n",
            "print(operator.eq(1, 0), operator.eq(1, 1), operator.eq(1, 2))\n",
            "print(operator.ne(1, 0), operator.ne(1, 1), operator.ne(1, 2))\n",
            "print(operator.ge(1, 0), operator.ge(1, 1), operator.ge(1, 2))\n",
            "print(operator.gt(1, 0), operator.gt(1, 1), operator.gt(1, 2))\n",
            "class EqBoom:\n",
            "    def __eq__(self, other):\n",
            "        raise SyntaxError\n",
            "class NeBoom:\n",
            "    def __ne__(self, other):\n",
            "        raise SyntaxError\n",
            "class TruthBoom:\n",
            "    def __bool__(self):\n",
            "        raise SyntaxError\n",
            "for expr in [lambda: operator.eq(EqBoom(), EqBoom()), lambda: operator.ne(NeBoom(), NeBoom()), lambda: operator.truth(TruthBoom()), lambda: operator.not_(TruthBoom())]:\n",
            "    try:\n",
            "        expr()\n",
            "    except SyntaxError as error:\n",
            "        print(type(error).__name__)\n",
            "print(operator.truth(5), operator.truth([0]), operator.truth(0), operator.truth([]))\n",
            "print(operator.not_(5), operator.not_([0]), operator.not_(0), operator.not_([]))\n",
            "a = []\n",
            "b = a\n",
            "c = []\n",
            "print(operator.is_(a, b), operator.is_(a, c), operator.is_not(a, b), operator.is_not(a, c))\n",
            "print(operator.is_none(a), operator.is_none(None), operator.is_not_none(a), operator.is_not_none(None))\n",
            "for expr in [lambda: operator.lt(), lambda: operator.truth(), lambda: operator.is_none(), lambda: operator.is_()]:\n",
            "    try:\n",
            "        expr()\n",
            "    except TypeError as error:\n",
            "        print(type(error).__name__)\n",
            "for label, callback in [('truth0', lambda: operator.truth()), ('truth2', lambda: operator.truth(1, 2)), ('not0', lambda: operator.not_())]:\n",
            "    try:\n",
            "        callback()\n",
            "    except TypeError as error:\n",
            "        print(label, type(error).__name__, str(error))\n",
        ),
        &[
            "False False True",
            "False True True",
            "False True False",
            "True False True",
            "True True False",
            "True False False",
            "SyntaxError",
            "SyntaxError",
            "SyntaxError",
            "SyntaxError",
            "True True False False",
            "False False True True",
            "True False False True",
            "False True True False",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "truth0 TypeError _operator.truth() takes exactly one argument (0 given)",
            "truth2 TypeError _operator.truth() takes exactly one argument (2 given)",
            "not0 TypeError _operator.not_() takes exactly one argument (0 given)",
        ],
    );
}

