// Adapted from CPython t-string coverage in Lib/test/test_tstring.py and
// Lib/test/test_unparse.py::test_tstrings. MiniPython keeps the same core
// Template/Interpolation shape for literal text, replacement expressions,
// conversions, format specs, debug fields, nested Template values, adjacent
// t-string literals, and template concatenation.
#[test]
fn cpython_t_string_basic_subset() {
    assert_output(
        "print(t'Hello')",
        &["Template(strings=('Hello',), interpolations=())"],
    );
    assert_output(
        "name = 'Python'\nt = t'Hello, {name}'\nprint(t.strings)\nprint(t.interpolations[0].value, t.interpolations[0].expression)",
        &["('Hello, ', '')", "Python name"],
    );
    assert_output(
        "first = 'Python'\nlast = 'Developer'\nt = t'{first} {last}'\nprint(t.strings)\nprint(t.interpolations[0].value, t.interpolations[0].expression)\nprint(t.interpolations[1].value, t.interpolations[1].expression)",
        &["('', ' ', '')", "Python first", "Developer last"],
    );
    assert_output(
        "def square(x):\n    return x * x\nt = t'Square: {square(5)}'\nprint(t.strings)\nprint(t.interpolations[0].value, t.interpolations[0].expression)",
        &["('Square: ', '')", "25 square(5)"],
    );
    assert_output(
        "class Person:\n    def __init__(self, name):\n        self.name = name\n    def label(self):\n        return self.name + '!'\nperson = Person('Alice')\nt = t'Name: {person.name}'\nmethod = t'Name: {person.label()}'\nprint(t.interpolations[0].value, t.interpolations[0].expression)\nprint(method.interpolations[0].value, method.interpolations[0].expression)",
        &["Alice person.name", "Alice! person.label()"],
    );
    assert_output(
        "data = {'name': 'Bob', 'age': 30}\nt = t\"Name: {data['name']}, Age: {data['age']}\"\nprint(t.strings)\nprint(t.interpolations[0].value, t.interpolations[0].expression)\nprint(t.interpolations[1].value, t.interpolations[1].expression)",
        &[
            "('Name: ', ', Age: ', '')",
            "Bob data['name']",
            "30 data['age']",
        ],
    );
    assert_output(
        "value = 3.14159\nt = t'Pi: {value:.2f}'\nprint(t.interpolations[0].value, t.interpolations[0].expression, t.interpolations[0].format_spec)",
        &["3.14159 value .2f"],
    );
    assert_output(
        "text = 'Cafe'\nprint(t'{text!s}'.interpolations[0].conversion, t'{text!r}'.interpolations[0].conversion, t'{text!a}'.interpolations[0].conversion)",
        &["s r a"],
    );
    assert_output(
        "value = 42\nt = t'Value: {value=}'\nprint(t.strings, t.interpolations[0].expression, t.interpolations[0].conversion)",
        &["('Value: value=', '') value r"],
    );
    assert_output(
        "value = 42\nt = t'Value: {value = }'\nprint(t.strings, t.interpolations[0].expression, t.interpolations[0].conversion)",
        &["('Value: value = ', '') value r"],
    );
    assert_output(
        "t = t'''{\n40 # forty\n+  # plus\n2 # two\n}'''\nprint(t.interpolations[0].value)",
        &["42"],
    );
    assert_output(
        "t = t'{1+2 = # my comment\n  }'\nprint(t.interpolations[0].value, t.interpolations[0].expression)",
        &["3 1+2"],
    );
    assert_output(
        "name = 'Python'\ninner = t'{name}'\nt = t'Language: {inner}'\nprint(t.strings)\nprint(t.interpolations[0].value.strings)\nprint(t.interpolations[0].value.interpolations[0].value, t.interpolations[0].value.interpolations[0].expression, t.interpolations[0].value.interpolations[0].conversion, t.interpolations[0].value.interpolations[0].format_spec == '')\nprint(t.interpolations[0].expression, t.interpolations[0].conversion, t.interpolations[0].format_spec == '')",
        &[
            "('Language: ', '')",
            "('', '')",
            "Python name None True",
            "inner None True",
        ],
    );
    assert_output(
        "name = 'Python'\nprint(t'Hello, ' t'{name}')\nprint(t'Hello, ' + t'world')",
        &[
            "Template(strings=('Hello, ', ''), interpolations=(Interpolation('Python', 'name', None, ''),))",
            "Template(strings=('Hello, world',), interpolations=())",
        ],
    );
}

// Adapted from CPython Lib/test/test_tstring.py::test_nested_templates and
// ::test_runtime_errors. Nested t-string values remain Template objects inside
