// Adapted from CPython Lib/test/test_tstring.py::test_raw_tstrings,
// ::test_template_concatenation, and ::test_triple_quoted. This extends the
// executable t-string slice beyond basic interpolation into raw literal
// preservation, Template + Template concatenation, invalid Template/string
// concatenation, and triple-quoted literal/interpolation segments.
#[test]
fn cpython_t_string_raw_concat_and_triple_subset() {
    assert_output(
        r#"path = r"C:\Users"
t = rt"{path}\Documents"
print(t.strings, t.interpolations[0].value, t.interpolations[0].expression)
t = tr"{path}\Documents"
print(t.strings, t.interpolations[0].value, t.interpolations[0].expression)"#,
        &[
            r#"('', '\\Documents') C:\Users path"#,
            r#"('', '\\Documents') C:\Users path"#,
        ],
    );
    assert_output(
        "name = 'Python'\nprint((t'Hello, ' + t'world').strings)\ncombined = t'Hello, ' + t'{name}'\nprint(combined.strings, combined.interpolations[0].value, combined.interpolations[0].expression)",
        &["('Hello, world',)", "('Hello, ', '') Python name"],
    );
    assert_error(
        "t1 = t'Hello'\nprint(t1 + ', world')",
        "runtime error: TypeError: can only concatenate string.templatelib.Template (not \"str\") to string.templatelib.Template",
    );
    assert_error(
        "name = 'Python'\nprint('Hello, ' + t'{name}')",
        "runtime error: TypeError: can only concatenate str (not \"string.templatelib.Template\") to str",
    );
    assert_output(
        "t = t'''\n        Hello,\n        world\n        '''\nprint(t.strings)\nname = 'Python'\nt = t'''\n        Hello,\n        {name}\n        '''\nprint(t.strings, t.interpolations[0].value, t.interpolations[0].expression)",
        &[
            "('\\n        Hello,\\n        world\\n        ',)",
            "('\\n        Hello,\\n        ', '\\n        ') Python name",
        ],
    );
}

// Adapted from CPython Lib/test/test_tstring.py and
// Lib/test/test_string/_support.py. CPython exposes Template and Interpolation
// through string.templatelib, and Template iteration yields strings and
// interpolation objects so user code can render t-strings with match patterns.
#[test]
fn cpython_t_string_templatelib_iteration_subset() {
    assert_output(
        concat!(
            "from string.templatelib import Template, Interpolation, convert\n",
            "def fstring(template):\n",
            "    parts = []\n",
            "    for item in template:\n",
            "        match item:\n",
            "            case str() as text:\n",
            "                parts.append(text)\n",
            "            case Interpolation(value, _, conversion, format_spec):\n",
            "                value = convert(value, conversion)\n",
            "                value = format(value, format_spec)\n",
            "                parts.append(value)\n",
            "    return ''.join(parts)\n",
            "name = 'Python'\n",
            "value = 3.14159\n",
            "template = t'Hello, {name}! Pi={value:.2f}'\n",
            "print(type(template).__name__, type(template.interpolations[0]).__name__)\n",
            "print(isinstance(template, Template), isinstance(template.interpolations[0], Interpolation))\n",
            "print(fstring(template))\n",
            "print([type(item).__name__ for item in t'A{name}B'])\n",
            "match template.interpolations[0]:\n",
            "    case Interpolation(value, expression, conversion, format_spec):\n",
            "        print(value, expression, conversion, format_spec == '')\n",
            "print(convert('Café', 'a'), convert('x', 'r'), convert('x', 's'), convert(3, None))\n",
            "try:\n",
            "    convert(1, 'z')\n",
            "except ValueError as error:\n",
            "    print(error)"
        ),
        &[
            "Template Interpolation",
            "True True",
            "Hello, Python! Pi=3.14",
            "['str', 'Interpolation', 'str']",
            "Python name None True",
            r#"'Caf\xe9' 'x' x 3"#,
            "invalid conversion specifier: z",
        ],
    );
}

// Adapted from CPython Lib/test/test_string/test_templatelib.py. This covers
// the user-callable Template and Interpolation constructors, Template.values,
// and the builtin type metadata CPython exposes for t-string runtime objects.
#[test]
fn cpython_templatelib_constructor_subset() {
    assert_output(
        concat!(
            "from string.templatelib import Template, Interpolation, convert\n",
            "def fstring(template):\n",
            "    parts = []\n",
            "    for item in template:\n",
            "        match item:\n",
            "            case str() as text:\n",
            "                parts.append(text)\n",
            "            case Interpolation(value, _, conversion, format_spec):\n",
            "                value = convert(value, conversion)\n",
            "                value = format(value, format_spec)\n",
            "                parts.append(value)\n",
            "    return ''.join(parts)\n",
            "print(type(t'').__name__, type(t'').__qualname__, type(t'').__module__)\n",
            "a = 'alpha'\n",
            "i = t'{a}'.interpolations[0]\n",
            "print(type(i).__name__, type(i).__qualname__, type(i).__module__)\n",
            "i = Interpolation('Maria', 'name', 'a', 'fmt')\n",
            "print(i.value, i.expression, i.conversion, i.format_spec)\n",
            "print(Interpolation('Maria', 'name', 'a').format_spec == '')\n",
            "print(Interpolation('Maria', 'name').conversion, Interpolation('Maria').expression == '')\n",
            "t = Template()\n",
            "print(t.strings, t.interpolations, t.values, fstring(t))\n",
            "t = Template(Interpolation('Maria', 'name', None, ''))\n",
            "print(t.strings, t.values, fstring(t))\n",
            "t = Template(Interpolation('Maria', 'name', None, ''), ' is my name')\n",
            "print(t.strings, t.values, fstring(t))\n",
            "t = Template('Hello', ', ', Interpolation('Maria', 'name', None, ''), '!')\n",
            "print(t.strings, t.values, fstring(t))\n",
            "t = Template(Interpolation('Maria', 'name', None, ''), Interpolation('Python', 'language', None, ''))\n",
            "print(t.strings, t.values, fstring(t))\n",
            "print(t'Hello, {a}'.values)\n",
            "try:\n",
            "    Template(3)\n",
            "except TypeError as error:\n",
            "    print(error)\n",
            "try:\n",
            "    Interpolation('x', 'expr', 'z')\n",
            "except ValueError as error:\n",
            "    print(error)\n",
            "try:\n",
            "    Interpolation('x', 'expr', 1)\n",
            "except TypeError as error:\n",
            "    print(error)\n",
            "try:\n",
            "    convert(1, 1)\n",
            "except ValueError as error:\n",
            "    print(error)"
        ),
        &[
            "Template Template string.templatelib",
            "Interpolation Interpolation string.templatelib",
            "Maria name a fmt",
            "True",
            "None True",
            "('',) () () ",
            "('', '') ('Maria',) Maria",
            "('', ' is my name') ('Maria',) Maria is my name",
            "('Hello, ', '!') ('Maria',) Hello, Maria!",
            "('', '', '') ('Maria', 'Python') MariaPython",
            "('alpha',)",
            "Template.__new__ *args need to be of type 'str' or 'Interpolation', got int",
            "Interpolation() argument 'conversion' must be one of 's', 'a' or 'r'",
            "Interpolation() argument 'conversion' must be str, not int",
            "invalid conversion specifier: 1",
        ],
    );
}

// Adapted from CPython Lib/test/test_string/test_templatelib.py. This covers
// the final built-in templatelib types plus the TemplateIter object returned by
// iter(t'...'), without pulling in collections.abc or pickle yet.
#[test]
fn cpython_templatelib_final_type_and_iterator_subset() {
    assert_output(
        concat!(
            "from string.templatelib import Template, Interpolation\n",
            "for base in [Template, Interpolation, type(iter(t''))]:\n",
            "    try:\n",
            "        class Sub(base):\n",
            "            pass\n",
            "    except TypeError as error:\n",
            "        print(base.__name__, error.__class__.__name__, 'acceptable base type' in str(error))\n",
            "x = 1\n",
            "it = iter(t'abc {x} yz')\n",
            "print(type(it).__name__, type(it).__qualname__, type(it).__module__, iter(it) is it)\n",
            "print(next(it))\n",
            "item = next(it)\n",
            "print(type(item).__name__, item.value, item.expression, item.conversion, item.format_spec == '')\n",
            "print(next(it))\n",
            "template_iter = iter(t'{1}')\n",
            "print(type(next(template_iter)).__name__)\n",
            "for _ in [0, 1]:\n",
            "    try:\n",
            "        next(template_iter)\n",
            "    except StopIteration as error:\n",
            "        print(error.__class__.__name__)"
        ),
        &[
            "Template TypeError True",
            "Interpolation TypeError True",
            "TemplateIter TypeError True",
            "TemplateIter TemplateIter string.templatelib True",
            "abc ",
            "Interpolation 1 x None True",
            " yz",
            "Interpolation",
            "StopIteration",
            "StopIteration",
        ],
    );
}

// Adapted from CPython Lib/test/test_string/test_templatelib.py::TemplateIterTests::test_abc
// and Lib/test/test_collections.py Iterable/Iterator ABC checks. MiniPython
// keeps a compact observable slice around the built-in iterables/iterators and
// the structural user-class checks that do not require the full abc module.
#[test]
fn cpython_collections_abc_iterable_iterator_subset() {
    assert_output(
        concat!(
            "from collections.abc import Iterable, Iterator\n",
            "print(isinstance(iter(t''), Iterable), isinstance(iter(t''), Iterator))\n",
            "iterable_samples = [b'', '', (), [], {}, set(), range(0), t'abc']\n",
            "print([isinstance(value, Iterable) for value in iterable_samples])\n",
            "print([isinstance(value, Iterator) for value in iterable_samples])\n",
            "iterator_samples = [iter(b''), iter(''), iter(()), iter([]), iter({}), iter(set()), iter(range(0)), iter(t'{1}')]\n",
            "print([isinstance(value, Iterator) for value in iterator_samples])\n",
            "print([isinstance(value, Iterable) for value in iterator_samples])\n",
            "non_samples = [None, 42, 3.14, 1j]\n",
            "print([isinstance(value, Iterable) for value in non_samples])\n",
            "class CustomIterable:\n",
            "    def __iter__(self):\n",
            "        return iter([])\n",
            "class NextOnly:\n",
            "    def __next__(self):\n",
            "        return 1\n",
            "class CustomIterator:\n",
            "    def __iter__(self):\n",
            "        return self\n",
            "    def __next__(self):\n",
            "        raise StopIteration\n",
            "print(isinstance(CustomIterable(), Iterable), isinstance(CustomIterable(), Iterator))\n",
            "print(isinstance(NextOnly(), Iterable), isinstance(NextOnly(), Iterator))\n",
            "print(isinstance(CustomIterator(), Iterable), isinstance(CustomIterator(), Iterator))\n",
            "print(issubclass(CustomIterable, Iterable), issubclass(CustomIterable, Iterator))\n",
            "print(issubclass(NextOnly, Iterable), issubclass(NextOnly, Iterator))\n",
            "print(issubclass(CustomIterator, Iterable), issubclass(CustomIterator, Iterator))\n",
            "class I(Iterable):\n",
            "    pass\n",
            "class It(Iterator):\n",
            "    pass\n",
            "print(issubclass(I, Iterable), issubclass(I, Iterator))\n",
            "print(issubclass(It, Iterable), issubclass(It, Iterator))\n",
            "print(issubclass(Iterator, Iterable), issubclass(Iterable, Iterator))"
        ),
        &[
            "True True",
            "[True, True, True, True, True, True, True, True]",
            "[False, False, False, False, False, False, False, False]",
            "[True, True, True, True, True, True, True, True]",
            "[True, True, True, True, True, True, True, True]",
            "[False, False, False, False]",
            "True False",
            "False False",
            "True True",
            "True False",
            "False False",
            "True True",
            "True False",
            "True True",
            "True False",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py::
// TestOneTrickPonyABCs::test_Iterable. This ports the public Iterable ABC
// non-sample/sample matrix, direct-subclass mixin, and None-blocking behavior.
#[test]
fn cpython_collections_abc_iterable_sample_matrix_subset() {
    assert_output(
        concat!(
            "from collections.abc import Iterable\n",
            "def _test_gen():\n",
            "    yield 1\n",
            "non_samples = [None, 42, 3.14, 1j]\n",
            "print([isinstance(x, Iterable) for x in non_samples])\n",
            "print([issubclass(type(x), Iterable) for x in non_samples])\n",
            "samples = [bytes(), str(), tuple(), list(), set(), frozenset(), dict(), dict().keys(), dict().items(), dict().values(), _test_gen(), (x for x in [])]\n",
            "print([isinstance(x, Iterable) for x in samples])\n",
            "print([issubclass(type(x), Iterable) for x in samples])\n",
            "class I(Iterable):\n",
            "    def __iter__(self):\n",
            "        return super().__iter__()\n",
            "print(list(I()))\n",
            "print(issubclass(str, I))\n",
            "class It:\n",
            "    def __iter__(self): return iter([])\n",
            "class ItBlocked(It):\n",
            "    __iter__ = None\n",
            "print(issubclass(It, Iterable), isinstance(It(), Iterable))\n",
            "print(issubclass(ItBlocked, Iterable), isinstance(ItBlocked(), Iterable))"
        ),
        &[
            "[False, False, False, False]",
            "[False, False, False, False]",
            "[True, True, True, True, True, True, True, True, True, True, True, True]",
            "[True, True, True, True, True, True, True, True, True, True, True, True]",
            "[]",
            "False",
            "True True",
            "False False",
        ],
    );
}

