// Adapted from CPython Lib/test/test_collections.py Mapping and MutableMapping
// mixin checks. This covers the concrete methods provided to explicit ABC
// subclasses while keeping full UserDict and custom view objects for later
// collections-module work.
#[test]
fn cpython_collections_abc_mapping_mixins_subset() {
    assert_output(
        concat!(
            "from collections.abc import Mapping, MutableMapping\n",
            "class MappingSubclass(Mapping):\n",
            "    def __init__(self, pairs=()):\n",
            "        self.store = dict(pairs)\n",
            "    def __getitem__(self, key):\n",
            "        return self.store[key]\n",
            "    def __iter__(self):\n",
            "        return iter(self.store)\n",
            "    def __len__(self):\n",
            "        return len(self.store)\n",
            "m = MappingSubclass([('red', 5), ('blue', 7)])\n",
            "print(isinstance(m, Mapping), isinstance(m, MutableMapping))\n",
            "print(m.get('red'), m.get('missing'), m.get('missing', 99))\n",
            "print(m.__contains__('red'), m.__contains__('missing'))\n",
            "print(list(m.keys()), sorted(m.values()), sorted(m.items()))\n",
            "print(m.__eq__({'blue': 7, 'red': 5}), m.__eq__({'red': 5}), m.__eq__([('red', 5)]))\n",
            "try:\n",
            "    reversed(m)\n",
            "except TypeError as error:\n",
            "    print(error.__class__.__name__)\n",
            "class MutableMappingSubclass(MutableMapping):\n",
            "    def __init__(self, pairs=()):\n",
            "        self.store = dict(pairs)\n",
            "    def __getitem__(self, key):\n",
            "        return self.store[key]\n",
            "    def __setitem__(self, key, value):\n",
            "        self.store[key] = value\n",
            "    def __delitem__(self, key):\n",
            "        del self.store[key]\n",
            "    def __iter__(self):\n",
            "        return iter(self.store)\n",
            "    def __len__(self):\n",
            "        return len(self.store)\n",
            "mm = MutableMappingSubclass()\n",
            "mm.update({'a': 1}, b=2)\n",
            "print(sorted(mm.items()))\n",
            "print(mm.setdefault('a', 9), mm.setdefault('c', 3), sorted(mm.items()))\n",
            "print(mm.pop('b'), mm.pop('missing', 'fallback'), sorted(mm.items()))\n",
            "try:\n",
            "    mm.pop('missing')\n",
            "except KeyError as error:\n",
            "    print(error.__class__.__name__)\n",
            "mm.update([('d', 4), ('e', 5)])\n",
            "print(mm.popitem(), sorted(mm.items()))\n",
            "mm.clear()\n",
            "print(len(mm), list(mm.items()))"
        ),
        &[
            "True False",
            "5 None 99",
            "True False",
            "['red', 'blue'] [5, 7] [('blue', 7), ('red', 5)]",
            "True False NotImplemented",
            "TypeError",
            "[('a', 1), ('b', 2)]",
            "1 3 [('a', 1), ('b', 2), ('c', 3)]",
            "2 fallback [('a', 1), ('c', 3)]",
            "KeyError",
            "('a', 1) [('c', 3), ('d', 4), ('e', 5)]",
            "0 []",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py Mapping and MutableMapping
// view checks. Explicit Mapping subclasses should receive live view objects
// from the Mapping.keys/items/values mixins instead of eager lists.
#[test]
fn cpython_collections_abc_mapping_mixin_views_subset() {
    assert_output(
        concat!(
            "from collections.abc import MutableMapping, MappingView, KeysView, ItemsView, ValuesView, Set, Collection\n",
            "class MutableMappingSubclass(MutableMapping):\n",
            "    def __init__(self, pairs=()):\n",
            "        self.store = dict(pairs)\n",
            "    def __getitem__(self, key):\n",
            "        return self.store[key]\n",
            "    def __setitem__(self, key, value):\n",
            "        self.store[key] = value\n",
            "    def __delitem__(self, key):\n",
            "        del self.store[key]\n",
            "    def __iter__(self):\n",
            "        return iter(self.store)\n",
            "    def __len__(self):\n",
            "        return len(self.store)\n",
            "mymap = MutableMappingSubclass([('red', 5)])\n",
            "keys = mymap.keys()\n",
            "items = mymap.items()\n",
            "values = mymap.values()\n",
            "print(isinstance(keys, MappingView), isinstance(keys, KeysView), isinstance(keys, Set))\n",
            "print(isinstance(items, MappingView), isinstance(items, ItemsView), isinstance(items, Set))\n",
            "print(isinstance(values, MappingView), isinstance(values, ValuesView), isinstance(values, Collection), isinstance(values, Set))\n",
            "print(list(keys), list(values), list(items))\n",
            "print('red' in keys, 5 in values, ('red', 5) in items, ('red', 9) in items)\n",
            "print(sorted(keys - {'orange'}), sorted(keys ^ {'red', 'blue'}), sorted(items & {('red', 5), ('blue', 7)}), keys <= {'red', 'orange'}, keys < {'red'})\n",
            "snapshot_keys = keys | {'orange'}\n",
            "snapshot_items = items | {('orange', 3)}\n",
            "mymap['blue'] = 7\n",
            "print(isinstance(snapshot_keys, set), sorted(snapshot_keys), sorted(keys), sorted(values), sorted(items))\n",
            "mymap['green'] = 9\n",
            "print(sorted(snapshot_items), sorted(items))"
        ),
        &[
            "True True True",
            "True True True",
            "True True True False",
            "['red'] [5] [('red', 5)]",
            "True True True False",
            "['red'] ['blue'] [('red', 5)] True False",
            "True ['orange', 'red'] ['blue', 'red'] [5, 7] [('blue', 7), ('red', 5)]",
            "[('orange', 3), ('red', 5)] [('blue', 7), ('green', 9), ('red', 5)]",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py::
// TestCollectionABCs::test_MutableMapping_subclass. UserDict view objects should
// satisfy the same ABC relationships as mapping views, and view set operations
// should return eager set snapshots that are not affected by later mutations.
#[test]
fn cpython_collections_abc_userdict_view_snapshot_subset() {
    assert_output(
        concat!(
            "from collections import UserDict\n",
            "from collections.abc import Collection, ItemsView, KeysView, Set, ValuesView\n",
            "mymap = UserDict()\n",
            "mymap['red'] = 5\n",
            "keys = mymap.keys()\n",
            "values = mymap.values()\n",
            "items = mymap.items()\n",
            "print(isinstance(keys, Set), isinstance(keys, KeysView))\n",
            "print(isinstance(values, Collection), isinstance(values, ValuesView))\n",
            "print(isinstance(items, Set), isinstance(items, ItemsView))\n",
            "z = mymap.keys() | {'orange'}\n",
            "print(isinstance(z, set), sorted(z))\n",
            "mymap['blue'] = 7\n",
            "print(sorted(z))\n",
            "mymap = UserDict()\n",
            "mymap['red'] = 5\n",
            "z = mymap.items() | {('orange', 3)}\n",
            "print(isinstance(z, set), sorted(z))\n",
            "mymap['blue'] = 7\n",
            "print(sorted(z))"
        ),
        &[
            "True True",
            "True True",
            "True True",
            "True ['orange', 'red']",
            "['orange', 'red']",
            "True [('orange', 3), ('red', 5)]",
            "[('orange', 3), ('red', 5)]",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py::
// TestCollectionABCs::test_issue26915. Container membership and Sequence
// mixins check object identity before equality, including for an always-false
// equality object and NaN floats whose direct equality remains false.
#[test]
fn cpython_collections_abc_issue26915_identity_first_object_subset() {
    assert_output(
        concat!(
            "from collections.abc import ItemsView, KeysView, Sequence, ValuesView\n",
            "class NeverEqual:\n",
            "    def __eq__(self, other):\n",
            "        return False\n",
            "class CustomSequence(Sequence):\n",
            "    def __init__(self, seq):\n",
            "        self._seq = seq\n",
            "    def __getitem__(self, index):\n",
            "        return self._seq[index]\n",
            "    def __len__(self):\n",
            "        return len(self._seq)\n",
            "nan = float('nan')\n",
            "other_nan = float('nan')\n",
            "obj = NeverEqual()\n",
            "seq = CustomSequence([nan, obj, nan])\n",
            "containers = [seq, ItemsView({1: nan, 2: obj}), KeysView({1: nan, 2: obj}), ValuesView({1: nan, 2: obj})]\n",
            "print(nan == nan, nan is nan, nan is other_nan)\n",
            "for container in containers:\n",
            "    row = []\n",
            "    for elem in container:\n",
            "        try:\n",
            "            row.append(elem in container)\n",
            "        except Exception as error:\n",
            "            row.append(error.__class__.__name__)\n",
            "    print(row)\n",
            "print(seq.index(nan))\n",
            "print(seq.index(obj))\n",
            "print(seq.count(nan))\n",
            "print(seq.count(obj))\n",
            "print((1, nan) in ItemsView({1: nan}))\n",
            "print((1, other_nan) in ItemsView({1: nan}))\n",
            "print(nan in ValuesView({1: nan}))\n",
            "print(other_nan in ValuesView({1: nan}))"
        ),
        &[
            "False True False",
            "[True, True, True]",
            "[True, True]",
            "[True, True]",
            "[True, True]",
            "0",
            "1",
            "2",
            "1",
            "True",
            "False",
            "True",
            "False",
        ],
    );
}

// Adapted from CPython Lib/test/test_dict.py::test_keys_contained and
// ::test_errors_in_view_containment_check. Dict key/item views use set-style
// rich comparisons, and item-view equality must propagate element comparison
// errors from Python-level __eq__ methods.
#[test]
fn cpython_dict_view_richcompare_subset() {
    assert_output_with_stack(
        concat!(
            "def compare_views(fn):\n",
            "    empty = fn(dict())\n",
            "    empty2 = fn(dict())\n",
            "    smaller = fn({1: 1, 2: 2})\n",
            "    larger = fn({1: 1, 2: 2, 3: 3})\n",
            "    larger2 = fn({1: 1, 2: 2, 3: 3})\n",
            "    larger3 = fn({4: 1, 2: 2, 3: 3})\n",
            "    print(smaller < larger, smaller <= larger, larger > smaller, larger >= smaller)\n",
            "    print(smaller >= larger, smaller > larger, larger <= smaller, larger < smaller)\n",
            "    print(smaller < larger3, smaller <= larger3, larger3 > smaller, larger3 >= smaller)\n",
            "    print(larger2 >= larger, larger2 <= larger, larger2 > larger, larger2 < larger)\n",
            "    print(larger == larger2, smaller != larger, empty == empty2, empty != empty2, empty == smaller, empty != smaller)\n",
            "    print(larger != larger3, larger == larger3)\n",
            "compare_views(lambda d: d.keys())\n",
            "compare_views(lambda d: d.items())\n",
            "class C:\n",
            "    def __eq__(self, other):\n",
            "        raise RuntimeError('boom')\n",
            "def result(fn):\n",
            "    try:\n",
            "        fn()\n",
            "    except RuntimeError as error:\n",
            "        print(error.__class__.__name__)\n",
            "d1 = {1: C()}\n",
            "d2 = {1: C()}\n",
            "result(lambda: d1.items() == d2.items())\n",
            "result(lambda: d1.items() != d2.items())\n",
            "result(lambda: d1.items() <= d2.items())\n",
            "result(lambda: d1.items() >= d2.items())\n",
            "d3 = {1: C(), 2: C()}\n",
            "result(lambda: d2.items() < d3.items())\n",
            "result(lambda: d3.items() > d2.items())"
        ),
        &[
            "True True True True",
            "False False False False",
            "False False False False",
            "True True False False",
            "True True True False False True",
            "True False",
            "True True True True",
            "False False False False",
            "False False False False",
            "True True False False",
            "True True True False False True",
            "True False",
            "RuntimeError",
            "RuntimeError",
            "RuntimeError",
            "RuntimeError",
            "RuntimeError",
            "RuntimeError",
        ],
        64 * 1024 * 1024,
    );
}

