// Adapted from CPython Lib/test/test_types.py::MappingProxyTests::test_missing.
// This covers a dict subclass used through MappingProxyType: `__getitem__`
// delegates missing keys to `__missing__`, while `get` and membership do not.
#[test]
fn cpython_types_mappingproxy_missing_subset() {
    assert_output(
        concat!(
            "from types import MappingProxyType\n",
            "class dictmissing(dict):\n",
            "    def __missing__(self, key):\n",
            "        return 'missing=%s' % key\n",
            "view = MappingProxyType(dictmissing(x=1))\n",
            "print(view['x'], view['y'])\n",
            "print(view.get('x'), view.get('y'), view.get('y', 42))\n",
            "print('x' in view, 'y' in view)"
        ),
        &["1 missing=y", "1 None 42", "True False"],
    );
}

