// Adapted from CPython Lib/test/test_collections.py::TestUserObjects
// test_dict_protocol and test_dict_copy. UserList and UserString behavior
// are covered by adjacent collections slices.
#[test]
fn cpython_collections_userdict_public_methods_subset() {
    assert_output(
        concat!(
            "from collections import UserDict\n",
            "from copy import copy\n",
            "print(set(dir(UserDict)) >= set(dir(dict)))\n",
            "obj = UserDict()\n",
            "obj[123] = 'abc'\n",
            "print(obj[123], list(obj), len(obj), 123 in obj, obj.get(999))\n",
            "print(repr(obj), str(obj), format(obj, ''))\n",
            "print(obj.__repr__(), obj.__str__(), obj.__format__(''))\n",
            "print(UserDict.__repr__(obj), UserDict.__str__(obj), UserDict.__format__(obj, ''))\n",
            "try:\n",
            "    obj.__format__('x')\n",
            "except TypeError as error:\n",
            "    print(error.__class__.__name__)\n",
            "recursive = UserDict()\n",
            "recursive['self'] = recursive\n",
            "print(repr(recursive), recursive.__repr__())\n",
            "internal = obj.copy()\n",
            "print(internal.data is obj.data, internal.data == obj.data, type(internal).__name__)\n",
            "obj.test = [1234]\n",
            "external = copy(obj)\n",
            "print(external.data is obj.data, external.data == obj.data, external.test is obj.test)\n",
            "del obj[123]\n",
            "print(list(obj), len(obj))\n",
            "class_obj = UserDict({'a': 1, 'b': 2})\n",
            "print(UserDict.__getitem__(class_obj, 'a'))\n",
            "print(UserDict.get(class_obj, 'missing', 9))\n",
            "print(list(UserDict.keys(class_obj)))\n",
            "print(list(UserDict.items(class_obj)))\n",
            "print(list(UserDict.values(class_obj)))\n",
            "print(UserDict.__contains__(class_obj, 'a'), UserDict.__len__(class_obj), list(UserDict.__iter__(class_obj)))\n",
            "print(UserDict.__setitem__(class_obj, 'c', 3), class_obj)\n",
            "print(UserDict.pop(class_obj, 'b'), class_obj)\n",
            "print(UserDict.setdefault(class_obj, 'd', 4), class_obj)\n",
            "print(UserDict.update(class_obj, {'e': 5}), class_obj)\n",
            "print(UserDict.__delitem__(class_obj, 'c'), class_obj)\n",
            "def show_missing(label, action):\n",
            "    try:\n",
            "        action()\n",
            "    except KeyError as error:\n",
            "        print(label, error.args[0] == 'missing', type(error.args[0]).__name__, str(error))\n",
            "def delete_missing_userdict():\n",
            "    del class_obj['missing']\n",
            "show_missing('delitem-missing', lambda: UserDict.__delitem__(class_obj, 'missing'))\n",
            "show_missing('del-syntax-missing', delete_missing_userdict)\n",
            "class UDSub(UserDict):\n",
            "    pass\n",
            "sub_obj = UDSub({'a': 1})\n",
            "def delete_missing_userdict_subclass():\n",
            "    del sub_obj['missing']\n",
            "show_missing('subclass-delitem-missing', lambda: UserDict.__delitem__(sub_obj, 'missing'))\n",
            "show_missing('subclass-del-syntax-missing', delete_missing_userdict_subclass)\n",
            "popitem_obj = UserDict({'z': 9})\n",
            "print('popitem-direct', UserDict.popitem(popitem_obj), popitem_obj)\n",
            "sub_popitem_obj = UDSub({'z': 9})\n",
            "print('subclass-popitem', sub_popitem_obj.popitem(), list(sub_popitem_obj.items()))\n",
            "def show_empty_popitem(label, action):\n",
            "    try:\n",
            "        action()\n",
            "    except KeyError as error:\n",
            "        print(label, len(error.args), str(error) == '')\n",
            "show_empty_popitem('popitem-empty', lambda: UserDict().popitem())\n",
            "show_empty_popitem('popitem-direct-empty', lambda: UserDict.popitem(UserDict()))\n",
            "show_empty_popitem('subclass-popitem-empty', lambda: UDSub().popitem())\n",
            "show_empty_popitem('subclass-direct-popitem-empty', lambda: UserDict.popitem(UDSub()))\n",
            "class_copy = UserDict.copy(class_obj)\n",
            "print(class_copy, type(class_copy).__name__, class_copy.data is class_obj.data)\n",
            "print(UserDict.clear(class_obj), class_obj)"
        ),
        &[
            "True",
            "abc [123] 1 True None",
            "{123: 'abc'} {123: 'abc'} {123: 'abc'}",
            "{123: 'abc'} {123: 'abc'} {123: 'abc'}",
            "{123: 'abc'} {123: 'abc'} {123: 'abc'}",
            "TypeError",
            "{'self': {...}} {'self': {...}}",
            "False True UserDict",
            "False True True",
            "[] 0",
            "1",
            "9",
            "['a', 'b']",
            "[('a', 1), ('b', 2)]",
            "[1, 2]",
            "True 2 ['a', 'b']",
            "None {'a': 1, 'b': 2, 'c': 3}",
            "2 {'a': 1, 'c': 3}",
            "4 {'a': 1, 'c': 3, 'd': 4}",
            "None {'a': 1, 'c': 3, 'd': 4, 'e': 5}",
            "None {'a': 1, 'd': 4, 'e': 5}",
            "delitem-missing True str 'missing'",
            "del-syntax-missing True str 'missing'",
            "subclass-delitem-missing True str 'missing'",
            "subclass-del-syntax-missing True str 'missing'",
            "popitem-direct ('z', 9) {}",
            "subclass-popitem ('z', 9) []",
            "popitem-empty 0 True",
            "popitem-direct-empty 0 True",
            "subclass-popitem-empty 0 True",
            "subclass-direct-popitem-empty 0 True",
            "{'a': 1, 'd': 4, 'e': 5} UserDict False",
            "None {}",
        ],
    );
}

