// Adapted from CPython Lib/test/test_collections.py::TestChainMap. This keeps
// the broad public ChainMap behavior together; copy/pickle/eval identity
// matrices are covered by the adjacent focused test.
#[test]
fn cpython_collections_chainmap_public_methods_subset() {
    assert_output(
        concat!(
            "from collections import ChainMap\n",
            "import copy\n",
            "print(ChainMap().maps)\n",
            "print(ChainMap({1: 2}).maps)\n",
            "print(bool(ChainMap()), bool(ChainMap({}, {})), bool(ChainMap({1: 2}, {})), bool(ChainMap({}, {1: 2})))\n",
            "c = ChainMap()\n",
            "c['a'] = 1\n",
            "c['b'] = 2\n",
            "m = {'b': 20, 'c': 30}\n",
            "d = c.new_child(m)\n",
            "print(d.maps, d.maps[0] is m)\n",
            "print(list(d.items()), list(d), len(d), dict(d))\n",
            "print('a' in d, 'b' in d, 'c' in d, 'z' in d)\n",
            "print(d['b'], d.parents['b'], d.get('z', 100))\n",
            "del d['b']\n",
            "print(d.maps, d['b'])\n",
            "e = c.new_child(b=20, c=30)\n",
            "print(e.maps)\n",
            "f = e.copy()\n",
            "print(f == e, f.maps == e.maps, f.maps[0] is e.maps[0], f.maps[1] is e.maps[1])\n",
            "g = copy.copy(e)\n",
            "print(g == e, g.maps[0] is e.maps[0], g.maps[1] is e.maps[1])\n",
            "baseline = {'music': 'bach', 'art': 'rembrandt'}\n",
            "adjustments = {'art': 'van gogh', 'opera': 'carmen'}\n",
            "cm = ChainMap(adjustments, baseline)\n",
            "print(cm.__repr__(), cm.__str__(), cm.__format__(''))\n",
            "print(ChainMap.__repr__(cm), ChainMap.__str__(cm), ChainMap.__format__(cm, ''))\n",
            "try:\n",
            "    cm.__format__('x')\n",
            "except TypeError as error:\n",
            "    print(error.__class__.__name__)\n",
            "combined = baseline.copy()\n",
            "combined.update(adjustments)\n",
            "print(list(combined.items()), list(cm.items()))\n",
            "print(dict(cm), dict(cm.items()))"
        ),
        &[
            "[{}]",
            "[{1: 2}]",
            "False False True True",
            "[{'b': 20, 'c': 30}, {'a': 1, 'b': 2}] True",
            "[('a', 1), ('b', 20), ('c', 30)] ['a', 'b', 'c'] 3 {'a': 1, 'b': 20, 'c': 30}",
            "True True True False",
            "20 2 100",
            "[{'c': 30}, {'a': 1, 'b': 2}] 2",
            "[{'b': 20, 'c': 30}, {'a': 1, 'b': 2}]",
            "True True False True",
            "True False True",
            "ChainMap({'art': 'van gogh', 'opera': 'carmen'}, {'music': 'bach', 'art': 'rembrandt'}) ChainMap({'art': 'van gogh', 'opera': 'carmen'}, {'music': 'bach', 'art': 'rembrandt'}) ChainMap({'art': 'van gogh', 'opera': 'carmen'}, {'music': 'bach', 'art': 'rembrandt'})",
            "ChainMap({'art': 'van gogh', 'opera': 'carmen'}, {'music': 'bach', 'art': 'rembrandt'}) ChainMap({'art': 'van gogh', 'opera': 'carmen'}, {'music': 'bach', 'art': 'rembrandt'}) ChainMap({'art': 'van gogh', 'opera': 'carmen'}, {'music': 'bach', 'art': 'rembrandt'})",
            "TypeError",
            "[('music', 'bach'), ('art', 'van gogh'), ('opera', 'carmen')] [('music', 'bach'), ('art', 'van gogh'), ('opera', 'carmen')]",
            "{'music': 'bach', 'art': 'van gogh', 'opera': 'carmen'} {'music': 'bach', 'art': 'van gogh', 'opera': 'carmen'}",
        ],
    );
}

// Mirrors CPython's public `ChainMap` instance `__doc__` type-attribute
// lookup while leaving full writable instance dictionaries outside this slice.
#[test]
fn cpython_collections_chainmap_instance_doc_attribute_subset() {
    assert_output(
        r#"from collections import ChainMap
for label, value in [('empty', ChainMap()), ('single', ChainMap({'a': 1})), ('multi', ChainMap({'a': 1}, {'b': 2}))]:
    doc = value.__doc__
    print(label, type(doc).__name__, doc == ChainMap.__doc__, '__doc__' in dir(value), doc.split('\n')[0], len(doc))"#,
        &[
            "empty str True True A ChainMap groups multiple dicts (or other mappings) together 407",
            "single str True True A ChainMap groups multiple dicts (or other mappings) together 407",
            "multi str True True A ChainMap groups multiple dicts (or other mappings) together 407",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py::TestChainMap constructor
// keyword rejection.
#[test]
fn cpython_collections_chainmap_keyword_error_subset() {
    assert_output(
        concat!(
            "from collections import ChainMap\n",
            "for label, callback in [\n",
            "    ('mapping', lambda: ChainMap(mapping={'a': 1})),\n",
            "    ('first-keyword', lambda: ChainMap(a={'a': 1}, b={'b': 2})),\n",
            "    ('pos-keyword', lambda: ChainMap({'a': 1}, mapping={'b': 2})),\n",
            "]:\n",
            "    try:\n",
            "        callback()\n",
            "    except TypeError as error:\n",
            "        print(label, type(error).__name__, str(error))"
        ),
        &[
            "mapping TypeError ChainMap.__init__() got an unexpected keyword argument 'mapping'",
            "first-keyword TypeError ChainMap.__init__() got an unexpected keyword argument 'a'",
            "pos-keyword TypeError ChainMap.__init__() got an unexpected keyword argument 'mapping'",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py::TestChainMap constructor
// storage behavior: maps are not validated until mapping operations need them.
#[test]
fn cpython_collections_chainmap_constructor_lazy_mapping_subset() {
    assert_output(
        concat!(
            "from collections import ChainMap\n",
            "for label, source in [('int', 1), ('list', []), ('none', None), ('tuple', (1, 2))]:\n",
            "    chain = ChainMap(source)\n",
            "    print(label, type(chain).__name__, repr(chain.maps))"
        ),
        &[
            "int ChainMap [1]",
            "list ChainMap [[]]",
            "none ChainMap [None]",
            "tuple ChainMap [(1, 2)]",
        ],
    );
}

