// Adapted from CPython Lib/test/test_collections.py defaultdict copying
// behavior. This keeps the slice to copy.copy() shallow-copy semantics, not
// deepcopy, pickle, merge operators, or defaultdict subclassing.
#[test]
fn cpython_collections_defaultdict_copy_module_subset() {
    assert_output(
        r#"from collections import defaultdict
from copy import copy

def show(label, thunk):
    try:
        value = thunk()
        print(label, type(value).__name__, repr(value))
    except Exception as error:
        print(label, type(error).__name__, str(error), getattr(error, 'args', None))

shared = []
d = defaultdict(list, {'a': shared})
c = copy(d)
print('copy-list', type(c).__name__, repr(c), c is d, c.default_factory is d.default_factory, c['a'] is d['a'])
c['a'].append(1)
c['b'].append(2)
print('after-copy-mutate', d['a'], c['a'], 'b' in d, sorted(c.items()))
d.default_factory = int
e = copy(d)
print('copy-int-before', type(e).__name__, repr(e), e is d, e.default_factory is int, 'n' in d, 'n' in e)
print('copy-int-missing', e['n'], 'n' in d, 'n' in e, sorted(e.items()))
d.default_factory = None
f = copy(d)
print('copy-none', type(f).__name__, repr(f), f.default_factory, f is d)
show('copy-none-missing', lambda: f['missing'])
print('original-factory', d.default_factory)"#,
        &[
            "copy-list defaultdict defaultdict(<class 'list'>, {'a': []}) False True True",
            "after-copy-mutate [1] [1] False [('a', [1]), ('b', [2])]",
            "copy-int-before defaultdict defaultdict(<class 'int'>, {'a': [1]}) False True False False",
            "copy-int-missing 0 False True [('a', [1]), ('n', 0)]",
            "copy-none defaultdict defaultdict(None, {'a': [1]}) None False",
            "copy-none-missing KeyError 'missing' ('missing',)",
            "original-factory None",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py defaultdict copying
// behavior. This pins the supported direct __copy__ public hook without
// expanding into descriptor type identity, deepcopy, pickle, or subclassing.
#[test]
fn cpython_collections_defaultdict_dunder_copy_subset() {
    assert_output(
        r#"from collections import defaultdict

def show(label, thunk):
    try:
        value = thunk()
        print(label, type(value).__name__, repr(value))
    except Exception as error:
        print(label, type(error).__name__, str(error), getattr(error, 'args', None))

shared = []
d = defaultdict(list, {'a': shared})
print('visible', '__copy__' in dir(defaultdict), '__copy__' in dir(d))
c = d.__copy__()
print('inst-copy', type(c).__name__, repr(c), c is d, c.default_factory is list, c['a'] is d['a'])
t = defaultdict.__copy__(d)
print('type-copy', type(t).__name__, repr(t), t is d, t.default_factory is list, t['a'] is d['a'])
c['b'].append(2)
print('mutated', 'b' in d, sorted(c.items()))
d.default_factory = None
n = d.__copy__()
print('none-copy', repr(n), n.default_factory)
show('none-missing', lambda: n['x'])"#,
        &[
            "visible True True",
            "inst-copy defaultdict defaultdict(<class 'list'>, {'a': []}) False True True",
            "type-copy defaultdict defaultdict(<class 'list'>, {'a': []}) False True True",
            "mutated False [('a', []), ('b', [2])]",
            "none-copy defaultdict(None, {'a': []}) None",
            "none-missing KeyError 'x' ('x',)",
        ],
    );
}

