// Adapted from CPython Lib/test/test_types.py::SimpleNamespaceTests. This
// first slice covers construction from mappings, pair iterables, and keywords;
// live `__dict__` access; attribute get/set/delete; repr/equality; unsupported
// mapping operations; and subclass construction through the inherited builtin
// initializer.
#[test]
fn cpython_types_simple_namespace_basic_subset() {
    assert_output(
        concat!(
            "import types\n",
            "from collections import UserDict\n",
            "def show(ns):\n",
            "    print(sorted(vars(ns).items()))\n",
            "empty = types.SimpleNamespace()\n",
            "ns = types.SimpleNamespace({'x': 1, 'y': 2}, x=4, z=3)\n",
            "show(empty)\n",
            "show(ns)\n",
            "user_ns = types.SimpleNamespace(UserDict({'x': 1, 'y': 2}), x=4, z=3)\n",
            "show(user_ns)\n",
            "print(ns.x, ns.y, ns.z, ns.__dict__ is vars(ns))\n",
            "ns.theta = None\n",
            "del ns.y\n",
            "show(ns)\n",
            "ns.__dict__['x'] = 70\n",
            "print(ns.x)\n",
            "print(repr(types.SimpleNamespace(x='spam')))\n",
            "print(types.SimpleNamespace(a=1) == types.SimpleNamespace(a=1), types.SimpleNamespace(a=1) != types.SimpleNamespace())\n",
            "print(type(empty) is types.SimpleNamespace, isinstance(empty, types.SimpleNamespace))\n",
            "pair_ns = types.SimpleNamespace([['x', 1], ['y', 2]], x=4, z=3)\n",
            "show(pair_ns)\n",
            "class Spam(types.SimpleNamespace):\n",
            "    pass\n",
            "spam = Spam(ham=8, eggs=9)\n",
            "print(type(spam).__name__, isinstance(spam, types.SimpleNamespace), sorted(vars(spam).items()))\n",
            "for expr in [lambda: empty.missing, lambda: len(ns), lambda: iter(ns), lambda: ('x' in ns), lambda: ns['x']]:\n",
            "    try:\n",
            "        expr()\n",
            "    except (AttributeError, TypeError) as error:\n",
            "        print(error.__class__.__name__)\n",
            "for expr in [lambda: types.SimpleNamespace([], []), lambda: types.SimpleNamespace(1), lambda: types.SimpleNamespace([['x']]), lambda: types.SimpleNamespace({1: 2}), lambda: types.SimpleNamespace([[1, 2]]), lambda: types.SimpleNamespace(UserDict({1: 2}))]:\n",
            "    try:\n",
            "        expr()\n",
            "    except (TypeError, ValueError) as error:\n",
            "        print(error.__class__.__name__)"
        ),
        &[
            "[]",
            "[('x', 4), ('y', 2), ('z', 3)]",
            "[('x', 4), ('y', 2), ('z', 3)]",
            "4 2 3 True",
            "[('theta', None), ('x', 4), ('z', 3)]",
            "70",
            "namespace(x='spam')",
            "True True",
            "True True",
            "[('x', 4), ('y', 2), ('z', 3)]",
            "Spam True [('eggs', 9), ('ham', 8)]",
            "AttributeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "ValueError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython Lib/test/test_types.py::SimpleNamespaceTests
// `test_recursive`, `test_recursive_repr`, `test_replace`, and
// `test_replace_subclass`.
#[test]
fn cpython_types_simple_namespace_recursive_and_replace_subset() {
    assert_output(
        concat!(
            "import copy\n",
            "import types\n",
            "ns1 = types.SimpleNamespace(c='cookie')\n",
            "ns2 = types.SimpleNamespace()\n",
            "ns3 = types.SimpleNamespace(x=1)\n",
            "ns1.spam = ns1\n",
            "ns2.spam = ns3\n",
            "ns3.spam = ns2\n",
            "print(ns1.spam is ns1, ns1.spam.spam is ns1, ns1.spam.spam is ns1.spam)\n",
            "print(ns2.spam is ns3, ns3.spam is ns2, ns2.spam.spam is ns2)\n",
            "print(repr(ns1))\n",
            "print(repr(ns2))\n",
            "print(ns1)\n",
            "print(ns2)\n",
            "ns = types.SimpleNamespace(x=11, y=22)\n",
            "ns_copy = copy.replace(ns)\n",
            "print(ns_copy == ns, ns_copy is ns, type(ns_copy) is types.SimpleNamespace, sorted(vars(ns_copy).items()))\n",
            "ns_copy.x = 3\n",
            "print(ns.x, ns_copy.x)\n",
            "ns.x = 4\n",
            "print(ns.x, ns_copy.x)\n",
            "print(sorted(vars(copy.replace(ns, x=1)).items()))\n",
            "print(sorted(vars(copy.replace(ns, y=2)).items()))\n",
            "print(sorted(vars(copy.replace(ns, x=1, y=2)).items()))\n",
            "class Spam(types.SimpleNamespace):\n",
            "    pass\n",
            "spam = Spam(ham=8, eggs=9)\n",
            "spam_copy = copy.replace(spam, ham=5)\n",
            "print(type(spam_copy).__name__, isinstance(spam_copy, types.SimpleNamespace), sorted(vars(spam_copy).items()), spam_copy is spam)"
        ),
        &[
            "True True True",
            "True True True",
            "namespace(c='cookie', spam=namespace(...))",
            "namespace(spam=namespace(x=1, spam=namespace(...)))",
            "namespace(c='cookie', spam=namespace(...))",
            "namespace(spam=namespace(x=1, spam=namespace(...)))",
            "True False True [('x', 11), ('y', 22)]",
            "11 3",
            "4 3",
            "[('x', 1), ('y', 22)]",
            "[('x', 4), ('y', 2)]",
            "[('x', 1), ('y', 2)]",
            "Spam True [('eggs', 9), ('ham', 5)] False",
        ],
    );
}

// Adapted from CPython main Lib/test/test_types.py::SimpleNamespaceTests
// ::test_replace_invalid_subtype plus public `SimpleNamespace.__new__` behavior.
// This guards the safety edge where a SimpleNamespace subclass constructor may
// return a non-namespace object; `copy.replace()` must turn that into a
// catchable TypeError instead of reusing stale fields or crashing.
#[test]
fn cpython_types_simple_namespace_new_and_invalid_replace_subset() {
    assert_output(
        concat!(
            "import copy, types\n",
            "created = False\n",
            "print(type(types.SimpleNamespace.__new__(types.SimpleNamespace)).__name__, repr(types.SimpleNamespace.__new__(types.SimpleNamespace)))\n",
            "print(type(types.SimpleNamespace.__new__(types.SimpleNamespace, 1, x=2)).__name__)\n",
            "try:\n",
            "    types.SimpleNamespace.__new__(int)\n",
            "except TypeError as error:\n",
            "    print(type(error).__name__, 'not a subtype of types.SimpleNamespace' in str(error))\n",
            "ns0 = types.SimpleNamespace(x=1)\n",
            "print(hasattr(types.SimpleNamespace, '__replace__'), hasattr(ns0, '__replace__'))\n",
            "print(types.SimpleNamespace.__replace__(ns0, y=3), ns0.__replace__(x=2))\n",
            "class MyNS(types.SimpleNamespace):\n",
            "    def __new__(cls, *args, **kwargs):\n",
            "        if created:\n",
            "            return 12345\n",
            "        return super().__new__(cls)\n",
            "ns = MyNS(ham=8, eggs=9)\n",
            "print(type(ns).__name__, sorted(vars(ns).items()))\n",
            "print(hasattr(ns, '__replace__'), type(ns.__replace__(eggs=10)).__name__, sorted(vars(ns.__replace__(eggs=10)).items()))\n",
            "created = True\n",
            "try:\n",
            "    copy.replace(ns, ham=5)\n",
            "except TypeError as error:\n",
            "    print(type(error).__name__, 'expect types.SimpleNamespace type' in str(error), 'MyNS()' in str(error), \"'int' object\" in str(error))"
        ),
        &[
            "SimpleNamespace namespace()",
            "SimpleNamespace",
            "TypeError True",
            "True True",
            "namespace(x=1, y=3) namespace(x=2)",
            "MyNS [('eggs', 9), ('ham', 8)]",
            "True MyNS [('eggs', 10), ('ham', 8)]",
            "TypeError True True True",
        ],
    );
}

// Adapted from CPython Lib/test/test_types.py::SimpleNamespaceTests. This
// covers the remaining public SimpleNamespace behavior that MiniPython can
// support without CPython's pickle byte-stream format: constructor order,
// underlying `__dict__` lifetime, delete/reassign edges, nested references,
// repr order, internal-payload pickle round trips, unsupported rich ordering,
// and fake-namespace comparison safety.
#[test]
fn cpython_types_simple_namespace_remaining_public_subset() {
    assert_output(
        concat!(
            "import pickle, types\n",
            "ordered = types.SimpleNamespace({'x': 1, 'y': 2}, x=4, z=3)\n",
            "print(list(vars(ordered).items()))\n",
            "pair_ordered = types.SimpleNamespace([['x', 1], ['y', 2]], x=4, z=3)\n",
            "print(list(vars(pair_ordered).items()))\n",
            "print(list(vars(types.SimpleNamespace([], x=4, z=3)).items()))\n",
            "print(list(vars(types.SimpleNamespace({})).items()))\n",
            "ns1 = types.SimpleNamespace()\n",
            "ns2 = types.SimpleNamespace(x=1, y=2)\n",
            "ns3 = types.SimpleNamespace(a=True, b=False)\n",
            "mapping = ns3.__dict__\n",
            "del ns3\n",
            "print(sorted(vars(ns1).items()), sorted(vars(ns2).items()), sorted(mapping.items()))\n",
            "try:\n",
            "    del ns1.spam\n",
            "except AttributeError as error:\n",
            "    print(type(error).__name__)\n",
            "ns2 = types.SimpleNamespace(x=1, y=2, w=3)\n",
            "try:\n",
            "    del ns2.spam\n",
            "except AttributeError as error:\n",
            "    print(type(error).__name__)\n",
            "del ns2.y\n",
            "print(sorted(vars(ns2).items()))\n",
            "ns2.y = 'spam'\n",
            "print(sorted(vars(ns2).items()))\n",
            "del ns2.y\n",
            "print(sorted(vars(ns2).items()))\n",
            "ns1.spam = 5\n",
            "print(sorted(vars(ns1).items()))\n",
            "del ns1.spam\n",
            "print(sorted(vars(ns1).items()))\n",
            "ns1 = types.SimpleNamespace(a=1, b=2)\n",
            "ns2 = types.SimpleNamespace()\n",
            "ns3 = types.SimpleNamespace(x=ns1)\n",
            "ns2.spam = ns1\n",
            "ns2.ham = '?'\n",
            "ns2.spam = ns3\n",
            "print(sorted(vars(ns1).items()))\n",
            "print(vars(ns2)['spam'] is ns3, vars(ns2)['ham'], vars(ns3)['x'] is ns1, ns3.x.a)\n",
            "print(repr(types.SimpleNamespace(x=1, y=2, w=3)))\n",
            "ns = types.SimpleNamespace()\n",
            "ns.x = 'spam'\n",
            "ns._y = 5\n",
            "print(repr(ns))\n",
            "ns = types.SimpleNamespace(breakfast='spam', lunch='spam')\n",
            "checked = 0\n",
            "for protocol in range(pickle.HIGHEST_PROTOCOL + 1):\n",
            "    restored = pickle.loads(pickle.dumps(ns, protocol))\n",
            "    if restored == ns and restored is not ns and type(restored) is types.SimpleNamespace and sorted(vars(restored).items()) == sorted(vars(ns).items()):\n",
            "        checked += 1\n",
            "print('pickle', checked, pickle.HIGHEST_PROTOCOL + 1)\n",
            "plain_left = types.SimpleNamespace(x=1)\n",
            "plain_right = types.SimpleNamespace(y=2)\n",
            "for expr in [lambda: plain_left > plain_right, lambda: plain_left >= plain_right, lambda: plain_left < plain_right, lambda: plain_left <= plain_right]:\n",
            "    try:\n",
            "        print(expr())\n",
            "    except TypeError as error:\n",
            "        print(type(error).__name__)\n",
            "class FakeSimpleNamespace(str):\n",
            "    __class__ = types.SimpleNamespace\n",
            "for expr in [lambda: types.SimpleNamespace() == FakeSimpleNamespace(), lambda: types.SimpleNamespace() != FakeSimpleNamespace(), lambda: types.SimpleNamespace() < FakeSimpleNamespace(), lambda: types.SimpleNamespace() <= FakeSimpleNamespace(), lambda: types.SimpleNamespace() > FakeSimpleNamespace(), lambda: types.SimpleNamespace() >= FakeSimpleNamespace()]:\n",
            "    try:\n",
            "        print(expr())\n",
            "    except TypeError as error:\n",
            "        print(type(error).__name__)"
        ),
        &[
            "[('x', 4), ('y', 2), ('z', 3)]",
            "[('x', 4), ('y', 2), ('z', 3)]",
            "[('x', 4), ('z', 3)]",
            "[]",
            "[] [('x', 1), ('y', 2)] [('a', True), ('b', False)]",
            "AttributeError",
            "AttributeError",
            "[('w', 3), ('x', 1)]",
            "[('w', 3), ('x', 1), ('y', 'spam')]",
            "[('w', 3), ('x', 1)]",
            "[('spam', 5)]",
            "[]",
            "[('a', 1), ('b', 2)]",
            "True ? True 1",
            "namespace(x=1, y=2, w=3)",
            "namespace(x='spam', _y=5)",
            "pickle 6 6",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "False",
            "True",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py::test_Sequence_mixins.
// MiniPython keeps the same observable comparison against native list/str
// index() behavior, then covers the other Sequence mixins in a compact form.
#[test]
fn cpython_collections_abc_sequence_mixins_subset() {
    assert_output_with_stack(
        concat!(
            "from collections.abc import Sequence\n",
            "class SequenceSubclass(Sequence):\n",
            "    def __init__(self, seq=()):\n",
            "        self.seq = seq\n",
            "    def __getitem__(self, index):\n",
            "        return self.seq[index]\n",
            "    def __len__(self):\n",
            "        return len(self.seq)\n",
            "def index_result(seq, args):\n",
            "    try:\n",
            "        return ('ok', seq.index(*args))\n",
            "    except ValueError:\n",
            "        return ('ValueError',)\n",
            "def compare_index(native, wrapped, args):\n",
            "    return index_result(native, args) == index_result(wrapped, args)\n",
            "total = 0\n",
            "mismatches = 0\n",
            "for native in [list('abracadabra'), 'abracadabra']:\n",
            "    wrapped = SequenceSubclass(native)\n",
            "    indexes = [-10000, -9999] + list(range(-3, len(native) + 3))\n",
            "    letters = set(native)\n",
            "    letters.add('z')\n",
            "    for letter in letters:\n",
            "        total += 1\n",
            "        if not compare_index(native, wrapped, (letter,)):\n",
            "            mismatches += 1\n",
            "        for start in indexes:\n",
            "            total += 1\n",
            "            if not compare_index(native, wrapped, (letter, start)):\n",
            "                mismatches += 1\n",
            "            for stop in indexes:\n",
            "                total += 1\n",
            "                if not compare_index(native, wrapped, (letter, start, stop)):\n",
            "                    mismatches += 1\n",
            "print(total, mismatches)\n",
            "wrapped = SequenceSubclass('abracadabra')\n",
            "print(''.join(wrapped), ''.join(reversed(wrapped)))\n",
            "print(wrapped.count('a'), wrapped.count('z'), wrapped.__contains__('c'), wrapped.__contains__('z'))\n",
            "print('a' in wrapped, 'z' in wrapped)\n",
            "print(wrapped.index(value='b'), wrapped.index('b', start=1), wrapped.count(value='a'))\n",
            "try:\n",
            "    wrapped.index('z')\n",
            "except ValueError as error:\n",
            "    print(error.__class__.__name__)"
        ),
        &[
            "4572 0",
            "abracadabra arbadacarba",
            "5 0 True False",
            "True False",
            "1 1 5",
            "ValueError",
        ],
        32 * 1024 * 1024,
    );
}

#[test]
fn cpython_collections_abc_sequence_contains_rich_compare_subset() {
    assert_output_with_stack(
        r#"from collections.abc import Sequence
class Probe:
    def __init__(self, tag):
        self.tag = tag
    def __eq__(self, other):
        print("seq-eq", self.tag, getattr(other, "tag", other))
        return self.tag == getattr(other, "tag", other)
class SequenceSubclass(Sequence):
    def __init__(self, values):
        self.values = values
    def __len__(self):
        return len(self.values)
    def __getitem__(self, index):
        return self.values[index]
items = SequenceSubclass([Probe("a"), Probe("b"), Probe("a")])
print("contains", Probe("b") in items)
print("dunder", items.__contains__(Probe("b")))
class Boom:
    def __eq__(self, other):
        raise ValueError("boom")
for label, expr in [
    ("contains-error", lambda: 1 in SequenceSubclass([Boom()])),
    ("dunder-error", lambda: SequenceSubclass([Boom()]).__contains__(1)),
]:
    try:
        print(label, expr())
    except Exception as error:
        print(label, type(error).__name__, str(error), error.args)"#,
        &[
            "seq-eq a b",
            "seq-eq b b",
            "contains True",
            "seq-eq a b",
            "seq-eq b b",
            "dunder True",
            "contains-error ValueError boom ('boom',)",
            "dunder-error ValueError boom ('boom',)",
        ],
        32 * 1024 * 1024,
    );
}

// Adapted from CPython Lib/test/test_collections.py::test_ByteString and
// ::test_Buffer. MiniPython does not yet have full memoryview/buffer protocol
// parity, so this pins the supported ABC relationships and structural checks.
#[test]
fn cpython_collections_abc_bytestring_buffer_subset() {
    assert_output(
        concat!(
            "from collections.abc import ByteString, Buffer, Sequence, Awaitable\n",
            "from collections.abc import Collection, Sized, Iterable, Container\n",
            "byte_samples = [b'', bytearray()]\n",
            "buffer_samples = [b'', bytearray(), memoryview(b'x')]\n",
            "print([isinstance(value, ByteString) for value in byte_samples])\n",
            "print([issubclass(type(value), ByteString) for value in byte_samples])\n",
            "print([isinstance(value, Buffer) for value in buffer_samples])\n",
            "print([issubclass(type(value), Buffer) for value in buffer_samples])\n",
            "print(isinstance(memoryview(b''), ByteString), issubclass(memoryview, ByteString))\n",
            "print(issubclass(bytes, Buffer), issubclass(bytearray, Buffer), issubclass(memoryview, Buffer))\n",
            "non_samples = ['', [], (), range(0), {}, set(), None, 42]\n",
            "print([isinstance(value, ByteString) for value in non_samples])\n",
            "print([isinstance(value, Buffer) for value in non_samples])\n",
            "print(issubclass(str, ByteString), issubclass(list, ByteString), issubclass(tuple, ByteString))\n",
            "print(issubclass(str, Buffer), issubclass(list, Buffer), issubclass(tuple, Buffer))\n",
            "print(issubclass(ByteString, Sequence), issubclass(ByteString, Buffer), issubclass(Buffer, ByteString))\n",
            "print(issubclass(ByteString, Collection), issubclass(ByteString, Sized), issubclass(ByteString, Iterable), issubclass(ByteString, Container))\n",
            "class X(ByteString):\n",
            "    pass\n",
            "class Z(ByteString, Awaitable):\n",
            "    pass\n",
            "print(issubclass(X, ByteString), issubclass(X, Sequence), issubclass(float, X))\n",
            "print(issubclass(Z, ByteString), issubclass(Z, Awaitable), issubclass(float, Z))\n",
            "class CustomBuffer:\n",
            "    def __buffer__(self):\n",
            "        return b''\n",
            "class BufferBlocked(CustomBuffer):\n",
            "    __buffer__ = None\n",
            "print(isinstance(CustomBuffer(), Buffer), issubclass(CustomBuffer, Buffer))\n",
            "print(isinstance(BufferBlocked(), Buffer), issubclass(BufferBlocked, Buffer))\n",
            "class DirectBuffer(Buffer):\n",
            "    pass\n",
            "print(issubclass(DirectBuffer, Buffer), issubclass(float, DirectBuffer))",
        ),
        &[
            "[True, True]",
            "[True, True]",
            "[True, True, True]",
            "[True, True, True]",
            "False False",
            "True True True",
            "[False, False, False, False, False, False, False, False]",
            "[False, False, False, False, False, False, False, False]",
            "False False False",
            "False False False",
            "True False False",
            "True True True True",
            "True True False",
            "True True False",
            "True True",
            "False False",
            "True False",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py::test_ByteString and
// ::test_ByteString_attribute_access. ByteString is deprecated in CPython, and
// public import, attribute access, isinstance checks, and subclass creation all
// emit DeprecationWarning without changing the supported ABC relationships.
#[test]
fn cpython_collections_abc_bytestring_deprecation_warnings_subset() {
    assert_output(
        concat!(
            "import sys, warnings\n",
            "for module in ('collections', '_collections_abc', 'collections.abc'):\n",
            "    sys.modules.pop(module, None)\n",
            "with warnings.catch_warnings(record=True) as caught:\n",
            "    warnings.simplefilter('always')\n",
            "    from collections.abc import ByteString, Awaitable\n",
            "print('import', len(caught), caught[0].category is DeprecationWarning, 'ByteString' in str(caught[0].message))\n",
            "sys.modules.pop('collections.abc', None)\n",
            "with warnings.catch_warnings(record=True) as caught:\n",
            "    warnings.simplefilter('always')\n",
            "    import collections.abc as abc\n",
            "    attr = abc.ByteString\n",
            "print('attr', len(caught), attr.__name__, caught[0].category is DeprecationWarning)\n",
            "with warnings.catch_warnings(record=True) as caught:\n",
            "    warnings.simplefilter('always')\n",
            "    results = [isinstance(value, ByteString) for value in [b'', bytearray(), '', [], (), memoryview(b'')]]\n",
            "print('instance', results, len(caught), [wm.category is DeprecationWarning for wm in caught])\n",
            "with warnings.catch_warnings(record=True) as caught:\n",
            "    warnings.simplefilter('always')\n",
            "    class X(ByteString):\n",
            "        pass\n",
            "    class Z(ByteString, Awaitable):\n",
            "        pass\n",
            "print('class', issubclass(X, ByteString), issubclass(Z, Awaitable), len(caught), [wm.category is DeprecationWarning for wm in caught])",
            "\nwith warnings.catch_warnings(record=True) as caught:\n",
            "    warnings.simplefilter('always')\n",
            "    C = type('C', (ByteString,), {'__getitem__': lambda self, index: 0, '__len__': lambda self: 0})\n",
            "    ok_name = type(C()).__name__\n",
            "    try:\n",
            "        type('C', (ByteString,), {'__len__': lambda self: 0})()\n",
            "    except TypeError as error:\n",
            "        missing_getitem = '__getitem__' in str(error)\n",
            "print('dynamic', ok_name, missing_getitem, len(caught), [wm.category is DeprecationWarning for wm in caught])",
        ),
        &[
            "import 1 True True",
            "attr 1 ByteString True",
            "instance [True, True, False, False, False, False] 6 [True, True, True, True, True, True]",
            "class True True 2 [True, True]",
            "dynamic C True 2 [True, True]",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py::test_MutableSequence and
// ::test_MutableSequence_mixins. This covers the currently supported registered
// built-ins plus explicit ABC subclass mixins.
#[test]
fn cpython_collections_abc_mutable_sequence_subset() {
    assert_output(
        concat!(
            "from collections.abc import MutableSequence, Sequence, Reversible\n",
            "from collections.abc import Collection, Sized, Iterable, Container\n",
            "from collections import deque\n",
            "import array\n",
            "non_samples = [(), '', b'', range(0), {}, set(), None, 42]\n",
            "print([isinstance(value, MutableSequence) for value in non_samples])\n",
            "print(issubclass(tuple, MutableSequence), issubclass(str, MutableSequence), issubclass(bytes, MutableSequence), issubclass(range, MutableSequence))\n",
            "samples = [[], bytearray(), deque()]\n",
            "print([isinstance(value, MutableSequence) for value in samples])\n",
            "print([issubclass(type(value), MutableSequence) for value in samples])\n",
            "print(issubclass(array.array, MutableSequence), issubclass(str, MutableSequence))\n",
            "print(issubclass(MutableSequence, Sequence), issubclass(MutableSequence, Reversible), issubclass(MutableSequence, Collection), issubclass(MutableSequence, Sized), issubclass(MutableSequence, Iterable), issubclass(MutableSequence, Container))\n",
            "class ProtocolOnly:\n",
            "    def __len__(self):\n",
            "        return 0\n",
            "    def __getitem__(self, index):\n",
            "        raise IndexError\n",
            "    def __setitem__(self, index, value):\n",
            "        pass\n",
            "    def __delitem__(self, index):\n",
            "        pass\n",
            "    def insert(self, index, value):\n",
            "        pass\n",
            "print(isinstance(ProtocolOnly(), MutableSequence), issubclass(ProtocolOnly, MutableSequence))\n",
            "class MutableSequenceSubclass(MutableSequence):\n",
            "    def __init__(self):\n",
            "        self.lst = []\n",
            "    def __setitem__(self, index, value):\n",
            "        self.lst[index] = value\n",
            "    def __getitem__(self, index):\n",
            "        return self.lst[index]\n",
            "    def __len__(self):\n",
            "        return len(self.lst)\n",
            "    def __delitem__(self, index):\n",
            "        del self.lst[index]\n",
            "    def insert(self, index, value):\n",
            "        self.lst.insert(index, value)\n",
            "mss = MutableSequenceSubclass()\n",
            "mss.append(0)\n",
            "mss.extend((1, 2, 3, 4))\n",
            "print(len(mss), mss[3], list(mss))\n",
            "mss.reverse()\n",
            "print(mss[3], list(mss))\n",
            "print(mss.pop(), len(mss), list(mss))\n",
            "mss.remove(3)\n",
            "print(len(mss), list(mss))\n",
            "mss += (10, 20, 30)\n",
            "print(len(mss), mss[-1], list(mss))\n",
            "mss.clear()\n",
            "print(len(mss), list(mss))\n",
            "items = 'ABCD'\n",
            "mss2 = MutableSequenceSubclass()\n",
            "mss2.extend(items + items)\n",
            "mss.clear()\n",
            "mss.extend(items)\n",
            "mss.extend(mss)\n",
            "print(len(mss), list(mss) == list(mss2), list(mss))",
        ),
        &[
            "[False, False, False, False, False, False, False, False]",
            "False False False False",
            "[True, True, True]",
            "[True, True, True]",
            "True False",
            "True True True True True True",
            "False False",
            "5 3 [0, 1, 2, 3, 4]",
            "1 [4, 3, 2, 1, 0]",
            "0 4 [4, 3, 2, 1]",
            "3 [4, 2, 1]",
            "6 30 [4, 2, 1, 10, 20, 30]",
            "0 []",
            "8 True ['A', 'B', 'C', 'D', 'A', 'B', 'C', 'D']",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py::test_Set,
// ::test_hash_Set, ::test_isdisjoint_Set, ::test_equality_Set,
// ::test_arithmetic_Set, ::test_MutableSet, and related MutableSet issue
// regressions. The registered built-in coverage includes set, frozenset, and
// supported set-like dict views.
#[test]
fn cpython_collections_abc_set_mutable_set_mixins_subset() {
    assert_output(
        concat!(
            "from collections.abc import Set, MutableSet, Collection, Sized, Iterable, Container\n",
            "print(isinstance(set(), Set), issubclass(set, Set), isinstance(set(), MutableSet), issubclass(set, MutableSet))\n",
            "print(isinstance(frozenset(), Set), issubclass(frozenset, Set), isinstance(frozenset(), MutableSet), issubclass(frozenset, MutableSet))\n",
            "keys = {1: 2}.keys()\n",
            "items = {1: 2}.items()\n",
            "values = {1: 2}.values()\n",
            "print(isinstance(keys, Set), isinstance(items, Set), isinstance(values, Set))\n",
            "print(issubclass(Set, Collection), issubclass(Set, Sized), issubclass(Set, Iterable), issubclass(Set, Container))\n",
            "print(issubclass(MutableSet, Set), issubclass(MutableSet, Collection), issubclass(MutableSet, Sized), issubclass(MutableSet, Iterable), issubclass(MutableSet, Container))\n",
            "class ProtocolSet:\n",
            "    def __contains__(self, item):\n",
            "        return False\n",
            "    def __iter__(self):\n",
            "        return iter(())\n",
            "    def __len__(self):\n",
            "        return 0\n",
            "    def add(self, item):\n",
            "        pass\n",
            "    def discard(self, item):\n",
            "        pass\n",
            "print(isinstance(ProtocolSet(), Set), issubclass(ProtocolSet, Set), isinstance(ProtocolSet(), MutableSet), issubclass(ProtocolSet, MutableSet))\n",
            "class MySet(Set):\n",
            "    def __init__(self, values=()):\n",
            "        self.contents = []\n",
            "        for value in values:\n",
            "            if value not in self.contents:\n",
            "                self.contents.append(value)\n",
            "    def __contains__(self, value):\n",
            "        return value in self.contents\n",
            "    def __iter__(self):\n",
            "        return iter(self.contents)\n",
            "    def __len__(self):\n",
            "        return len(self.contents)\n",
            "class HashSet(MySet):\n",
            "    def __hash__(self):\n",
            "        return self._hash()\n",
            "s1 = MySet((1, 2, 3))\n",
            "s2 = MySet((3, 4, 5))\n",
            "s3 = MySet((1, 2, 3))\n",
            "print(issubclass(MySet, Set), isinstance(s1, Set), issubclass(float, MySet))\n",
            "print(s1.__le__(s3), s1.__lt__(s3), s1.__ge__(s3), s1.__gt__(s2), s1.__eq__(s3), s1.__eq__([1, 2, 3]))\n",
            "print(s1.isdisjoint(MySet((4, 5))), s1.isdisjoint(s2))\n",
            "print(isinstance(s1.__and__(s2), MySet), sorted(list(s1.__and__(s2))))\n",
            "print(isinstance(s1.__or__(s2), MySet), sorted(list(s1.__or__(s2))))\n",
            "print(isinstance(s1.__sub__(s2), MySet), sorted(list(s1.__sub__(s2))))\n",
            "print(isinstance(s1.__xor__(s2), MySet), sorted(list(s1.__xor__(s2))))\n",
            "print(hash(HashSet((1, 2, 3))) == hash(HashSet((3, 2, 1))))\n",
            "class WithSet(MutableSet):\n",
            "    def __init__(self, values=()):\n",
            "        self.data = set(values)\n",
            "    def __contains__(self, value):\n",
            "        return value in self.data\n",
            "    def __iter__(self):\n",
            "        return iter(self.data)\n",
            "    def __len__(self):\n",
            "        return len(self.data)\n",
            "    def add(self, value):\n",
            "        self.data.add(value)\n",
            "    def discard(self, value):\n",
            "        self.data.discard(value)\n",
            "m = WithSet('abcd')\n",
            "m.__iand__(WithSet('cdef'))\n",
            "print(sorted(list(m)))\n",
            "m = WithSet(range(4))\n",
            "popped = m.pop()\n",
            "print(len(m), popped in [0, 1, 2, 3], popped in m)\n",
            "m = WithSet(range(4))\n",
            "alias = m\n",
            "m.__isub__(m)\n",
            "print(len(m), m is alias)\n",
            "m = WithSet(range(4))\n",
            "m.__ixor__(m)\n",
            "print(len(m))\n",
            "m = WithSet((1, 2))\n",
            "m.__ior__((2, 3))\n",
            "print(sorted(list(m)))\n",
            "m.remove(2)\n",
            "print(sorted(list(m)))\n",
            "m.clear()\n",
            "print(len(m))",
        ),
        &[
            "True True True True",
            "True True False False",
            "True True False",
            "True True True True",
            "True True True True True",
            "False False False False",
            "True True False",
            "True False True False True NotImplemented",
            "True False",
            "True [3]",
            "True [1, 2, 3, 4, 5]",
            "True [1, 2]",
            "True [1, 2, 4, 5]",
            "True",
            "['c', 'd']",
            "3 True False",
            "0 True",
            "0",
            "[1, 2, 3]",
            "[1, 3]",
            "0",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py::
// TestCollectionABCs::test_issue16373. This pins the public behavior where Set
// rich comparisons with a subclass returning NotImplemented fall back without
// recursive comparison errors.
#[test]
fn cpython_collections_abc_set_noncomparable_comparison_subset() {
    assert_output(
        concat!(
            "from collections.abc import Set\n",
            "class MyComparableSet(Set):\n",
            "    def __contains__(self, x):\n",
            "        return False\n",
            "    def __len__(self):\n",
            "        return 0\n",
            "    def __iter__(self):\n",
            "        return iter([])\n",
            "class MyNonComparableSet(Set):\n",
            "    def __contains__(self, x):\n",
            "        return False\n",
            "    def __len__(self):\n",
            "        return 0\n",
            "    def __iter__(self):\n",
            "        return iter([])\n",
            "    def __le__(self, x):\n",
            "        return NotImplemented\n",
            "    def __lt__(self, x):\n",
            "        return NotImplemented\n",
            "cs = MyComparableSet()\n",
            "ncs = MyNonComparableSet()\n",
            "print(ncs < cs)\n",
            "print(ncs <= cs)\n",
            "print(ncs > cs)\n",
            "print(ncs >= cs)"
        ),
        &["False", "True", "False", "True"],
    );
}

// Adapted from CPython Lib/test/test_collections.py::test_Set_from_iterable.
// The key public behavior is that normal and in-place MutableSet operators use
// the ABC mixin methods, including an instance-level _from_iterable override.
#[test]
fn cpython_collections_abc_set_from_iterable_operator_subset() {
    assert_output_with_stack(
        concat!(
            "from collections.abc import MutableSet\n",
            "class SetUsingInstanceFromIterable(MutableSet):\n",
            "    def __init__(self, values, created_by):\n",
            "        if not created_by:\n",
            "            raise ValueError('created_by must be specified')\n",
            "        self.created_by = created_by\n",
            "        self._values = set(values)\n",
            "    def _from_iterable(self, values):\n",
            "        return type(self)(values, 'from_iterable')\n",
            "    def __contains__(self, value):\n",
            "        return value in self._values\n",
            "    def __iter__(self):\n",
            "        yield from self._values\n",
            "    def __len__(self):\n",
            "        return len(self._values)\n",
            "    def add(self, value):\n",
            "        self._values.add(value)\n",
            "    def discard(self, value):\n",
            "        self._values.discard(value)\n",
            "impl = SetUsingInstanceFromIterable([1, 2, 3], 'test')\n",
            "for actual in [impl - {1}, impl | {4}, impl & {2}, impl ^ {3, 4}]:\n",
            "    print(isinstance(actual, SetUsingInstanceFromIterable), actual.created_by, sorted(list(actual)))\n",
            "impl ^= [3, 4]\n",
            "print(isinstance(impl, SetUsingInstanceFromIterable), impl.created_by, sorted(list(impl)))"
        ),
        &[
            "True from_iterable [2, 3]",
            "True from_iterable [1, 2, 3, 4]",
            "True from_iterable [2]",
            "True from_iterable [1, 2, 4]",
            "True test [1, 2, 4]",
        ],
        32 * 1024 * 1024,
    );
}

// Adapted from CPython Lib/test/test_collections.py::
// test_Set_interoperability_with_real_sets. This ports the operator and
// comparison matrix for a concrete collections.abc.Set subclass interacting
// with built-in set values and plain iterables.
#[test]
fn cpython_collections_abc_set_real_set_interoperability_subset() {
    assert_output_with_stack(
        concat!(
            "from collections.abc import Set\n",
            "class ListSet(Set):\n",
            "    def __init__(self, elements=()):\n",
            "        self.data = []\n",
            "        for elem in elements:\n",
            "            if elem not in self.data:\n",
            "                self.data.append(elem)\n",
            "    def __contains__(self, elem):\n",
            "        return elem in self.data\n",
            "    def __iter__(self):\n",
            "        return iter(self.data)\n",
            "    def __len__(self):\n",
            "        return len(self.data)\n",
            "r1 = set('abc')\n",
            "r2 = set('bcd')\n",
            "r3 = set('abcde')\n",
            "f1 = ListSet('abc')\n",
            "f2 = ListSet('bcd')\n",
            "f3 = ListSet('abcde')\n",
            "l1 = list('abccba')\n",
            "l2 = list('bcddcb')\n",
            "l3 = list('abcdeedcba')\n",
            "for value in [f1 & f2, f1 & r2, r2 & f1, f1 & l2]:\n",
            "    print(sorted(list(value)))\n",
            "for value in [f1 | f2, f1 | r2, r2 | f1, f1 | l2]:\n",
            "    print(sorted(list(value)))\n",
            "for value in [f1 - f2, f2 - f1, f1 - r2, f2 - r1, r1 - f2, r2 - f1, f1 - l2, f2 - l1]:\n",
            "    print(sorted(list(value)))\n",
            "for value in [f1 ^ f2, f1 ^ r2, r2 ^ f1, f1 ^ l2]:\n",
            "    print(sorted(list(value)))\n",
            "print(f1 < f3, f1 < f1, f1 < f2, r1 < f3, r1 < f1, r1 < f2, r1 < r3, r1 < r1, r1 < r2)\n",
            "for expr in [lambda: f1 < l3, lambda: f1 <= l1, lambda: f1 > l2, lambda: f1 >= l3]:\n",
            "    try:\n",
            "        expr()\n",
            "    except TypeError as error:\n",
            "        print(error.__class__.__name__)\n",
            "print(f1 <= f3, f1 <= f1, f1 <= f2, r1 <= f3, r1 <= f1, r1 <= f2)\n",
            "print(f3 > f1, f1 > f1, f2 > f1, r3 > r1, f1 > r1, f2 > r1)\n",
            "print(f3 >= f1, f1 >= f1, f2 >= f1, r3 >= r1, f1 >= r1, f2 >= r1)\n",
            "print(f1 == f1, r1 == f1, f1 == r1, f1 == f3, r1 == f3, f1 == r3, f1 == l3)\n",
            "print(f1 != f1, r1 != f1, f1 != r1, f1 != f3, r1 != f3, f1 != r3, f1 != l3)"
        ),
        &[
            "['b', 'c']",
            "['b', 'c']",
            "['b', 'c']",
            "['b', 'c']",
            "['a', 'b', 'c', 'd']",
            "['a', 'b', 'c', 'd']",
            "['a', 'b', 'c', 'd']",
            "['a', 'b', 'c', 'd']",
            "['a']",
            "['d']",
            "['a']",
            "['d']",
            "['a']",
            "['d']",
            "['a']",
            "['d']",
            "['a', 'd']",
            "['a', 'd']",
            "['a', 'd']",
            "['a', 'd']",
            "True False False True False False True False False",
            "TypeError",
            "TypeError",
            "TypeError",
            "TypeError",
            "True True False True True False",
            "True False False True False False",
            "True True False True True False",
            "True True True False False False False",
            "False False False True True True True",
        ],
        32 * 1024 * 1024,
    );
}

// Adapted from CPython Lib/test/test_collections.py::
// test_Set_hash_matches_frozenset. This ports the current public Set._hash()
// mixin algorithm for supported hashable element shapes; it must match the
// builtin frozenset hash.
#[test]
fn cpython_collections_abc_set_hash_matches_frozenset_subset() {
    assert_output(
        concat!(
            "import sys\n",
            "from collections.abc import Set\n",
            "samples = [\n",
            "    (), (1,), (None,), (-1,), (0.0,), ('abc',), (1, 2, 3),\n",
            "    (10**100, 10**101), ('a', 'b', 'ab', ''), (False, True),\n",
            "    (object(), object(), object()), (float('nan'),), (frozenset(),),\n",
            "    tuple(range(1000)), tuple(x for x in range(1000) if x not in (100, 200, 300)),\n",
            "    tuple(range(sys.maxsize - 10, sys.maxsize + 10)),\n",
            "]\n",
            "for sample in samples:\n",
            "    fs = frozenset(sample)\n",
            "    print(hash(fs) == Set._hash(fs))"
        ),
        &[
            "True", "True", "True", "True", "True", "True", "True", "True", "True", "True", "True",
            "True", "True", "True", "True", "True",
        ],
    );
}

