// Adapted from CPython Lib/test/test_collections.py::test_Reversible.
// MiniPython already supports the reversed() runtime protocol; this test pins
// the matching collections.abc.Reversible instance/subclass behavior for the
// supported built-in and structural user-class subset.
#[test]
fn cpython_collections_abc_reversible_subset() {
    assert_output(
        concat!(
            "from collections.abc import Reversible, Sequence, Mapping, MutableMapping\n",
            "non_samples = [None, 42, 3.14, 1j, set(), iter([]), reversed([])]\n",
            "print([isinstance(value, Reversible) for value in non_samples])\n",
            "samples = [b'', '', (), [], {}, range(0), {}.keys(), {}.items(), {}.values()]\n",
            "print([isinstance(value, Reversible) for value in samples])\n",
            "print([issubclass(type(value), Reversible) for value in samples])\n",
            "print(issubclass(Sequence, Reversible), issubclass(Mapping, Reversible), issubclass(MutableMapping, Reversible))\n",
            "print(issubclass(list, Reversible), issubclass(dict, Reversible), issubclass(set, Reversible))\n",
            "class RevNoIter:\n",
            "    def __reversed__(self):\n",
            "        return reversed([])\n",
            "class RevPlusIter(RevNoIter):\n",
            "    def __iter__(self):\n",
            "        return iter([])\n",
            "print(isinstance(RevNoIter(), Reversible), issubclass(RevNoIter, Reversible))\n",
            "print(isinstance(RevPlusIter(), Reversible), issubclass(RevPlusIter, Reversible))\n",
            "class Rev:\n",
            "    def __iter__(self):\n",
            "        return iter([])\n",
            "    def __reversed__(self):\n",
            "        return reversed([])\n",
            "class RevItBlocked(Rev):\n",
            "    __iter__ = None\n",
            "class RevRevBlocked(Rev):\n",
            "    __reversed__ = None\n",
            "print(isinstance(Rev(), Reversible), issubclass(Rev, Reversible))\n",
            "print(isinstance(RevItBlocked(), Reversible), issubclass(RevItBlocked, Reversible))\n",
            "print(isinstance(RevRevBlocked(), Reversible), issubclass(RevRevBlocked, Reversible))\n",
            "class R(Reversible):\n",
            "    pass\n",
            "print(issubclass(R, Reversible), issubclass(float, R))"
        ),
        &[
            "[False, False, False, False, False, False, False]",
            "[True, True, True, True, True, True, True, True, True]",
            "[True, True, True, True, True, True, True, True, True]",
            "True False False",
            "True True False",
            "False False",
            "True True",
            "True True",
            "False False",
            "False False",
            "True False",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py Awaitable, Coroutine,
// AsyncIterable, and AsyncIterator ABC checks. MiniPython covers native
// coroutine objects plus the structural special-method subset its VM can
// represent. Iterable-coroutine and registration-propagation cases are covered
// by `cpython_collections_abc_types_coroutine_subset`.
#[test]
fn cpython_collections_abc_async_runtime_subset() {
    assert_output(
        concat!(
            "from collections.abc import Awaitable, Coroutine, AsyncIterable, AsyncIterator\n",
            "def plain_gen():\n",
            "    yield 1\n",
            "async def coro():\n",
            "    return 1\n",
            "c = coro()\n",
            "print(isinstance(c, Awaitable), isinstance(c, Coroutine))\n",
            "print(issubclass(type(c), Awaitable), issubclass(type(c), Coroutine))\n",
            "print(c.close())\n",
            "class AwaitOnly:\n",
            "    def __await__(self):\n",
            "        yield 1\n",
            "print(isinstance(AwaitOnly(), Awaitable), issubclass(AwaitOnly, Awaitable), isinstance(AwaitOnly(), Coroutine), issubclass(AwaitOnly, Coroutine))\n",
            "class CoroLike:\n",
            "    def __await__(self):\n",
            "        yield\n",
            "    def send(self, value):\n",
            "        return value\n",
            "    def throw(self, typ, val=None, tb=None):\n",
            "        pass\n",
            "    def close(self):\n",
            "        pass\n",
            "class MissingThrow:\n",
            "    def __await__(self):\n",
            "        yield\n",
            "    def send(self, value):\n",
            "        return value\n",
            "    def close(self):\n",
            "        pass\n",
            "print(isinstance(CoroLike(), Awaitable), isinstance(CoroLike(), Coroutine), issubclass(CoroLike, Coroutine))\n",
            "print(isinstance(MissingThrow(), Coroutine), issubclass(MissingThrow, Coroutine))\n",
            "class AI:\n",
            "    def __aiter__(self):\n",
            "        return self\n",
            "class AIter(AI):\n",
            "    async def __anext__(self):\n",
            "        raise StopAsyncIteration\n",
            "class AnextOnly:\n",
            "    async def __anext__(self):\n",
            "        raise StopAsyncIteration\n",
            "print(isinstance(AI(), AsyncIterable), issubclass(AI, AsyncIterable), isinstance(AI(), AsyncIterator), issubclass(AI, AsyncIterator))\n",
            "print(isinstance(AIter(), AsyncIterable), isinstance(AIter(), AsyncIterator), issubclass(AIter, AsyncIterator), issubclass(AsyncIterator, AsyncIterable))\n",
            "print(isinstance(AnextOnly(), AsyncIterator), issubclass(AnextOnly, AsyncIterator))\n",
            "async_iterator_non_samples = [None, object, []]\n",
            "print([isinstance(value, AsyncIterator) for value in async_iterator_non_samples])\n",
            "print([issubclass(type(value), AsyncIterator) for value in async_iterator_non_samples])\n",
            "class AIBlocked(AI):\n",
            "    __aiter__ = None\n",
            "class ANextBlocked(AIter):\n",
            "    __anext__ = None\n",
            "print(isinstance(AIBlocked(), AsyncIterable), issubclass(AIBlocked, AsyncIterable), isinstance(ANextBlocked(), AsyncIterator), issubclass(ANextBlocked, AsyncIterator))\n",
            "print([isinstance(value, Awaitable) for value in [None, 1, plain_gen(), object()]])\n",
            "print([isinstance(value, AsyncIterable) for value in [None, object(), []]])"
        ),
        &[
            "True True",
            "True True",
            "None",
            "True True False False",
            "True True True",
            "False False",
            "True True False False",
            "True True True True",
            "False False",
            "[False, False, False]",
            "[False, False, False]",
            "False False False False",
            "[False, False, False, False]",
            "[False, False, False]",
        ],
    );
}

