// Adapted from CPython Lib/_collections_abc.py::AsyncGenerator and
// Lib/test/test_collections.py::TestOneTrickPonyABCs::test_AsyncGenerator.
// This ports the default athrow() and aclose() mixin behavior for direct
// subclasses.
#[test]
fn cpython_collections_abc_async_generator_throw_close_mixin_subset() {
    assert_output_with_stack(
        concat!(
            "from collections.abc import AsyncGenerator, Awaitable, Coroutine\n",
            "class MinimalAGen(AsyncGenerator):\n",
            "    async def asend(self, value):\n",
            "        return value\n",
            "    async def athrow(self, typ, val=None, tb=None):\n",
            "        await super().athrow(typ, val, tb)\n",
            "class FailOnClose(AsyncGenerator):\n",
            "    async def asend(self, value):\n",
            "        return value\n",
            "    async def athrow(self, *args):\n",
            "        raise ValueError('bad close')\n",
            "class IgnoreGeneratorExit(AsyncGenerator):\n",
            "    async def asend(self, value):\n",
            "        return value\n",
            "    async def athrow(self, *args):\n",
            "        pass\n",
            "def run_async(coro):\n",
            "    result = None\n",
            "    while True:\n",
            "        try:\n",
            "            coro.send(None)\n",
            "        except StopIteration as ex:\n",
            "            result = ex.args[0] if ex.args else None\n",
            "            break\n",
            "    return result\n",
            "async def run():\n",
            "    mgen = MinimalAGen()\n",
            "    abc_throw = AsyncGenerator.athrow(mgen, ValueError)\n",
            "    print(type(abc_throw).__name__, isinstance(abc_throw, Awaitable), isinstance(abc_throw, Coroutine))\n",
            "    try:\n",
            "        run_async(abc_throw)\n",
            "    except ValueError:\n",
            "        print('abc athrow ValueError')\n",
            "    abc_close = AsyncGenerator.aclose(mgen)\n",
            "    print(type(abc_close).__name__, isinstance(abc_close, Awaitable), isinstance(abc_close, Coroutine))\n",
            "    print(run_async(abc_close))\n",
            "    closed = AsyncGenerator.aclose(mgen)\n",
            "    print(closed.close())\n",
            "    try:\n",
            "        closed.send(None)\n",
            "    except RuntimeError as error:\n",
            "        print('closed reuse', error)\n",
            "    print(await mgen.aclose())\n",
            "    try:\n",
            "        await mgen.athrow(ValueError)\n",
            "    except ValueError:\n",
            "        print('athrow ValueError')\n",
            "    try:\n",
            "        await mgen.athrow(ValueError, ValueError('explicit'), None)\n",
            "    except ValueError as error:\n",
            "        print('athrow explicit', error)\n",
            "    try:\n",
            "        raise IndexError(9)\n",
            "    except Exception as error:\n",
            "        tb = error.__traceback__\n",
            "    try:\n",
            "        await mgen.athrow(ValueError, None, tb)\n",
            "    except ValueError as error:\n",
            "        print('athrow traceback object', error.__traceback__ is tb)\n",
            "    try:\n",
            "        await mgen.athrow(ValueError, None, 5)\n",
            "    except TypeError as error:\n",
            "        print('athrow traceback', error)\n",
            "    try:\n",
            "        await FailOnClose().aclose()\n",
            "    except ValueError as error:\n",
            "        print('close-error', error)\n",
            "    try:\n",
            "        await IgnoreGeneratorExit().aclose()\n",
            "    except RuntimeError as error:\n",
            "        print('close-runtime', error)\n",
            "coro = run()\n",
            "try:\n",
            "    coro.send(None)\n",
            "except StopIteration:\n",
            "    pass"
        ),
        &[
            "coroutine True True",
            "abc athrow ValueError",
            "coroutine True True",
            "None",
            "None",
            "closed reuse cannot reuse already awaited coroutine",
            "None",
            "athrow ValueError",
            "athrow explicit explicit",
            "athrow traceback object False",
            "athrow traceback __traceback__ must be a traceback or None",
            "close-error bad close",
            "close-runtime asynchronous generator ignored GeneratorExit",
        ],
        16 * 1024 * 1024,
    );
}

// Adapted from CPython Lib/test/test_collections.py::
// TestOneTrickPonyABCs::test_Awaitable and ::test_Coroutine. This ports the
// public `types.coroutine()` iterable-coroutine distinction plus the
// `Coroutine.register()` propagation through `Awaitable`.
#[test]
fn cpython_collections_abc_types_coroutine_subset() {
    assert_output(
        concat!(
            "import types\n",
            "from collections.abc import Awaitable, Coroutine\n",
            "def plain_gen():\n",
            "    yield 'plain'\n",
            "@types.coroutine\n",
            "def iterable_coro():\n",
            "    yield 'tick'\n",
            "    return 'done'\n",
            "async def native_coro():\n",
            "    return 'native'\n",
            "plain = plain_gen()\n",
            "wrapped = iterable_coro()\n",
            "native = native_coro()\n",
            "print(types.coroutine(plain_gen) is plain_gen)\n",
            "print(isinstance(plain, Awaitable), isinstance(plain, Coroutine))\n",
            "print(isinstance(wrapped, Awaitable), isinstance(wrapped, Coroutine))\n",
            "print(issubclass(type(wrapped), Awaitable), issubclass(type(wrapped), Coroutine))\n",
            "print(isinstance(native, Awaitable), isinstance(native, Coroutine))\n",
            "print(native.close())\n",
            "async def main():\n",
            "    result = await iterable_coro()\n",
            "    print('result', result)\n",
            "    return 'outer'\n",
            "c = main()\n",
            "print(c.send(None))\n",
            "try:\n",
            "    c.send(None)\n",
            "except StopIteration as done:\n",
            "    print(done)\n",
            "class CoroLike:\n",
            "    pass\n",
            "Coroutine.register(CoroLike)\n",
            "print(isinstance(CoroLike(), Awaitable), issubclass(CoroLike, Awaitable))\n",
            "print(isinstance(CoroLike(), Coroutine), issubclass(CoroLike, Coroutine))"
        ),
        &[
            "True",
            "False False",
            "False False",
            "False False",
            "True True",
            "None",
            "tick",
            "result done",
            "outer",
            "True True",
            "True True",
        ],
    );
}

// Adapted from CPython Lib/_collections_abc.py::Coroutine and
// Lib/test/test_collections.py::TestOneTrickPonyABCs::test_Coroutine. This
// ports the public direct-subclass mixin behavior for send(), throw(), and
// close().
#[test]
fn cpython_collections_abc_coroutine_mixin_subset() {
    assert_output(
        concat!(
            "from collections.abc import Awaitable, Coroutine\n",
            "class DefaultCoro(Coroutine):\n",
            "    def __await__(self):\n",
            "        yield\n",
            "    def send(self, value):\n",
            "        return super().send(value)\n",
            "    def throw(self, typ, val=None, tb=None):\n",
            "        return super().throw(typ, val, tb)\n",
            "coro = DefaultCoro()\n",
            "print(isinstance(coro, Awaitable), isinstance(coro, Coroutine), issubclass(DefaultCoro, Coroutine))\n",
            "try:\n",
            "    coro.send(None)\n",
            "except StopIteration as done:\n",
            "    print('send', done.__class__.__name__, done)\n",
            "try:\n",
            "    coro.throw(ValueError('bad'))\n",
            "except ValueError as error:\n",
            "    print('throw', error)\n",
            "print(coro.close())\n",
            "class IgnoreExit(Coroutine):\n",
            "    def __await__(self):\n",
            "        yield\n",
            "    def send(self, value):\n",
            "        return value\n",
            "    def throw(self, typ, val=None, tb=None):\n",
            "        return 'ignored'\n",
            "try:\n",
            "    IgnoreExit().close()\n",
            "except RuntimeError as error:\n",
            "    print('close', error)\n",
            "class FailClose(Coroutine):\n",
            "    def __await__(self):\n",
            "        yield\n",
            "    def send(self, value):\n",
            "        return value\n",
            "    def throw(self, typ, val=None, tb=None):\n",
            "        raise ValueError('bad close')\n",
            "try:\n",
            "    FailClose().close()\n",
            "except ValueError as error:\n",
            "    print('close-error', error)"
        ),
        &[
            "True True True",
            "send StopIteration ",
            "throw bad",
            "None",
            "close coroutine ignored GeneratorExit",
            "close-error bad close",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py::ABCTestCase::
// validate_abstract_methods as used by TestOneTrickPonyABCs. This ports the
// public abstract-method instantiation behavior without copying ABCMeta's
// internal cache machinery.
fn cpython_abstract_instantiation_error(class_name: &str, methods: &[&str]) -> String {
    let mut methods = methods.to_vec();
    methods.sort_unstable();
    methods.dedup();
    let plural = if methods.len() == 1 {
        "method"
    } else {
        "methods"
    };
    let methods = methods
        .iter()
        .map(|method| format!("'{method}'"))
        .collect::<Vec<_>>()
        .join(", ");
    format!(
        "Can't instantiate abstract class {class_name} without an implementation for abstract {plural} {methods}"
    )
}

#[test]
fn cpython_collections_abc_abstract_methods_subset() {
    let source = concat!(
        "from collections.abc import Awaitable, Coroutine, AsyncIterable, AsyncIterator\n",
        "from collections.abc import Hashable, Iterable, Iterator, Reversible, Collection\n",
        "from collections.abc import Generator, AsyncGenerator, Sized, Container, Callable\n",
        "def stub(self, *args):\n",
        "    return 0\n",
        "cases = [\n",
        "    (Awaitable, ('__await__',)),\n",
        "    (Coroutine, ('__await__', 'send', 'throw')),\n",
        "    (Hashable, ('__hash__',)),\n",
        "    (AsyncIterable, ('__aiter__',)),\n",
        "    (AsyncIterator, ('__anext__',)),\n",
        "    (Iterable, ('__iter__',)),\n",
        "    (Reversible, ('__reversed__', '__iter__')),\n",
        "    (Collection, ('__len__', '__iter__', '__contains__')),\n",
        "    (Iterator, ('__next__',)),\n",
        "    (Generator, ('send', 'throw')),\n",
        "    (AsyncGenerator, ('asend', 'athrow')),\n",
        "    (Sized, ('__len__',)),\n",
        "    (Container, ('__contains__',)),\n",
        "    (Callable, ('__call__',)),\n",
        "]\n",
        "for abc, names in cases:\n",
        "    namespace = {}\n",
        "    for name in names:\n",
        "        namespace[name] = stub\n",
        "    C = type('C', (abc,), namespace)\n",
        "    instance = C()\n",
        "    print(abc.__name__, 'complete', isinstance(instance, abc), issubclass(C, abc))\n",
        "    for missing in names:\n",
        "        namespace = {}\n",
        "        for name in names:\n",
        "            if name != missing:\n",
        "                namespace[name] = stub\n",
        "        C = type('C', (abc,), namespace)\n",
        "        try:\n",
        "            C()\n",
        "        except TypeError as error:\n",
        "            print(abc.__name__, missing, str(error))\n",
        "for abc, names in cases:\n",
        "    try:\n",
        "        abc()\n",
        "    except TypeError as error:\n",
        "        print(abc.__name__, 'direct', str(error))"
    );
    let cases: [(&str, &[&str]); 14] = [
        ("Awaitable", &["__await__"]),
        ("Coroutine", &["__await__", "send", "throw"]),
        ("Hashable", &["__hash__"]),
        ("AsyncIterable", &["__aiter__"]),
        ("AsyncIterator", &["__anext__"]),
        ("Iterable", &["__iter__"]),
        ("Reversible", &["__reversed__", "__iter__"]),
        ("Collection", &["__len__", "__iter__", "__contains__"]),
        ("Iterator", &["__next__"]),
        ("Generator", &["send", "throw"]),
        ("AsyncGenerator", &["asend", "athrow"]),
        ("Sized", &["__len__"]),
        ("Container", &["__contains__"]),
        ("Callable", &["__call__"]),
    ];
    let mut expected = Vec::new();
    for (abc, names) in cases {
        expected.push(format!("{abc} complete True True"));
        for missing in names {
            expected.push(format!(
                "{abc} {missing} {}",
                cpython_abstract_instantiation_error("C", &[*missing])
            ));
        }
    }
    for (abc, names) in cases {
        expected.push(format!(
            "{abc} direct {}",
            cpython_abstract_instantiation_error(abc, names)
        ));
    }
    assert_eq!(run_source(source), Ok(expected), "source:\n{source}");
}

// Adapted from CPython Lib/test/test_collections.py::TestCollectionABCs
// validate_abstract_methods calls. This covers direct ABC construction
// rejection and incomplete explicit subclasses for composite ABCs without
// copying ABCMeta's internal cache machinery.
#[test]
fn cpython_collections_abc_composite_abstract_methods_subset() {
    let source = concat!(
        "from collections.abc import Buffer, ByteString, Mapping, MutableMapping\n",
        "from collections.abc import MutableSequence, MutableSet, Sequence, Set\n",
        "def show_direct(abc):\n",
        "    try:\n",
        "        abc()\n",
        "    except TypeError as error:\n",
        "        print(abc.__name__, 'direct', str(error))\n",
        "for abc in [Set, MutableSet, Mapping, MutableMapping, Sequence, MutableSequence, ByteString, Buffer]:\n",
        "    show_direct(abc)\n",
        "def show(label, cls):\n",
        "    try:\n",
        "        obj = cls()\n",
        "    except TypeError as error:\n",
        "        print(label, 'ERR', str(error))\n",
        "    else:\n",
        "        print(label, 'OK', isinstance(obj, cls))\n",
        "class CompleteSet(Set):\n",
        "    def __contains__(self, x): return False\n",
        "    def __iter__(self): return iter([])\n",
        "    def __len__(self): return 0\n",
        "class MissingSet(Set):\n",
        "    def __iter__(self): return iter([])\n",
        "    def __len__(self): return 0\n",
        "show('CompleteSet', CompleteSet)\n",
        "show('MissingSet', MissingSet)\n",
        "class CompleteMutableSet(MutableSet):\n",
        "    def __contains__(self, x): return False\n",
        "    def __iter__(self): return iter([])\n",
        "    def __len__(self): return 0\n",
        "    def add(self, x): pass\n",
        "    def discard(self, x): pass\n",
        "class MissingMutableSet(MutableSet):\n",
        "    def __contains__(self, x): return False\n",
        "    def __iter__(self): return iter([])\n",
        "    def __len__(self): return 0\n",
        "    def add(self, x): pass\n",
        "show('CompleteMutableSet', CompleteMutableSet)\n",
        "show('MissingMutableSet', MissingMutableSet)\n",
        "class CompleteMapping(Mapping):\n",
        "    def __iter__(self): return iter([])\n",
        "    def __len__(self): return 0\n",
        "    def __getitem__(self, key): raise KeyError(key)\n",
        "class MissingMapping(Mapping):\n",
        "    def __iter__(self): return iter([])\n",
        "    def __len__(self): return 0\n",
        "show('CompleteMapping', CompleteMapping)\n",
        "show('MissingMapping', MissingMapping)\n",
        "class CompleteMutableMapping(MutableMapping):\n",
        "    def __iter__(self): return iter([])\n",
        "    def __len__(self): return 0\n",
        "    def __getitem__(self, key): raise KeyError(key)\n",
        "    def __setitem__(self, key, value): pass\n",
        "    def __delitem__(self, key): pass\n",
        "class MissingMutableMapping(MutableMapping):\n",
        "    def __iter__(self): return iter([])\n",
        "    def __len__(self): return 0\n",
        "    def __getitem__(self, key): raise KeyError(key)\n",
        "    def __setitem__(self, key, value): pass\n",
        "show('CompleteMutableMapping', CompleteMutableMapping)\n",
        "show('MissingMutableMapping', MissingMutableMapping)\n",
        "class CompleteSequence(Sequence):\n",
        "    def __len__(self): return 0\n",
        "    def __getitem__(self, index): raise IndexError\n",
        "class MissingSequence(Sequence):\n",
        "    def __len__(self): return 0\n",
        "show('CompleteSequence', CompleteSequence)\n",
        "show('MissingSequence', MissingSequence)\n",
        "class CompleteMutableSequence(MutableSequence):\n",
        "    def __len__(self): return 0\n",
        "    def __getitem__(self, index): raise IndexError\n",
        "    def __setitem__(self, index, value): pass\n",
        "    def __delitem__(self, index): pass\n",
        "    def insert(self, index, value): pass\n",
        "class MissingMutableSequence(MutableSequence):\n",
        "    def __len__(self): return 0\n",
        "    def __getitem__(self, index): raise IndexError\n",
        "    def __setitem__(self, index, value): pass\n",
        "    def __delitem__(self, index): pass\n",
        "show('CompleteMutableSequence', CompleteMutableSequence)\n",
        "show('MissingMutableSequence', MissingMutableSequence)\n",
        "class CompleteByteString(ByteString):\n",
        "    def __len__(self): return 0\n",
        "    def __getitem__(self, index): raise IndexError\n",
        "class MissingByteString(ByteString):\n",
        "    def __len__(self): return 0\n",
        "show('CompleteByteString', CompleteByteString)\n",
        "show('MissingByteString', MissingByteString)\n",
        "class CompleteBuffer(Buffer):\n",
        "    def __buffer__(self, flags=0): return memoryview(b'')\n",
        "class MissingBuffer(Buffer):\n",
        "    pass\n",
        "show('CompleteBuffer', CompleteBuffer)\n",
        "show('MissingBuffer', MissingBuffer)"
    );
    let direct_cases: [(&str, &[&str]); 8] = [
        ("Set", &["__contains__", "__iter__", "__len__"]),
        (
            "MutableSet",
            &["__contains__", "__iter__", "__len__", "add", "discard"],
        ),
        ("Mapping", &["__getitem__", "__iter__", "__len__"]),
        (
            "MutableMapping",
            &[
                "__delitem__",
                "__getitem__",
                "__iter__",
                "__len__",
                "__setitem__",
            ],
        ),
        ("Sequence", &["__getitem__", "__len__"]),
        (
            "MutableSequence",
            &[
                "__delitem__",
                "__getitem__",
                "__len__",
                "__setitem__",
                "insert",
            ],
        ),
        ("ByteString", &["__getitem__", "__len__"]),
        ("Buffer", &["__buffer__"]),
    ];
    let mut expected = Vec::new();
    for (abc, methods) in direct_cases {
        expected.push(format!(
            "{abc} direct {}",
            cpython_abstract_instantiation_error(abc, methods)
        ));
    }
    for (line, missing) in [
        ("CompleteSet OK True", None),
        (
            "MissingSet ERR",
            Some(("MissingSet", &["__contains__"][..])),
        ),
        ("CompleteMutableSet OK True", None),
        (
            "MissingMutableSet ERR",
            Some(("MissingMutableSet", &["discard"][..])),
        ),
        ("CompleteMapping OK True", None),
        (
            "MissingMapping ERR",
            Some(("MissingMapping", &["__getitem__"][..])),
        ),
        ("CompleteMutableMapping OK True", None),
        (
            "MissingMutableMapping ERR",
            Some(("MissingMutableMapping", &["__delitem__"][..])),
        ),
        ("CompleteSequence OK True", None),
        (
            "MissingSequence ERR",
            Some(("MissingSequence", &["__getitem__"][..])),
        ),
        ("CompleteMutableSequence OK True", None),
        (
            "MissingMutableSequence ERR",
            Some(("MissingMutableSequence", &["insert"][..])),
        ),
        ("CompleteByteString OK True", None),
        (
            "MissingByteString ERR",
            Some(("MissingByteString", &["__getitem__"][..])),
        ),
        ("CompleteBuffer OK True", None),
        (
            "MissingBuffer ERR",
            Some(("MissingBuffer", &["__buffer__"][..])),
        ),
    ] {
        if let Some((class_name, methods)) = missing {
            expected.push(format!(
                "{line} {}",
                cpython_abstract_instantiation_error(class_name, methods)
            ));
        } else {
            expected.push(line.to_string());
        }
    }
    assert_eq!(run_source(source), Ok(expected), "source:\n{source}");
}

// Adapted from CPython Lib/test/test_collections.py Generator and
// AsyncGenerator ABC checks. This covers native generator objects and the
// public structural method-recognition matrix.
#[test]
fn cpython_collections_abc_generator_runtime_subset() {
    assert_output(
        concat!(
            "from collections.abc import Generator, Iterator, AsyncGenerator, AsyncIterator\n",
            "def gen():\n",
            "    yield 1\n",
            "class GenLike:\n",
            "    def __iter__(self):\n",
            "        return self\n",
            "    def __next__(self):\n",
            "        return None\n",
            "    def send(self, value):\n",
            "        return value\n",
            "    def throw(self, typ, val=None, tb=None):\n",
            "        pass\n",
            "    def close(self):\n",
            "        pass\n",
            "class MissingSend:\n",
            "    def __iter__(self):\n",
            "        return self\n",
            "    def __next__(self):\n",
            "        return None\n",
            "    def throw(self, typ, val=None, tb=None):\n",
            "        pass\n",
            "    def close(self):\n",
            "        pass\n",
            "print(isinstance(gen(), Iterator), isinstance(gen(), Generator), issubclass(type(gen()), Generator), issubclass(Generator, Iterator))\n",
            "print(isinstance(GenLike(), Generator), issubclass(GenLike, Generator))\n",
            "print(isinstance(MissingSend(), Generator), issubclass(MissingSend, Generator))\n",
            "class GenBlocked(GenLike):\n",
            "    send = None\n",
            "print(isinstance(GenBlocked(), Generator), issubclass(GenBlocked, Generator))\n",
            "class G(Generator):\n",
            "    pass\n",
            "print(issubclass(G, Generator), issubclass(float, G))\n",
            "async def agen():\n",
            "    yield 1\n",
            "class AGenLike:\n",
            "    def __aiter__(self):\n",
            "        return self\n",
            "    async def __anext__(self):\n",
            "        raise StopAsyncIteration\n",
            "    async def asend(self, value):\n",
            "        return value\n",
            "    async def athrow(self, typ, val=None, tb=None):\n",
            "        pass\n",
            "    async def aclose(self):\n",
            "        pass\n",
            "class MissingASend:\n",
            "    def __aiter__(self):\n",
            "        return self\n",
            "    async def __anext__(self):\n",
            "        raise StopAsyncIteration\n",
            "    async def athrow(self, typ, val=None, tb=None):\n",
            "        pass\n",
            "    async def aclose(self):\n",
            "        pass\n",
            "class NonAGen1:\n",
            "    def __aiter__(self):\n",
            "        return self\n",
            "    def __anext__(self):\n",
            "        return None\n",
            "    def aclose(self):\n",
            "        pass\n",
            "    def athrow(self, typ, val=None, tb=None):\n",
            "        pass\n",
            "class NonAGen2:\n",
            "    def __aiter__(self):\n",
            "        return self\n",
            "    def __anext__(self):\n",
            "        return None\n",
            "    def aclose(self):\n",
            "        pass\n",
            "    def asend(self, value):\n",
            "        return value\n",
            "class NonAGen3:\n",
            "    def aclose(self):\n",
            "        pass\n",
            "    def asend(self, value):\n",
            "        return value\n",
            "    def athrow(self, typ, val=None, tb=None):\n",
            "        pass\n",
            "ag = agen()\n",
            "print(isinstance(ag, AsyncIterator), isinstance(ag, AsyncGenerator), issubclass(type(ag), AsyncGenerator), issubclass(AsyncGenerator, AsyncIterator))\n",
            "print(isinstance(AGenLike(), AsyncGenerator), issubclass(AGenLike, AsyncGenerator))\n",
            "print(isinstance(MissingASend(), AsyncGenerator), issubclass(MissingASend, AsyncGenerator))\n",
            "for value in [NonAGen1(), NonAGen2(), NonAGen3()]:\n",
            "    print(type(value).__name__, isinstance(value, AsyncGenerator), issubclass(type(value), AsyncGenerator))\n",
            "class AGenBlocked(AGenLike):\n",
            "    asend = None\n",
            "print(isinstance(AGenBlocked(), AsyncGenerator), issubclass(AGenBlocked, AsyncGenerator))\n",
            "class AG(AsyncGenerator):\n",
            "    pass\n",
            "print(issubclass(AG, AsyncGenerator), issubclass(float, AG))"
        ),
        &[
            "True True True True",
            "True True",
            "False False",
            "False False",
            "True False",
            "True True True True",
            "True True",
            "False False",
            "NonAGen1 False False",
            "NonAGen2 False False",
            "NonAGen3 False False",
            "False False",
            "True False",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py::
// TestOneTrickPonyABCs::test_Generator. This ports the public Generator ABC
// non-sample/sample matrix.
#[test]
fn cpython_collections_abc_generator_sample_matrix_subset() {
    assert_output(
        concat!(
            "from collections.abc import Generator, Iterator\n",
            "class NonGen1:\n",
            "    def __iter__(self): return self\n",
            "    def __next__(self): return None\n",
            "    def close(self): pass\n",
            "    def throw(self, typ, val=None, tb=None): pass\n",
            "class NonGen2:\n",
            "    def __iter__(self): return self\n",
            "    def __next__(self): return None\n",
            "    def close(self): pass\n",
            "    def send(self, value): return value\n",
            "class NonGen3:\n",
            "    def close(self): pass\n",
            "    def send(self, value): return value\n",
            "    def throw(self, typ, val=None, tb=None): pass\n",
            "non_samples = [None, 42, 3.14, 1j, b'', '', (), [], {}, set(), iter(()), iter([]), NonGen1(), NonGen2(), NonGen3()]\n",
            "print([isinstance(x, Generator) for x in non_samples])\n",
            "print([issubclass(type(x), Generator) for x in non_samples])\n",
            "class Gen:\n",
            "    def __iter__(self): return self\n",
            "    def __next__(self): return None\n",
            "    def close(self): pass\n",
            "    def send(self, value): return value\n",
            "    def throw(self, typ, val=None, tb=None): pass\n",
            "class MinimalGen(Generator):\n",
            "    def send(self, value):\n",
            "        return value\n",
            "    def throw(self, typ, val=None, tb=None):\n",
            "        super().throw(typ, val, tb)\n",
            "def gen():\n",
            "    yield 1\n",
            "samples = [gen(), (lambda: (yield))(), Gen(), MinimalGen()]\n",
            "print([isinstance(x, Iterator) for x in samples])\n",
            "print([isinstance(x, Generator) for x in samples])\n",
            "print([issubclass(type(x), Generator) for x in samples])"
        ),
        &[
            "[False, False, False, False, False, False, False, False, False, False, False, False, False, False, False]",
            "[False, False, False, False, False, False, False, False, False, False, False, False, False, False, False]",
            "[True, True, True, True]",
            "[True, True, True, True]",
            "[True, True, True, True]",
        ],
    );
}

// Adapted from CPython Lib/test/test_collections.py::
// TestOneTrickPonyABCs::test_Generator. This ports the public Generator ABC
// mixin behavior for direct subclasses, including __iter__, __next__, throw,
// and close.
#[test]
fn cpython_collections_abc_generator_mixin_subset() {
    assert_output(
        concat!(
            "from collections.abc import Generator\n",
            "class MinimalGen(Generator):\n",
            "    def send(self, value):\n",
            "        return value\n",
            "    def throw(self, typ, val=None, tb=None):\n",
            "        super().throw(typ, val, tb)\n",
            "mgen = MinimalGen()\n",
            "print(iter(mgen) is mgen)\n",
            "print(mgen.send(None) is next(mgen))\n",
            "print(mgen.send(2))\n",
            "print(mgen.close())\n",
            "try:\n",
            "    mgen.throw(ValueError)\n",
            "except ValueError as error:\n",
            "    print(error.__class__.__name__, str(error) == '')\n",
            "try:\n",
            "    mgen.throw(ValueError, ValueError('huhu'))\n",
            "except ValueError as error:\n",
            "    print(error.__class__.__name__, str(error))\n",
            "try:\n",
            "    mgen.throw(StopIteration())\n",
            "except StopIteration as error:\n",
            "    print(error.__class__.__name__, str(error) == '')\n",
            "class FailOnClose(Generator):\n",
            "    def send(self, value): return value\n",
            "    def throw(self, *args): raise ValueError\n",
            "try:\n",
            "    FailOnClose().close()\n",
            "except ValueError as error:\n",
            "    print(error.__class__.__name__, str(error) == '')\n",
            "class IgnoreGeneratorExit(Generator):\n",
            "    def send(self, value): return value\n",
            "    def throw(self, *args): pass\n",
            "try:\n",
            "    IgnoreGeneratorExit().close()\n",
            "except RuntimeError as error:\n",
            "    print(error.__class__.__name__, str(error))"
        ),
        &[
            "True",
            "True",
            "2",
            "None",
            "ValueError True",
            "ValueError huhu",
            "StopIteration True",
            "ValueError True",
            "RuntimeError generator ignored GeneratorExit",
        ],
    );
}

// Adapted from CPython t-string helper grammar rules and the plain `string`
// grammar rule. MiniPython models t-strings as Template/Interpolation values,
// so the test checks literal middle parts, replacement fields, conversions,
// full format specs, and nested replacement fields inside format specs.
#[test]
fn cpython_string_and_tstring_helper_rules_subset() {
    assert_output("print('a' \"b\" '''c''')", &["abc"]);
    assert_output("print(r'\\n' == '\\\\n')", &["True"]);
    assert_output("print('a' f'{1}' \"b\")", &["a1b"]);
    assert_output(
        "template = t'a' t'{1}'\nprint(template.strings, template.interpolations[0].value)",
        &["('a', '') 1"],
    );
    assert_output(
        "name = 'Python'\nt = t'Hello {name}!'\nprint(t.strings)\nprint(t.interpolations[0].value, t.interpolations[0].expression, t.interpolations[0].conversion, t.interpolations[0].format_spec == '')",
        &["('Hello ', '!')", "Python name None True"],
    );
    assert_output(
        "text = 'Cafe'\nt = t'{text!r:^10}'\nprint(t.interpolations[0].conversion, t.interpolations[0].format_spec)",
        &["r ^10"],
    );
    assert_output(
        "value = 3.14159\nwidth = 6\nprec = 2\nt = t'{value:{width}.{prec}f}'\nprint(t.interpolations[0].expression, t.interpolations[0].format_spec)",
        &["value 6.2f"],
    );
    assert_output(
        "value = 42\nt = t'{value=}'\nprint(t.strings, t.interpolations[0].expression, t.interpolations[0].conversion)",
        &["('value=', '') value r"],
    );
    assert_output(
        "def g():\n    t = t'{yield \"need\"!s:^6}'\n    yield t.interpolations[0].value\n    yield t.interpolations[0].conversion\n    yield t.interpolations[0].format_spec\ngen = g()\nprint(next(gen))\nprint(gen.send('ok'))\nprint(next(gen))\nprint(next(gen))",
        &["need", "ok", "s", "^6"],
    );
}

// Adapted from CPython's invalid f-string grammar rules and
// Lib/test/test_fstring.py syntax-error coverage. MiniPython reports its own
// Rust error prefix but rejects the same source shapes before VM execution.
#[test]
fn cpython_invalid_f_string_syntax_subset() {
    assert_error("f'", "lex error: unterminated f-string literal");
    assert_error("f\"", "lex error: unterminated f-string literal");
    assert_error(
        "f'''",
        "lex error: unterminated triple-quoted f-string literal",
    );
    assert_error(
        "f\"\"\"",
        "lex error: unterminated triple-quoted f-string literal",
    );
    assert_error(
        "print(f'}')",
        "lex error: single '}' is not allowed in f-string literal",
    );
    assert_error(
        "print(f'{}')",
        "lex error: f-string: valid expression required before '}'",
    );
    assert_error(
        "print(f'{ }')",
        "lex error: f-string: valid expression required before '}'",
    );
    assert_error(
        "print(f' {} ')",
        "lex error: f-string: valid expression required before '}'",
    );
    assert_error(
        "print(f'{10:{ }}')",
        "lex error: f-string: valid expression required before '}'",
    );
    assert_error(
        "print(f' { } ')",
        "lex error: f-string: valid expression required before '}'",
    );
    assert_error(
        "print(f'{\n}')",
        "lex error: f-string: valid expression required before '}'",
    );
    assert_error(
        "print(f'''{\t\x0c\r\n}''')",
        "lex error: f-string: valid expression required before '}'",
    );
    assert_error(
        "print(f'{=x}')",
        "lex error: f-string: valid expression required before '='",
    );
    assert_error(
        "print(f'{=}')",
        "lex error: f-string: valid expression required before '='",
    );
    assert_error(
        "print(f'{ =}')",
        "lex error: f-string: valid expression required before '='",
    );
    assert_error(
        "print(f'{ =:}')",
        "lex error: f-string: valid expression required before '='",
    );
    assert_error(
        "print(f'{   =!}')",
        "lex error: f-string: valid expression required before '='",
    );
    assert_error(
        "print(f'''{\t\x0c\r\n=}''')",
        "lex error: f-string: valid expression required before '='",
    );
    assert_error(
        "print(f'{=')",
        "lex error: f-string: valid expression required before '='",
    );
    assert_error(
        "print(f'{!x}')",
        "lex error: f-string: valid expression required before '!'",
    );
    assert_error(
        "print(f'{!r}')",
        "lex error: f-string: valid expression required before '!'",
    );
    assert_error(
        "print(f'{ !r}')",
        "lex error: f-string: valid expression required before '!'",
    );
    assert_error(
        "print(f'{!}')",
        "lex error: f-string: valid expression required before '!'",
    );
    assert_error(
        "print(f'{!s:')",
        "lex error: f-string: valid expression required before '!'",
    );
    assert_error(
        "print(f'{ !xr}')",
        "lex error: f-string: valid expression required before '!'",
    );
    assert_error(
        "print(f'{!x:}')",
        "lex error: f-string: valid expression required before '!'",
    );
    assert_error(
        "print(f'{!x:a}')",
        "lex error: f-string: valid expression required before '!'",
    );
    assert_error(
        "print(f'{ !xr:}')",
        "lex error: f-string: valid expression required before '!'",
    );
    assert_error(
        "print(f'{ !xr:a}')",
        "lex error: f-string: valid expression required before '!'",
    );
    assert_error(
        "print(f'''{\t\x0c\r\n!a}''')",
        "lex error: f-string: valid expression required before '!'",
    );
    assert_error(
        "print(f'{:x}')",
        "lex error: f-string: valid expression required before ':'",
    );
    assert_error(
        "print(f'{:}')",
        "lex error: f-string: valid expression required before ':'",
    );
    assert_error(
        "print(f'{ :!}')",
        "lex error: f-string: valid expression required before ':'",
    );
    assert_error(
        "print(f'{:2}')",
        "lex error: f-string: valid expression required before ':'",
    );
    assert_error(
        "print(f'''{\t\x0c\r\n:a}''')",
        "lex error: f-string: valid expression required before ':'",
    );
    assert_error(
        "print(f'{:')",
        "lex error: f-string: valid expression required before ':'",
    );
    assert_error(
        "print(f'''{\u{a0}}''')",
        "parse error: f-string: invalid non-printable character U+00A0",
    );
    for source in [
        "print(f'{lambda x:x}')",
        "print(f'{lambda :x}')",
        "print(f'{lambda *arg, :x}')",
        "print(f'{1, lambda:x}')",
        "print(f'{lambda x:}')",
        "print(f'{lambda :}')",
    ] {
        assert_error(
            source,
            "parse error: f-string: lambda expressions are not allowed without parentheses",
        );
    }
    assert_parse_error("print(f'{+ lambda:None}')");
    // Adapted from CPython Lib/test/test_fstring.py
    // test_syntax_error_for_starred_expressions.
    assert_rejected("print(f'{*a}')");
    assert_rejected("print(f'{**a}')");
    assert_error("print(f'{3')", "lex error: f-string: expecting '}'");
    assert_error("print(f'{3!')", "lex error: f-string: expecting '}'");
    assert_error("print(f'{3!s')", "lex error: f-string: expecting '}'");
    assert_error("print(f'x{')", "lex error: f-string: expecting '}'");
    assert_error("print(f'x{x')", "lex error: f-string: expecting '}'");
    assert_error(
        "print(f'{?}')",
        "parse error: f-string: unexpected character: ?",
    );
    assert_error(
        "print(f'{x y}')",
        "parse error: f-string expression parse error: expected end of input, found Identifier(\"y\")",
    );
    for source in [
        "print(f'{1#}')",
        "print(f'{#}')",
        "print(f'one: {1#}')",
        "print(f'{1# one} {2 this is a comment still#}')",
        "print(f'{)#}')",
    ] {
        assert_rejected(source);
    }
    assert_error(
        "print(f'{x=y}')",
        "lex error: f-string: expecting '!', or ':', or '}'",
    );
    // Adapted from CPython Lib/test/test_fstring.py
    // test_invalid_syntax_error_message.
    assert_rejected("print(f'{a $ b}')");
    assert_rejected("print(f'{x;y}')");
    assert_rejected("print(f'{x:{;}}')");
    assert_error(
        "print(f'{x!}')",
        "lex error: f-string: missing conversion character",
    );
    assert_rejected("print(f'{x!:}')");
    assert_rejected("print(f'{x!:}' )");
    assert_error(
        "print(f'{x=!}')",
        "lex error: f-string: missing conversion character",
    );
    assert_error(
        "print(f'{x=!3}')",
        "lex error: f-string: invalid conversion character: 3",
    );
    assert_error(
        "print(f'{x!z}')",
        "lex error: f-string: invalid conversion character: z",
    );
    assert_error(
        "print(f'{x! s}')",
        "lex error: f-string: conversion type must come right after the exclamation mark",
    );
    assert_error(
        "print(f'{x!ss}')",
        "lex error: f-string: invalid conversion character: ss",
    );
    assert_error(
        "print(f'{x!ss:}')",
        "lex error: f-string: invalid conversion character: ss",
    );
    assert_error(
        "print(f'{x!ss:s}')",
        "lex error: f-string: invalid conversion character: ss",
    );
    assert_error(
        "print(f'{x!3}')",
        "lex error: f-string: invalid conversion character: 3",
    );
    assert_error(
        "print(f'{x!!}')",
        "lex error: f-string: invalid conversion character: !",
    );
    assert_error(
        "print(f'{x!s!}')",
        "lex error: f-string: expecting ':' or '}'",
    );
    assert_error(
        "print(f'{x!s:')",
        "lex error: f-string: expecting '}', or format specs",
    );
    assert_error(
        "print(f'{1:d\n}')",
        "lex error: f-string: newlines are not allowed in format specifiers",
    );
    assert_error(
        "print(f'{1:{2}\n}')",
        "lex error: f-string: newlines are not allowed in format specifiers",
    );
    assert_error(
        "print(f'{3:}>10}')",
        "lex error: single '}' is not allowed in f-string literal",
    );
    assert_error(
        "print(f'{3:}}>10}')",
        "lex error: single '}' is not allowed in f-string literal",
    );
    assert_error("print(f'{1#}')", "lex error: f-string: expecting '}'");
    assert_error("print(f'{#}')", "lex error: f-string: expecting '}'");
    assert_error("print(f'one: {1#}')", "lex error: f-string: expecting '}'");
    // Adapted from CPython Lib/test/test_fstring.py
    // test_syntax_error_after_debug.
    for source in [
        "print(f'{1=}{;')",
        "print(f'{1=}{+;')",
        "print(f'{1=}{2}{;')",
        "print(f'{1=}{3}{;')",
        "print(f'{1=}{1;')",
        "print(f'{1=}{1;}')",
    ] {
        assert_rejected(source);
    }
    for source in [
        r#"print(f'{\'a\'}')"#,
        r#"print(rf'{\'a\'}')"#,
        r#"print(f'{\t3}')"#,
        r#"print(rf'{\t3}')"#,
        r#"print(f'{\}')"#,
        r#"print(rf'{\}')"#,
    ] {
        assert_rejected(source);
    }
}

