// Adapted from CPython tokenizer COMMENT/NL examples in Lib/test/test_tokenize.py.
// MiniPython does not expose comment tokens; it preserves the same executable
// structure by ignoring comments and retaining newlines as statement boundaries.
#[test]
fn cpython_tokenize_comments_subset() {
    assert_output("# leading\nprint(1) # inline\n# trailing", &["1"]);
    assert_output(
        "if True:\n    # NL\n    \n    print(\"body\") # NEWLINE\n",
        &["body"],
    );
}

// Adapted from CPython tokenizer implicit line-joining coverage for bracketed
// expressions. MiniPython ignores physical newlines inside (), [], and {}.
#[test]
fn cpython_tokenize_implicit_line_joining_subset() {
    assert_output("print(\n    1,\n    2,\n)", &["1 2"]);
    assert_output("items = [\n    1,\n    2,\n]\nprint(items)", &["[1, 2]"]);
    assert_output(
        "mapping = {\n    \"a\": 1,\n    \"b\": 2,\n}\nprint(mapping[\"b\"])",
        &["2"],
    );
    assert_output(
        "a = (3,4, \n5,6)\ny = [3, 4,\n5]\nz = {'a': 5,\n'b':15, 'c':True}\nx = len(y) + 5 - a[\n3] - a[2]\n+ len(z) - z[\n'b']\nprint(x)",
        &["-3"],
    );

    let source = "[\n    # A comment here\n    1\n]\n";
    let tokens = tokenize_with_spans(source).unwrap();
    assert_token_text_span(source, &tokens[0], Token::LeftBracket, "[", 1, 1, 1, 2);
    assert_token_text_span(source, &tokens[1], Token::Number(1), "1", 3, 5, 3, 6);
    assert_token_text_span(source, &tokens[2], Token::RightBracket, "]", 4, 1, 4, 2);
    assert_token_text_span(source, &tokens[3], Token::Newline, "\n", 4, 2, 5, 1);
    assert_token_span(&tokens[4], Token::Eof, 5, 1, 5, 1);
}

// Adapted from CPython tokenizer explicit line-joining coverage in
// Lib/test/test_tokenize.py::test_backslash_continuation and
// Lib/test/test_syntax.py::test_invalid_line_continuation_error_position,
// plus SyntaxErrorTestCase::test_empty_line_after_linecont and
// ::test_continuation_bad_indentation.
#[test]
fn cpython_tokenize_explicit_line_joining_subset() {
    fn token_text_signature(source: &str) -> Vec<(Token, String)> {
        tokenize_with_spans(source)
            .unwrap()
            .into_iter()
            .map(|token| {
                let text = spanned_token_text(source, &token);
                (token.token, text)
            })
            .collect()
    }

    assert_output("x = 1 + \\\n2\nprint(x)", &["3"]);
    assert_output("x = 1 + \\\r\n2\r\nprint(x)", &["3"]);
    assert_output("x = 1 + \\\n    2\nprint(x)", &["3"]);
    assert_output("items = [1, \\\n2]\nprint(items)", &["[1, 2]"]);
    assert_output("print(1) # \\\nprint(2)", &["1", "2"]);
    assert_output("# Comment \\\nx = 0\nprint(x)", &["0"]);
    assert_output("pass\n    \\\n\nprint(\"after\")", &["after"]);
    assert_output("pass\n        \\\n\npass\nprint(\"ok\")", &["ok"]);
    assert_output(
        "def fib(n):\n    \\\n'''Print a Fibonacci series up to n.'''\n    \\\na, b = 0, 1\n    return a + b\nprint(fib(0))",
        &["1"],
    );
    assert_output(
        "def fib(n):\n    \\\n'''Print a Fibonacci series up to n.'''\n    \\\na, b = 0, 1\nprint(\"defined\")",
        &["defined"],
    );
    assert_output(
        "if True:\n    y = 1\n    \\\n            \\\n        \\\n    \\\n    print(y)",
        &["1"],
    );

    let continuation_docstring =
        "def fib(n):\n    \\\n'''Print a Fibonacci series up to n.'''\n    \\\na, b = 0, 1";
    let plain_docstring =
        "def fib(n):\n    '''Print a Fibonacci series up to n.'''\n    a, b = 0, 1";
    assert_eq!(
        token_text_signature(continuation_docstring),
        token_text_signature(plain_docstring),
    );

    let continuation_between_passes = "pass\n    \\\n\npass";
    let plain_passes = "pass\npass";
    assert_eq!(
        token_text_signature(continuation_between_passes),
        token_text_signature(plain_passes),
    );

    assert_error(
        r#"a = 3 \ 4"#,
        "lex error: unexpected character after line continuation character",
    );
    assert_error(
        "1,\\#\n2",
        "lex error: unexpected character after line continuation character",
    );
    assert_error(
        "\nfgdfgf\n1,\\#\n2\n",
        "lex error: unexpected character after line continuation character",
    );
    assert_error(
        "A.\u{018a}\\ ",
        "lex error: unexpected character after line continuation character",
    );
    assert_error("A.\u{03bc}\\\n", "lex error: unexpected EOF while parsing");
    assert_error(
        "if x:\n    y = 1\n  \\\n  foo = 1\n        ",
        "lex error: unindent does not match any outer indentation level",
    );

    assert_lex_error_diagnostic(
        r#"a = 3 \ 4"#,
        "unexpected character after line continuation character",
        1,
        8,
        1,
        9,
    );
    assert_lex_error_diagnostic(
        "1,\\#\n2",
        "unexpected character after line continuation character",
        1,
        4,
        1,
        5,
    );
    assert_lex_error_diagnostic(
        "\nfgdfgf\n1,\\#\n2\n",
        "unexpected character after line continuation character",
        3,
        4,
        3,
        5,
    );
    assert_lex_error_diagnostic(
        "A.\u{018a}\\ ",
        "unexpected character after line continuation character",
        1,
        5,
        1,
        6,
    );
    assert_lex_error_diagnostic("A.\u{03bc}\\\n", "unexpected EOF while parsing", 1, 5, 2, 1);
}

// Adapted from CPython
// Lib/test/test_syntax.py::SyntaxErrorTestCase::test_error_parenthesis.
// This pins the syntax-layer behavior for unmatched, mismatched, and unclosed
// delimiters, including byte-source decoding before parser diagnostics.
#[test]
fn cpython_syntax_error_parenthesis_subset() {
    for (source, expected) in [
        ("(1 + 2", "'(' was never closed"),
        ("[1 + 2", "'[' was never closed"),
        ("{1 + 2", "'{' was never closed"),
        ("a = ( 1, 2, 3\nb=3", "'(' was never closed"),
        ("a = [ 1, 2, 3\nb=3", "'[' was never closed"),
        ("a = { 1, 2, 3\nb=3", "'{' was never closed"),
    ] {
        assert_error_contains(source, expected);
    }

    for (source, expected) in [
        (")1 + 2", "lex error: unmatched ')'"),
        ("]1 + 2", "lex error: unmatched ']'"),
        ("}1 + 2", "lex error: unmatched '}'"),
    ] {
        assert_error(source, expected);
    }

    assert_error(
        "func(\n    a=[\"unclosed], # Need a quote in this comment: \"\n    b=2,\n)\n",
        "lex error: closing parenthesis ')' does not match opening parenthesis '['",
    );
    assert_error_contains("match y:\n case e(e=v,v,", "was never closed");
    assert_bytes_error(
        b"# coding=latin\n(aaaaaaaaaaaaaaaaa\naaaaaaaaaaa\xb5",
        "'(' was never closed",
    );
}

