// Adapted from CPython tokenizer formfeed handling in Parser/lexer/lexer.c.
// CPython treats formfeed as whitespace and resets indentation columns when it
// appears in leading whitespace.
#[test]
fn cpython_tokenize_formfeed_whitespace_subset() {
    assert_output("x\x0c=1\nprint(x)", &["1"]);
    assert_output("if True:\n\x0c    print(1)", &["1"]);

    let tokens = tokenize_with_spans("x\x0c=1").unwrap();
    assert_token_text_span(
        "x\x0c=1",
        &tokens[0],
        Token::Identifier("x".to_string()),
        "x",
        1,
        1,
        1,
        2,
    );
    assert_token_text_span("x\x0c=1", &tokens[1], Token::Equal, "=", 1, 3, 1, 4);
}

// Adapted from CPython's Lib/test/test_tokenize.py::test_max_indent. CPython
// accepts 99 nested indentation levels and rejects the 100th nested level.
#[test]
fn cpython_tokenize_max_indent_subset() {
    fn nested_source(indents: usize) -> String {
        let mut source = String::new();
        for level in 0..indents {
            source.push_str(&"  ".repeat(level));
            source.push_str("if True:\n");
        }
        source.push_str(&"  ".repeat(indents));
        source.push_str("pass\n");
        source
    }

    let accepted = tokenize_cpython_with_spans(&nested_source(99)).unwrap();
    assert_eq!(
        accepted
            .iter()
            .filter(|token| matches!(&token.token, Token::Indent))
            .count(),
        99
    );
    assert_eq!(
        accepted
            .iter()
            .filter(|token| matches!(&token.token, Token::Dedent))
            .count(),
        99
    );

    let error = tokenize_cpython_with_spans(&nested_source(100))
        .expect_err("expected the 100th nested indentation level to fail");
    assert_eq!(error.message, "too many levels of indentation");
}

// Adapted from CPython TokenError/ERRORTOKEN cases in
// Lib/test/test_tokenize.py. MiniPython does not expose CPython's token stream,
// but it must still reject these tokenizer-level bad source shapes before
// successful execution.
#[test]
fn cpython_tokenize_error_token_subset() {
    assert_rejected("€");
    assert_lex_error_diagnostic("€", "unexpected character: €", 1, 1, 1, 2);
    assert_rejected("\u{a0}");
    assert_lex_error_diagnostic(
        "\u{a0}",
        "invalid non-printable character U+00A0",
        1,
        1,
        1,
        2,
    );
    assert_lex_error_diagnostic(
        "print\x17(\"Hello\")",
        "invalid non-printable character U+0017",
        1,
        6,
        1,
        7,
    );
    assert_lex_error_diagnostic(
        "with(0,,):\n\x01",
        "invalid non-printable character U+0001",
        2,
        1,
        2,
        2,
    );
    assert_error("import ä £", "lex error: unexpected character: £");
    assert_lex_error_diagnostic("import ä £", "unexpected character: £", 1, 10, 1, 11);
    assert_error("]", "lex error: unmatched ']'");
    assert_lex_error_diagnostic("]", "unmatched ']'", 1, 1, 1, 2);
    assert_error(
        "(1+2]",
        "lex error: closing parenthesis ']' does not match opening parenthesis '('",
    );
    assert_lex_error_diagnostic(
        "(1+2]",
        "closing parenthesis ']' does not match opening parenthesis '('",
        1,
        5,
        1,
        6,
    );
    assert_error(
        "(1+2}",
        "lex error: closing parenthesis '}' does not match opening parenthesis '('",
    );
    assert_lex_error_diagnostic(
        "(1+2}",
        "closing parenthesis '}' does not match opening parenthesis '('",
        1,
        5,
        1,
        6,
    );
    assert_error(
        "{1+2]",
        "lex error: closing parenthesis ']' does not match opening parenthesis '{'",
    );
    assert_lex_error_diagnostic(
        "{1+2]",
        "closing parenthesis ']' does not match opening parenthesis '{'",
        1,
        5,
        1,
        6,
    );
    assert_lex_error_diagnostic(
        "(\n]",
        "closing parenthesis ']' does not match opening parenthesis '('",
        2,
        1,
        2,
        2,
    );
    assert_lex_error_diagnostic("(", "EOF in multi-line statement", 1, 2, 1, 2);
    assert_lex_error_diagnostic("[", "EOF in multi-line statement", 1, 2, 1, 2);
    assert_lex_error_diagnostic("{", "EOF in multi-line statement", 1, 2, 1, 2);
    assert_lex_error_diagnostic("(1\n", "EOF in multi-line statement", 2, 1, 2, 1);
    assert_lex_error_diagnostic("[1", "EOF in multi-line statement", 1, 3, 1, 3);
    assert_lex_error_diagnostic("{1: 2", "EOF in multi-line statement", 1, 6, 1, 6);
    assert_lex_error_diagnostic(
        "'''sdfsdf''",
        "unterminated triple-quoted string literal",
        1,
        1,
        1,
        12,
    );
    assert_lex_error_diagnostic(
        "\"\"\"sdfsdf\nsecond",
        "unterminated triple-quoted string literal",
        1,
        1,
        2,
        7,
    );
    assert_rejected("f'__{\n    x:d\n}__'");
    assert_error("\\", "lex error: unexpected EOF while parsing");
    assert_lex_error_diagnostic("\\", "unexpected EOF while parsing", 1, 1, 1, 2);
    assert_rejected(" a\n\u{0}");
    assert_lex_error_diagnostic(
        " a\n\u{0}",
        "source code cannot contain null bytes",
        2,
        1,
        2,
        2,
    );
    assert_error(
        &format!("{}a{}", "(".repeat(1000), ")".repeat(1000)),
        "lex error: too many nested parentheses",
    );
}

