// Adapted from CPython Lib/test/test_compile.py::TestStaticAttributes.
// CPython collects Store targets named exactly `self.<attr>` into a sorted
// tuple on the nearest class as `__static_attributes__`.
#[test]
fn cpython_compile_static_attributes_exact_subset() {
    assert_output(
        "class C:\n    def f(self):\n        self.a = self.b = 42\n        self.f()\n        self.arr[3]\nprint(isinstance(C.__static_attributes__, tuple), sorted(C.__static_attributes__))",
        &["True ['a', 'b']"],
    );
    assert_output(
        "class C:\n    def f(self):\n        self.x = 1\n        self.y = 2\n        self.x = 3\n    def g(self, obj):\n        self.y = 4\n        self.z = 5\n        def h(self, a):\n            self.u = 6\n            self.v = 7\n        obj.self = 8\nprint(sorted(C.__static_attributes__))",
        &["['u', 'v', 'x', 'y', 'z']"],
    );
    assert_output(
        "class C:\n    def f(self):\n        self.x = 42\n        self.y = 42\n    class D:\n        def g(self):\n            self.y = 42\n            self.z = 42\nprint(sorted(C.__static_attributes__), sorted(C.D.__static_attributes__))",
        &["['x', 'y'] ['y', 'z']"],
    );
    assert_output(
        "class C:\n    def f(self):\n        self.x = 42\n        self.y = 42\nclass D(C):\n    def g(self):\n        self.y = 42\n        self.z = 42\nprint(sorted(C.__static_attributes__), sorted(D.__static_attributes__))",
        &["['x', 'y'] ['y', 'z']"],
    );
}

